import { Inject, Injectable, NestInterceptor, ExecutionContext, CallHandler, SetMetadata } from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Observable, from, of, switchMap } from 'rxjs';

import { TypedCacheService } from './typed-cache.service';

const CACHEABLE_TTL = 'cacheable:ttl';
const CACHEABLE_KEY_GENERATOR = 'cacheable:keyGenerator';
const CACHE_EVICT_PATTERN = 'cacheEvict:pattern';

export const Cacheable = (ttl?: number, keyGenerator?: (...args: any[]) => string) => {
  const decorators: (ClassDecorator | MethodDecorator)[] = [];
  if (ttl !== undefined) {
    decorators.push(SetMetadata(CACHEABLE_TTL, ttl));
  }
  if (keyGenerator) {
    decorators.push(SetMetadata(CACHEABLE_KEY_GENERATOR, keyGenerator));
  }
  return (target: any, propertyKey?: string, descriptor?: PropertyDescriptor) => {
    decorators.forEach((decorator) => {
      if (descriptor && propertyKey) {
        (decorator as MethodDecorator)(target, propertyKey, descriptor);
      } else {
        (decorator as ClassDecorator)(target);
      }
    });
  };
};

export const CacheEvict = (pattern: string) => SetMetadata(CACHE_EVICT_PATTERN, pattern);

@Injectable()
export class CacheInterceptor implements NestInterceptor {
  constructor(
    private readonly reflector: Reflector,
    @Inject(TypedCacheService) private readonly cacheService: TypedCacheService,
  ) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const ttl = this.reflector.get<number>(CACHEABLE_TTL, context.getHandler());
    const keyGenerator = this.reflector.get<(...args: any[]) => string>(
      CACHEABLE_KEY_GENERATOR,
      context.getHandler(),
    );

    const className = context.getClass().name;
    const methodName = context.getHandler().name;
    const args = context.getArgs();

    const cacheKey = keyGenerator
      ? keyGenerator(...args)
      : `${className}:${methodName}:${JSON.stringify(args)}`;

    return from(this.cacheService.get<any>(cacheKey)).pipe(
      switchMap((cached) => {
        if (cached !== null) {
          return of(cached);
        }

        return next.handle().pipe(
          switchMap((result) =>
            from(this.cacheService.set(cacheKey, result, ttl)).pipe(
              switchMap(() => of(result)),
            ),
          ),
        );
      }),
    );
  }
}

@Injectable()
export class CacheEvictInterceptor implements NestInterceptor {
  constructor(
    private readonly reflector: Reflector,
    @Inject(TypedCacheService) private readonly cacheService: TypedCacheService,
  ) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const pattern = this.reflector.get<string>(CACHE_EVICT_PATTERN, context.getHandler());

    return next.handle().pipe(
      switchMap((result) => {
        if (pattern) {
          return from(this.cacheService.invalidate(pattern)).pipe(
            switchMap(() => of(result)),
          );
        }
        return of(result);
      }),
    );
  }
}

import { REDIS_KEY_PREFIX, REDIS_KEY_SEPARATOR } from '../redis/redis.service';

export interface CacheKey {
  module: string;
  entity: string;
  id: string;
  version?: number;
  params?: Record<string, string>;
}

export class CacheKeyBuilder {
  private static join(...parts: string[]): string {
    return parts.filter(Boolean).join(REDIS_KEY_SEPARATOR);
  }

  static build(key: CacheKey): string {
    const parts = [REDIS_KEY_PREFIX, key.module, key.entity, key.id];
    if (key.version !== undefined) {
      parts.push(`v${key.version}`);
    }
    return CacheKeyBuilder.join(...parts);
  }

  static withHashTag(key: CacheKey, slotKey?: string): string {
    const built = CacheKeyBuilder.build(key);
    const slot = slotKey ?? key.id;
    const inner = `${REDIS_KEY_PREFIX}${REDIS_KEY_SEPARATOR}${slot}`;
    return `{${inner}}${REDIS_KEY_SEPARATOR}${CacheKeyBuilder.join(key.module, key.entity, key.id)}`;
  }

  static userProfile(userId: string): string {
    return CacheKeyBuilder.build({ module: 'user', entity: 'profile', id: userId });
  }

  static styleProfile(userId: string): string {
    return CacheKeyBuilder.build({ module: 'user', entity: 'style', id: userId });
  }

  static quizQuestions(quizId?: string): string {
    return CacheKeyBuilder.build({ module: 'quiz', entity: 'questions', id: quizId ?? 'all' });
  }

  static recommendations(userId: string, context?: string): string {
    const id = context ? `${userId}:${context}` : userId;
    return CacheKeyBuilder.build({ module: 'recommendation', entity: 'list', id });
  }

  static aiResult(userId: string, resultId: string): string {
    return CacheKeyBuilder.build({ module: 'ai', entity: 'result', id: `${userId}:${resultId}` });
  }

  static clothingItem(itemId: string): string {
    return CacheKeyBuilder.build({ module: 'clothing', entity: 'item', id: itemId });
  }

  static communityPosts(sortBy?: string, page?: number): string {
    const id = `${sortBy ?? 'latest'}:${page ?? 1}`;
    return CacheKeyBuilder.build({ module: 'community', entity: 'posts', id });
  }

  static pattern(module: string, entity: string): string {
    return CacheKeyBuilder.join(REDIS_KEY_PREFIX, module, entity) + `${REDIS_KEY_SEPARATOR}*`;
  }
}

﻿/**
 * Environment Variable Validation
 *
 * This module provides validation for critical environment variables
 * to ensure security requirements are met before the application starts.
 */

import { Logger } from '@nestjs/common';

const logger = new Logger('EnvValidation');
type EnvConfig = Record<string, string | undefined>;

/**
 * Validation result for environment variables
 */
interface ValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
}

/**
 * Check if running in production environment
 */
function isProduction(nodeEnv?: string): boolean {
  return nodeEnv === 'production';
}

/**
 * Validate JWT secret key strength
 */
function validateJwtSecret(
  secret: string | undefined,
  name: string,
  nodeEnv?: string,
): string[] {
  const errors: string[] = [];

  if (!secret) {
    errors.push(`${name} is not set`);
    return errors;
  }

  // Check for placeholder values
  const placeholderPatterns = [
    /your-.*-here/i,
    /<.*>/,
    /change.*production/i,
    /xuno-dev-secret/i,
  ];

  for (const pattern of placeholderPatterns) {
    if (pattern.test(secret)) {
      errors.push(`${name} contains a placeholder value - please set a real secret`);
      return errors;
    }
  }

  // Production-specific validation
  if (isProduction(nodeEnv)) {
    if (secret.length < 64) {
      errors.push(`${name} must be at least 64 characters in production (current: ${secret.length})`);
    }

    // Check for weak patterns
    const weakPatterns = [
      /^[a-zA-Z0-9]{1,20}$/,  // Simple alphanumeric
      /^(password|secret|key|token)/i,  // Common prefixes
      /123456/,  // Sequential numbers
      /qwerty/i,  // Common patterns
    ];

    for (const pattern of weakPatterns) {
      if (pattern.test(secret)) {
        errors.push(`${name} appears to be weak or predictable in production`);
        break;
      }
    }
  }

  return errors;
}

/**
 * Validate database credentials
 */
function validateDatabaseCredentials(
  url: string | undefined,
  password: string | undefined,
  nodeEnv: string | undefined,
  warnings: string[],
): string[] {
  const errors: string[] = [];

  if (!url && !password) {
    errors.push('DATABASE_URL or POSTGRES_PASSWORD must be set');
    return errors;
  }

  // Check for placeholder values in URL
  if (url) {
    const placeholderPatterns = [
      /your-.*-here/i,
      /<.*>/,
    ];

    for (const pattern of placeholderPatterns) {
      if (pattern.test(url)) {
        errors.push('DATABASE_URL contains a placeholder value - please set real credentials');
        return errors;
      }
    }

    // Check for weak default credentials
    if (url.includes('postgres:postgres@')) {
      if (isProduction(nodeEnv)) {
        errors.push('DATABASE_URL uses default postgres password - not allowed in production');
      } else {
        warnings.push('DATABASE_URL uses default postgres password - consider using a stronger password');
      }
    }
  }

  // Check password placeholder
  if (password) {
    const placeholderPatterns = [
      /your-.*-here/i,
      /<.*>/,
    ];

    for (const pattern of placeholderPatterns) {
      if (pattern.test(password)) {
        errors.push('POSTGRES_PASSWORD contains a placeholder value - please set a real password');
        break;
      }
    }
  }

  return errors;
}

/**
 * Validate Redis configuration
 */
function validateRedisConfig(
  url: string | undefined,
  password: string | undefined,
  nodeEnv: string | undefined,
  warnings: string[],
): string[] {
  const errors: string[] = [];

  if (!url) {
    errors.push('REDIS_URL must be set');
    return errors;
  }

  // Check for placeholder values
  const placeholderPatterns = [
    /your-.*-here/i,
    /<.*>/,
  ];

  for (const pattern of placeholderPatterns) {
    if (pattern.test(url)) {
      errors.push('REDIS_URL contains a placeholder value - please set real credentials');
      return errors;
    }
  }

  // Check if Redis has password
  const hasPasswordInUrl = url.includes(':@') === false && url.match(/:[^:@]+@/);
  const hasPassword = password || hasPasswordInUrl;

  if (isProduction(nodeEnv) && !hasPassword) {
    errors.push('Redis must have a password configured in production (set REDIS_PASSWORD or include in REDIS_URL)');
  } else if (!hasPassword) {
    warnings.push('Redis has no password configured - consider adding REDIS_PASSWORD for better security');
  }

  return errors;
}

/**
 * Validate MinIO/S3 credentials
 */
function validateStorageCredentials(
  accessKey: string | undefined,
  secretKey: string | undefined,
  nodeEnv: string | undefined,
  warnings: string[],
): string[] {
  const errors: string[] = [];

  // Check for placeholder values
  const placeholderPatterns = [
    /your-.*-here/i,
    /<.*>/,
  ];

  if (accessKey) {
    for (const pattern of placeholderPatterns) {
      if (pattern.test(accessKey)) {
        errors.push('MINIO_ACCESS_KEY contains a placeholder value - please set real credentials');
        return errors;
      }
    }
  }

  if (secretKey) {
    for (const pattern of placeholderPatterns) {
      if (pattern.test(secretKey)) {
        errors.push('MINIO_SECRET_KEY contains a placeholder value - please set real credentials');
        return errors;
      }
    }
  }

  // Check for default credentials
  if (accessKey === 'minioadmin' && secretKey === 'minioadmin') {
    if (isProduction(nodeEnv)) {
      errors.push('MinIO is using default credentials (minioadmin:minioadmin) - not allowed in production');
    } else {
      warnings.push('MinIO is using default credentials - consider changing for better security');
    }
  }

  return errors;
}

/**
 * Validate API keys (GLM, OpenAI, etc.)
 */
function validateApiKeys(env: EnvConfig, warnings: string[]): string[] {
  const errors: string[] = [];
  const glmApiKey = env.GLM_API_KEY;
  const openaiApiKey = env.OPENAI_API_KEY;
  const aiStylistApiKey = env.AI_STYLIST_API_KEY;

  // Check for placeholder values
  const placeholderPatterns = [
    /your-.*-here/i,
    /<.*>/,
  ];

  if (glmApiKey) {
    for (const pattern of placeholderPatterns) {
      if (pattern.test(glmApiKey)) {
        errors.push('GLM_API_KEY contains a placeholder value - please set a real API key or remove it');
        return errors;
      }
    }
  }

  if (openaiApiKey) {
    for (const pattern of placeholderPatterns) {
      if (pattern.test(openaiApiKey)) {
        warnings.push('OPENAI_API_KEY contains a placeholder value');
        break;
      }
    }
  }

  // At least one LLM API key should be configured
  if (!glmApiKey && !openaiApiKey && !aiStylistApiKey) {
    warnings.push('No LLM API key configured (GLM_API_KEY, OPENAI_API_KEY, or AI_STYLIST_API_KEY) - AI features may not work');
  }

  return errors;
}

/**
 * Main validation function - validates all critical environment variables
 */
export function validateEnvironment(env: EnvConfig = process.env): ValidationResult {
  const errors: string[] = [];
  const warnings: string[] = [];
  const nodeEnv = env.NODE_ENV;

  logger.log('Validating environment variables...');

  // Validate JWT secrets
  errors.push(...validateJwtSecret(env.JWT_SECRET, 'JWT_SECRET', nodeEnv));

  if (env.JWT_REFRESH_SECRET) {
    errors.push(...validateJwtSecret(env.JWT_REFRESH_SECRET, 'JWT_REFRESH_SECRET', nodeEnv));
  }

  // Validate CSRF secret
  errors.push(...validateJwtSecret(env.CSRF_SECRET, 'CSRF_SECRET', nodeEnv));

  // Validate database credentials
  errors.push(
    ...validateDatabaseCredentials(
      env.DATABASE_URL,
      env.POSTGRES_PASSWORD,
      nodeEnv,
      warnings,
    ),
  );

  // Validate Redis configuration
  errors.push(
    ...validateRedisConfig(
      env.REDIS_URL,
      env.REDIS_PASSWORD,
      nodeEnv,
      warnings,
    ),
  );

  // Validate storage credentials
  errors.push(
    ...validateStorageCredentials(
      env.MINIO_ACCESS_KEY,
      env.MINIO_SECRET_KEY,
      nodeEnv,
      warnings,
    ),
  );

  // Validate API keys
  errors.push(...validateApiKeys(env, warnings));

  // Log results
  if (errors.length > 0) {
    logger.error('Environment validation failed:');
    errors.forEach(err => logger.error(`  - ${err}`));
  }

  if (warnings.length > 0) {
    logger.warn('Environment validation warnings:');
    warnings.forEach(warn => logger.warn(`  - ${warn}`));
  }

  if (errors.length === 0 && warnings.length === 0) {
    logger.log('Environment validation passed');
  }

  return {
    valid: errors.length === 0,
    errors,
    warnings,
  };
}

/**
 * NestJS factory function for environment validation
 * Use this in app.module.ts to validate on startup
 */
export function envValidationFactory(config: Record<string, any>) {
  const result = validateEnvironment(config as EnvConfig);

  // In production, fail fast on errors
  if (isProduction(config.NODE_ENV) && !result.valid) {
    throw new Error(`Environment validation failed:\n${result.errors.join('\n')}`);
  }

  // In development, just warn
  if (!result.valid) {
    logger.warn('Environment has validation errors - some features may not work correctly');
  }

  return config;
}

import { Type, applyDecorators } from "@nestjs/common";
import { ApiExtraModels, ApiOkResponse, getSchemaPath } from "@nestjs/swagger";

export class JsonApiDataDto {
  id!: string;
  type!: string;
  attributes!: Record<string, any>;
}

export class JsonApiResponseDto {
  data!: JsonApiDataDto | JsonApiDataDto[];
  included?: JsonApiDataDto[];
  meta?: Record<string, any>;
}

export const ApiJsonApiResponse = <TModel extends Type<any>>(model: TModel, options?: { isArray?: boolean }) => {
  return applyDecorators(
    ApiExtraModels(JsonApiResponseDto, model),
    ApiOkResponse({
      description: options?.isArray ? "JSON:API 列表响应" : "JSON:API 单条响应",
      schema: {
        allOf: [
          { $ref: getSchemaPath(JsonApiResponseDto) },
          {
            properties: {
              data: options?.isArray
                ? { type: "array", items: { $ref: getSchemaPath(model) } }
                : { $ref: getSchemaPath(model) },
            },
          },
        ],
      },
    }),
  );
};

import { Type, applyDecorators } from "@nestjs/common";
import { ApiExtraModels, ApiOkResponse, getSchemaPath } from "@nestjs/swagger";

export class PaginatedDto<T> {
  data!: T[];
  meta!: {
    total: number;
    page: number;
    limit: number;
    totalPages: number;
    hasNext: boolean;
    hasPrev: boolean;
  };
}

export const ApiPaginatedResponse = <TModel extends Type<any>>(model: TModel) => {
  return applyDecorators(
    ApiExtraModels(PaginatedDto, model),
    ApiOkResponse({
      description: "分页数据",
      schema: {
        allOf: [
          { $ref: getSchemaPath(PaginatedDto) },
          {
            properties: {
              data: {
                type: "array",
                items: { $ref: getSchemaPath(model) },
              },
            },
          },
        ],
      },
    }),
  );
};

import { applyDecorators } from "@nestjs/common";
import {
  ApiExtraModels,
  ApiOkResponse,
  ApiQuery,
  getSchemaPath,
} from "@nestjs/swagger";

import { PaginatedMetaDto, PaginatedResponseDto } from "../dto/paginated-response.dto";

export function ApiPaginated(model: () => new (...args: any[]) => any) {
  return applyDecorators(
    ApiExtraModels(model, PaginatedResponseDto, PaginatedMetaDto),
    ApiOkResponse({
      description: "Paginated response",
      schema: {
        allOf: [
          { $ref: getSchemaPath(PaginatedResponseDto) },
          {
            properties: {
              items: {
                type: "array",
                items: { $ref: getSchemaPath(model) },
              },
              meta: {
                $ref: getSchemaPath(PaginatedMetaDto),
              },
            },
          },
        ],
      },
    }),
    ApiQuery({
      name: "cursor",
      required: false,
      type: String,
      description: "Cursor for pagination (Base64URL encoded)",
    }),
    ApiQuery({
      name: "limit",
      required: false,
      type: Number,
      description: "Number of items per page (1-100, default: 20)",
    }),
    ApiQuery({
      name: "sort",
      required: false,
      type: String,
      description: "Sort field (default: createdAt)",
    }),
    ApiQuery({
      name: "order",
      required: false,
      enum: ["asc", "desc"],
      description: "Sort direction (default: desc)",
    }),
  );
}

﻿import { ConfigService } from "@nestjs/config";
import { Test, TestingModule } from "@nestjs/testing";

import { EmailService, EmailOptions, EmailResult } from "./email.service";

describe("EmailService", () => {
  let service: EmailService;
  let configService: ConfigService;

  const mockConfigService = {
    get: jest.fn((key: string, defaultValue?: any) => {
