/**
 * @fileoverview 全局异常过滤器 - 企业级错误处理
 *
 * 提供统一的错误响应格式，支持：
 * - 请求ID追踪 (RequestId)
 * - 结构化日志记录
 * - 敏感信息脱敏
 * - 开发/生产环境区分
 * - 业务错误码映射
 * - 自定义异常处理 (BusinessException, ValidationException, NotFoundException, ForbiddenException)
 * - 数据库错误处理 (QueryFailedError)
 *
 * @example
 * ```typescript
 * // 在 main.ts 中全局应用
 * app.useGlobalFilters(new AllExceptionsFilter());
 * ```
 */

import { AsyncLocalStorage } from "async_hooks";

import {
  ExceptionFilter,
  Catch,
  ArgumentsHost,
  HttpException,
  HttpStatus,
  Injectable,
  Inject,
  Optional,
} from "@nestjs/common";
import { Prisma } from "@prisma/client";
import { Request, Response } from "express";

import {
  BusinessException,
  ValidationException,
  NotFoundException,
  ForbiddenException,
  ValidationErrorItem,
} from "../exceptions";
import { StructuredLoggerService, RequestContext } from "../logging/structured-logger.service";
import { SentryService } from "../sentry/sentry.service";

/**
 * 验证错误项接口（兼容旧格式）
 */
interface ValidationError {
  field: string;
  message: string;
}

/**
 * 标准API错误响应接口
 * 符合 API.md 文档规范
 */
export interface ErrorResponse {
  /** 5位业务错误码 */
  code: number;
  /** 错误消息 */
  message: string;
  /** 验证错误详情（可选） */
  errors?: ValidationError[];
  /** 错误详情（可选） */
  details?: Record<string, unknown>;
  /** ISO 8601 时间戳 */
  timestamp: string;
  /** 请求路径 */
  path: string;
  /** 请求ID（用于追踪） */
  requestId?: string;
  /** 堆栈信息（仅开发环境） */
  stack?: string;
}

/**
 * 业务错误码映射表
 * 格式: XXYYZ
 * - XX: 错误类别 (40=客户端, 50=服务端)
 * - YY: 具体错误类型
 * - Z: 严重程度 (0=低, 9=高)
 */
const BUSINESS_ERROR_CODES: Record<number, number> = {
  // 4xx 客户端错误
  400: 40000, // 通用请求错误
  401: 40100, // 认证失败
  403: 40300, // 权限不足
  404: 40400, // 资源不存在
  405: 40500, // 方法不允许
  409: 40900, // 资源冲突
  422: 42200, // 验证失败
  429: 42900, // 请求过于频繁
  // 5xx 服务端错误
  500: 50000, // 内部服务器错误
  502: 50200, // 网关错误
  503: 50300, // 服务不可用
  504: 50400, // 网关超时
};

/**
 * 敏感字段列表（用于日志脱敏）
 */
const SENSITIVE_FIELDS = [
  "password",
  "passwordHash",
  "token",
  "accessToken",
  "refreshToken",
  "apiKey",
  "secret",
  "creditCard",
  "cvv",
  "ssn",
  "phone",
  "mobile",
  "idCard",
  "email",
];

/**
 * 全局异常过滤器
 *
 * @class AllExceptionsFilter
 * @implements {ExceptionFilter}
 */
@Catch()
@Injectable()
export class AllExceptionsFilter implements ExceptionFilter {
  private readonly isProduction: boolean;
  private readonly internalLogger = new console.Console({
    stdout: process.stdout,
    stderr: process.stderr,
  });

  constructor(
    @Optional()
    @Inject("ASYNC_LOCAL_STORAGE")
    private readonly asyncLocalStorage?: AsyncLocalStorage<RequestContext>,
    @Optional()
    private readonly logger?: StructuredLoggerService,
    @Optional()
    private readonly sentryService?: SentryService,
  ) {
    this.isProduction = process.env.NODE_ENV === "production";
    if (this.logger) {
      this.logger.setContext("AllExceptionsFilter");
    }
  }

  /**
   * 捕获并处理异常
   */
  catch(exception: unknown, host: ArgumentsHost): void {
    const ctx = host.switchToHttp();
    const response = ctx.getResponse<Response>();
    const request = ctx.getRequest<Request>();

    const errorResponse = this.buildErrorResponse(exception, request);

    this.logError(exception, request, errorResponse);

    this.reportToSentry(exception, request, errorResponse);

    const statusCode = this.getStatusCode(exception);

    response.status(statusCode).json(errorResponse);
  }

  /**
   * 构建标准化错误响应
   */
  private buildErrorResponse(exception: unknown, request: Request): ErrorResponse {
    const timestamp = new Date().toISOString();
    const path = request.url;
    const requestId = this.getRequestId();

    // 处理自定义异常
    if (exception instanceof ValidationException) {
      return this.handleValidationException(exception, timestamp, path, requestId);
    }

    if (exception instanceof NotFoundException) {
      return this.handleNotFoundException(exception, timestamp, path, requestId);
    }

    if (exception instanceof ForbiddenException) {
      return this.handleForbiddenException(exception, timestamp, path, requestId);
    }

    if (exception instanceof BusinessException) {
      return this.handleBusinessException(exception, timestamp, path, requestId);
    }

    // 处理数据库错误
    if (exception instanceof Prisma.PrismaClientKnownRequestError) {
      return this.handleDatabaseError(exception, timestamp, path, requestId);
    }

    // 处理 HTTP 异常
    if (exception instanceof HttpException) {
      return this.handleHttpException(exception, timestamp, path, requestId);
    }

    // 处理通用错误
    return this.handleGenericError(exception, timestamp, path, requestId);
  }

  /**
   * 处理验证异常 (ValidationException)
   */
  private handleValidationException(
    exception: ValidationException,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const response: ErrorResponse = {
      code: exception.code,
      message: exception.message,
      errors: exception.errors.map((e: ValidationErrorItem) => ({
        field: e.field,
        message: e.message,
      })),
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    if (!this.isProduction) {
      response.stack = exception.stack;
    }

    return response;
  }

  /**
   * 处理资源不存在异常 (NotFoundException)
   */
  private handleNotFoundException(
    exception: NotFoundException,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const response: ErrorResponse = {
      code: exception.code,
      message: exception.message,
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    if (!this.isProduction) {
      response.stack = exception.stack;
    }

    return response;
  }

  /**
   * 处理权限不足异常 (ForbiddenException)
   */
  private handleForbiddenException(
    exception: ForbiddenException,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const response: ErrorResponse = {
      code: exception.code,
      message: exception.message,
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    if (!this.isProduction) {
      response.stack = exception.stack;
    }

    return response;
  }

  /**
   * 处理业务异常 (BusinessException)
   */
  private handleBusinessException(
    exception: BusinessException,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const response: ErrorResponse = {
      code: exception.businessCode,
      message: exception.message,
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    // 开发环境添加详情和堆栈
    if (!this.isProduction) {
      if (exception.details) {
        response.details = exception.details;
      }
      response.stack = exception.stack;
    }

    return response;
  }

  /**
   * 处理数据库错误 (Prisma)
   */
  private handleDatabaseError(
    exception: Prisma.PrismaClientKnownRequestError,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    let message = "数据库操作失败";
    let code = 50001;

    // 解析 Prisma 错误码
    // https://www.prisma.io/docs/reference/api-reference/error-reference
    switch (exception.code) {
      case "P2002":
        // 唯一约束冲突
        message = "资源已存在";
        code = 40901;
        break;
      case "P2025":
        // 记录不存在
        message = "资源不存在";
        code = 40401;
        break;
      case "P2003":
        // 外键约束失败
        message = "关联资源不存在";
        code = 40402;
        break;
      case "P2011":
        // 非空约束失败
        message = "必填字段缺失";
        code = 42201;
        break;
      default:
        break;
    }

    const response: ErrorResponse = {
      code,
      message: this.isProduction ? message : exception.message,
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    if (!this.isProduction) {
      response.stack = exception.stack;
      response.details = {
        prismaCode: exception.code,
        meta: exception.meta,
      };
    }

    return response;
  }

  /**
   * 处理HTTP异常（NestJS内置异常）
   */
  private handleHttpException(
    exception: HttpException,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const status = exception.getStatus();
    const exceptionResponse = exception.getResponse();

    let message: string;
    let errors: ValidationError[] | undefined = undefined;
    let code = this.getBusinessErrorCode(status);

    if (typeof exceptionResponse === "string") {
      message = exceptionResponse;
    } else if (typeof exceptionResponse === "object") {
      const responseObj = exceptionResponse as Record<string, unknown>;
      message = (responseObj.message as string) || exception.message;

      // 处理 class-validator 验证错误
      if (Array.isArray(responseObj.message)) {
        message = "Validation failed";
        errors = this.parseValidationErrors(responseObj.message as string[]);
        code = 40001; // 验证错误码
      }

      // 使用自定义错误码（如果提供）
      if (typeof responseObj.code === "number") {
        code = responseObj.code;
      }
    } else {
      message = exception.message;
    }

    // 合并数组消息
    if (Array.isArray(message)) {
      message = message.join(", ");
    }

    const response: ErrorResponse = {
      code,
      message,
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    if (errors && errors.length > 0) {
      response.errors = errors;
    }

    // 开发环境添加堆栈信息
    if (!this.isProduction) {
      response.stack = exception.stack;
    }

    return response;
  }

  /**
   * 解析 class-validator 验证错误
   */
  private parseValidationErrors(messages: string[]): ValidationError[] {
    return messages.map((msg) => {
      // 尝试匹配 "fieldName error message" 格式
      const match = msg.match(/^(\w+)\s+(.+)$/);
      if (match) {
        return {
          field: match[1] ?? "unknown",
          message: match[2] ?? msg,
        };
      }
      return { field: "unknown", message: msg };
    });
  }

  /**
   * 处理通用/意外错误
   */
  private handleGenericError(
    exception: unknown,
    timestamp: string,
    path: string,
    requestId: string | undefined,
  ): ErrorResponse {
    const error = exception as Error;

    const response: ErrorResponse = {
      code: 50000, // 内部服务器错误码
      message: this.isProduction
        ? "An unexpected error occurred"
        : error.message || "Unknown error",
      timestamp,
      path,
    };

    if (requestId) {
      response.requestId = requestId;
    }

    // 开发环境添加堆栈信息
    if (!this.isProduction && error.stack) {
      response.stack = error.stack;
    }

    return response;
  }

  /**
   * 获取HTTP状态码
   */
  private getStatusCode(exception: unknown): number {
    if (exception instanceof HttpException) {
      return exception.getStatus();
    }
    return HttpStatus.INTERNAL_SERVER_ERROR;
  }

  /**
   * 获取业务错误码
   */
  private getBusinessErrorCode(status: number): number {
    return BUSINESS_ERROR_CODES[status] || 50000;
  }

  /**
   * 获取请求ID
   */
  private getRequestId(): string | undefined {
    try {
      const store = this.asyncLocalStorage?.getStore();
      return store?.requestId;
    } catch {
      return undefined;
    }
  }

  /**
   * 记录错误日志（带敏感信息脱敏）
   */
  private logError(
    exception: unknown,
    request: Request,
    errorResponse: ErrorResponse,
  ): void {
    // 脱敏请求体
    const sanitizedBody = this.sanitizeRequestBody(request.body);

    // 构建日志数据
    const logData = {
      method: request.method,
      url: request.url,
      query: request.query,
      body: sanitizedBody,
      ip: this.maskIp(request.ip),
      userAgent: request.headers["user-agent"]?.substring(0, 100),
      errorCode: errorResponse.code,
      errorMessage: errorResponse.message,
    };

    if (exception instanceof HttpException) {
      const status = exception.getStatus();

      if (status >= 500) {
        // 服务端错误 - Error级别
        if (this.logger) {
          this.logger.error(
            `Server error: ${exception.message}`,
            exception.stack,
            "HttpException",
            logData,
          );
        } else {
          this.internalLogger.error(`Server error: ${exception.message}`, exception.stack);
        }
      } else if (status >= 400) {
        // 客户端错误 - Warn级别
        if (this.logger) {
          this.logger.warn("Client error occurred", "HttpException", logData);
        } else {
          this.internalLogger.warn("Client error occurred");
        }
      }
    } else {
      // 意外错误 - Error级别
      const error = exception as Error;
      if (this.logger) {
        this.logger.error(
          `Unexpected error: ${error.message}`,
          error.stack,
          "UnhandledException",
          logData,
        );
      } else {
        this.internalLogger.error(`Unexpected error: ${error.message}`, error.stack);
      }
    }
  }

  /**
   * 脱敏请求体
   */
  private sanitizeRequestBody(body: unknown): unknown {
    if (!body || typeof body !== "object") {
      return body;
    }

    const sanitized: Record<string, unknown> = {};
    const bodyObj = body as Record<string, unknown>;

    for (const [key, value] of Object.entries(bodyObj)) {
      const lowerKey = key.toLowerCase();

      // 检查是否为敏感字段
      if (SENSITIVE_FIELDS.some((field) => lowerKey.includes(field.toLowerCase()))) {
        sanitized[key] = this.maskValue(value);
      } else if (value && typeof value === "object") {
        // 递归处理嵌套对象
        sanitized[key] = this.sanitizeRequestBody(value);
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  /**
   * 遮罩敏感值
   */
  private maskValue(value: unknown): string {
    if (value === null || value === undefined) {
      return "[REDACTED]";
    }

    const strValue = String(value);
    if (strValue.length <= 4) {
      return "****";
    }

    // 保留前后各2个字符
    return strValue.substring(0, 2) + "****" + strValue.substring(strValue.length - 2);
  }

  /**
   * 遮罩IP地址
   */
  private maskIp(ip: string | undefined): string {
    if (!ip) {return "unknown";}

    if (ip.includes(".")) {
      const parts = ip.split(".");
      if (parts.length === 4) {
        return `${parts[0]}.${parts[1]}.*.*`;
      }
    }

    if (ip.includes(":")) {
      const parts = ip.split(":");
      if (parts.length >= 2) {
        return `${parts[0]}:${parts[1]}:****`;
      }
    }

    return ip;
  }

  private reportToSentry(
    exception: unknown,
    request: Request,
    errorResponse: ErrorResponse,
  ): void {
    if (!this.sentryService?.isEnabled()) {return;}

    const statusCode = this.getStatusCode(exception);

    if (statusCode < 500 && !(exception instanceof Prisma.PrismaClientKnownRequestError)) {
      return;
    }

    const requestId = this.getRequestId();
    const sanitizedBody = this.sanitizeRequestBody(request.body);

    this.sentryService.setTag("error_code", String(errorResponse.code));
    this.sentryService.setTag("http_method", request.method);
    this.sentryService.setTag("http_status", String(statusCode));

    if (requestId) {
      this.sentryService.setTag("request_id", requestId);
    }

    const store = this.asyncLocalStorage?.getStore();
    if (store?.userId) {
      this.sentryService.setUser({ id: store.userId });
    }

    this.sentryService.captureException(exception, {
      request: {
        method: request.method,
        url: request.url,
        query: request.query,
        body: sanitizedBody,
        headers: {
          "user-agent": request.headers["user-agent"]?.substring(0, 100),
          "content-type": request.headers["content-type"],
        },
      },
      errorResponse: {
        code: errorResponse.code,
        message: errorResponse.message,
        requestId,
      },
    });
  }
}

import { HttpException, HttpStatus } from '@nestjs/common';

import { BusinessException } from '../exceptions/business.exception';
import { ForbiddenException } from '../exceptions/forbidden.exception';
import { NotFoundException } from '../exceptions/not-found.exception';
import { ValidationException } from '../exceptions/validation.exception';

import { HttpExceptionFilter } from './http-exception.filter';

function createMockHost(requestId?: string, headerRequestId?: string) {
  const json = jest.fn();
  const status = jest.fn().mockReturnValue({ json });
  const response = { status, json } as any;
  const request = {
    requestId,
    headers: headerRequestId ? { 'x-request-id': headerRequestId } : {},
  } as any;

  return {
    switchToHttp: () => ({
      getResponse: () => response,
      getRequest: () => request,
    }),
    json,
    response,
    request,
  };
}

describe('HttpExceptionFilter', () => {
  let filter: HttpExceptionFilter;
  const originalEnv = process.env.NODE_ENV;

  beforeEach(() => {
    process.env.NODE_ENV = 'test';
    filter = new HttpExceptionFilter();
  });

  afterEach(() => {
    process.env.NODE_ENV = originalEnv;
  });

  describe('ValidationException', () => {
    it('should map each error with source.pointer=/data/attributes/{field}', () => {
      const exception = new ValidationException([
        { field: 'email', message: 'Invalid email' },
        { field: 'name', message: 'Name required' },
      ]);
      const host = createMockHost(undefined, 'req-1');

      filter.catch(exception, host as any);

      expect(host.response.status).toHaveBeenCalledWith(HttpStatus.UNPROCESSABLE_ENTITY);
      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '422',
            code: '42200',
            title: 'Unprocessable Entity',
            detail: 'Invalid email',
            source: { pointer: '/data/attributes/email' },
            meta: expect.objectContaining({ timestamp: expect.any(String), requestId: 'req-1' }),
          },
          {
            status: '422',
            code: '42200',
            title: 'Unprocessable Entity',
            detail: 'Name required',
            source: { pointer: '/data/attributes/name' },
            meta: expect.objectContaining({ timestamp: expect.any(String), requestId: 'req-1' }),
          },
        ],
      });
    });
  });

  describe('BusinessException', () => {
    it('should map with businessCode, errorKey as title, details in meta', () => {
      const exception = new BusinessException(
        'INSUFFICIENT_BALANCE',
        'Balance too low',
        { currentBalance: 50, required: 100 },
        40103,
        HttpStatus.BAD_REQUEST,
      );
      const host = createMockHost(undefined, 'req-2');

      filter.catch(exception, host as any);

      expect(host.response.status).toHaveBeenCalledWith(HttpStatus.BAD_REQUEST);
      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '400',
            code: '40103',
            title: 'INSUFFICIENT_BALANCE',
            detail: 'Balance too low',
            meta: expect.objectContaining({
              timestamp: expect.any(String),
              requestId: 'req-2',
              details: { currentBalance: 50, required: 100 },
            }),
          },
        ],
      });
    });
  });

  describe('NotFoundException', () => {
    it('should map to 404 with code RESOURCE_NOT_FOUND', () => {
      const exception = new NotFoundException('User', 'user-123');
      const host = createMockHost(undefined, 'req-3');

      filter.catch(exception, host as any);

      expect(host.response.status).toHaveBeenCalledWith(HttpStatus.NOT_FOUND);
      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '404',
            code: 'RESOURCE_NOT_FOUND',
            title: 'Not Found',
            detail: 'User 不存在',
            meta: expect.objectContaining({ timestamp: expect.any(String), requestId: 'req-3' }),
          },
        ],
      });
    });
  });

  describe('ForbiddenException', () => {
    it('should map to 403 with code FORBIDDEN', () => {
      const exception = new ForbiddenException('delete_user', 'user:delete');
      const host = createMockHost(undefined, 'req-4');

      filter.catch(exception, host as any);

      expect(host.response.status).toHaveBeenCalledWith(HttpStatus.FORBIDDEN);
      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '403',
            code: 'FORBIDDEN',
            title: 'Forbidden',
            detail: expect.any(String),
            meta: expect.objectContaining({ timestamp: expect.any(String), requestId: 'req-4' }),
          },
        ],
      });
    });
  });

  describe('Generic HttpException', () => {
    it('should map with status-derived code and title', () => {
      const exception = new HttpException('Not found', HttpStatus.NOT_FOUND);
      const host = createMockHost();

      filter.catch(exception, host as any);

      expect(host.response.status).toHaveBeenCalledWith(HttpStatus.NOT_FOUND);
      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '404',
            code: 'NOT_FOUND',
            title: 'Not Found',
            detail: 'Not found',
            meta: expect.objectContaining({ timestamp: expect.any(String) }),
          },
        ],
      });
    });

    it('should map 500 to INTERNAL_ERROR', () => {
      const exception = new HttpException('Server error', HttpStatus.INTERNAL_SERVER_ERROR);
      const host = createMockHost();

      filter.catch(exception, host as any);

      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '500',
            code: 'INTERNAL_ERROR',
            title: 'Internal Server Error',
            detail: 'Server error',
            meta: expect.objectContaining({ timestamp: expect.any(String) }),
          },
        ],
      });
    });

    it('should map unknown status to ERROR code', () => {
      const exception = new HttpException('Custom', 418);
      const host = createMockHost();

      filter.catch(exception, host as any);

      expect(host.json).toHaveBeenCalledWith({
        errors: [
          {
            status: '418',
            code: 'ERROR',
            title: 'Error',
            detail: 'Custom',
            meta: expect.objectContaining({ timestamp: expect.any(String) }),
          },
        ],
      });
    });
  });

  describe('HttpException with array message', () => {
    it('should map to validation errors with source.pointer', () => {
      const exception = new HttpException(
        { message: ['email must be a valid email', 'password is too short'] },
        HttpStatus.BAD_REQUEST,
      );
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors).toHaveLength(2);
      expect(call.errors[0].code).toBe('VALIDATION_ERROR');
      expect(call.errors[0].detail).toBe('email must be a valid email');
      expect(call.errors[0].source.pointer).toBe('/data/attributes/email');
      expect(call.errors[1].source.pointer).toBe('/data/attributes/password');
    });

    it('should handle array message without field pattern', () => {
      const exception = new HttpException(
        { message: ['validation failed on multiple fields'] },
        HttpStatus.BAD_REQUEST,
      );
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].code).toBe('VALIDATION_ERROR');
      expect(call.errors[0].source).toEqual({ pointer: '/data/attributes/validation' });
    });
  });

  describe('Production mode', () => {
    beforeEach(() => {
      process.env.NODE_ENV = 'production';
      filter = new HttpExceptionFilter();
    });

    it('should exclude stack trace', () => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].meta.stack).toBeUndefined();
    });
  });

  describe('Non-production mode', () => {
    it('should include stack trace', () => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].meta.stack).toBeDefined();
    });
  });

  describe('requestId', () => {
    it('should use request.requestId when available', () => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);
      const host = createMockHost('direct-request-id');

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].meta.requestId).toBe('direct-request-id');
    });

    it('should fall back to X-Request-Id header', () => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);
      const host = createMockHost(undefined, 'header-request-id');

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].meta.requestId).toBe('header-request-id');
    });

    it('should omit requestId when neither is available', () => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].meta.requestId).toBeUndefined();
    });
  });

  describe('extractDetail', () => {
    it('should extract string response', () => {
      const exception = new HttpException('Simple message', HttpStatus.BAD_REQUEST);
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].detail).toBe('Simple message');
    });

    it('should extract message from object response', () => {
      const exception = new HttpException(
        { message: 'Object message', code: 400 },
        HttpStatus.BAD_REQUEST,
      );
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].detail).toBe('Object message');
    });

    it('should fall back to exception.message when response has no message string', () => {
      const exception = new HttpException(
        { error: 'Bad Request', statusCode: 400 },
        HttpStatus.BAD_REQUEST,
      );
      const host = createMockHost();

      filter.catch(exception, host as any);

      const call = host.json.mock.calls[0][0];
      expect(call.errors[0].detail).toBeDefined();
      expect(typeof call.errors[0].detail).toBe('string');
    });
  });
});

import { Logger, UsePipes, ValidationPipe } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { JwtService } from "@nestjs/jwt";
import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  ConnectedSocket,
  MessageBody,
} from "@nestjs/websockets";
import { Server, Socket } from "socket.io";

import { RedisService } from "../redis/redis.service";
import { WebSocketNotificationData } from "../types/common.types";

export interface JoinRoomData {
  room: string;
}

export interface NotificationPayload {
  type:
    | "try_on_complete"
    | "try_on_progress"
    | "recommendation"
    | "price_drop"
    | "customization_update"
    | "system"
    | "subscription"
    | "social"
    | "order";
  title: string;
  message: string;
  data?: Record<string, unknown>;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(",").filter(Boolean) || (process.env.NODE_ENV === "production" ? [] : ["http://localhost:3000"]),
    credentials: true,
  },
  namespace: "/ws",
})
@UsePipes(new ValidationPipe())
export class NotificationGateway
  implements OnGatewayConnection, OnGatewayDisconnect
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(NotificationGateway.name);
  private userSocketMap = new Map<string, Set<string>>();

  constructor(
    private configService: ConfigService,
    private jwtService: JwtService,
    private redisService: RedisService,
  ) {}

  async handleConnection(client: Socket) {
    try {
      const userId = this.extractUserId(client);
      if (!userId) {
        client.disconnect();
        return;
      }

      client.data.userId = userId;

      if (!this.userSocketMap.has(userId)) {
        this.userSocketMap.set(userId, new Set());
      }
      this.userSocketMap.get(userId)!.add(client.id);

      await client.join(`user:${userId}`);

      this.logger.log(`Client connected: ${client.id} (User: ${userId})`);

      const pendingNotifications = await this.getPendingNotifications(userId);
      if (pendingNotifications.length > 0) {
        pendingNotifications.forEach((notification) => {
          client.emit("notification", notification);
        });
        await this.clearPendingNotifications(userId);
      }
    } catch (error) {
      this.logger.error(`Connection error: ${this.getErrorMessage(error)}`);
      client.disconnect();
    }
  }

  async handleDisconnect(client: Socket) {
    const userId = client.data.userId;
    if (userId) {
      const userSockets = this.userSocketMap.get(userId);
      if (userSockets) {
        userSockets.delete(client.id);
        if (userSockets.size === 0) {
          this.userSocketMap.delete(userId);
        }
      }
      this.logger.log(`Client disconnected: ${client.id} (User: ${userId})`);
    }
  }

  @SubscribeMessage("joinRoom")
  handleJoinRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: JoinRoomData,
  ) {
    client.join(data.room);
    this.logger.log(`Client ${client.id} joined room: ${data.room}`);
    client.emit("joinedRoom", { room: data.room });
  }

  @SubscribeMessage("leaveRoom")
  handleLeaveRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: JoinRoomData,
  ) {
    client.leave(data.room);
    this.logger.log(`Client ${client.id} left room: ${data.room}`);
  }

  @SubscribeMessage("ping")
  handlePing(@ConnectedSocket() client: Socket) {
    client.emit("pong", { timestamp: Date.now() });
  }

  async sendToUser(userId: string, event: string, data: unknown): Promise<boolean> {
    if (!this.userSocketMap.has(userId)) {
      await this.storePendingNotification(userId, {
        type: "system",
        title: "新消息",
        message: "您有新的通知",
        data: { event, payload: data },
      });
      return false;
    }

    this.server.to(`user:${userId}`).emit(event, data);
    return true;
  }

  async sendNotification(
    userId: string,
    notification: NotificationPayload,
  ): Promise<boolean> {
    return this.sendToUser(userId, "notification", {
      ...notification,
      timestamp: new Date().toISOString(),
    });
  }

  broadcastToAll(event: string, data: unknown) {
    this.server.emit(event, data);
  }

  broadcastToRoom(room: string, event: string, data: unknown) {
    this.server.to(room).emit(event, data);
  }

  isUserOnline(userId: string): boolean {
    return this.userSocketMap.has(userId);
  }

  getOnlineUserCount(): number {
    return this.userSocketMap.size;
  }

  private extractUserId(client: Socket): string | null {
    const auth = client.handshake.auth;
    const query = client.handshake.query;

    const token = auth?.token || query?.token;
    if (!token) {
      return null;
    }

    return this.validateToken(token as string);
  }

  private validateToken(token: string): string | null {
    try {
      const jwtSecret = this.configService.get<string>("JWT_SECRET");
      if (!jwtSecret) {
        this.logger.error("JWT_SECRET is not configured");
        return null;
      }

      const payload = this.jwtService.verify(token, {
        secret: jwtSecret,
      });

      const userId = payload.sub || payload.userId;
      if (!userId) {
        this.logger.warn("Token payload missing user identifier");
        return null;
      }

      return userId;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(`Token validation failed: ${errorMessage}`);
      return null;
    }
  }

  private async getPendingNotifications(
    userId: string,
  ): Promise<NotificationPayload[]> {
    try {
      const key = `pending_notifications:${userId}`;
      const data = await this.redisService.get(key);
      return data ? JSON.parse(data) : [];
    } catch (error) {
      this.logger.error(
        `Failed to get pending notifications for user ${userId}: ${this.getErrorMessage(error)}. User may miss pending notifications.`,
      );
      return [];
    }
  }

  private async storePendingNotification(
    userId: string,
    notification: NotificationPayload,
  ) {
    try {
      const key = `pending_notifications:${userId}`;
      const existing = await this.getPendingNotifications(userId);
      existing.push(notification);
      await this.redisService.setex(
        key,
        86400,
        JSON.stringify(existing.slice(-50)),
      );
    } catch (error) {
      this.logger.error(
        `Failed to store pending notification: ${this.getErrorMessage(error)}`,
      );
    }
  }

  private async clearPendingNotifications(userId: string) {
    try {
      const key = `pending_notifications:${userId}`;
      await this.redisService.del(key);
    } catch (error) {
      this.logger.error(
        `Failed to clear pending notifications: ${this.getErrorMessage(error)}`,
      );
    }
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : "Unknown error";
  }
}

/**
 * CSRF Controller
 * Provides endpoint to retrieve CSRF token
 */
import { Controller, Get, Res, Headers } from '@nestjs/common';
import { ApiTags, ApiOperation, ApiResponse } from '@nestjs/swagger';
import { Response } from 'express';

import { CsrfService } from './csrf.service';
import { ExcludeCsrf } from './decorators/exclude-csrf.decorator';

@ApiTags('csrf')
@Controller('csrf')
export class CsrfController {
  constructor(private readonly csrfService: CsrfService) {}

  /**
   * Get CSRF token
   * This endpoint is excluded from CSRF protection
   * Frontend should call this to get the initial token
   */
  @Get('token')
  @ExcludeCsrf()
  @ApiOperation({ summary: '获取 CSRF Token', description: '获取 CSRF 令牌，前端应在首次请求时调用此接口获取令牌' })
  @ApiResponse({ status: 200, description: '成功返回 CSRF Token 信息' })
  getToken(@Res() res: Response): void {
    // The token will be automatically set in the response by CsrfGuard
    res.json({
      message: 'CSRF token is available in X-CSRF-Token header',
      headerName: this.csrfService.getHeaderName(),
      cookieName: this.csrfService.getCookieName(),
    });
  }
}

/**
 * CSRF Guard
 * Protects routes from CSRF attacks
 */
import {
  Injectable,
  CanActivate,
  ExecutionContext,
  BadRequestException,
  Logger,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Response } from 'express';

import { RequestWithUser } from '../../types/common.types';

import { CSRF_COOKIE_NAME, CSRF_HEADER_NAME, CSRF_ERROR_MESSAGES } from './csrf.constants';
import { CsrfService } from './csrf.service';
import { EXCLUDE_CSRF_KEY } from './decorators/exclude-csrf.decorator';

@Injectable()
export class CsrfGuard implements CanActivate {
  private readonly logger = new Logger(CsrfGuard.name);

  constructor(
    private readonly csrfService: CsrfService,
    private readonly reflector: Reflector,
  ) {}

  canActivate(context: ExecutionContext): boolean {
    // Check if route is excluded from CSRF protection
    const isExcluded = this.reflector.getAllAndOverride<boolean>(EXCLUDE_CSRF_KEY, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (isExcluded) {
      return true;
    }

    const request = context.switchToHttp().getRequest();
    const response = context.switchToHttp().getResponse();

    // Skip CSRF validation for GET, HEAD, OPTIONS requests
    const method = request.method.toUpperCase();
    if (['GET', 'HEAD', 'OPTIONS'].includes(method)) {
      return this.handleSafeRequest(request, response);
    }

    // Validate CSRF token for state-changing requests
    return this.handleStateChangingRequest(request, context);
  }

  /**
   * Handle safe requests (GET, HEAD, OPTIONS)
   * Generate and expose CSRF token
   */
  private handleSafeRequest(request: RequestWithUser, response: Response): boolean {
    try {
      // Get session ID (you may need to adjust this based on your auth implementation)
      const sessionId = this.getSessionId(request);

      if (sessionId) {
        const csrfToken = this.csrfService.generateToken(sessionId);

        // Set CSRF cookie
        response.cookie(CSRF_COOKIE_NAME, csrfToken, {
          httpOnly: false,
          secure: process.env.NODE_ENV === 'production',
          sameSite: 'lax',
          maxAge: 86400, // 24 hours
        });

        // Expose CSRF token in header
        response.setHeader(CSRF_HEADER_NAME, csrfToken);
        response.setHeader('Access-Control-Expose-Headers', CSRF_HEADER_NAME);

        // Attach token to request for easy access
        request.csrfToken = csrfToken;
      }

      return true;
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Error generating CSRF token: ${errorMessage}`);
      return true; // Don't block on token generation errors
    }
  }

  /**
   * Handle state-changing requests (POST, PUT, DELETE, PATCH)
   * Validate CSRF token
   */
  private handleStateChangingRequest(request: RequestWithUser, context: ExecutionContext): boolean {
    try {
      const sessionId = this.getSessionId(request);

      if (!sessionId) {
        // Allow if no session (public endpoints should use @ExcludeCsrf)
        return true;
      }

      // Get token from header
      const token = request.headers[CSRF_HEADER_NAME];

      if (!token) {
        this.logger.warn(`CSRF token missing for ${request.method} ${request.path}`);
        throw new BadRequestException(CSRF_ERROR_MESSAGES.MISSING_TOKEN);
      }

      // Validate token
      const isValid = this.csrfService.validateToken(sessionId, token as string);

      if (!isValid) {
        this.logger.warn(`Invalid CSRF token for ${request.method} ${request.path}`);
        throw new BadRequestException(CSRF_ERROR_MESSAGES.INVALID_TOKEN);
      }

      return true;
    } catch (error) {
      if (error instanceof BadRequestException) {
        throw error;
      }
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Error validating CSRF token: ${errorMessage}`);
      throw new BadRequestException(CSRF_ERROR_MESSAGES.INVALID_TOKEN);
    }
  }

  /**
   * Get session ID from request
   * Adjust this based on your authentication implementation
   */
  private getSessionId(request: RequestWithUser): string | null {
    // Try to get from JWT user
    if (request.user?.id) {
      return request.user.id;
    }

    // Try to get from session
    if (request.session?.id) {
      return request.session.id;
    }

    // Try to get from authorization header (for API usage)
    const authHeader = request.headers['authorization'];
    if (authHeader?.startsWith('Bearer ')) {
      const token = authHeader.substring(7);
      return token.substring(0, 32); // Use first 32 chars as session identifier
    }

    return null;
  }
}

/**
 * Example Usage of CSRF Protection
 *
 * This file demonstrates how to use CSRF protection in your controllers.
 * Copy the patterns shown here to your own controllers.
 */

import { Controller, Get, Post, Put, Delete, Body, Param, UseGuards } from '@nestjs/common';

import { CsrfGuard } from './csrf.guard';
import { ExcludeCsrf } from './decorators/exclude-csrf.decorator';

/**
 * Example 1: Standard CRUD Controller with CSRF Protection
 * All routes are protected by default
 */
@Controller('api/v1/example')
@UseGuards(CsrfGuard)
export class ExampleController {
  /**
   * GET request - automatically generates and exposes CSRF token
   * Frontend can read the token from X-CSRF-Token header
   */
  @Get()
  findAll() {
    return { message: 'This GET request generates a CSRF token in the response headers' };
  }

  /**
   * POST request - requires CSRF token in X-CSRF-Token header
   * Frontend must include the token from previous GET request
   */
  @Post()
  create(@Body() _createDto: any) {
    return { message: 'This POST request requires valid CSRF token' };
  }

  /**
   * PUT request - requires CSRF token
   */
  @Put(':id')
  update(@Param('id') id: string, @Body() _updateDto: any) {
    return { message: `This PUT request for ID ${id} requires valid CSRF token` };
  }

  /**
   * DELETE request - requires CSRF token
   */
  @Delete(':id')
  remove(@Param('id') id: string) {
    return { message: `This DELETE request for ID ${id} requires valid CSRF token` };
  }
}

/**
 * Example 2: Webhook Controller with CSRF Exclusion
 * Webhooks from external services should exclude CSRF protection
 */
@Controller('api/v1/webhooks')
export class WebhookController {
  /**
   * Stripe webhook - excluded from CSRF protection
   * External services can't provide our CSRF tokens
   */
  @Post('stripe')
  @ExcludeCsrf()
  handleStripeWebhook(@Body() _webhook: any) {
    return { message: 'This webhook does not require CSRF token' };
  }

  /**
   * Payment gateway callback - excluded
   */
  @Post('payment-callback')
  @ExcludeCsrf()
  handlePaymentCallback(@Body() _callback: any) {
    return { message: 'This callback does not require CSRF token' };
  }
}

/**
 * Example 3: Public API Controller
 * Some public endpoints might need CSRF exclusion
 */
@Controller('api/v1/public')
export class PublicController {
  /**
   * Public search endpoint - excluded from CSRF
   * Read-only operations can be excluded
   */
  @Get('search')
  @ExcludeCsrf()
  search(@Body() _searchDto: any) {
    return { message: 'This search endpoint does not require CSRF token' };
  }

  /**
   * Contact form submission - requires CSRF
   * State-changing operations should have CSRF protection
   */
  @Post('contact')
  @UseGuards(CsrfGuard)
  submitContactForm(@Body() _contactDto: any) {
    return { message: 'This contact form requires valid CSRF token' };
  }
}

/**
 * Example 4: Mixed Protection Controller
 * Some routes protected, some excluded
 */
@Controller('api/v1/mixed')
export class MixedController {
  /**
   * Public endpoint - no CSRF required
   */
  @Get('info')
  @ExcludeCsrf()
  getInfo() {
    return { message: 'No CSRF required for this GET request' };
  }

  /**
   * Protected endpoint - CSRF required
   */
  @Post('subscribe')
  @UseGuards(CsrfGuard)
  subscribe(@Body() _subscribeDto: any) {
    return { message: 'This subscription requires valid CSRF token' };
  }

  /**
   * Admin endpoint - CSRF required
   */
  @Put('admin/settings')
  @UseGuards(CsrfGuard)
  updateSettings(@Body() _settings: any) {
    return { message: 'This admin endpoint requires valid CSRF token' };
  }
}

/**
 * Frontend Integration Example
 *
 * TypeScript/JavaScript example for frontend usage:
 *
 * ```typescript
 * // Service class to handle CSRF tokens
 * class ApiService {
 *   private csrfToken: string | null = null;
 *
 *   // Get CSRF token from API
 *   async getCsrfToken(): Promise<string> {
 *     const response = await fetch('http://localhost:3001/api/csrf/token', {
 *       method: 'GET',
 *       credentials: 'include',
 *     });
 *
 *     this.csrfToken = response.headers.get('X-CSRF-Token');
 *     return this.csrfToken!;
 *   }
 *
 *   // Make POST request with CSRF token
 *   async postData(url: string, data: any): Promise<any> {
 *     if (!this.csrfToken) {
 *       await this.getCsrfToken();
 *     }
 *
 *     const response = await fetch(url, {
 *       method: 'POST',
 *       headers: {
 *         'Content-Type': 'application/json',
 *         'X-CSRF-Token': this.csrfToken!,
 *       },
 *       credentials: 'include',
 *       body: JSON.stringify(data),
 *     });
 *
 *     // Update token from response
 *     const newToken = response.headers.get('X-CSRF-Token');
 *     if (newToken) {
 *       this.csrfToken = newToken;
 *     }
 *
 *     return response.json();
 *   }
 *
 *   // Make GET request (automatically refreshes token)
 *   async getData(url: string): Promise<any> {
 *     const response = await fetch(url, {
 *       method: 'GET',
 *       credentials: 'include',
 *     });
 *
 *     // Update token from response
 *     const newToken = response.headers.get('X-CSRF-Token');
 *     if (newToken) {
 *       this.csrfToken = newToken;
 *     }
 *
 *     return response.json();
 *   }
 * }
 *
 * // Usage example
 * const api = new ApiService();
 *
 * // Get initial token
 * await api.getCsrfToken();
 *
 * // Make POST request
 * const result = await api.postData('http://localhost:3001/api/v1/example', {
 *   name: 'Test',
 * });
 * ```
 */

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
} from "@nestjs/common";
import { Reflector } from "@nestjs/core";
import { Request } from "express";
import { Observable, of, tap } from "rxjs";

import { CacheService } from "../../modules/cache/cache.service";
import {
  CACHE_KEY_METADATA,
  CACHE_TTL_METADATA,
  CACHE_CLEAR_METADATA,
} from "../decorators/cache.decorators";

@Injectable()
export class CacheInterceptor implements NestInterceptor {
  private readonly logger = new Logger(CacheInterceptor.name);

  constructor(
    private readonly cacheService: CacheService,
    private readonly reflector: Reflector,
  ) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest<Request>();
    const method = request.method.toUpperCase();

    // Handle cache invalidation on mutations
    const clearPatterns = this.reflector.get<string[]>(
      CACHE_CLEAR_METADATA,
      context.getHandler(),
    );

    if (clearPatterns && clearPatterns.length > 0 && method !== "GET") {
      return next.handle().pipe(
        tap(async () => {
          for (const pattern of clearPatterns) {
            try {
              await this.cacheService.delPattern(pattern);
            } catch (error) {
              const msg = error instanceof Error ? error.message : String(error);
              this.logger.warn(`Failed to clear pattern ${pattern}: ${msg}`);
            }
          }
        }),
      );
    }

    // Handle cache read/write on GET requests
    if (method !== "GET") {
      return next.handle();
    }

    const cacheKey = this.reflector.get<string>(
      CACHE_KEY_METADATA,
      context.getHandler(),
    );
    const cacheTtl = this.reflector.get<number>(
      CACHE_TTL_METADATA,
      context.getHandler(),
    );

    if (!cacheKey) {
      return next.handle();
    }

    // Build full cache key including query params
    const fullKey = this.buildKey(cacheKey, request);
    const ttl = cacheTtl ?? 300; // Default 5 minutes

    return new Observable((subscriber) => {
      (async () => {
        try {
          const cached = await this.cacheService.get(fullKey);
          if (cached !== null) {
            // Cache HIT
            if (request.res) {
              request.res.setHeader("X-Cache", "HIT");
            }
            subscriber.next(cached);
            subscriber.complete();
            return;
          }

          // Cache MISS - execute handler
          if (request.res) {
            request.res.setHeader("X-Cache", "MISS");
          }

          next.handle().subscribe({
            next: async (data) => {
              // Cache the result in background
              try {
                await this.cacheService.set(fullKey, data, ttl);
              } catch (error) {
                const msg = error instanceof Error ? error.message : String(error);
                this.logger.warn(`Failed to cache key ${fullKey}: ${msg}`);
              }
              subscriber.next(data);
              subscriber.complete();
            },
            error: (err) => {
              subscriber.error(err);
            },
          });
        } catch (error) {
          const msg = error instanceof Error ? error.message : String(error);
          this.logger.warn(`Cache interceptor error: ${msg}`);
          // Fallback to handler on cache errors
          next.handle().subscribe({
            next: (data) => {
              subscriber.next(data);
              subscriber.complete();
            },
            error: (err) => subscriber.error(err),
          });
        }
      })();
    });
  }

  private buildKey(baseKey: string, request: Request): string {
    const params = request.params;
    const query = request.query;

    const parts = [baseKey];

    if (params && Object.keys(params).length > 0) {
      parts.push(JSON.stringify(params));
    }

    if (query && Object.keys(query).length > 0) {
      const sortedQuery = Object.keys(query)
        .sort()
        .reduce(
          (acc, key) => {
            acc[key] = query[key];
            return acc;
          },
          {} as Record<string, unknown>,
        );
      parts.push(JSON.stringify(sortedQuery));
    }

    return parts.join(":");
  }
}

import {
  ExecutionContext,
  CallHandler,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { Prisma } from '@prisma/client';
import { of, throwError } from 'rxjs';


import { BusinessException } from '../exceptions/business.exception';
import { ForbiddenException } from '../exceptions/forbidden.exception';
import { NotFoundException } from '../exceptions/not-found.exception';
import { ValidationException } from '../exceptions/validation.exception';

import { ErrorInterceptor } from './error.interceptor';

function createMockContext(requestId?: string) {
  return {
    switchToHttp: () => ({
      getRequest: () => ({
        headers: requestId ? { 'x-request-id': requestId } : {},
      }),
    }),
  } as ExecutionContext;
}

function createMockCallHandler(error: any) {
  return { handle: () => throwError(() => error) } as CallHandler;
}

describe('ErrorInterceptor', () => {
  let interceptor: ErrorInterceptor;
  const originalEnv = process.env.NODE_ENV;

  beforeEach(() => {
    process.env.NODE_ENV = 'test';
    interceptor = new ErrorInterceptor();
  });

  afterEach(() => {
    process.env.NODE_ENV = originalEnv;
  });

  describe('ValidationException', () => {
    it('should map each validation error to a separate JsonApiError with source.pointer', (done) => {
      const exception = new ValidationException([
        { field: 'email', message: 'Invalid email format' },
        { field: 'password', message: 'Password too short' },
      ]);

      interceptor
        .intercept(createMockContext('req-1'), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err).toBeInstanceOf(HttpException);
            expect(err.getStatus()).toBe(HttpStatus.UNPROCESSABLE_ENTITY);
            const body = err.getResponse();
            expect(body.errors).toHaveLength(2);
            expect(body.errors[0].source.pointer).toBe('/email');
            expect(body.errors[0].detail).toBe('Invalid email format');
            expect(body.errors[1].source.pointer).toBe('/password');
            expect(body.errors[1].detail).toBe('Password too short');
            expect(body.errors[0].meta.requestId).toBe('req-1');
            expect(body.errors[0].meta.timestamp).toBeDefined();
            done();
          },
        });
    });

    it('should include constraint in meta in non-production', (done) => {
      const exception = new ValidationException([
        { field: 'email', message: 'Invalid', constraint: 'isEmail' },
      ]);

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].meta.constraint).toBe('isEmail');
            done();
          },
        });
    });
  });

  describe('NotFoundException', () => {
    it('should map to 404 with source.pointer', (done) => {
      const exception = new NotFoundException('User', 'user-123');

      interceptor
        .intercept(createMockContext('req-2'), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.NOT_FOUND);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('404');
            expect(body.errors[0].source.pointer).toBe('/user');
            expect(body.errors[0].detail).toBe('User 不存在');
            done();
          },
        });
    });
  });

  describe('ForbiddenException', () => {
    it('should map to 403 with source.parameter', (done) => {
      const exception = new ForbiddenException('delete_user', 'user:delete');

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.FORBIDDEN);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('403');
            expect(body.errors[0].source.parameter).toBe('user:delete');
            done();
          },
        });
    });

    it('should use operation as source.parameter when requiredPermission is absent', (done) => {
      const exception = new ForbiddenException('some_operation');

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].source.parameter).toBe('some_operation');
            done();
          },
        });
    });
  });

  describe('BusinessException', () => {
    it('should map with businessCode, errorKey, and details in meta', (done) => {
      const exception = new BusinessException(
        'INSUFFICIENT_BALANCE',
        'Balance too low',
        { currentBalance: 50, required: 100 },
        40103,
        HttpStatus.BAD_REQUEST,
      );

      interceptor
        .intercept(createMockContext('req-3'), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.BAD_REQUEST);
            const body = err.getResponse();
            expect(body.errors[0].code).toBe('40103');
            expect(body.errors[0].source.parameter).toBe('INSUFFICIENT_BALANCE');
            expect(body.errors[0].detail).toBe('Balance too low');
            expect(body.errors[0].meta.details).toEqual({
              currentBalance: 50,
              required: 100,
            });
            done();
          },
        });
    });
  });

  describe('Prisma errors', () => {
    it('should map P2002 to 409 Conflict', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Unique constraint failed',
        { code: 'P2002', clientVersion: '5.0.0', meta: { target: ['email'] } } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.CONFLICT);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('409');
            expect(body.errors[0].title).toBe('Conflict');
            done();
          },
        });
    });

    it('should map P2025 to 404 Not Found', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Record not found',
        { code: 'P2025', clientVersion: '5.0.0' } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.NOT_FOUND);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('404');
            done();
          },
        });
    });

    it('should map P2003 to 404 Not Found', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Foreign key constraint failed',
        { code: 'P2003', clientVersion: '5.0.0' } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.NOT_FOUND);
            done();
          },
        });
    });

    it('should map P2011 to 422 Unprocessable Entity', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Null constraint violation',
        { code: 'P2011', clientVersion: '5.0.0' } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.UNPROCESSABLE_ENTITY);
            done();
          },
        });
    });

    it('should map unknown Prisma error to 500', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Unknown error',
        { code: 'P9999', clientVersion: '5.0.0' } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.INTERNAL_SERVER_ERROR);
            done();
          },
        });
    });

    it('should include prismaCode and meta in non-production', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Unique constraint failed',
        { code: 'P2002', clientVersion: '5.0.0', meta: { target: ['email'] } } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].meta.prismaCode).toBe('P2002');
            expect(body.errors[0].meta.meta).toEqual({ target: ['email'] });
            done();
          },
        });
    });
  });

  describe('HttpException', () => {
    it('should map with status-derived code and title', (done) => {
      const exception = new HttpException('Not found', HttpStatus.NOT_FOUND);

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.NOT_FOUND);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('404');
            expect(body.errors[0].code).toBe('40400');
            expect(body.errors[0].title).toBe('Not Found');
            expect(body.errors[0].detail).toBe('Not found');
            done();
          },
        });
    });

    it('should map array message to validation errors with source.pointer', (done) => {
      const exception = new HttpException(
        { message: ['email is not valid', 'password is too short'] },
        HttpStatus.BAD_REQUEST,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].detail).toBe('email is not valid; password is too short');
            expect(body.errors[0].source.pointer).toBe('/request-body');
            done();
          },
        });
    });
  });

  describe('Generic Error', () => {
    it('should map to 500', (done) => {
      const exception = new Error('Something went wrong');

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            expect(err.getStatus()).toBe(HttpStatus.INTERNAL_SERVER_ERROR);
            const body = err.getResponse();
            expect(body.errors[0].status).toBe('500');
            expect(body.errors[0].code).toBe('50000');
            expect(body.errors[0].detail).toBe('Something went wrong');
            done();
          },
        });
    });
  });

  describe('Production mode', () => {
    beforeEach(() => {
      process.env.NODE_ENV = 'production';
      interceptor = new ErrorInterceptor();
    });

    it('should sanitize generic error messages', (done) => {
      const exception = new Error('Internal database connection string');

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].detail).toBe('An unexpected error occurred');
            expect(body.errors[0].meta.stack).toBeUndefined();
            done();
          },
        });
    });

    it('should sanitize Prisma error messages', (done) => {
      const exception = new Prisma.PrismaClientKnownRequestError(
        'Raw database error message',
        { code: 'P2002', clientVersion: '5.0.0' } as any,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].detail).toBe('Resource already exists');
            expect(body.errors[0].meta.prismaCode).toBeUndefined();
            done();
          },
        });
    });

    it('should exclude stack from BusinessException', (done) => {
      const exception = new BusinessException(
        'TEST_ERROR',
        'Test error',
        { foo: 'bar' },
        40000,
        HttpStatus.BAD_REQUEST,
      );

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].meta.stack).toBeUndefined();
            expect(body.errors[0].meta.details).toBeUndefined();
            done();
          },
        });
    });
  });

  describe('Non-production mode', () => {
    it('should include stack trace', (done) => {
      const exception = new HttpException('Error', HttpStatus.BAD_REQUEST);

      interceptor
        .intercept(createMockContext(), createMockCallHandler(exception))
        .subscribe({
          error: (err) => {
            const body = err.getResponse();
            expect(body.errors[0].meta.stack).toBeDefined();
            done();
          },
        });
    });
  });
});

