import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  SetMetadata,
} from '@nestjs/common';
import { Reflector } from '@nestjs/core';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

import { SKIP_RESPONSE_TRANSFORM } from './transform.interceptor';

export const JSON_API_TYPE = 'json_api_type';
export const SKIP_JSON_API = 'skip_json_api';

export interface JsonApiResource {
  type: string;
  id: string;
  attributes: Record<string, unknown>;
  relationships?: Record<string, JsonApiRelationships>;
  links?: { self: string };
}

export interface JsonApiRelationships {
  data: { type: string; id: string } | Array<{ type: string; id: string }>;
  links?: { self: string; related: string };
}

export interface JsonApiResponse {
  data: JsonApiResource | JsonApiResource[] | null;
  included?: JsonApiResource[];
  meta: {
    requestId?: string;
    timestamp: string;
    total?: number;
    nextCursor?: string;
    hasMore?: boolean;
  };
  links?: {
    self: string;
    next?: string;
  };
}

export interface JsonApiError {
  status: string;
  code: string;
  title: string;
  detail: string;
  source?: {
    pointer?: string;
    parameter?: string;
  };
  meta?: Record<string, unknown>;
}

export interface JsonApiDocument {
  data: JsonApiResource | JsonApiResource[] | null;
  included?: JsonApiResource[];
  meta: Record<string, unknown>;
  links?: Record<string, string>;
  errors?: JsonApiError[];
}

export const JsonApiType = (type: string) => SetMetadata(JSON_API_TYPE, type);
export const SkipJsonApi = () => SetMetadata(SKIP_JSON_API, true);

@Injectable()
export class JsonApiInterceptor implements NestInterceptor {
  constructor(private readonly reflector: Reflector) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const skipJsonApi = this.reflector.getAllAndOverride<boolean>(SKIP_JSON_API, [
      context.getHandler(),
      context.getClass(),
    ]);

    const skipTransform = this.reflector.getAllAndOverride<boolean>(SKIP_RESPONSE_TRANSFORM, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (skipJsonApi || skipTransform) {
      return next.handle();
    }

    const request = context.switchToHttp().getRequest<{
      url: string;
      headers: Record<string, string>;
    }>();

    const resourceType = this.getResourceType(context);
    const requestId = request.headers['x-request-id'] as string | undefined;
    const selfLink = request.url;

    return next.handle().pipe(
      map((data: unknown) => {
        const timestamp = new Date().toISOString();

        if (data === null || data === undefined) {
          return {
            data: null,
            meta: {
              requestId,
              timestamp,
            },
            links: { self: selfLink },
          } as JsonApiResponse;
        }

        if (this.isPaginatedResponse(data)) {
          return this.transformPaginated(data, resourceType, requestId, timestamp, selfLink);
        }

        if (Array.isArray(data)) {
          return this.transformArray(data, resourceType, requestId, timestamp, selfLink);
        }

        if (typeof data === 'object') {
          return this.transformSingle(data as Record<string, unknown>, resourceType, requestId, timestamp, selfLink);
        }

        return {
          data: null,
          meta: { requestId, timestamp },
          links: { self: selfLink },
        } as JsonApiResponse;
      }),
    );
  }

  private getResourceType(context: ExecutionContext): string {
    const customType = this.reflector.getAllAndOverride<string>(JSON_API_TYPE, [
      context.getHandler(),
      context.getClass(),
    ]);

    if (customType) {
      return customType;
    }

    const className = context.getClass().name;
    const withoutSuffix = className
      .replace(/Controller$/, '')
      .replace(/Service$/, '');

    return withoutSuffix
      .replace(/([A-Z])/g, (match, offset: number) =>
        offset > 0 ? '-' + match.toLowerCase() : match.toLowerCase(),
      )
      .replace(/-+$/, '')
      .toLowerCase();
  }

  private isPaginatedResponse(data: unknown): data is {
    items: unknown[];
    meta: { nextCursor?: string; hasMore?: boolean; total?: number };
  } {
    if (!data || typeof data !== 'object') {
      return false;
    }

    const obj = data as Record<string, unknown>;
    return (
      Array.isArray(obj.items) &&
      typeof obj.meta === 'object' &&
      obj.meta !== null
    );
  }

  private transformPaginated(
    data: { items: unknown[]; meta: { nextCursor?: string; hasMore?: boolean; total?: number } },
    resourceType: string,
    requestId: string | undefined,
    timestamp: string,
    selfLink: string,
  ): JsonApiResponse {
    const included: JsonApiResource[] = [];
    const resources: JsonApiResource[] = [];

    for (const item of data.items) {
      if (item && typeof item === 'object') {
        const { resource, included: itemIncluded } = this.serializeResource(
          item as Record<string, unknown>,
          resourceType,
        );
        resources.push(resource);
        included.push(...itemIncluded);
      }
    }

    const response: JsonApiResponse = {
      data: resources,
      included: included.length > 0 ? this.deduplicateIncluded(included) : undefined,
      meta: {
        requestId,
        timestamp,
        total: data.meta.total ?? data.items.length,
        nextCursor: data.meta.nextCursor,
        hasMore: data.meta.hasMore,
      },
      links: {
        self: selfLink,
        ...(data.meta.nextCursor ? { next: `${selfLink}${selfLink.includes('?') ? '&' : '?'}cursor=${data.meta.nextCursor}` } : {}),
      },
    };

    return response;
  }

  private transformArray(
    data: unknown[],
    resourceType: string,
    requestId: string | undefined,
    timestamp: string,
    selfLink: string,
  ): JsonApiResponse {
    const included: JsonApiResource[] = [];
    const resources: JsonApiResource[] = [];

    for (const item of data) {
      if (item && typeof item === 'object') {
        const { resource, included: itemIncluded } = this.serializeResource(
          item as Record<string, unknown>,
          resourceType,
        );
        resources.push(resource);
        included.push(...itemIncluded);
      }
    }

    return {
      data: resources,
      included: included.length > 0 ? this.deduplicateIncluded(included) : undefined,
      meta: {
        requestId,
        timestamp,
        total: resources.length,
      },
      links: { self: selfLink },
    };
  }

  private transformSingle(
    data: Record<string, unknown>,
    resourceType: string,
    requestId: string | undefined,
    timestamp: string,
    selfLink: string,
  ): JsonApiResponse {
    const { resource, included } = this.serializeResource(data, resourceType);

    return {
      data: resource,
      included: included.length > 0 ? this.deduplicateIncluded(included) : undefined,
      meta: {
        requestId,
        timestamp,
      },
      links: { self: selfLink },
    };
  }

  private serializeResource(
    data: Record<string, unknown>,
    defaultType: string,
  ): { resource: JsonApiResource; included: JsonApiResource[] } {
    const included: JsonApiResource[] = [];
    const id = this.extractId(data);
    const type = (data.type as string) || defaultType;

    const attributes: Record<string, unknown> = {};
    const relationships: Record<string, JsonApiRelationships> = {};

    const idKeys = new Set(['id', '_id', 'uuid']);
    const skipKeys = new Set(['id', '_id', 'uuid', 'type']);

    for (const [key, value] of Object.entries(data)) {
      if (skipKeys.has(key)) {
        continue;
      }

      if (this.isRelationshipObject(value)) {
        const relType = (value as Record<string, unknown>).type as string || this.inferTypeFromKey(key);
        const relId = String(this.extractId(value as Record<string, unknown>));

        relationships[key] = {
          data: { type: relType, id: relId },
        };

        const { resource: includedResource, included: nestedIncluded } = this.serializeResource(
          value as Record<string, unknown>,
          relType,
        );
        included.push(includedResource, ...nestedIncluded);
        continue;
      }

      if (Array.isArray(value) && value.length > 0 && this.isRelationshipObject(value[0])) {
        const relType = (value[0] as Record<string, unknown>).type as string || this.inferTypeFromKey(key);
        const relData: Array<{ type: string; id: string }> = [];

        for (const item of value) {
          if (this.isRelationshipObject(item)) {
            const relId = String(this.extractId(item as Record<string, unknown>));
            relData.push({ type: relType, id: relId });

            const { resource: includedResource, included: nestedIncluded } = this.serializeResource(
              item as Record<string, unknown>,
              relType,
            );
            included.push(includedResource, ...nestedIncluded);
          }
        }

        relationships[key] = {
          data: relData,
        };
        continue;
      }

      attributes[key] = value;
    }

    const resource: JsonApiResource = {
      type,
      id,
      attributes,
      ...(Object.keys(relationships).length > 0 ? { relationships } : {}),
    };

    return { resource, included };
  }

  private extractId(data: Record<string, unknown>): string {
    if (data.id !== undefined && data.id !== null) {
      return String(data.id);
    }
    if (data._id !== undefined && data._id !== null) {
      return String(data._id);
    }
    if (data.uuid !== undefined && data.uuid !== null) {
      return String(data.uuid);
    }
    return '';
  }

  private isRelationshipObject(value: unknown): boolean {
    if (!value || typeof value !== 'object' || Array.isArray(value)) {
      return false;
    }

    const obj = value as Record<string, unknown>;
    return (
      (obj.id !== undefined && obj.id !== null) ||
      (obj._id !== undefined && obj._id !== null) ||
      (obj.uuid !== undefined && obj.uuid !== null)
    );
  }

  private inferTypeFromKey(key: string): string {
    const singularMap: Record<string, string> = {
      items: 'item',
      users: 'user',
      products: 'product',
      clothing: 'clothing',
      categories: 'category',
      orders: 'order',
      messages: 'message',
      photos: 'photo',
      recommendations: 'recommendation',
      favorites: 'favorite',
      outfits: 'outfit',
      tags: 'tag',
      brands: 'brand',
      notifications: 'notification',
      sessions: 'session',
      addresses: 'address',
      cartItems: 'cart-item',
      wardrobeItems: 'wardrobe-item',
    };

    if (singularMap[key]) {
      return singularMap[key];
    }

    if (key.endsWith('s') && key.length > 1) {
      return key.slice(0, -1).replace(/([A-Z])/g, '-$1').toLowerCase().replace(/^-/, '');
    }

    return key.replace(/([A-Z])/g, '-$1').toLowerCase().replace(/^-/, '');
  }

  private deduplicateIncluded(included: JsonApiResource[]): JsonApiResource[] {
    const seen = new Map<string, JsonApiResource>();

    for (const resource of included) {
      const key = `${resource.type}:${resource.id}`;
      if (!seen.has(key)) {
        seen.set(key, resource);
      }
    }

    return Array.from(seen.values());
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Logger,
} from "@nestjs/common";
import { Request, Response } from "express";
import { Observable, tap } from "rxjs";

import { MetricsService } from "../../modules/metrics/metrics.service";

const SLOW_REQUEST_THRESHOLD_MS = 500;

@Injectable()
export class PerformanceInterceptor implements NestInterceptor {
  private readonly logger = new Logger(PerformanceInterceptor.name);

  constructor(private readonly metricsService: MetricsService) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    const request = context.switchToHttp().getRequest<Request>();
    const response = context.switchToHttp().getResponse<Response>();

    const { method } = request;
    const url = request.url || "/";
    const route = url.split("?")[0] ?? "/";

    const startHr = process.hrtime();

    return next.handle().pipe(
      tap({
        next: () => {
          const diff = process.hrtime(startHr);
          const durationMs = diff[0] * 1000 + diff[1] / 1_000_000;
          const durationSec = durationMs / 1000;

          const statusCode = response.statusCode?.toString() ?? "200";

          // Record Prometheus metrics
          this.metricsService.recordHttpRequest(
            method,
            route,
            parseInt(statusCode, 10),
            durationSec,
          );

          // Set response time header
          if (response.setHeader) {
            response.setHeader("X-Response-Time", `${durationMs.toFixed(1)}ms`);
          }

          // Log slow requests
          if (durationMs > SLOW_REQUEST_THRESHOLD_MS) {
            this.logger.warn(
              `Slow request: ${method} ${url} ${statusCode} ${durationMs.toFixed(1)}ms`,
            );
          }
        },
      }),
    );
  }
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from "@nestjs/common";
import { Observable } from "rxjs";
import { map } from "rxjs/operators";

const SENSITIVE_PROFILE_FIELDS = [
  "shoulder",
  "bust",
  "waist",
  "hip",
  "inseam",
  "height",
  "weight",
] as const;

const SENSITIVE_NESTED_PREFIXES = ["analysisResult", "measurements"];

@Injectable()
export class SensitiveDataInterceptor implements NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    return next.handle().pipe(
      map((data) => this.sanitizeResponse(data)),
    );
  }

  private sanitizeResponse(data: any): any {
    if (!data || typeof data !== "object") {
      return data;
    }

    if (Array.isArray(data)) {
      return data.map((item) => this.sanitizeResponse(item));
    }

    const sanitized = { ...data };

    for (const field of SENSITIVE_PROFILE_FIELDS) {
      if (field in sanitized) {
        delete sanitized[field];
      }
    }

    for (const prefix of SENSITIVE_NESTED_PREFIXES) {
      if (prefix in sanitized && sanitized[prefix] !== null && sanitized[prefix] !== undefined) {
        delete sanitized[prefix];
      }
    }

    if (sanitized.profile && typeof sanitized.profile === "object") {
      sanitized.profile = this.sanitizeResponse(sanitized.profile);
    }

    if (sanitized.userProfile && typeof sanitized.userProfile === "object") {
      sanitized.userProfile = this.sanitizeResponse(sanitized.userProfile);
    }

    return sanitized;
  }
}

import { AsyncLocalStorage } from 'async_hooks';
import { randomUUID } from 'crypto';

import { Injectable, NestMiddleware, Inject } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';

import { PINO_ASYNC_LOCAL_STORAGE } from './logger.module';
import { PinoLoggerService } from './logger.service';

interface RequestContext {
  requestId: string;
  userId?: string;
  [key: string]: unknown;
}

@Injectable()
export class TraceIdMiddleware implements NestMiddleware {
  constructor(
    @Inject(PINO_ASYNC_LOCAL_STORAGE)
    private readonly asyncLocalStorage: AsyncLocalStorage<RequestContext>,
    private readonly logger: PinoLoggerService,
  ) {}

  use(req: Request, res: Response, next: NextFunction): void {
    const traceId = this.getOrGenerateTraceId(req);
    const userId = this.extractUserId(req);
    const startTime = Date.now();

    const requestContext: RequestContext = {
      requestId: traceId,
      userId,
      method: req.method,
      url: req.originalUrl,
      ip: req.ip,
    };

    res.setHeader('X-Request-Id', traceId);

    this.logger.log('Request started', 'TraceIdMiddleware', {
      method: req.method,
      url: req.originalUrl,
      ip: req.ip,
      userAgent: req.headers['user-agent']?.substring(0, 100),
    });

    res.on('finish', () => {
      const duration = Date.now() - startTime;

      this.logger.log('Request completed', 'TraceIdMiddleware', {
        method: req.method,
        url: req.originalUrl,
        statusCode: res.statusCode,
        duration: `${duration}ms`,
      });
    });

    res.on('error', (error: Error) => {
      const duration = Date.now() - startTime;

      this.logger.error('Request failed', error.stack, 'TraceIdMiddleware', {
        method: req.method,
        url: req.originalUrl,
        statusCode: res.statusCode || 500,
        duration: `${duration}ms`,
        errorMessage: error.message,
      });
    });

    this.asyncLocalStorage.run(requestContext, () => {
      next();
    });
  }

  private getOrGenerateTraceId(req: Request): string {
    const headerTraceId = req.headers['x-request-id'];
    if (typeof headerTraceId === 'string' && headerTraceId.trim()) {
      return headerTraceId.trim();
    }

    const queryTraceId = req.query.requestId;
    if (typeof queryTraceId === 'string' && queryTraceId.trim()) {
      return queryTraceId.trim();
    }

    return `req_${randomUUID().replace(/-/g, '')}`;
  }

  private extractUserId(req: Request): string | undefined {
    const user = req.user as { id?: string; sub?: string } | undefined;
    if (user?.id) {return user.id;}
    if (user?.sub) {return user.sub;}

    const userIdHeader = req.headers['x-user-id'];
    if (typeof userIdHeader === 'string' && userIdHeader.trim()) {
      return userIdHeader.trim();
    }

    return undefined;
  }
}

import { AsyncLocalStorage } from 'async_hooks';

import { Module, Global, Provider, DynamicModule } from '@nestjs/common';
import { ConfigModule, ConfigService } from '@nestjs/config';

import { TraceIdMiddleware } from './logger.middleware';
import { PinoLoggerService, PinoChildLogger } from './logger.service';

export const PINO_ASYNC_LOCAL_STORAGE = 'PINO_ASYNC_LOCAL_STORAGE';

interface RequestContext {
  requestId: string;
  userId?: string;
  [key: string]: unknown;
}

export interface LoggerModuleOptions {
  isGlobal?: boolean;
}

@Global()
@Module({})
export class LoggerModule {
  static forRoot(options: LoggerModuleOptions = {}): DynamicModule {
    const asyncLocalStorageProvider: Provider = {
      provide: PINO_ASYNC_LOCAL_STORAGE,
      useValue: new AsyncLocalStorage<RequestContext>(),
    };

    const pinoLoggerProvider: Provider = {
      provide: PinoLoggerService,
      useFactory: (
        configService: ConfigService,
        asyncLocalStorage: AsyncLocalStorage<RequestContext>,
      ) => {
        return new PinoLoggerService(configService, asyncLocalStorage);
      },
      inject: [ConfigService, PINO_ASYNC_LOCAL_STORAGE],
    };

    return {
      module: LoggerModule,
      imports: [ConfigModule],
      providers: [
        asyncLocalStorageProvider,
        pinoLoggerProvider,
        TraceIdMiddleware,
      ],
      exports: [PinoLoggerService, PinoChildLogger, TraceIdMiddleware],
      global: options.isGlobal !== false,
    };
  }
}

import { AsyncLocalStorage } from 'async_hooks';

import { Injectable, LoggerService, Scope, Optional } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import pino, { Logger, LoggerOptions } from 'pino';

const SENSITIVE_FIELDS = [
  'password',
  'passwordHash',
  'token',
  'accessToken',
  'refreshToken',
  'apiKey',
  'secret',
  'creditCard',
  'cvv',
  'ssn',
  'phone',
  'mobile',
  'idCard',
  'encryptionKey',
  'privateKey',
];

interface RequestContext {
  requestId: string;
  userId?: string;
  [key: string]: unknown;
}

@Injectable({ scope: Scope.DEFAULT })
export class PinoLoggerService implements LoggerService {
  private readonly pino: Logger;
  private readonly context?: string;
  private readonly serviceName: string;
  private readonly asyncLocalStorage: AsyncLocalStorage<RequestContext>;

  constructor(
    private readonly configService: ConfigService,
    @Optional() asyncLocalStorage?: AsyncLocalStorage<RequestContext>,
    @Optional() context?: string,
  ) {
    this.context = context;
    this.serviceName = this.configService.get<string>('SERVICE_NAME', 'xuno-backend');
    this.asyncLocalStorage = asyncLocalStorage || new AsyncLocalStorage<RequestContext>();
    this.pino = this.createLogger();
  }

  private createLogger(): Logger {
    const nodeEnv = this.configService.get<string>('NODE_ENV', 'development');
    const logLevel = this.configService.get<string>('LOG_LEVEL', nodeEnv === 'production' ? 'warn' : 'debug');
    const isProduction = nodeEnv === 'production';

    const options: LoggerOptions = {
      level: logLevel,
      formatters: {
        level(label) {
          return { level: label };
        },
        bindings(bindings) {
          return {
            service: bindings.name || 'xuno-backend',
            pid: bindings.pid,
          };
        },
        log(object) {
          return object;
        },
      },
      timestamp: pino.stdTimeFunctions.isoTime,
      redact: {
        paths: SENSITIVE_FIELDS.map((field) => `*.${field}`),
        censor: '[REDACTED]',
      },
      serializers: {
        err: pino.stdSerializers.err,
        req: pino.stdSerializers.req,
        res: pino.stdSerializers.res,
      },
    };

    if (isProduction) {
      return pino(options);
    }

    return pino(options, pino.transport({
      target: 'pino-pretty',
      options: {
        colorize: true,
        translateTime: 'SYS:yyyy-mm-dd HH:MM:ss.l',
        ignore: 'pid,hostname',
        singleLine: true,
      },
    }));
  }

  private getTraceId(): string | undefined {
    const store = this.asyncLocalStorage.getStore();
    return store?.requestId;
  }

  private getUserId(): string | undefined {
    const store = this.asyncLocalStorage.getStore();
    return store?.userId;
  }

  private enrichMeta(meta?: Record<string, unknown>): Record<string, unknown> {
    const enriched: Record<string, unknown> = {};

    const traceId = this.getTraceId();
    if (traceId) {
      enriched.traceId = traceId;
    }

    const userId = this.getUserId();
    if (userId) {
      enriched.userId = userId;
    }

    if (this.context) {
      enriched.context = this.context;
    }

    if (meta) {
      const sanitized = this.sanitizeData(meta);
      Object.assign(enriched, sanitized);
    }

    return enriched;
  }

  private sanitizeData(data: Record<string, unknown>): Record<string, unknown> {
    const sanitized: Record<string, unknown> = {};

    for (const [key, value] of Object.entries(data)) {
      const lowerKey = key.toLowerCase();

      if (SENSITIVE_FIELDS.some((field) => lowerKey.includes(field.toLowerCase()))) {
        sanitized[key] = this.maskValue(value);
      } else if (typeof value === 'string') {
        sanitized[key] = this.sanitizeString(value, key);
      } else if (value && typeof value === 'object' && !Array.isArray(value)) {
        sanitized[key] = this.sanitizeData(value as Record<string, unknown>);
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  private sanitizeString(value: string, key: string): string {
    const lowerKey = key.toLowerCase();

    if (lowerKey.includes('email') && value.includes('@')) {
      const parts = value.split('@');
      const localPart = parts[0];
      const domain = parts[1];
      if (localPart && domain) {
        return `${localPart.charAt(0)}***@${domain}`;
      }
    }

    if (lowerKey.includes('phone') || lowerKey.includes('mobile')) {
      if (/^\d{11}$/.test(value)) {
        return value.replace(/(\d{3})\d{4}(\d{4})/, '$1****$2');
      }
    }

    if (lowerKey.includes('idcard') || lowerKey.includes('id_card')) {
      if (/^\d{17}[\dXx]$/.test(value)) {
        return value.replace(/(\d{6})\d{8}(\d{4})/, '$1********$2');
      }
    }

    return value;
  }

  private maskValue(value: unknown): string {
    if (value === null || value === undefined) {
      return '[REDACTED]';
    }

    const strValue = String(value);
    if (strValue.length <= 4) {
      return '****';
    }

    return strValue.substring(0, 2) + '****' + strValue.substring(strValue.length - 2);
  }

  verbose(message: string, context?: string, ...optionalParams: unknown[]): void {
    const meta = this.buildMeta(context, optionalParams);
    this.pino.trace(meta, message);
  }

  debug(message: string, context?: string, ...optionalParams: unknown[]): void {
    const meta = this.buildMeta(context, optionalParams);
    this.pino.debug(meta, message);
  }

  log(message: string, context?: string, ...optionalParams: unknown[]): void {
    const meta = this.buildMeta(context, optionalParams);
    this.pino.info(meta, message);
  }

  warn(message: string, context?: string, ...optionalParams: unknown[]): void {
    const meta = this.buildMeta(context, optionalParams);
    this.pino.warn(meta, message);
  }

  error(message: string, trace?: string, context?: string, ...optionalParams: unknown[]): void {
    const meta = this.buildMeta(context, optionalParams);
    if (trace) {
      meta.stack = trace;
    }
    this.pino.error(meta, message);
  }

  private buildMeta(
    context?: string,
    optionalParams?: unknown[],
  ): Record<string, unknown> {
    const meta = this.enrichMeta();

    if (context) {
      meta.context = context;
    }

    if (optionalParams && optionalParams.length > 0) {
      const lastParam = optionalParams[optionalParams.length - 1];
      if (lastParam && typeof lastParam === 'object' && !Array.isArray(lastParam)) {
        Object.assign(meta, this.sanitizeData(lastParam as Record<string, unknown>));
      }
    }

    return meta;
  }

  setContext(context: string): void {
    (this as unknown as { context?: string }).context = context;
  }

  createChildLogger(context: string): PinoChildLogger {
    return new PinoChildLogger(this, context);
  }

  getAsyncLocalStorage(): AsyncLocalStorage<RequestContext> {
    return this.asyncLocalStorage;
  }
}

export class PinoChildLogger {
  constructor(
    private readonly logger: PinoLoggerService,
    private readonly context: string,
  ) {}

  debug(message: string, data?: Record<string, unknown>): void {
    this.logger.debug(message, this.context, data);
  }

  log(message: string, data?: Record<string, unknown>): void {
    this.logger.log(message, this.context, data);
  }

  info(message: string, data?: Record<string, unknown>): void {
    this.logger.log(message, this.context, data);
  }

  warn(message: string, data?: Record<string, unknown>): void {
    this.logger.warn(message, this.context, data);
  }

  error(message: string, trace?: string, data?: Record<string, unknown>): void {
    this.logger.error(message, trace, this.context, data);
  }
}

/**
 * @fileoverview Structured Logger Service - 企业级结构化日志系统
 *
 * 提供结构化JSON格式日志，支持：
 * - 请求ID追踪 (RequestId)
 * - 用户ID关联 (UserId)
 * - 时间戳 (ISO 8601)
 * - 敏感信息脱敏
 * - 多日志级别 (debug, log, warn, error)
 * - 上下文信息注入
 *
 * @example
 * ```typescript
 * // 基础使用
 * this.logger.log('用户登录成功', { userId: '123', email: 'test@example.com' });
 *
 * // 输出JSON格式
 * {
 *   "level": "info",
 *   "message": "用户登录成功",
 *   "timestamp": "2026-04-01T10:30:00.000Z",
 *   "context": "AuthService",
 *   "requestId": "req-abc123",
 *   "userId": "123",
 *   "data": { "email": "t***@example.com" }  // 脱敏后
 * }
 * ```
 */

import { AsyncLocalStorage } from "async_hooks";

import { Injectable, LoggerService, Scope } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

/**
 * 日志级别枚举
 */
export type LogLevel = "debug" | "info" | "warn" | "error";

/**
 * 结构化日志条目接口
 */
export interface StructuredLogEntry {
  /** 日志级别 */
  level: LogLevel;
  /** 日志消息 */
  message: string;
  /** ISO 8601 时间戳 */
  timestamp: string;
  /** 日志上下文（通常是类名） */
  context: string;
  /** 请求ID（用于追踪请求链路） */
  requestId?: string;
  /** 用户ID */
  userId?: string;
  /** 附加数据 */
  data?: Record<string, unknown>;
  /** 错误堆栈（仅error级别） */
  stack?: string;
  /** 环境标识 */
  env?: string;
  /** 服务名称 */
  service?: string;
}

/**
 * 请求上下文接口
 */
export interface RequestContext {
  requestId: string;
  userId?: string;
  [key: string]: unknown;
}

/**
 * 敏感字段配置
 */
const SENSITIVE_FIELDS = [
  "password",
  "passwordHash",
  "token",
  "accessToken",
  "refreshToken",
  "apiKey",
  "secret",
  "creditCard",
  "cvv",
  "ssn",
  "phone",
  "mobile",
  "idCard",
];

/**
 * 结构化日志服务
 *
 * @class StructuredLoggerService
 * @implements {LoggerService}
 */
@Injectable({ scope: Scope.DEFAULT })
export class StructuredLoggerService implements LoggerService {
  private readonly context?: string;
  private readonly asyncLocalStorage: AsyncLocalStorage<RequestContext>;
  private readonly isProduction: boolean;
  private readonly serviceName: string;
  private readonly logLevel: LogLevel;

  constructor(
    private readonly configService: ConfigService,
    asyncLocalStorage?: AsyncLocalStorage<RequestContext>,
  ) {
    this.asyncLocalStorage = asyncLocalStorage || new AsyncLocalStorage<RequestContext>();
    this.isProduction = this.configService.get<string>("NODE_ENV") === "production";
    this.serviceName = this.configService.get<string>("SERVICE_NAME", "xuno-backend");
    this.logLevel = this.configService.get<LogLevel>("LOG_LEVEL", "info");
  }

  /**
   * 设置上下文
   */
  setContext(context: string): void {
    (this as unknown as { context?: string }).context = context;
  }

  /**
   * 获取当前请求上下文
   */
  private getRequestContext(): Partial<RequestContext> {
    const store = this.asyncLocalStorage.getStore();
    return store || {};
  }

  /**
   * 创建结构化日志条目
   */
  private createLogEntry(
    level: LogLevel,
    message: string,
    context: string,
    data?: Record<string, unknown>,
    stack?: string,
  ): StructuredLogEntry {
    const requestContext = this.getRequestContext();

    const entry: StructuredLogEntry = {
      level,
      message,
      timestamp: new Date().toISOString(),
      context,
      env: this.isProduction ? "production" : "development",
      service: this.serviceName,
    };

    // 注入请求上下文
    if (requestContext.requestId) {
      entry.requestId = requestContext.requestId;
    }
    if (requestContext.userId) {
      entry.userId = requestContext.userId;
    }

    // 脱敏处理附加数据
    if (data && Object.keys(data).length > 0) {
      entry.data = this.sanitizeData(data);
    }

    // 错误堆栈
    if (stack) {
      entry.stack = stack;
    }

    return entry;
  }

  /**
   * 敏感信息脱敏
   */
  private sanitizeData(data: Record<string, unknown>): Record<string, unknown> {
    const sanitized: Record<string, unknown> = {};

    for (const [key, value] of Object.entries(data)) {
      const lowerKey = key.toLowerCase();

      // 检查是否为敏感字段
      if (SENSITIVE_FIELDS.some((field) => lowerKey.includes(field.toLowerCase()))) {
        sanitized[key] = this.maskValue(value);
      } else if (typeof value === "string") {
        // 检查字符串是否包含敏感信息
        sanitized[key] = this.sanitizeString(value, key);
      } else if (value && typeof value === "object") {
        // 递归处理嵌套对象
        sanitized[key] = this.sanitizeData(value as Record<string, unknown>);
      } else {
        sanitized[key] = value;
      }
    }

    return sanitized;
  }

  /**
   * 脱敏字符串值
   */
  private sanitizeString(value: string, key: string): string {
    const lowerKey = key.toLowerCase();

    // 邮箱脱敏: test@example.com -> t***@example.com
    if (lowerKey.includes("email") && value.includes("@")) {
      const parts = value.split("@");
      const localPart = parts[0];
      const domain = parts[1];
      if (localPart && domain) {
        const maskedLocal = localPart.charAt(0) + "***";
        return `${maskedLocal}@${domain}`;
      }
    }

    // 手机号脱敏: 13812345678 -> 138****5678
    if (lowerKey.includes("phone") || lowerKey.includes("mobile")) {
      if (/^\d{11}$/.test(value)) {
        return value.replace(/(\d{3})\d{4}(\d{4})/, "$1****$2");
      }
    }

    // 身份证脱敏: 110101199001011234 -> 110101********1234
    if (lowerKey.includes("idcard") || lowerKey.includes("id_card")) {
      if (/^\d{17}[\dXx]$/.test(value)) {
        return value.replace(/(\d{6})\d{8}(\d{4})/, "$1********$2");
      }
    }

    // 银行卡脱敏: 6222021234567890 -> 6222****7890
    if (lowerKey.includes("card") || lowerKey.includes("account")) {
      if (/^\d{16,19}$/.test(value)) {
        return value.replace(/(\d{4})\d+(\d{4})/, "$1****$2");
      }
    }

    return value;
  }

  /**
   * 遮罩敏感值
   */
  private maskValue(value: unknown): string {
    if (value === null || value === undefined) {
      return "[REDACTED]";
    }

    const strValue = String(value);
    if (strValue.length <= 4) {
      return "****";
    }

    // 保留前后各2个字符
    return strValue.substring(0, 2) + "****" + strValue.substring(strValue.length - 2);
  }

  /**
   * 格式化输出日志
   */
  private formatOutput(entry: StructuredLogEntry): string {
    if (this.isProduction) {
      // 生产环境：JSON格式（便于日志聚合分析）
      return JSON.stringify(entry);
    } else {
      // 开发环境：可读格式 + JSON数据
      const { level, message, context, requestId, userId, data } = entry;
      const prefix = `[${level.toUpperCase()}] ${context}`;
      const contextInfo = requestId ? ` [req:${requestId}]` : "";
      const userInfo = userId ? ` [user:${userId}]` : "";

      if (data && Object.keys(data).length > 0) {
        return `${prefix}${contextInfo}${userInfo} ${message} | ${JSON.stringify(data)}`;
      }
      return `${prefix}${contextInfo}${userInfo} ${message}`;
    }
  }

  /**
   * 检查日志级别是否应该输出
   */
  private shouldLog(level: LogLevel): boolean {
    const levels: LogLevel[] = ["debug", "info", "warn", "error"];
    const currentLevelIndex = levels.indexOf(this.logLevel);
    const messageLevelIndex = levels.indexOf(level);
    return messageLevelIndex >= currentLevelIndex;
  }

  /**
   * Debug级别日志
   */
  debug(message: string, context?: string, data?: Record<string, unknown>): void;
  debug(message: string, data?: Record<string, unknown>): void;
  debug(message: string, contextOrData?: string | Record<string, unknown>, data?: Record<string, unknown>): void {
    if (!this.shouldLog("debug")) {return;}

    const { context, data: logData } = this.parseArguments(contextOrData, data);
    const entry = this.createLogEntry("debug", message, context, logData);
    console.debug(this.formatOutput(entry));
  }

  /**
   * Info级别日志
   */
  log(message: string, context?: string, data?: Record<string, unknown>): void;
  log(message: string, data?: Record<string, unknown>): void;
  log(message: string, contextOrData?: string | Record<string, unknown>, data?: Record<string, unknown>): void {
    if (!this.shouldLog("info")) {return;}

    const { context, data: logData } = this.parseArguments(contextOrData, data);
    const entry = this.createLogEntry("info", message, context, logData);
    console.log(this.formatOutput(entry));
  }

  /**
   * Warn级别日志
   */
  warn(message: string, context?: string, data?: Record<string, unknown>): void;
  warn(message: string, data?: Record<string, unknown>): void;
  warn(message: string, contextOrData?: string | Record<string, unknown>, data?: Record<string, unknown>): void {
    if (!this.shouldLog("warn")) {return;}

    const { context, data: logData } = this.parseArguments(contextOrData, data);
    const entry = this.createLogEntry("warn", message, context, logData);
    console.warn(this.formatOutput(entry));
  }

  /**
   * Error级别日志
   */
  error(message: string, trace?: string, context?: string, data?: Record<string, unknown>): void;
  error(message: string, data?: Record<string, unknown>): void;
  error(message: string, traceOrData?: string | Record<string, unknown>, contextOrData?: string | Record<string, unknown>, data?: Record<string, unknown>): void {
    if (!this.shouldLog("error")) {return;}

    let trace: string | undefined;
    let context: string | undefined;
    let logData: Record<string, unknown> | undefined;

    if (typeof traceOrData === "string") {
      trace = traceOrData;
      if (typeof contextOrData === "string") {
        context = contextOrData;
        logData = data;
      } else {
        logData = contextOrData;
      }
    } else {
      logData = traceOrData;
    }

    const finalContext = context || this.context || "Application";
    const entry = this.createLogEntry("error", message, finalContext, logData, trace);
    console.error(this.formatOutput(entry));
  }

  /**
   * 解析参数重载
   */
  private parseArguments(
    contextOrData?: string | Record<string, unknown>,
    data?: Record<string, unknown>,
  ): { context: string; data?: Record<string, unknown> } {
    if (typeof contextOrData === "string") {
      return {
        context: contextOrData,
        data,
      };
    } else {
      return {
        context: this.context || "Application",
        data: contextOrData,
      };
    }
  }

  /**
   * 创建子日志器（带固定上下文）
   */
  createChildLogger(context: string): ContextualLogger {
    return new ContextualLogger(this, context);
  }

  /**
   * 获取AsyncLocalStorage实例（用于拦截器注入请求上下文）
   */
  getAsyncLocalStorage(): AsyncLocalStorage<RequestContext> {
    return this.asyncLocalStorage;
  }
}

/**
 * 带上下文的日志器
 */
export class ContextualLogger {
  constructor(
    private readonly logger: StructuredLoggerService,
    private readonly context: string,
  ) {}

  debug(message: string, data?: Record<string, unknown>): void {
    this.logger.debug(message, this.context, data);
  }

  log(message: string, data?: Record<string, unknown>): void {
    this.logger.log(message, this.context, data);
  }

  warn(message: string, data?: Record<string, unknown>): void {
    this.logger.warn(message, this.context, data);
  }

  error(message: string, trace?: string, data?: Record<string, unknown>): void {
    this.logger.error(message, trace, this.context, data);
  }
}

import { Request, Response, NextFunction } from 'express';

import { ApiVersionMiddleware, SUPPORTED_API_VERSIONS } from './api-version.middleware';

function createMockRequest(url: string) {
  return {
    url,
    originalUrl: url,
    headers: {},
    apiVersion: undefined,
  } as unknown as Request;
}

function createMockResponse() {
  const res = {
    setHeader: jest.fn(),
    status: jest.fn().mockReturnThis(),
    json: jest.fn().mockReturnThis(),
  } as unknown as Response;
  return res;
}

function createMockNext() {
  return jest.fn() as NextFunction;
}

describe('ApiVersionMiddleware', () => {
  let middleware: ApiVersionMiddleware;
  let res: Response;
  let next: NextFunction;

  beforeEach(() => {
    middleware = new ApiVersionMiddleware();
    res = createMockResponse();
    next = createMockNext();
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('valid versioned paths', () => {
    it('should pass through /api/v1/users and set apiVersion', () => {
      const req = createMockRequest('/api/v1/users');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBe('1');
      expect(res.setHeader).toHaveBeenCalledWith('X-API-Version', 'v1');
      expect(next).toHaveBeenCalled();
    });

    it('should pass through /api/v1/clothing/123', () => {
      const req = createMockRequest('/api/v1/clothing/123');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBe('1');
      expect(next).toHaveBeenCalled();
    });
  });

  describe('unsupported versions', () => {
    it('should return 400 with JSON:API error for /api/v2/users', () => {
      const req = createMockRequest('/api/v2/users');

      middleware.use(req, res, next);

      expect(next).not.toHaveBeenCalled();
      expect(res.status).toHaveBeenCalledWith(400);
      expect((res as any).json).toHaveBeenCalledWith({
        errors: [
          {
            status: '400',
            code: 'UNSUPPORTED_API_VERSION',
            title: 'Unsupported API Version',
            detail: "API version 'v2' is not supported. Supported versions: v1",
            source: { parameter: 'version' },
          },
        ],
      });
    });

    it('should return 400 for /api/v99/endpoint', () => {
      const req = createMockRequest('/api/v99/endpoint');

      middleware.use(req, res, next);

      expect(res.status).toHaveBeenCalledWith(400);
    });
  });

  describe('unversioned /api/ paths', () => {
    it('should rewrite /api/users to /api/v1/users', () => {
      const req = createMockRequest('/api/users');

      middleware.use(req, res, next);

      expect(req.url).toBe('/api/v1/users');
      expect(req.apiVersion).toBe('1');
      expect(res.setHeader).toHaveBeenCalledWith('X-API-Version', 'v1');
      expect(next).toHaveBeenCalled();
    });

    it('should preserve query string during rewrite', () => {
      const req = createMockRequest('/api/users?page=1&limit=20');

      middleware.use(req, res, next);

      expect(req.url).toContain('/api/v1/users');
      expect(req.originalUrl).toContain('page=1&limit=20');
      expect(next).toHaveBeenCalled();
    });
  });

  describe('skip paths', () => {
    it('should pass through /health without modification', () => {
      const req = createMockRequest('/health');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(res.setHeader).not.toHaveBeenCalled();
      expect(next).toHaveBeenCalled();
    });

    it('should pass through /metrics without modification', () => {
      const req = createMockRequest('/metrics');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(next).toHaveBeenCalled();
    });

    it('should pass through /api/docs without modification', () => {
      const req = createMockRequest('/api/docs');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(next).toHaveBeenCalled();
    });

    it('should pass through /api/docs-json without modification', () => {
      const req = createMockRequest('/api/docs-json');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(next).toHaveBeenCalled();
    });

    it('should pass through /api/docs-yaml without modification', () => {
      const req = createMockRequest('/api/docs-yaml');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(next).toHaveBeenCalled();
    });
  });

  describe('non-/api/ paths', () => {
    it('should pass through non-API paths without modification', () => {
      const req = createMockRequest('/some/other/path');

      middleware.use(req, res, next);

      expect(req.apiVersion).toBeUndefined();
      expect(res.setHeader).not.toHaveBeenCalled();
      expect(next).toHaveBeenCalled();
    });
  });

  describe('custom supported versions', () => {
    it('should accept custom supported versions via constructor', () => {
      const customMiddleware = new ApiVersionMiddleware(['1', '2']);
      const req = createMockRequest('/api/v2/users');

      customMiddleware.use(req, res, next);

      expect(req.apiVersion).toBe('2');
      expect(res.setHeader).toHaveBeenCalledWith('X-API-Version', 'v2');
      expect(next).toHaveBeenCalled();
    });

    it('should reject versions not in custom list', () => {
      const customMiddleware = new ApiVersionMiddleware(['2']);
      const req = createMockRequest('/api/v1/users');

      customMiddleware.use(req, res, next);

      expect(res.status).toHaveBeenCalledWith(400);
      expect(next).not.toHaveBeenCalled();
    });
  });

  describe('SUPPORTED_API_VERSIONS constant', () => {
    it('should default to ["1"]', () => {
      expect(SUPPORTED_API_VERSIONS).toEqual(['1']);
    });
  });
});

import { Injectable, NestMiddleware } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';

export const SUPPORTED_API_VERSIONS = ['1'];

const SKIP_PATHS = [
  '/api/docs',
  '/api/docs-json',
  '/api/docs-yaml',
  '/health',
  '/metrics',
];

const VERSION_PATTERN = /^\/api\/v(\d+)\//;
const API_PREFIX_PATTERN = /^\/api\//;

interface JsonApiError {
  status: string;
  code: string;
  title: string;
  detail: string;
  source: { parameter: string };
}

interface JsonApiErrorResponse {
  errors: JsonApiError[];
}

declare global {
  namespace Express {
    interface Request {
      apiVersion?: string;
    }
  }
}

@Injectable()
export class ApiVersionMiddleware implements NestMiddleware {
  private readonly supportedVersions: string[];

  constructor(supportedVersions: string[] = SUPPORTED_API_VERSIONS) {
    this.supportedVersions = supportedVersions;
  }

  use(req: Request, res: Response, next: NextFunction): void {
    const path = req.originalUrl || req.url;

    if (SKIP_PATHS.some((skipPath) => path.startsWith(skipPath))) {
      next();
      return;
    }

    if (!API_PREFIX_PATTERN.test(path)) {
      next();
      return;
    }

    const versionMatch = path.match(VERSION_PATTERN);

    if (versionMatch) {
      const requestedVersion = versionMatch[1]!;

      if (!this.supportedVersions.includes(requestedVersion)) {
        const supportedList = this.supportedVersions.map((v) => `v${v}`).join(', ');
        const errorResponse: JsonApiErrorResponse = {
          errors: [
            {
              status: '400',
              code: 'UNSUPPORTED_API_VERSION',
              title: 'Unsupported API Version',
              detail: `API version 'v${requestedVersion}' is not supported. Supported versions: ${supportedList}`,
              source: { parameter: 'version' },
            },
          ],
        };
        res.status(400).json(errorResponse);
        return;
      }

      req.apiVersion = requestedVersion;
      res.setHeader('X-API-Version', `v${requestedVersion}`);
      next();
      return;
    }

    const rewrittenPath = path.replace(/^\/api\//, `/api/v${this.supportedVersions[0]}/`);
    req.url = rewrittenPath;

    const queryStringIndex = req.originalUrl.indexOf('?');
    const queryString = queryStringIndex !== -1 ? req.originalUrl.substring(queryStringIndex) : '';
    req.originalUrl = rewrittenPath + queryString;

    req.apiVersion = this.supportedVersions[0];
    res.setHeader('X-API-Version', `v${this.supportedVersions[0]}`);
    next();
  }
}

/**
 * @fileoverview 全局错误处理中间件
 *
 * 提供请求级别的错误捕获和处理能力：
 * - 请求上下文注入（requestId, timestamp）
 * - 异常捕获和转换
 * - 请求超时处理
 * - 错误响应标准化
 *
 * 与 AllExceptionsFilter 配合使用，形成完整的错误处理链：
 * Middleware (请求预处理) -> Controller -> Service -> Filter (异常后处理)
 *
 * @example
 * ```typescript
 * // 在 main.ts 中应用
 * app.use(new ErrorHandlerMiddleware().use);
 * ```
 */

import { Injectable, NestMiddleware, HttpStatus, Logger } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';
import { v4 as uuidv4 } from 'uuid';

/**
 * 错误响应接口
 */
interface ErrorResponseBody {
  code: number;
  message: string;
  details?: Record<string, unknown>;
  timestamp: string;
  requestId: string;
  path: string;
}

/**
 * 扩展 Request 接口
 */
declare global {
  namespace Express {
    interface Request {
      /** 请求唯一标识符 */
      requestId: string;
      /** 请求开始时间戳 */
      requestStartTime: number;
    }
  }
}

/**
 * 全局错误处理中间件
 *
 * @class ErrorHandlerMiddleware
 * @implements {NestMiddleware}
 */
@Injectable()
export class ErrorHandlerMiddleware implements NestMiddleware {
  private readonly isProduction: boolean;
  private readonly logger = new Logger('ErrorHandlerMiddleware');

  constructor() {
    this.isProduction = process.env.NODE_ENV === 'production';
  }

  /**
   * 中间件主方法
   */
  use(req: Request, res: Response, next: NextFunction): void {
    // 注入请求上下文
    this.injectRequestContext(req, res);

    // 设置请求超时处理
    this.setupTimeoutHandler(req, res);

    // 设置响应完成监听
    this.setupResponseListener(req, res);

    // 包装响应的 json 方法以标准化错误响应
    this.wrapJsonResponse(req, res);

    next();
  }

  /**
   * 注入请求上下文
   */
  private injectRequestContext(req: Request, res: Response): void {
    req.requestId = (req.headers['x-request-id'] as string) || uuidv4();
    req.requestStartTime = Date.now();

    // 设置响应头
    res.setHeader('X-Request-Id', req.requestId);
  }

  /**
   * 设置请求超时处理
   */
  private setupTimeoutHandler(req: Request, res: Response): void {
    const timeout = parseInt(process.env.REQUEST_TIMEOUT_MS || '30000', 10);

    req.setTimeout(timeout, () => {
      this.handleTimeout(req, res);
    });

    res.setTimeout(timeout, () => {
      this.handleTimeout(req, res);
    });
  }

  /**
   * 处理请求超时
   */
  private handleTimeout(req: Request, res: Response): void {
    if (!res.headersSent) {
      const errorResponse: ErrorResponseBody = {
        code: 50400,
        message: '请求超时',
        timestamp: new Date().toISOString(),
        requestId: req.requestId,
        path: req.url,
      };

      this.logger.warn({
        message: 'Request timeout',
        requestId: req.requestId,
        method: req.method,
        url: req.url,
        duration: Date.now() - req.requestStartTime,
      });

      res.status(HttpStatus.GATEWAY_TIMEOUT).json(errorResponse);
    }
  }

  /**
   * 设置响应完成监听
   */
  private setupResponseListener(req: Request, res: Response): void {
    res.on('finish', () => {
      const duration = Date.now() - req.requestStartTime;

      if (res.statusCode >= 400) {
        this.logger.warn({
          message: 'Request completed with error',
          requestId: req.requestId,
          method: req.method,
          url: req.url,
          statusCode: res.statusCode,
          duration,
        });
      }
    });
  }

  /**
   * 包装响应的 json 方法
   */
  private wrapJsonResponse(req: Request, res: Response): void {
    const originalJson = res.json.bind(res);

    res.json = (body: unknown): Response => {
      // 如果是错误响应且未标准化，进行标准化处理
      if (res.statusCode >= 400 && body && typeof body === 'object') {
        const bodyObj = body as Record<string, unknown>;

        // 检查是否已经是标准格式
        if (!('code' in bodyObj) || !('timestamp' in bodyObj)) {
          const standardizedBody = this.standardizeErrorResponse(
            bodyObj,
            req,
            res.statusCode,
          );
          return originalJson(standardizedBody);
        }
      }

      return originalJson(body);
    };
  }

  /**
   * 标准化错误响应
   */
  private standardizeErrorResponse(
    body: Record<string, unknown>,
    req: Request,
    statusCode: number,
  ): ErrorResponseBody {
    return {
      code: (body.code as number) ?? this.inferErrorCode(statusCode),
      message: (body.message as string) ?? 'An error occurred',
      details: body.details as Record<string, unknown> | undefined,
      timestamp: new Date().toISOString(),
      requestId: req.requestId,
      path: req.url,
    };
  }

  /**
   * 根据 HTTP 状态码推断错误码
   */
  private inferErrorCode(statusCode: number): number {
    const mapping: Record<number, number> = {
      400: 40000,
      401: 40100,
      403: 40300,
      404: 40400,
      409: 40900,
      422: 42200,
      429: 42900,
      500: 50000,
      502: 50200,
      503: 50300,
      504: 50400,
    };

    return mapping[statusCode] ?? 50000;
  }
}

// 导出一个工厂函数，方便在 main.ts 中使用
export function createErrorHandlerMiddleware(): ErrorHandlerMiddleware {
  return new ErrorHandlerMiddleware();
}

import {
  Injectable,
  NestMiddleware,
  Logger,
} from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';

import { MetricsService } from '../../modules/metrics/metrics.service';

@Injectable()
export class MetricsMiddleware implements NestMiddleware {
  private readonly logger = new Logger(MetricsMiddleware.name);

  constructor(private readonly metricsService: MetricsService) {}

  use(req: Request, res: Response, next: NextFunction) {
    const start = Date.now();
    const { method, originalUrl } = req;

    // 获取路由路径（移除参数）
    const route = this.getRoutePath(req);

    // 监听响应完成事件
    res.on('finish', () => {
      const duration = (Date.now() - start) / 1000; // 转换为秒
      const statusCode = res.statusCode;

      // 记录 HTTP 请求指标
      this.metricsService.recordHttpRequest(method, route, statusCode, duration);

      // 慢请求日志
      if (duration > 2) {
        this.logger.warn(
          `Slow request: ${method} ${route} - ${duration.toFixed(3)}s - ${statusCode}`,
        );
      }
    });

    next();
  }

  /**
   * 获取路由路径，将动态参数替换为占位符
   * 例如: /users/123 -> /users/:id
   */
  private getRoutePath(req: Request): string {
    // 尝试从路由中获取路径模式
    if (req.route?.path) {
      return req.route.path;
    }

    // 如果没有路由信息，使用原始 URL 但移除查询参数
    const url = req.originalUrl || req.url;
    const [path = "/"] = url.split('?');

    // 尝试将数字 ID 替换为 :id
    return path.replace(/\/\d+/g, '/:id');
  }
}

import { Injectable, NestMiddleware, Logger } from '@nestjs/common';
import { Request, Response, NextFunction } from 'express';

/**
 * Soft Delete Middleware
 *
 * 这个中间件自动将 DELETE 请求转换为软删除操作
 * 通过设置 req.softDelete 标志，让服务层知道应该执行软删除
 *
 * 软删除实体列表：
 * - ClothingItem (商品)
 * - Order (订单)
 * - CommunityPost (社区帖子)
 * - PostComment (评论)
 */
@Injectable()
export class SoftDeleteMiddleware implements NestMiddleware {
  private readonly logger = new Logger(SoftDeleteMiddleware.name);

  /**
   * 需要软删除的实体路由模式
   */
  private readonly softDeletePatterns = [
    // Clothing items
    /\/clothing\/[\w-]+$/,
    // Orders
    /\/orders\/[\w-]+$/,
    // Community posts
    /\/posts\/[\w-]+$/,
    // Comments
    /\/comments\/[\w-]+$/,
  ];

  use(req: Request, res: Response, next: NextFunction) {
    const { method, originalUrl } = req;

    // 只处理 DELETE 请求
    if (method === 'DELETE') {
      // 检查是否是软删除实体的端点
      const shouldSoftDelete = this.softDeletePatterns.some(pattern =>
        pattern.test(req.path || originalUrl),
      );

      if (shouldSoftDelete) {
        // 设置软删除标志
        (req as any).softDelete = true;

        this.logger.debug(
          `Soft delete detected for ${method} ${originalUrl}`,
        );
      }
    }

    next();
  }

  /**
   * 检查请求是否应该执行软删除
   */
  isSoftDeleteRequest(req: Request): boolean {
    return (req as any).softDelete === true;
  }
}

import { Injectable, OnModuleInit, OnModuleDestroy, Logger } from "@nestjs/common";
import { PrismaClient, Prisma } from "@prisma/client";

/**
 * Prisma Service
 * 包装 PrismaClient 以便在 NestJS 中使用依赖注入
 *
 * 通过扩展 PrismaClient，自动继承所有 Prisma 模型属性
 * 如 user, userProfile, paymentRecord, notification 等
 *
 * 注意：由于 PrismaClient 使用动态属性代理，TypeScript 在某些情况下
 * 无法正确推断类型。我们使用类型断言来解决这个问题。
 *
 * 连接池配置说明:
 * - poolSize: 连接池最大连接数 (默认: 20)
 * - idleTimeout: 空闲连接超时时间 (默认: 30秒)
 * - connectionTimeout: 获取连接超时时间 (默认: 2秒)
 *
 * 通过 DATABASE_URL 环境变量配置连接池参数:
 * postgresql://user:pass@host:5432/db?connection_limit=20&pool_timeout=30&connect_timeout=10
 *
 * 推荐配置:
 * - 开发环境: connection_limit=5
 * - 生产环境: connection_limit=20 (根据数据库服务器配置调整)
 * - 使用 PgBouncer 时: connection_limit=50&pgbouncer=true
 */
@Injectable()
export class PrismaService
  extends PrismaClient
  implements OnModuleInit, OnModuleDestroy
{
  private readonly logger = new Logger(PrismaService.name);
  private isConnected = false;
  private reconnectAttempts = 0;
  private readonly MAX_RECONNECT_ATTEMPTS = 5;
  private readonly RECONNECT_DELAY_MS = 1000;

  constructor() {
    super({
      log: [
        { emit: "event", level: "query" },
        { emit: "stdout", level: "error" },
        { emit: "stdout", level: "warn" },
      ],
      // 数据库连接池配置通过 DATABASE_URL 环境变量传递
      // 推荐的 DATABASE_URL 格式:
      // postgresql://user:pass@host:5432/db?connection_limit=20&pool_timeout=30&connect_timeout=10
      //
      // 连接池参数说明:
      // - connection_limit: 最大连接数，默认为 CPU 核心数 * 2 + 1
      // - pool_timeout: 等待可用连接的超时时间(秒)，默认 30
      // - connect_timeout: 建立连接的超时时间(秒)，默认 5
      // - idle_in_transaction_session_timeout: 事务中空闲会话超时(毫秒)
      // - statement_timeout: 单个语句超时(毫秒)
    });

    // 监听慢查询 (超过 500ms 的查询)
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    (this as any).$on("query", (e: Prisma.QueryEvent) => {
      if (e.duration > 500) {
        this.logger.warn(
          `Slow Prisma query detected (${e.duration}ms): ${e.query.substring(0, 200)}...`,
        );
      }
    });
  }

  async onModuleInit() {
    await this.connectWithRetry();
  }

  async onModuleDestroy() {
    await this.$disconnect();
    this.isConnected = false;
    this.logger.log("Prisma disconnected from database");
  }

  /**
   * 带重试机制的数据库连接
   */
  private async connectWithRetry(): Promise<void> {
    while (this.reconnectAttempts < this.MAX_RECONNECT_ATTEMPTS) {
      try {
        await this.$connect();
        this.isConnected = true;
        this.reconnectAttempts = 0;
        this.logger.log("Prisma connected to database");
        return;
      } catch (error: unknown) {
        this.reconnectAttempts++;
        const errorMessage = error instanceof Error ? error.message : String(error);
        this.logger.error(
          `Failed to connect to database (attempt ${this.reconnectAttempts}/${this.MAX_RECONNECT_ATTEMPTS}): ${errorMessage}`,
        );

        if (this.reconnectAttempts < this.MAX_RECONNECT_ATTEMPTS) {
          const delay = this.RECONNECT_DELAY_MS * Math.pow(2, this.reconnectAttempts - 1);
          this.logger.log(`Retrying in ${delay}ms...`);
          await new Promise((resolve) => setTimeout(resolve, delay));
        } else {
          throw error;
        }
      }
    }
  }

  /**
   * 健康检查方法
   */
  async isHealthy(): Promise<boolean> {
    try {
      await this.$queryRaw`SELECT 1`;
      return true;
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Database health check failed: ${errorMessage}`);
      return false;
    }
  }

  /**
   * 获取连接状态
   */
  getConnectionStatus(): { connected: boolean; reconnectAttempts: number } {
    return {
      connected: this.isConnected,
      reconnectAttempts: this.reconnectAttempts,
    };
  }

  /**
   * 清理测试数据库（仅用于测试环境）
   */
  async cleanDatabase() {
    if (process.env.NODE_ENV === "production") {
      throw new Error("Cannot clean database in production");
    }

    const models = Reflect.ownKeys(this).filter(
      (key) =>
        typeof key === "string" && !key.startsWith("_") && !key.startsWith("$"),
    );

    return Promise.all(
      models.map((model) => {
        return (this as any)[model].deleteMany();
      }),
    );
  }
}

// 使用模块扩展来添加类型声明
// 这确保 TypeScript 正确识别 PrismaClient 的所有动态属性
import type { PrismaClient as PrismaClientType } from "@prisma/client";

declare module "./prisma.service" {
  // eslint-disable-next-line @typescript-eslint/no-empty-object-type
  interface PrismaService extends PrismaClientType {}
}

import { Prisma } from '@prisma/client';

/**
 * Prisma 扩展操作参数类型
 */
interface ExtensionArgs {
  where?: Record<string, unknown>;
  data?: Record<string, unknown>;
  [key: string]: unknown;
}

/**
 * Prisma 扩展上下文类型
 */
interface ExtensionContext {
  model: string;
  operation: string;
}

/**
 * $allOperations 回调参数类型
 * Prisma 内部类型的简化版本，允许访问 where 属性
 */
interface OperationArgs {
  where?: Record<string, unknown>;
  [key: string]: unknown;
}

/**
 * Soft Delete Prisma Extension
 *
 * 自动为所有查询添加软删除过滤 (isDeleted: false)
 * 这样可以确保已删除的记录永远不会被查询到
 *
 * 支持的模型：
 * - ClothingItem (商品)
 * - Order (订单)
 * - CommunityPost (社区帖子)
 * - PostComment (评论)
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export const softDeleteExtension = Prisma.defineExtension((client) => {
  return client.$extends({
    query: {
      $allModels: {
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        async $allOperations({ args, query, model }: { args: OperationArgs; query: (args: OperationArgs) => Promise<unknown>; model: string }) {
          // 需要软删除的模型列表
          const softDeleteModels = [
            'ClothingItem',
            'Order',
            'CommunityPost',
            'PostComment',
          ];

          // 如果是软删除模型，自动添加 isDeleted: false 过滤
          if (softDeleteModels.includes(model)) {
            const currentWhere = (args.where || {});

            // 处理 findFirst, findMany, findUnique, update, delete 等
            if (!('isDeleted' in currentWhere)) {
              // 为 where 子句添加软删除过滤
              args.where = {
                ...currentWhere,
                isDeleted: false,
              };
            }
          }

          return query(args);
        },
      },
    },
    model: {
      $allModels: {
        /**
         * 软删除方法
         * 将记录标记为已删除，而不是真正删除
         */
        async softDelete<T extends { update: (args: ExtensionArgs) => Promise<unknown> }>(
          this: T,
          args: ExtensionArgs,
        ): Promise<unknown> {
          const context = Prisma.getExtensionContext(this) as T;

          return context.update({
            where: args.where,
            data: {
              ...args.data,
              isDeleted: true,
              deletedAt: new Date(),
            },
          });
        },

        /**
         * 批量软删除方法
         */
        async softDeleteMany<T extends { updateMany: (args: ExtensionArgs) => Promise<unknown> }>(
          this: T,
          args: ExtensionArgs,
        ): Promise<unknown> {
          const context = Prisma.getExtensionContext(this) as T;

          return context.updateMany({
            where: args.where,
            data: {
              ...args.data,
              isDeleted: true,
              deletedAt: new Date(),
            },
          });
        },
      },
    },
  });
});

/**
 * 创建带有软删除扩展的 Prisma 客户端
 *
 * 注意: $extends 的参数类型在 @prisma/client 中未完整导出，
 * 使用 any 是当前唯一可行的方案（已知的 Prisma 类型系统限制）
 */
// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function createSoftDeletePrismaClient<T extends { $extends: (extension: any) => any }>(
  prisma: T,
): ReturnType<T['$extends']> {
  return prisma.$extends(softDeleteExtension);
}

import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
  Optional,
} from "@nestjs/common";
import * as Sentry from "@sentry/node";
import { Observable } from "rxjs";
import { tap } from "rxjs/operators";

import { SentryService } from "../sentry/sentry.service";

@Injectable()
export class SentryInterceptor implements NestInterceptor {
  constructor(@Optional() private readonly sentryService?: SentryService) {}

  intercept(context: ExecutionContext, next: CallHandler): Observable<unknown> {
    if (!this.sentryService?.isEnabled()) {
      return next.handle();
    }

    const request = context.switchToHttp().getRequest();
    const { method, url } = request;
    const controllerClass = context.getClass();
    const handler = context.getHandler();

    const span = this.sentryService.startSpan({
      name: `${controllerClass.name}.${handler.name}`,
      op: "http.server",
      tags: {
        "http.method": method,
        "http.url": url,
      },
    });

    return next.handle().pipe(
      tap({
        next: () => {
          if (span) {
            span.end();
          }
        },
        error: (error) => {
          if (span) {
            span.setStatus({ code: 2, message: "internal_error" });
            span.end();
          }
        },
      }),
    );
  }
}

