      const chains = sharpMock._getAllChains();
      const resizeChain = chains.find((c: any) => c.resize.mock.calls.length > 0);
      expect(resizeChain.resize).toHaveBeenCalledWith(500, 500, expect.objectContaining({ fit: 'inside' }));
    });
