import { Injectable, Logger } from '@nestjs/common';
import sharp from 'sharp';

import { IMAGE_SIZES, ImageSizeConfig, ImageSizeName, DEFAULT_SIZES } from '../utils/image-sizes';

export interface GeneratedImage {
  size: ImageSizeName;
  buffer: Buffer;
  width: number;
  height: number;
  format: string;
  contentType: string;
}

export interface ImageMetadata {
  width: number;
  height: number;
  size: number;
  format: string;
  contentType: string;
  density?: number;
  hasAlpha: boolean;
}

export interface OptimizeOptions {
  quality?: number;
  format?: 'webp' | 'jpeg' | 'png';
  width?: number;
  height?: number;
  fit?: 'cover' | 'inside' | 'outside';
}

@Injectable()
export class ImageProcessingService {
  private readonly logger = new Logger(ImageProcessingService.name);

  async generateSizes(buffer: Buffer, sizes: ImageSizeName[] = DEFAULT_SIZES): Promise<GeneratedImage[]> {
    const metadata = await sharp(buffer).metadata();
    const results: GeneratedImage[] = [];

    for (const sizeName of sizes) {
      const config = IMAGE_SIZES[sizeName];
      try {
        const generated = await this.generateSize(buffer, config, metadata);
        results.push(generated);
      } catch (error) {
        this.logger.error(`Failed to generate size '${sizeName}': ${error instanceof Error ? error.message : String(error)}`);
        throw error;
      }
    }

    return results;
  }

  private async generateSize(buffer: Buffer, config: ImageSizeConfig, metadata: sharp.Metadata): Promise<GeneratedImage> {
    let pipeline = sharp(buffer);

    if (config.name === 'original') {
      // original: keep original dimensions, just re-encode
    } else {
      pipeline = pipeline.resize(config.width, config.height, {
        fit: config.fit,
        withoutEnlargement: true,
        ...(config.fit === 'cover' ? { position: sharp.strategy.attention } : {}),
      });
    }

    const webpBuffer = await pipeline
      .webp({ quality: config.quality, effort: 4 })
      .toBuffer();

    const outputMetadata = await sharp(webpBuffer).metadata();

    return {
      size: config.name,
      buffer: webpBuffer,
      width: outputMetadata.width ?? (config.name === 'original' ? metadata.width ?? 0 : config.width),
      height: outputMetadata.height ?? (config.name === 'original' ? metadata.height ?? 0 : config.height),
      format: 'webp',
      contentType: 'image/webp',
    };
  }

  async optimize(buffer: Buffer, options: OptimizeOptions = {}): Promise<Buffer> {
    const { quality = 80, format = 'webp', width, height, fit = 'inside' } = options;

    let pipeline = sharp(buffer);

    if (width || height) {
      pipeline = pipeline.resize(width, height, { fit, withoutEnlargement: true });
    }

    switch (format) {
      case 'webp':
        return pipeline.webp({ quality, effort: 4 }).toBuffer();
      case 'jpeg':
        return pipeline.jpeg({ quality }).toBuffer();
      case 'png':
        return pipeline.png({ quality }).toBuffer();
      default:
        return pipeline.webp({ quality, effort: 4 }).toBuffer();
    }
  }

  async getMetadata(buffer: Buffer): Promise<ImageMetadata> {
    const metadata = await sharp(buffer).metadata();

    const formatMap: Record<string, string> = {
      jpeg: 'image/jpeg',
      jpg: 'image/jpeg',
      png: 'image/png',
      webp: 'image/webp',
      gif: 'image/gif',
      avif: 'image/avif',
      tiff: 'image/tiff',
    };

    return {
      width: metadata.width ?? 0,
      height: metadata.height ?? 0,
      size: metadata.size ?? buffer.length,
      format: metadata.format ?? 'unknown',
      contentType: formatMap[metadata.format ?? ''] ?? 'application/octet-stream',
      density: metadata.density,
      hasAlpha: metadata.hasAlpha ?? false,
    };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { PrismaClient } from '@prisma/client';

/**
 * Prisma 客户端接口（支持动态模型访问）
 */
interface PrismaClientWithModels extends PrismaClient {
  [model: string]: any;
}

/**
 * Soft Delete Service
 *
 * 提供统一的软删除操作服务
 * 确保软删除操作的一致性和可维护性
 */
@Injectable()
export class SoftDeleteService {
  private readonly logger = new Logger(SoftDeleteService.name);

  /**
   * 执行软删除
   * @param prisma Prisma client 或 transaction
   * @param model 模型名称
   * @param id 记录ID
   * @returns 是否成功删除
   */
  async softDelete(
    prisma: PrismaClientWithModels,
    model: string,
    id: string,
  ): Promise<boolean> {
    try {
      const result = await prisma[model].update({
        where: { id },
        data: {
          isDeleted: true,
          deletedAt: new Date(),
        },
      });

      this.logger.log(`Soft deleted ${model} with id: ${id}`);
      return true;
    } catch (error) {
      this.logger.error(
        `Failed to soft delete ${model} with id ${id}: ${error}`,
      );
      return false;
    }
  }

  /**
   * 批量软删除
   * @param prisma Prisma client 或 transaction
   * @param model 模型名称
   * @param ids 记录ID数组
   * @returns 成功删除的数量
   */
  async softDeleteMany(
    prisma: PrismaClientWithModels,
    model: string,
    ids: string[],
  ): Promise<number> {
    try {
      const result = await prisma[model].updateMany({
        where: {
          id: { in: ids },
        },
        data: {
          isDeleted: true,
          deletedAt: new Date(),
        },
      });

      this.logger.log(`Soft deleted ${result.count} ${model} records`);
      return result.count;
    } catch (error) {
      this.logger.error(
        `Failed to soft delete multiple ${model} records: ${error}`,
      );
      return 0;
    }
  }

  /**
   * 恢复已删除的记录
   * @param prisma Prisma client 或 transaction
   * @param model 模型名称
   * @param id 记录ID
   * @returns 是否成功恢复
   */
  async restore(
    prisma: PrismaClientWithModels,
    model: string,
    id: string,
  ): Promise<boolean> {
    try {
      const result = await prisma[model].update({
        where: { id },
        data: {
          isDeleted: false,
          deletedAt: null,
        },
      });

      this.logger.log(`Restored ${model} with id: ${id}`);
      return true;
    } catch (error) {
      this.logger.error(
        `Failed to restore ${model} with id ${id}: ${error}`,
      );
      return false;
    }
  }

  /**
   * 批量恢复已删除的记录
   * @param prisma Prisma client 或 transaction
   * @param model 模型名称
   * @param ids 记录ID数组
   * @returns 成功恢复的数量
   */
  async restoreMany(
    prisma: PrismaClientWithModels,
    model: string,
    ids: string[],
  ): Promise<number> {
    try {
      const result = await prisma[model].updateMany({
        where: {
          id: { in: ids },
          isDeleted: true,
        },
        data: {
          isDeleted: false,
          deletedAt: null,
        },
      });

      this.logger.log(`Restored ${result.count} ${model} records`);
      return result.count;
    } catch (error) {
      this.logger.error(
        `Failed to restore multiple ${model} records: ${error}`,
      );
      return 0;
    }
  }

  /**
   * 永久删除已软删除的记录（硬删除）
   * @param prisma Prisma client 或 transaction
   * @param model 模型名称
   * @param daysBefore 多少天前的记录
   * @returns 删除的数量
   */
  async permanentDeleteOld(
    prisma: PrismaClientWithModels,
    model: string,
    daysBefore: number = 30,
  ): Promise<number> {
    try {
      const cutoffDate = new Date();
      cutoffDate.setDate(cutoffDate.getDate() - daysBefore);

      const result = await prisma[model].deleteMany({
        where: {
          isDeleted: true,
          deletedAt: {
            lt: cutoffDate,
          },
        },
      });

      this.logger.log(
        `Permanently deleted ${result.count} old ${model} records`,
      );
      return result.count;
    } catch (error) {
      this.logger.error(
        `Failed to permanently delete old ${model} records: ${error}`,
      );
      return 0;
    }
  }
}

import { Global, Module } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import { PrismaService } from "../prisma/prisma.service";
import { UserKeyService } from "../security/user-key.service";

import { StorageController } from "./storage.controller";
import { StorageService } from "./storage.service";

@Global()
@Module({
  controllers: [StorageController],
  providers: [StorageService, UserKeyService, PrismaService],
  exports: [StorageService, UserKeyService],
})
export class StorageModule {}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import * as Minio from "minio";
import sharp from "sharp";
import { v4 as uuidv4 } from "uuid";

import { sanitizeImage } from "../security/image-sanitizer";
import { UserKeyService } from "../security/user-key.service";

/**
 * Multer 文件类型定义
 * 用于处理上传的文件
 */
interface MulterFile {
  fieldname: string;
  originalname: string;
  encoding: string;
  mimetype: string;
  buffer: Buffer;
  size: number;
  destination?: string;
  filename?: string;
  path?: string;
  stream?: NodeJS.ReadableStream;
}

@Injectable()
export class StorageService {
  private readonly logger = new Logger(StorageService.name);
  private readonly minioClient: Minio.Client;
  private readonly bucket: string;

  constructor(
    private configService: ConfigService,
    private userKeyService: UserKeyService,
  ) {
    const accessKey = this.configService.get<string>("MINIO_ACCESS_KEY");
    const secretKey = this.configService.get<string>("MINIO_SECRET_KEY");
    
    if (!accessKey || !secretKey) {
      throw new Error(
        "MINIO_ACCESS_KEY and MINIO_SECRET_KEY environment variables are required. " +
        "Please configure these in your .env file. " +
        "See .env.example for reference."
      );
    }
    
    const port = this.configService.get<string>("MINIO_PORT", "9000");
    const endpoint = this.configService.get<string>("MINIO_ENDPOINT");
    if (!endpoint) {
      throw new Error("MINIO_ENDPOINT environment variable is required");
    }
    
    this.minioClient = new Minio.Client({
      endPoint: endpoint,
      port: parseInt(port, 10) || 9000,
      useSSL:
        this.configService.get<string>("MINIO_USE_SSL", "false") === "true",
      accessKey,
      secretKey,
    });
    this.bucket = this.configService.get<string>("MINIO_BUCKET", "xuno");
    this.logger.log(`StorageService initialized with endpoint: ${endpoint}, bucket: ${this.bucket}`);
    this.ensureBucket();
  }

  private async ensureBucket() {
    try {
      const exists = await this.minioClient.bucketExists(this.bucket);
      if (!exists) {
        await this.minioClient.makeBucket(this.bucket);
        this.logger.log(`Created bucket: ${this.bucket}`);
      }
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to ensure bucket: ${errorMessage}`);
    }
  }

  async uploadImage(
    file: MulterFile,
    folder: string = "uploads",
  ): Promise<{ url: string; thumbnailUrl?: string }> {
    const ext = file.originalname.split(".").pop() || "jpg";
    const filename = `${folder}/${uuidv4()}.${ext}`;

    await this.minioClient.putObject(
      this.bucket,
      filename,
      file.buffer,
      file.size,
      { "Content-Type": file.mimetype },
    );

    const url = await this.getFileUrl(filename);

    let thumbnailUrl: string | undefined;
    if (folder === "photos") {
      thumbnailUrl = await this.createThumbnail(file, filename);
    }

    return { url, thumbnailUrl };
  }

  async uploadBuffer(
    filename: string,
    buffer: Buffer,
    contentType: string = 'application/octet-stream',
  ): Promise<void> {
    await this.minioClient.putObject(
      this.bucket,
      filename,
      buffer,
      buffer.length,
      { 'Content-Type': contentType },
    );
  }

  private async createThumbnail(
    file: MulterFile,
    originalFilename: string,
  ): Promise<string | undefined> {
    try {
      const thumbnail = await sanitizeImage(sharp(file.buffer))
        .resize(300, 300, { fit: "cover" })
        .toBuffer();

      const thumbnailFilename = originalFilename.replace(
        /(\.\w+)$/,
        "-thumbnail$1",
      );

      await this.minioClient.putObject(
        this.bucket,
        thumbnailFilename,
        thumbnail,
        thumbnail.length,
        { "Content-Type": file.mimetype },
      );

      return await this.getFileUrl(thumbnailFilename);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to create thumbnail: ${errorMessage}`);
      return undefined;
    }
  }

  /**
   * 上传临时文件（用于数据导出等场景）
   * @param filename 文件名（包含路径）
   * @param content 文件内容
   * @param expiresIn 过期时间（秒）
   * @returns 预签名下载 URL
   */
  async uploadTemporary(
    filename: string,
    content: Buffer,
    expiresIn: number = 7 * 24 * 60 * 60, // 默认 7 天
  ): Promise<string> {
    await this.minioClient.putObject(
      this.bucket,
      filename,
      content,
      content.length,
      { "Content-Type": "application/json" },
    );

    return this.getFileUrl(filename, expiresIn);
  }

  /**
   * 删除文件
   * @param filenameOrUrl 文件名或完整 URL
   */
  async delete(filenameOrUrl: string): Promise<void> {
    // 如果是完整 URL，提取文件名
    let filename = filenameOrUrl;
    try {
      const url = new URL(filenameOrUrl);
      // 从 URL 路径中提取文件名（移除开头的 /）
      filename = url.pathname.substring(1);
      // 如果有 bucket 名称在路径中，移除它
      if (filename.startsWith(`${this.bucket}/`)) {
        filename = filename.substring(this.bucket.length + 1);
      }
    } catch (error) {
      // 不是有效的 URL，记录并直接使用原始值作为文件名
      this.logger.debug(
        `Input '${filenameOrUrl.substring(0, 50)}...' is not a valid URL, treating as filename. Error: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    await this.minioClient.removeObject(this.bucket, filename);
  }

  /**
   * 获取文件预签名 URL
   * @param filename 文件名
   * @param expiresIn 过期时间（秒）
   */
  async fileExists(filename: string): Promise<boolean> {
    try {
      await this.minioClient.statObject(this.bucket, filename);
      return true;
    } catch {
      return false;
    }
  }

  async getFileUrl(
    filename: string,
    expiresIn: number = 86400,
  ): Promise<string> {
    return await this.minioClient.presignedUrl(
      "GET",
      this.bucket,
      filename,
      expiresIn,
    );
  }

  /**
   * 删除文件（旧方法，保持向后兼容）
   * @deprecated 使用 delete() 方法代替
   */
  async deleteFile(filename: string): Promise<void> {
    await this.delete(filename);
  }

  async fetchRemoteAsset(
    url: string,
  ): Promise<{
    body: Buffer;
    contentType: string;
    cacheControl: string;
  }> {
    const response = await fetch(url);

    if (!response.ok) {
      throw new Error(`Failed to fetch asset: ${response.status}`);
    }

    return {
      body: Buffer.from(await response.arrayBuffer()),
      contentType:
        response.headers.get("content-type") ?? "application/octet-stream",
      cacheControl:
        response.headers.get("cache-control") ?? "private, max-age=300",
    };
  }

  async fetchRemoteAssetDataUri(url: string): Promise<string> {
    const asset = await this.fetchRemoteAsset(url);
    return `data:${asset.contentType};base64,${asset.body.toString("base64")}`;
  }

  async generateWatermarkedImage(
    imageUrl: string,
    watermarkText: string = "寻裳 AI 试衣",
  ): Promise<string> {
    const asset = await this.fetchRemoteAsset(imageUrl);
    const imageBuffer = asset.body;

    const svgWatermark = `
      <svg width="300" height="40">
        <text x="0" y="28" font-family="sans-serif" font-size="24" fill="white" opacity="0.6">
          ${watermarkText}
        </text>
      </svg>`;

    const watermarkedBuffer = await sharp(imageBuffer)
      .composite([
        {
          input: Buffer.from(svgWatermark),
          gravity: "southeast",
        },
      ])
      .png()
      .toBuffer();

    const filename = `tryon-results/watermarked/${uuidv4()}.png`;
    await this.minioClient.putObject(
      this.bucket,
      filename,
      watermarkedBuffer,
      watermarkedBuffer.length,
      { "Content-Type": "image/png" },
    );

    return this.getFileUrl(filename);
  }

  async getCDNUrl(path: string): Promise<string> {
    const cdnBaseUrl = this.configService.get<string>("CDN_BASE_URL");
    if (cdnBaseUrl) {
      return `${cdnBaseUrl}/${path}`;
    }
    return this.getFileUrl(path);
  }

  async uploadEncrypted(
    userId: string,
    file: MulterFile,
    folder: string = "uploads",
  ): Promise<{ url: string; thumbnailUrl?: string }> {
    const encryptedBuffer = await this.userKeyService.encryptBufferForUser(
      userId,
      file.buffer,
    );

    const ext = file.originalname.split(".").pop() || "jpg";
    const filename = `${folder}/${uuidv4()}.${ext}.enc`;

    await this.minioClient.putObject(
      this.bucket,
      filename,
      encryptedBuffer,
      encryptedBuffer.length,
      {
        "Content-Type": "application/octet-stream",
        "X-Encrypted": "true",
        "X-Original-Content-Type": file.mimetype,
      },
    );

    const url = await this.getFileUrl(filename);

    let thumbnailUrl: string | undefined;
    if (folder === "photos") {
      thumbnailUrl = await this.createThumbnail(file, filename);
    }

    return { url, thumbnailUrl };
  }

  async downloadEncrypted(
    userId: string,
    filenameOrUrl: string,
  ): Promise<Buffer> {
    const filename = this.extractFilename(filenameOrUrl);
    const dataStream = await this.minioClient.getObject(this.bucket, filename);
    const chunks: Buffer[] = [];

    for await (const chunk of dataStream) {
      chunks.push(Buffer.isBuffer(chunk) ? chunk : Buffer.from(chunk));
    }

    const encryptedBuffer = Buffer.concat(chunks);
    return this.userKeyService.decryptBufferForUser(userId, encryptedBuffer);
  }

  private extractFilename(filenameOrUrl: string): string {
    try {
      const url = new URL(filenameOrUrl);
      let filename = url.pathname.substring(1);
      if (filename.startsWith(`${this.bucket}/`)) {
        filename = filename.substring(this.bucket.length + 1);
      }
      return filename;
    } catch {
      return filenameOrUrl;
    }
  }
}

/**
 * 通用类型定义
 * 用于替代 any 类型，提高类型安全性
 */

import { Prisma } from "@prisma/client";
