import { Injectable, Logger } from "@nestjs/common";
import { OrderStatus } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";

const REVENUE_STATUSES: OrderStatus[] = ["delivered" as OrderStatus];

@Injectable()
export class AdminDashboardService {
  private readonly logger = new Logger(AdminDashboardService.name);

  constructor(private readonly prisma: PrismaService) {}

  async getOverviewStats() {
    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekStart = new Date(todayStart);
    weekStart.setDate(weekStart.getDate() - 7);
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

    const [
      totalUsers,
      newUsersToday,
      newUsersThisWeek,
      newUsersThisMonth,
      totalOrders,
      ordersToday,
      ordersThisWeek,
      ordersThisMonth,
      revenueResult,
      revenueTodayResult,
      revenueWeekResult,
      revenueMonthResult,
      activeUsers,
    ] = await Promise.all([
      this.prisma.user.count({ where: { isDeleted: false } }),
      this.prisma.user.count({
        where: { isDeleted: false, createdAt: { gte: todayStart } },
      }),
      this.prisma.user.count({
        where: { isDeleted: false, createdAt: { gte: weekStart } },
      }),
      this.prisma.user.count({
        where: { isDeleted: false, createdAt: { gte: monthStart } },
      }),
      this.prisma.order.count(),
      this.prisma.order.count({ where: { createdAt: { gte: todayStart } } }),
      this.prisma.order.count({ where: { createdAt: { gte: weekStart } } }),
      this.prisma.order.count({ where: { createdAt: { gte: monthStart } } }),
      this.prisma.order.aggregate({
        _sum: { totalAmount: true },
        where: { status: { in: REVENUE_STATUSES } },
      }),
      this.prisma.order.aggregate({
        _sum: { totalAmount: true },
        where: {
          status: { in: REVENUE_STATUSES },
          createdAt: { gte: todayStart },
        },
      }),
      this.prisma.order.aggregate({
        _sum: { totalAmount: true },
        where: {
          status: { in: REVENUE_STATUSES },
          createdAt: { gte: weekStart },
        },
      }),
      this.prisma.order.aggregate({
        _sum: { totalAmount: true },
        where: {
          status: { in: REVENUE_STATUSES },
          createdAt: { gte: monthStart },
        },
      }),
      this.prisma.user.count({
        where: {
          isDeleted: false,
          updatedAt: { gte: weekStart },
        },
      }),
    ]);

    const safeAmount = (agg: any): number =>
      Number(agg?._sum?.totalAmount ?? 0);

    return {
      users: {
        total: totalUsers,
        newToday: newUsersToday,
        newThisWeek: newUsersThisWeek,
        newThisMonth: newUsersThisMonth,
        activeIn30Days: activeUsers,
      },
      orders: {
        total: totalOrders,
        today: ordersToday,
        thisWeek: ordersThisWeek,
        thisMonth: ordersThisMonth,
      },
      revenue: {
        total: safeAmount(revenueResult),
        today: safeAmount(revenueTodayResult),
        thisWeek: safeAmount(revenueWeekResult),
        thisMonth: safeAmount(revenueMonthResult),
      },
    };
  }

  async getTopProducts(limit: number = 20) {
    const topItems = await this.prisma.orderItem.groupBy({
      by: ["itemId"],
      _sum: { quantity: true },
      _count: { id: true },
      orderBy: { _sum: { quantity: "desc" } },
      take: limit,
    });

    const itemIds = topItems.map((item: { itemId: string }) => item.itemId);

    const items = await this.prisma.clothingItem.findMany({
      where: { id: { in: itemIds } },
      select: {
        id: true,
        name: true,
        mainImage: true,
        price: true,
        category: true,
      },
    });

    const itemMap = new Map(items.map((item: { id: string }) => [item.id, item]));

    return topItems.map((entry: { itemId: string; _sum: { quantity: number | null }; _count: { id: number } }) => ({
      ...(itemMap.get(entry.itemId) ?? {}),
      totalSold: entry._sum.quantity ?? 0,
      orderCount: entry._count.id,
    }));
  }

  async getConversionRates() {
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const [totalVisits, totalOrders, totalCarts, cartToOrders] =
      await Promise.all([
        this.prisma.userBehavior.count({
          where: {
            type: "page_view",
            createdAt: { gte: thirtyDaysAgo },
          },
        }),
        this.prisma.order.count({
          where: { createdAt: { gte: thirtyDaysAgo } },
        }),
        this.prisma.cartItem.count(),
        this.prisma.order.count({
          where: {
            createdAt: { gte: thirtyDaysAgo },
            status: { notIn: ["cancelled" as OrderStatus] },
          },
        }),
      ]);

    return {
      visitToOrder: totalVisits > 0 ? totalOrders / totalVisits : 0,
      cartToOrder: totalCarts > 0 ? cartToOrders / totalCarts : 0,
      period: "30d",
    };
  }

  async getRetentionStats() {
    const now = new Date();
    const thirtyDaysAgo = new Date(now);
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    const usersActiveInPeriod = await this.prisma.user.findMany({
      where: {
        isDeleted: false,
        createdAt: { gte: thirtyDaysAgo },
      },
      select: { id: true, createdAt: true },
    });

    if (usersActiveInPeriod.length === 0) {
      return { d1: 0, d7: 0, d30: 0 };
    }

    const userIds = usersActiveInPeriod.map((u: { id: string; createdAt: Date }) => u.id);

    const userCreatedAtMap = new Map<string, Date>(
      usersActiveInPeriod.map((u: { id: string; createdAt: Date }) => [u.id, u.createdAt]),
    );

    const returnBehaviors = await this.prisma.userBehavior.findMany({
      where: {
        userId: { in: userIds },
        type: "login",
      },
      select: { userId: true, createdAt: true },
    });

    const userReturnDates = new Map<string, Date[]>();
    for (const behavior of returnBehaviors) {
      const dates = userReturnDates.get(behavior.userId) ?? [];
      dates.push(behavior.createdAt);
      userReturnDates.set(behavior.userId, dates);
    }

    let d1 = 0;
    let d7 = 0;
    let d30 = 0;

    const oneDayMs = 86400000;

    for (const userId of userIds) {
      const created = userCreatedAtMap.get(userId);
      if (!created) {continue;}

      const returnDates = userReturnDates.get(userId) ?? [];
      const createdTime = created.getTime();

      const hasD1 = returnDates.some(
        (d: Date) => d.getTime() > createdTime && d.getTime() <= createdTime + oneDayMs,
      );
      const hasD7 = returnDates.some(
        (d: Date) => d.getTime() > createdTime && d.getTime() <= createdTime + 7 * oneDayMs,
      );
      const hasD30 = returnDates.some(
        (d: Date) => d.getTime() > createdTime && d.getTime() <= createdTime + 30 * oneDayMs,
      );

      if (hasD1) {d1++;}
      if (hasD7) {d7++;}
      if (hasD30) {d30++;}
    }

    const total = userIds.length;
    return {
      d1: total > 0 ? d1 / total : 0,
      d7: total > 0 ? d7 / total : 0,
      d30: total > 0 ? d30 / total : 0,
    };
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { Prisma } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";

import { AdminAuditService } from "./admin-audit.service";

export interface ReviewQueueFilters {
  page?: number;
  pageSize?: number;
  contentType?: string;
  priority?: string;
  startDate?: Date;
  endDate?: Date;
}

@Injectable()
export class ContentReviewService {
  private readonly logger = new Logger(ContentReviewService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly auditService: AdminAuditService,
  ) {}

  async getReviewQueue(filters: ReviewQueueFilters) {
    const {
      page = 1,
      pageSize = 20,
      contentType,
      priority,
      startDate,
      endDate,
    } = filters;

    const where: Prisma.CommunityPostWhereInput = {
      isDeleted: false,
      moderationStatus: { in: ["pending", "flagged"] },
    };

    if (startDate || endDate) {
      const createdAt: Prisma.DateTimeFilter = {};
      if (startDate) {createdAt.gte = startDate;}
      if (endDate) {createdAt.lte = endDate;}
      where.createdAt = createdAt;
    }

    if (priority === "high") {
      where.reportCount = { gt: 0 };
    }

    const orderBy: Prisma.CommunityPostOrderByWithRelationInput = {
      reportCount: "desc" as const,
    };

    const [items, total] = await Promise.all([
      this.prisma.communityPost.findMany({
        where,
        orderBy: [orderBy, { createdAt: "asc" as const }],
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          author: {
            select: { id: true, nickname: true, avatar: true },
          },
          _count: {
            select: { likes: true, comments: true, reports: true },
          },
        },
      }),
      this.prisma.communityPost.count({ where }),
    ]);

    return {
      data: items,
      meta: {
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      },
    };
  }

  async reviewContent(
    id: string,
    reviewerId: string,
    action: "approve" | "reject" | "delete",
    note?: string,
  ) {
    const post = await this.prisma.communityPost.findUnique({
      where: { id },
    });

    if (!post || post.isDeleted) {
      return null;
    }

    if (action === "delete") {
      await this.prisma.communityPost.update({
        where: { id },
        data: { isDeleted: true, deletedAt: new Date() },
      });
    } else {
      const newStatus = action === "approve" ? "approved" : "rejected";
      await this.prisma.communityPost.update({
        where: { id },
        data: { moderationStatus: newStatus },
      });
    }

    await this.prisma.contentModerationLog.create({
      data: {
        contentType: "post",
        contentId: id,
        action: action === "delete" ? "manual_delete" : `manual_${action}`,
        reason: note ?? undefined,
        moderatorId: reviewerId,
      },
    });

    await this.auditService.log({
      userId: reviewerId,
      action: `content.${action}`,
      resource: "community_post",
      resourceId: id,
      details: { note: note ?? null, previousStatus: post.moderationStatus },
    });

    return { success: true };
  }

  async batchReview(
    ids: string[],
    reviewerId: string,
    action: "approve" | "reject" | "delete",
    note?: string,
  ) {
    const results = { processed: 0, failed: 0 };

    await this.prisma.$transaction(async (tx: Prisma.TransactionClient) => {
      for (const id of ids) {
        try {
          const post = await tx.communityPost.findUnique({ where: { id } });
          if (!post || post.isDeleted) {
            results.failed++;
            continue;
          }

          if (action === "delete") {
            await tx.communityPost.update({
              where: { id },
              data: { isDeleted: true, deletedAt: new Date() },
            });
          } else {
            const newStatus = action === "approve" ? "approved" : "rejected";
            await tx.communityPost.update({
              where: { id },
              data: { moderationStatus: newStatus },
            });
          }

          await tx.contentModerationLog.create({
            data: {
              contentType: "post",
              contentId: id,
              action: action === "delete" ? "manual_delete" : `manual_${action}`,
              reason: note ?? undefined,
              moderatorId: reviewerId,
            },
          });

          results.processed++;
        } catch {
          results.failed++;
        }
      }
    });

    await this.auditService.log({
      userId: reviewerId,
      action: `content.batch_${action}`,
      resource: "community_post",
      details: { ids, note: note ?? null, processed: results.processed, failed: results.failed },
    });

    return results;
  }

  async getReviewStats() {
    const now = new Date();
    const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
    const weekStart = new Date(todayStart);
    weekStart.setDate(weekStart.getDate() - 7);
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

    const [
      pendingCount,
      flaggedCount,
      reviewedToday,
      reviewedThisWeek,
      reviewedThisMonth,
      approvedCount,
      rejectedCount,
    ] = await Promise.all([
      this.prisma.communityPost.count({
        where: { moderationStatus: "pending", isDeleted: false },
      }),
      this.prisma.communityPost.count({
        where: { moderationStatus: "flagged", isDeleted: false },
      }),
      this.prisma.contentModerationLog.count({
        where: {
          action: { in: ["manual_approve", "manual_reject", "manual_delete"] },
          createdAt: { gte: todayStart },
        },
      }),
      this.prisma.contentModerationLog.count({
        where: {
          action: { in: ["manual_approve", "manual_reject", "manual_delete"] },
          createdAt: { gte: weekStart },
        },
      }),
      this.prisma.contentModerationLog.count({
        where: {
          action: { in: ["manual_approve", "manual_reject", "manual_delete"] },
          createdAt: { gte: monthStart },
        },
      }),
      this.prisma.contentModerationLog.count({
        where: { action: "manual_approve", createdAt: { gte: monthStart } },
      }),
      this.prisma.contentModerationLog.count({
        where: { action: "manual_reject", createdAt: { gte: monthStart } },
      }),
    ]);

    const totalReviewed = approvedCount + rejectedCount;
    const approvalRate = totalReviewed > 0 ? approvedCount / totalReviewed : 0;
    const rejectionRate = totalReviewed > 0 ? rejectedCount / totalReviewed : 0;

    return {
      pending: pendingCount,
      flagged: flaggedCount,
      reviewedToday,
      reviewedThisWeek,
      reviewedThisMonth,
      approvalRate,
      rejectionRate,
    };
  }
}

import { HttpService } from '@nestjs/axios';
import { ConfigService } from '@nestjs/config';
import { Test, TestingModule } from '@nestjs/testing';
import { of, throwError } from 'rxjs';

import { AISafetyService, ValidationResult, ValidationContext } from './ai-safety.service';

describe('AISafetyService', () => {
  let service: AISafetyService;
  let httpService: HttpService;
  let configService: ConfigService;

  const mockDetectionCounter = { inc: jest.fn() };
  const mockHallucinationRate = { set: jest.fn() };
  const mockValidationLatency = { observe: jest.fn() };

  const mockConfigService = {
    get: jest.fn((key: string, defaultValue?: string) => {
      const config: Record<string, string> = {
        ML_SERVICE_URL: 'http://localhost:8001',
      };
      return config[key] ?? defaultValue;
    }),
  };

  const mockHttpService = {
    post: jest.fn(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        AISafetyService,
        { provide: ConfigService, useValue: mockConfigService },
        { provide: HttpService, useValue: mockHttpService },
        { provide: 'PROM_METRIC_HALLUCINATION_DETECTION_TOTAL', useValue: mockDetectionCounter },
        { provide: 'PROM_METRIC_HALLUCINATION_RATE', useValue: mockHallucinationRate },
        { provide: 'PROM_METRIC_VALIDATION_LATENCY_SECONDS', useValue: mockValidationLatency },
      ],
    }).compile();

    service = module.get<AISafetyService>(AISafetyService);
    httpService = module.get<HttpService>(HttpService);
    configService = module.get<ConfigService>(ConfigService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe('validateResponse', () => {
    it('应该返回有效结果当 ML 服务返回高置信度', async () => {
      const mockResponse = {
        data: {
          is_hallucination: false,
          confidence_score: 0.95,
          issues: [],
        },
      };
      mockHttpService.post.mockReturnValue(of(mockResponse));

      const result: ValidationResult = await service.validateResponse(
        '建议穿白色衬衫搭配深色西裤',
        { occasion: 'business' },
      );

      expect(result.isValid).toBe(true);
      expect(result.confidenceScore).toBe(0.95);
      expect(result.issues).toEqual([]);
      expect(result.processingTimeMs).toBeGreaterThanOrEqual(0);
      expect(result.validatedAt).toBeTruthy();
    });

    it('应该返回无效结果当检测到幻觉', async () => {
      const mockResponse = {
        data: {
          is_hallucination: true,
          confidence_score: 0.3,
          issues: [
            {
              type: 'factual_error',
              severity: 'error',
              description: 'Temperature claim is incorrect',
              confidence: 0.9,
            },
          ],
        },
      };
      mockHttpService.post.mockReturnValue(of(mockResponse));

      const result = await service.validateResponse(
        '今天30度，建议穿羽绒服',
        { temperature: 30 },
      );

      expect(result.isValid).toBe(false);
      expect(result.confidenceScore).toBe(0.3);
      expect(result.issues.length).toBeGreaterThan(0);
    });

    it('应该在 ML 服务不可用时使用回退验证', async () => {
      mockHttpService.post.mockReturnValue(
        throwError(() => new Error('Connection refused')),
      );

      const result = await service.validateResponse(
        '建议穿短裤参加商务会议',
        { occasion: 'business' },
      );

      expect(result.issues.length).toBeGreaterThan(0);
      expect(result.issues.some((i) => i.type === 'fashion_rule')).toBe(true);
    });

    it('应该在 ML 服务不可用时对温度不一致发出警告', async () => {
      mockHttpService.post.mockReturnValue(
        throwError(() => new Error('Connection refused')),
      );

      const result = await service.validateResponse(
        '今天气温5度，建议穿T恤',
        { temperature: 25 },
      );

      expect(result.issues.some((i) => i.type === 'numerical_error')).toBe(true);
    });

    it('应该在 ML 服务返回异常时返回保守的无效结果', async () => {
      mockHttpService.post.mockReturnValue(
        throwError(() => new Error('Unexpected error')),
      );

      const result = await service.validateResponse('正常回复', {});

      expect(result.isValid).toBe(true);
      expect(result.confidenceScore).toBeLessThan(1);
    });
  });

  describe('validateAndCorrect', () => {
    it('应该在检测到严重问题时添加警告前缀', async () => {
      const mockResponse = {
        data: {
          is_hallucination: true,
          confidence_score: 0.2,
          issues: [
            {
              type: 'factual_error',
              severity: 'error',
              description: '严重事实错误',
              confidence: 0.9,
            },
          ],
        },
      };
      mockHttpService.post.mockReturnValue(of(mockResponse));

      const { correctedResponse, validation } = await service.validateAndCorrect(
        '建议穿羽绒服去海边',
        {},
      );

      expect(validation.isValid).toBe(false);
      expect(correctedResponse).toContain('提示');
    });

    it('应该在结果有效时保持原样', async () => {
      const mockResponse = {
        data: {
          is_hallucination: false,
          confidence_score: 0.9,
          issues: [],
        },
      };
      mockHttpService.post.mockReturnValue(of(mockResponse));

      const original = '建议穿白色衬衫搭配深色西裤';
      const { correctedResponse, validation } = await service.validateAndCorrect(
        original,
        {},
      );

      expect(validation.isValid).toBe(true);
      expect(correctedResponse).toBe(original);
    });
  });

  describe('quickCheck', () => {
    it('应该对包含绝对性词语的回复返回 false', async () => {
      const result = await service.quickCheck('你绝对必须穿这件衣服');
      expect(result).toBe(false);
    });

    it('应该对包含英文绝对性词语的回复返回 false', async () => {
      const result = await service.quickCheck('You must always wear this');
      expect(result).toBe(false);
    });

    it('应该对正常回复返回 true', async () => {
      const result = await service.quickCheck('建议穿白色衬衫搭配深色西裤');
      expect(result).toBe(true);
    });

    it('应该对包含异常高价位的回复返回 false', async () => {
      const result = await service.quickCheck('这件衣服售价$1000000');
      expect(result).toBe(false);
    });
  });

  describe('getStatistics', () => {
    it('应该返回统计信息结构', async () => {
      const stats = await service.getStatistics();

      expect(stats).toHaveProperty('totalDetections');
      expect(stats).toHaveProperty('hallucinationRate');
      expect(stats).toHaveProperty('averageConfidence');
      expect(stats).toHaveProperty('issuesByType');
      expect(stats).toHaveProperty('issuesBySeverity');
    });
  });
});

/**
 * AI Safety Service
 *
 * Main service for LLM output validation and hallucination detection.
 * Integrates with Python ML service for advanced detection capabilities.
 *
 * 2026 AI Safety Best Practices Implementation
 */

import { HttpService } from '@nestjs/axios';
import { Injectable, Logger } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { InjectMetric } from '@willsoto/nestjs-prometheus';
import { AxiosResponse } from 'axios';
import { Counter, Histogram, Gauge } from 'prom-client';
import { firstValueFrom } from 'rxjs';

// Types
export interface ValidationResult {
  isValid: boolean;
  confidenceScore: number;
  issues: DetectedIssue[];
  processingTimeMs: number;
  validatedAt: string;
}

export interface DetectedIssue {
  type: string;
  severity: 'error' | 'warning' | 'info';
  description: string;
  confidence: number;
  location?: string;
  suggestion?: string;
  details?: Record<string, any>;
}

export interface ValidationContext {
  occasion?: string;
  season?: string;
  bodyType?: string;
  colorSeason?: string;
  temperature?: number;
  userId?: string;
  sessionId?: string;
  knowledgeContext?: string[];
  userPreferences?: Record<string, any>;
}

export interface HallucinationLog {
  id: string;
  response: string;
  detection: { isHallucination?: boolean; confidenceScore: number; issues: DetectedIssue[] };
  context: ValidationContext;
  timestamp: Date;
  resolved: boolean;
  resolution?: string;
}

@Injectable()
export class AISafetyService {
  private readonly logger = new Logger(AISafetyService.name);
  private readonly mlServiceUrl: string;

  constructor(
    private readonly configService: ConfigService,
    private readonly httpService: HttpService,
    @InjectMetric('hallucination_detection_total')
    private readonly detectionCounter: Counter<string>,
    @InjectMetric('hallucination_rate')
    private readonly hallucinationRate: Gauge<string>,
    @InjectMetric('validation_latency_seconds')
    private readonly validationLatency: Histogram<string>,
  ) {
    this.mlServiceUrl = this.configService.get<string>(
      'ML_SERVICE_URL',
      'http://localhost:8001'
    );
  }

  /**
   * Validate LLM response for hallucinations
   *
   * @param response - LLM generated response text
   * @param context - Validation context (occasion, season, body_type, etc.)
   * @returns ValidationResult with confidence score and detected issues
   */
  async validateResponse(
    response: string,
    context: ValidationContext = {},
  ): Promise<ValidationResult> {
    const startTime = Date.now();

    try {
      // Call Python ML service for detection
      const detectionResult = await this.callMLService(response, context);

      // Record metrics
      this.recordMetrics(detectionResult, context);

      // Log if hallucination detected
      if (detectionResult.isHallucination || detectionResult.confidenceScore < 0.7) {
        await this.logHallucination(response, detectionResult, context);
      }

      const processingTime = Date.now() - startTime;

      // Record latency
      this.validationLatency.observe(processingTime / 1000);

      return {
        isValid: !detectionResult.isHallucination && detectionResult.confidenceScore >= 0.5,
        confidenceScore: detectionResult.confidenceScore,
        issues: detectionResult.issues,
        processingTimeMs: processingTime,
        validatedAt: new Date().toISOString(),
      };
    } catch (error) {
      this.logger.error(
        `Validation failed: ${this.getErrorMessage(error)}`,
        error instanceof Error ? error.stack : undefined,
      );

      // Return a conservative result on error
      return {
        isValid: false,
        confidenceScore: 0,
        issues: [
          {
            type: 'validation_error',
            severity: 'error',
            description: 'Failed to validate response',
            confidence: 1.0,
            details: { error: this.getErrorMessage(error) },
          },
        ],
        processingTimeMs: Date.now() - startTime,
        validatedAt: new Date().toISOString(),
      };
    }
  }

  /**
   * Validate and correct response if possible
   *
   * @param response - Original response
   * @param context - Validation context
   * @returns Corrected response and validation result
   */
  async validateAndCorrect(
    response: string,
    context: ValidationContext = {},
  ): Promise<{ correctedResponse: string; validation: ValidationResult }> {
    const validation = await this.validateResponse(response, context);

    let correctedResponse = response;

    // If hallucination detected, add disclaimer
    if (!validation.isValid) {
      const criticalIssues = validation.issues.filter(
        (i) => i.severity === 'error'
      );

      if (criticalIssues.length > 0) {
        // Add warning prefix for critical issues
        correctedResponse = this.addWarningPrefix(response, criticalIssues);
      }
    }

    return {
      correctedResponse,
      validation,
    };
  }

  /**
   * Log hallucination detection for analysis
   *
   * @param response - The response with hallucination
   * @param detection - Detection result (partial ValidationResult)
   */
  async logHallucination(
    response: string,
    detection: { isHallucination?: boolean; confidenceScore: number; issues: DetectedIssue[] },
    context: ValidationContext = {},
  ): Promise<void> {
    const logEntry: HallucinationLog = {
      id: this.generateLogId(),
      response: response.substring(0, 500), // Truncate for storage
      detection,
      context,
      timestamp: new Date(),
      resolved: false,
    };

    // Log to console for now (could be extended to database)
    this.logger.warn({
      message: 'Hallucination detected',
      logId: logEntry.id,
      confidenceScore: detection.confidenceScore,
      issueCount: detection.issues.length,
      criticalIssues: detection.issues.filter((i) => i.severity === 'error').length,
      context: {
        occasion: context.occasion,
        season: context.season,
        bodyType: context.bodyType,
      },
    });

    // In production, this would be stored in a database for analysis
    // await this.hallucinationLogRepository.save(logEntry);
  }

  /**
   * Get hallucination statistics
   */
  async getStatistics(
    startDate?: Date,
    endDate?: Date,
  ): Promise<{
    totalDetections: number;
    hallucinationRate: number;
    averageConfidence: number;
    issuesByType: Record<string, number>;
    issuesBySeverity: Record<string, number>;
  }> {
    // In production, this would query the database
    // For now, return placeholder data
    return {
      totalDetections: 0,
      hallucinationRate: 0,
      averageConfidence: 1.0,
      issuesByType: {},
      issuesBySeverity: {},
    };
  }

  /**
   * Quick validation check (lightweight, for real-time use)
   */
  async quickCheck(response: string): Promise<boolean> {
    try {
      // Simple checks without full ML service call
      const suspiciousPatterns = [
        /绝对|一定|必须|always|never|must/gi,
        /\d{4}年|year \d{4}/g, // Future dates
        /\$\d{6,}/g, // Unusually high prices
      ];

      for (const pattern of suspiciousPatterns) {
        if (pattern.test(response)) {
          return false;
        }
      }

      return true;
    } catch (error) {
      // Log unexpected error but default to true to avoid blocking responses
      this.logger.warn(
        `quickCheck encountered unexpected error: ${this.getErrorMessage(error)}. Defaulting to true.`,
      );
      return true;
    }
  }

  /**
   * Call Python ML service for hallucination detection
   */
  private async callMLService(
    textToValidate: string,
    context: ValidationContext,
  ): Promise<{
    isHallucination: boolean;
    confidenceScore: number;
    issues: DetectedIssue[];
  }> {
    try {
      const response = await firstValueFrom(
        this.httpService.post<{
          is_hallucination?: boolean;
          confidence_score?: number;
          issues?: Array<{ type: string; severity: string; description: string }>;
        }>(
          `${this.mlServiceUrl}/api/v1/hallucination/detect`,
          {
            text: textToValidate,
            context: {
              occasion: context.occasion,
              season: context.season,
              body_type: context.bodyType,
              color_season: context.colorSeason,
              temperature: context.temperature,
            },
          },
          {
            headers: {
              'Content-Type': 'application/json',
            },
            timeout: 5000,
          },
        ),
      );

      const data = response.data;

      return {
        isHallucination: data.is_hallucination ?? false,
        confidenceScore: data.confidence_score ?? 1.0,
        issues: (data.issues ?? []).map((issue: { type: string; severity: string; description: string; confidence?: number; location?: string; suggestion?: string; details?: Record<string, unknown> }) => ({
          type: issue.type,
          severity: issue.severity as 'error' | 'warning' | 'info',
          description: issue.description,
          confidence: issue.confidence ?? 0.5,
          location: issue.location,
          suggestion: issue.suggestion,
          details: issue.details,
        })),
      };
    } catch (error) {
      // If ML service is unavailable, use fallback validation
      this.logger.warn(
        `ML service unavailable, using fallback: ${this.getErrorMessage(error)}`,
      );
      return this.fallbackValidation(textToValidate, context);
    }
  }

  /**
   * Fallback validation when ML service is unavailable
   */
  private fallbackValidation(
    response: string,
    context: ValidationContext,
  ): {
    isHallucination: boolean;
    confidenceScore: number;
    issues: DetectedIssue[];
  } {
    const issues: DetectedIssue[] = [];

    // Temperature consistency check
    if (context.temperature !== undefined) {
      const tempMatch = response.match(/(-?\d+)\s*[°度]C?/i);
      const mentionedTempText = tempMatch?.[1];
      if (mentionedTempText) {
        const mentionedTemp = parseInt(mentionedTempText, 10);
        if (Math.abs(mentionedTemp - context.temperature) > 15) {
          issues.push({
            type: 'numerical_error',
            severity: 'warning',
            description: `Temperature ${mentionedTemp}C differs significantly from actual ${context.temperature}C`,
            confidence: 0.8,
          });
        }
      }
    }

    // Occasion appropriateness check
    if (context.occasion) {
      const forbiddenPatterns: Record<string, RegExp[]> = {
        business: [/短裤|sandals|flip.?flops/i],
        formal: [/jeans|sneakers|t-?shirt/i],
        interview: [/casual|jeans|sneakers/i],
      };

      const patterns = forbiddenPatterns[context.occasion.toLowerCase()];
      if (patterns) {
        for (const pattern of patterns) {
          if (pattern.test(response)) {
            issues.push({
              type: 'fashion_rule',
              severity: 'warning',
              description: `Item may not be appropriate for ${context.occasion} occasion`,
              confidence: 0.7,
            });
          }
        }
      }
    }

    const confidenceScore = issues.length > 0
      ? Math.max(0.3, 1 - issues.length * 0.2)
      : 0.8; // Lower confidence for fallback

    return {
      isHallucination: confidenceScore < 0.5,
      confidenceScore,
      issues,
    };
  }

  /**
   * Record metrics for monitoring
   */
  private recordMetrics(
    result: { isHallucination: boolean; confidenceScore: number; issues: DetectedIssue[] },
    context: ValidationContext,
  ): void {
    // Increment detection counter
    this.detectionCounter.inc({
      status: result.isHallucination ? 'hallucination' : 'valid',
      occasion: context.occasion || 'unknown',
    });

    // Update hallucination rate gauge
    this.hallucinationRate.set(
      { occasion: context.occasion || 'all' },
      result.isHallucination ? 1 : 0,
    );
  }

  /**
   * Add warning prefix to response with critical issues
   */
  private addWarningPrefix(
    response: string,
    issues: DetectedIssue[],
  ): string {
    const warningPrefix = '[提示：该建议可能包含不准确信息，请谨慎参考]\n\n';
    return warningPrefix + response;
  }

  /**
   * Generate unique log ID
   */
  private generateLogId(): string {
    return `hallucination_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : 'Unknown error';
  }
}

