    name: "section",
    required: false,
    type: String,
    enum: ["git", "database", "services", "resources", "files", "all"],
    description: "指定返回的数据分区，默认返回全部",
  })
  @ApiResponse({
    status: 200,
    description: "系统上下文信息",
