        return { nextAction: { type: "poll_analysis" }, missingFields };
      }
      if (!slots.occasion) {
        missingFields.push("occasion");
        session.state.currentStage = "collecting_scene";
        return { nextAction: { type: "ask_question", field: "occasion" }, missingFields };
