import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { PhotoType } from "@prisma/client";

import { AiStylistChatService } from "./services/chat.service";
import { AiStylistContextService } from "./services/context.service";
import { AiStylistRecommendationService } from "./services/recommendation.service";
import { AiStylistSessionService } from "./services/session.service";
import type { StylistContextInternal } from "./services/session.service";
import type {
  ChatMessage,
  StylistActionType,
  StylistAction,
  StylistSlots,
  StylistBodyProfile,
  StylistSessionState,
  StylistOutfitItem,
  StylistOutfitPlan,
  StylistResolution,
  StylistProgress,
  ChatResult,
  StylistContext,
} from "./types";

export type { ChatMessage };
export type { StylistActionType };
export type { StylistAction };
export type { StylistSlots };
export type { StylistBodyProfile };
export type { StylistSessionState };
export type { StylistOutfitItem };
export type { StylistOutfitPlan };
export type { StylistResolution };
export type { StylistProgress };
export type { ChatResult };

export interface CreateSessionInput {
  entry?: string;
  goal?: string;
  context?: Record<string, unknown>;
}

export type { StylistSession } from "./services/session.service";

@Injectable()
export class AiStylistService {
  private readonly logger = new Logger(AiStylistService.name);

  constructor(
    private configService: ConfigService,
    private sessionService: AiStylistSessionService,
    private chatService: AiStylistChatService,
    private contextService: AiStylistContextService,
    private recommendationService: AiStylistRecommendationService,
  ) {}

  async createSession(
    userId: string,
    input: CreateSessionInput = {},
  ): Promise<ChatResult> {
    const context = await this.contextService.buildUserContext(userId);
    const session = this.buildSession(userId, context, input);
    const orchestration = this.contextService.deriveOrchestration(session);
    const { message, isFallback } = await this.chatService.composeAssistantMessage(
      session,
      orchestration.nextAction,
      {},
      orchestration.missingFields,
      "session_init",
      (s, na) => this.chatService.buildTemplateMessage(s, na, this.contextService.getOccasionName.bind(this.contextService)),
    );

    session.conversationHistory.push({ role: "assistant", content: message });
    await this.sessionService.persistSession(session);

    return this.chatService.buildChatResult(session, message, {
      nextAction: orchestration.nextAction,
      missingFields: orchestration.missingFields,
      isFallback,
    }, this.sessionService.sessionTtl, this.chatService.buildProgress.bind(this.chatService));
  }

  async chat(
    userId: string,
    message: string,
    conversationHistory: ChatMessage[] = [],
  ): Promise<ChatResult> {
    return this.chatService.processChat(
      userId,
      message,
      conversationHistory,
      (uid, ctx) => this.buildSession(uid, ctx),
      (session, msg) => this.processMessageInSession(session, msg),
    );
  }

  async sendMessage(
    userId: string,
    sessionId: string,
    message: string,
    weatherContext?: string,
  ): Promise<ChatResult> {
    return this.chatService.sendMessage(
      userId,
      sessionId,
      message,
      (session, msg) => {
        if (weatherContext) {
          session.state.slots.weather = weatherContext;
        }
        return this.processMessageInSession(session, msg);
      },
    );
  }

  async uploadSessionPhoto(
    userId: string,
    sessionId: string,
    file: Express.Multer.File,
    type: PhotoType = PhotoType.full_body,
  ): Promise<ChatResult> {
    return this.chatService.uploadSessionPhoto(
      userId,
      sessionId,
      file,
      type,
      (session, msg, opts) => this.chatService.buildChatResult(session, msg, opts, this.sessionService.sessionTtl, this.chatService.buildProgress.bind(this.chatService)),
    );
  }

  async attachExistingPhoto(
    userId: string,
    sessionId: string,
    photoId: string,
  ): Promise<ChatResult> {
    return this.chatService.attachExistingPhoto(
      userId,
      sessionId,
      photoId,
      (s) => this.contextService.deriveOrchestration(s),
      (session, msg, opts) => this.chatService.buildChatResult(session, msg, opts, this.sessionService.sessionTtl, this.chatService.buildProgress.bind(this.chatService)),
    );
  }

  async getSessionStatus(
    userId: string,
    sessionId: string,
  ): Promise<ChatResult> {
    return this.chatService.getSessionStatus(
      userId,
      sessionId,
      (s) => this.contextService.deriveOrchestration(s),
      (s, na) => this.chatService.buildTemplateMessage(s, na, this.contextService.getOccasionName.bind(this.contextService)),
      (session, msg, opts) => this.chatService.buildChatResult(session, msg, opts, this.sessionService.sessionTtl, this.chatService.buildProgress.bind(this.chatService)),
    );
  }

  async resolveSession(userId: string, sessionId: string): Promise<ChatResult> {
    return this.recommendationService.resolveSession(
      userId,
      sessionId,
      (s) => this.contextService.deriveOrchestration(s),
      (session, nextAction, slotUpdates, missingFields, stage) =>
        this.chatService.composeAssistantMessage(
          session, nextAction, slotUpdates, missingFields, stage,
          (s, na) => this.chatService.buildTemplateMessage(s, na, this.contextService.getOccasionName.bind(this.contextService)),
        ),
      (session, msg, opts) => this.chatService.buildChatResult(session, msg, opts, this.sessionService.sessionTtl, this.chatService.buildProgress.bind(this.chatService)),
    );
  }

  async listSessions(
    userId: string,
    options?: { limit?: number; offset?: number },
  ): Promise<{
    sessions: Array<{
      id: string;
      createdAt: string;
      updatedAt: string;
      state: StylistSessionState;
      result?: StylistResolution;
    }>;
    total: number;
  }> {
    return this.sessionService.listSessions(userId, options);
  }

  async deleteSession(
    userId: string,
    sessionId: string,
  ): Promise<{ success: boolean }> {
    return this.sessionService.deleteSession(userId, sessionId);
  }

  async submitFeedback(
    userId: string,
    sessionId: string,
    outfitIndex: number,
    action: "like" | "dislike",
    itemId?: string,
    rating?: number,
    dislikeReason?: string,
    dislikeDetail?: string,
  ): Promise<{ success: boolean; message: string }> {
    return this.recommendationService.submitFeedback(
      userId,
      sessionId,
      outfitIndex,
      action,
      itemId,
      rating,
      dislikeReason,
      dislikeDetail,
    );
  }

  async getSessionFeedback(
    userId: string,
    sessionId: string,
  ): Promise<{
    likes: Array<{ outfitIndex: number; itemId?: string; timestamp: string }>;
    dislikes: Array<{
      outfitIndex: number;
      itemId?: string;
      timestamp: string;
    }>;
  }> {
    return this.recommendationService.getSessionFeedback(userId, sessionId);
  }

  async generateDynamicStyleOptions(): Promise<
    Array<{ id: string; label: string }>
  > {
    return this.recommendationService.generateDynamicStyleOptions();
  }

  async generateDynamicOccasionOptions(): Promise<
    Array<{ id: string; label: string }>
  > {
    return this.recommendationService.generateDynamicOccasionOptions();
  }

  private buildSession(
    userId: string,
    context: StylistContextInternal,
    input: CreateSessionInput = {},
  ): import("./services/session.service").StylistSession {
    const now = new Date().toISOString();
    const preferredStyles = this.contextService.getInitialPreferredStyles(context);
    const contextRecord = input.context || {};
    const bodyProfile: StylistBodyProfile = {
      bodyType: context.userProfile?.bodyType,
      skinTone: context.userProfile?.skinTone,
      faceShape: context.userProfile?.faceShape,
      colorSeason: context.userProfile?.colorSeason,
      height: context.userProfile?.height,
      weight: context.userProfile?.weight,
      shapeFeatures: [],
    };

    return {
      id: crypto.randomUUID(),
      userId,
      createdAt: now,
      updatedAt: now,
      conversationHistory: [],
      state: {
        sceneReady: false,
        bodyReady: this.contextService.hasBodyProfile(bodyProfile),
        styleReady: preferredStyles.length > 0,
        candidateReady: false,
        commerceReady: false,
        currentStage: "collecting_scene",
        slots: {
          occasion:
            typeof contextRecord.occasion === "string"
              ? this.contextService.normalizeOccasion(contextRecord.occasion)
              : undefined,
          weather:
            typeof contextRecord.weather === "string"
              ? contextRecord.weather
              : undefined,
          budgetMin:
            typeof contextRecord.budgetMin === "number"
              ? contextRecord.budgetMin
              : undefined,
          budgetMax:
            typeof contextRecord.budgetMax === "number"
              ? contextRecord.budgetMax
              : undefined,
          preferredStyles,
          styleAvoidances: [],
          fitGoals: [],
          preferredColors: [],
        },
        bodyProfile,
      },
    };
  }

  private async processMessageInSession(
    session: import("./services/session.service").StylistSession,
    message: string,
  ): Promise<ChatResult> {
    return this.chatService.processMessageInSession(
      session,
      message,
      (s) => this.contextService.deriveOrchestration(s),
      (session, nextAction, slotUpdates, missingFields, stage) =>
        this.chatService.composeAssistantMessage(
          session, nextAction, slotUpdates, missingFields, stage,
          (s, na) => this.chatService.buildTemplateMessage(s, na, this.contextService.getOccasionName.bind(this.contextService)),
        ),
      (session, assistantMessage, opts) =>
        this.chatService.buildChatResult(
          session, assistantMessage, opts, this.sessionService.sessionTtl,
          this.chatService.buildProgress.bind(this.chatService),
        ),
    );
  }
}

/**
 * @fileoverview LLM Provider Service - Multi-provider abstraction layer.
 *
 * Provides a unified interface for calling LLM APIs with automatic
 * provider failover (DeepSeek -> Qwen -> ZhipuAI GLM), retry logic,
 * structured response parsing, and streaming support.
 *
 * Provider priority:
 *   1. DeepSeek V3 (cheapest, excellent Chinese quality)
 *   2. Qwen / DashScope (generous free tier via Alibaba Cloud)
 *   3. ZhipuAI GLM-4-Flash (completely free, 128K context)
 *   4. OpenAI-compatible (custom endpoint)
 *
 * @module LlmProviderService
 */

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

// Import shared types
import {
  type LlmProvider,
  type LlmChatMessage,
  type LlmChatResponse,
  type LlmStructuredResponse,
  type LlmHealthCheck,
  type LlmStreamChunk,
  type RetryConfig,
  type LlmProviderConfig,
  type LlmUsageMetrics,
} from "./types";

const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxRetries: 2,
  baseDelayMs: 500,
  maxDelayMs: 5000,
  retryableStatusCodes: [429, 500, 502, 503, 504],
};

/**
 * Known provider endpoint defaults.
 */
const PROVIDER_DEFAULTS = {
  deepseek: {
    endpoint: "https://api.deepseek.com/v1",
    model: "deepseek-chat",
  },
  qwen: {
    endpoint: "https://dashscope.aliyuncs.com/compatible-mode/v1",
    model: "qwen-plus",
  },
  zhipu: {
    endpoint: "https://open.bigmodel.cn/api/paas/v4",
    model: "glm-5",
  },
  openai: {
    endpoint: "https://api.openai.com/v1",
    model: "gpt-4o-mini",
  },
} as const;

// ==================== Service ====================

/**
 * LLM Provider Service
 *
 * Abstracts LLM API interactions with:
 * - Multi-provider failover chain (DeepSeek -> Qwen -> ZhipuAI -> OpenAI)
 * - Automatic retry with exponential backoff per provider
 * - Structured JSON response parsing
 * - SSE streaming support
 * - Per-provider circuit breaker
 * - Usage metrics logging
 *
 * @example
 * ```typescript
 * const response = await llmProvider.chat({
 *   messages: [
 *     { role: "system", content: "You are a stylist." },
 *     { role: "user", content: "I need an interview outfit" }
 *   ],
 *   maxTokens: 800,
 * });
 *
 * const structured = await llmProvider.chatStructured<MySlots>({
 *   messages: [...],
 *   responseHint: "Return JSON with fields: occasion, styles, budget"
 * });
 * ```
 */
@Injectable()
export class LlmProviderService implements OnModuleInit {
  private readonly logger = new Logger(LlmProviderService.name);
  private config!: LlmProviderConfig;
  private readonly fallbackChain: LlmProviderConfig[] = [];
  private readonly retryConfig: RetryConfig;
  private readonly circuitBreakers = new Map<LlmProvider, {
    consecutiveFailures: number;
    lastFailureTime: number;
  }>();
  private readonly circuitBreakerThreshold = 5;
  private readonly circuitBreakerResetMs = 60_000;

  constructor(private readonly configService: ConfigService) {
    this.retryConfig = DEFAULT_RETRY_CONFIG;
  }

  onModuleInit(): void {
    const providers = this.resolveAllProviders();
    this.config = providers.primary;
    this.fallbackChain.length = 0;
    this.fallbackChain.push(...providers.fallbacks);

    const chainDescription = [
      `${this.config.provider}/${this.config.model}`,
      ...this.fallbackChain.map(
        (fallback) => `${fallback.provider}/${fallback.model}`,
      ),
    ].join(" -> ");

    this.logger.log(`LLM Provider chain: ${chainDescription}`);
    this.logger.log(
      `API key status: ${this.config.apiKey ? "configured" : "NOT configured - using fallback mode"}`,
    );
  }

  // ==================== Public API ====================

  /**
   * Check if the LLM provider is configured and ready.
   */
  get isConfigured(): boolean {
    return Boolean(this.config?.apiKey && this.config?.endpoint && this.config?.model);
  }

  /**
   * Get the current primary provider name.
   */
  get providerName(): string {
    return this.config?.provider ?? "none";
  }

  /**
   * Get the current primary model name.
   */
  get modelName(): string {
    return this.config?.model ?? "none";
  }

  /**
   * Send a chat completion request with automatic provider failover.
   *
   * Tries the primary provider first. If it fails, falls back through
   * the configured chain (DeepSeek -> Qwen -> ZhipuAI).
   *
   * @param params - Chat parameters including messages and optional overrides
   * @returns The LLM response
   * @throws Error if all providers fail
   */
  async chat(params: {
    messages: LlmChatMessage[];
    maxTokens?: number;
    temperature?: number;
    requestId?: string;
  }): Promise<LlmChatResponse> {
    if (!this.isConfigured) {
      throw new Error(
        "LLM provider is not configured. Set DEEPSEEK_API_KEY, DASHSCOPE_API_KEY, or GLM_API_KEY in .env",
      );
    }

    const maxTokens = params.maxTokens ?? this.config.maxTokens;
    const temperature = params.temperature ?? this.config.temperature;
    const requestId = params.requestId ?? `chat-${Date.now()}`;

    this.logger.debug(
      `[${requestId}] Sending chat request (${params.messages.length} messages)`,
    );

    // Try primary provider
    if (this.isProviderAvailable(this.config.provider)) {
      try {
        const response = await this.executeWithRetry(
          this.config,
          params.messages,
          maxTokens,
          temperature,
          requestId,
        );
        this.logUsageMetrics({
          provider: response.provider,
          model: response.model,
          latencyMs: 0,
          promptTokens: response.usage.promptTokens,
          completionTokens: response.usage.completionTokens,
          totalTokens: response.usage.totalTokens,
          requestId,
          success: true,
          fallbackUsed: false,
        });
        return response;
      } catch (primaryError) {
        const errorMessage =
          primaryError instanceof Error ? primaryError.message : String(primaryError);
        this.logger.warn(
          `[${requestId}] Primary provider (${this.config.provider}) failed: ${errorMessage}`,
        );
      }
    }

    // Try fallback providers
    for (const fallbackConfig of this.fallbackChain) {
      if (!this.isProviderAvailable(fallbackConfig.provider)) {
        continue;
      }

      this.logger.log(
        `[${requestId}] Falling back to ${fallbackConfig.provider}/${fallbackConfig.model}`,
      );

      try {
        const response = await this.executeWithRetry(
          fallbackConfig,
          params.messages,
          maxTokens,
          temperature,
          requestId,
        );
        this.logUsageMetrics({
          provider: response.provider,
          model: response.model,
          latencyMs: 0,
          promptTokens: response.usage.promptTokens,
          completionTokens: response.usage.completionTokens,
          totalTokens: response.usage.totalTokens,
          requestId,
          success: true,
          fallbackUsed: true,
        });
        return response;
      } catch (fallbackError) {
        const errorMessage =
          fallbackError instanceof Error ? fallbackError.message : String(fallbackError);
        this.logger.warn(
          `[${requestId}] Fallback provider (${fallbackConfig.provider}) failed: ${errorMessage}`,
        );
      }
    }

    // All providers failed
    throw new Error(
      "All LLM providers failed. Check your API keys and network connectivity.",
    );
  }

  /**
   * Send a chat request and parse the response as structured JSON.
   *
   * Attempts to extract a JSON object from the LLM response, handling
   * common formatting issues like markdown code blocks.
   *
   * @param params - Chat parameters plus optional response schema hint
   * @returns The structured response with parsed data
   */
  async chatStructured<T = Record<string, unknown>>(params: {
    messages: LlmChatMessage[];
    maxTokens?: number;
    temperature?: number;
    requestId?: string;
    responseHint?: string;
  }): Promise<LlmStructuredResponse<T>> {
    const messages = [...params.messages];

    if (params.responseHint) {
      messages.push({
        role: "user",
        content: `重要：请只返回JSON，不要加任何markdown标记或其他文字。${params.responseHint}`,
      });
    }

    try {
      const response = await this.chat({
        ...params,
        messages,
        temperature: params.temperature ?? 0.2,
      });

      const parsed = this.parseJsonResponse<T>(response.content);

      return {
        raw: response,
        parsed,
        parseError: parsed === null ? "Failed to parse JSON from response" : null,
      };
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(`Structured chat request failed: ${errorMessage}`);

      return {
        raw: {
          content: "",
          usage: { promptTokens: 0, completionTokens: 0, totalTokens: 0 },
          model: this.config.model,
          provider: this.config.provider,
          finishReason: "error",
        },
        parsed: null,
        parseError: errorMessage,
      };
    }
  }

  /**
   * Perform a health check on all configured providers.
   *
   * Sends a minimal request to verify connectivity and authentication.
   */
  async healthCheck(): Promise<LlmHealthCheck[]> {
    const results: LlmHealthCheck[] = [];
    const allConfigs = [this.config, ...this.fallbackChain].filter(
      (config) => config.apiKey,
    );

    for (const providerConfig of allConfigs) {
      const startTime = Date.now();
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 10_000);

        const url = `${providerConfig.endpoint}/chat/completions`;
        const response = await fetch(url, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${providerConfig.apiKey}`,
          },
          body: JSON.stringify({
            model: providerConfig.model,
            messages: [{ role: "user", content: "Hi" }],
            max_tokens: 5,
            temperature: 0.1,
          }),
          signal: controller.signal,
        });

        clearTimeout(timeoutId);

        results.push({
          provider: providerConfig.provider,
          model: providerConfig.model,
          available: response.ok,
          latencyMs: Date.now() - startTime,
          error: response.ok ? null : `HTTP ${response.status}`,
        });
      } catch (error) {
        results.push({
          provider: providerConfig.provider,
          model: providerConfig.model,
          available: false,
          latencyMs: Date.now() - startTime,
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }

    return results;
  }

  // ==================== Provider Resolution ====================

  /**
   * Resolve all available provider configurations from environment variables.
   *
   * Returns the primary provider and an ordered list of fallback providers.
   * Priority order:
   *   1. Explicit AI_STYLIST_* config (if set, takes over completely)
   *   2. DEEPSEEK_API_KEY (cheapest, excellent quality)
   *   3. DASHSCOPE_API_KEY (Qwen - generous free tier)
   *   4. GLM_API_KEY (ZhipuAI - completely free)
   *   5. OPENAI_API_KEY (OpenAI-compatible)
   */
  private resolveAllProviders(): {
    primary: LlmProviderConfig;
    fallbacks: LlmProviderConfig[];
  } {
    const defaultConfig: LlmProviderConfig = {
      provider: "zhipu",
      apiKey: "",
      endpoint: PROVIDER_DEFAULTS.zhipu.endpoint,
      model: PROVIDER_DEFAULTS.zhipu.model,
      maxTokens: 800,
      temperature: 0.3,
      timeoutMs: 30_000,
    };

    // Check for explicit AI_STYLIST_* override
    const stylistKey = this.configService.get<string>("AI_STYLIST_API_KEY", "");
    const stylistEndpoint = this.configService.get<string>(
      "AI_STYLIST_API_ENDPOINT",
      "",
    );
    const stylistModel = this.configService.get<string>("AI_STYLIST_MODEL", "");

    if (stylistKey && stylistEndpoint) {
      return {
        primary: {
          provider: "custom",
          apiKey: stylistKey,
          endpoint: stylistEndpoint,
          model: stylistModel || "glm-5",
          maxTokens: 800,
          temperature: 0.3,
          timeoutMs: 30_000,
        },
        fallbacks: [],
      };
    }

    // Build provider chain from available keys
    const availableProviders: LlmProviderConfig[] = [];

    // DeepSeek (priority 1 - cheapest, excellent Chinese quality)
    const deepseekKey = this.configService.get<string>("DEEPSEEK_API_KEY", "");
    if (deepseekKey) {
      availableProviders.push({
        provider: "deepseek",
        apiKey: deepseekKey,
        endpoint:
          this.configService.get<string>(
            "DEEPSEEK_API_ENDPOINT",
            PROVIDER_DEFAULTS.deepseek.endpoint,
          ),
        model: this.configService.get<string>(
          "DEEPSEEK_MODEL",
          PROVIDER_DEFAULTS.deepseek.model,
        ),
        maxTokens: 800,
        temperature: 0.3,
        timeoutMs: 30_000,
      });
    }

    // Qwen / DashScope (priority 2 - generous free tier)
    const qwenKey =
      this.configService.get<string>("DASHSCOPE_API_KEY", "") ||
      this.configService.get<string>("QWEN_API_KEY", "");
    if (qwenKey) {
      availableProviders.push({
        provider: "qwen",
        apiKey: qwenKey,
        endpoint:
          this.configService.get<string>(
            "QWEN_API_ENDPOINT",
            PROVIDER_DEFAULTS.qwen.endpoint,
          ),
        model: this.configService.get<string>(
          "QWEN_MODEL",
          PROVIDER_DEFAULTS.qwen.model,
        ),
        maxTokens: 800,
        temperature: 0.3,
        timeoutMs: 30_000,
      });
    }

    // ZhipuAI GLM (priority 3 - completely free)
    const glmKey =
      this.configService.get<string>("GLM_API_KEY", "") ||
      this.configService.get<string>("ZHIPU_API_KEY", "");
    if (glmKey) {
      availableProviders.push({
        provider: "zhipu",
        apiKey: glmKey,
        endpoint:
          this.configService.get<string>(
            "GLM_API_ENDPOINT",
            PROVIDER_DEFAULTS.zhipu.endpoint,
          ),
        model: this.configService.get<string>(
          "GLM_MODEL",
          PROVIDER_DEFAULTS.zhipu.model,
        ),
        maxTokens: 800,
        temperature: 0.3,
        timeoutMs: 30_000,
      });
    }

    // OpenAI-compatible (priority 4)
    const openaiKey = this.configService.get<string>("OPENAI_API_KEY", "");
    if (openaiKey) {
      availableProviders.push({
        provider: "openai",
        apiKey: openaiKey,
        endpoint: this.configService.get<string>(
          "OPENAI_API_ENDPOINT",
          PROVIDER_DEFAULTS.openai.endpoint,
        ),
        model: this.configService.get<string>(
          "OPENAI_MODEL",
          PROVIDER_DEFAULTS.openai.model,
        ),
        maxTokens: 800,
        temperature: 0.3,
        timeoutMs: 30_000,
      });
    }

    if (availableProviders.length === 0) {
      this.logger.warn(
        "No LLM API key configured. Set DEEPSEEK_API_KEY, DASHSCOPE_API_KEY, or GLM_API_KEY in .env. " +
        "The AI stylist will use fallback template responses.",
      );
      return { primary: defaultConfig, fallbacks: [] };
    }

    const primary = availableProviders[0] as LlmProviderConfig;
    const fallbacks = availableProviders.slice(1);

    return { primary, fallbacks };
  }

  // ==================== Request Execution ====================

  /**
   * Execute a chat request with retry logic for a specific provider.
   */
  private async executeWithRetry(
    providerConfig: LlmProviderConfig,
    messages: LlmChatMessage[],
    maxTokens: number,
    temperature: number,
    requestId: string,
  ): Promise<LlmChatResponse> {
    const startTime = Date.now();
    let lastError: Error | null = null;

    for (let attempt = 0; attempt <= this.retryConfig.maxRetries; attempt++) {
      try {
        const response = await this.executeChatRequest(
          providerConfig,
          messages,
          maxTokens,
          temperature,
          requestId,
        );

        this.onProviderSuccess(providerConfig.provider, requestId, Date.now() - startTime);

        return {
          ...response,
          provider: providerConfig.provider,
        };
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));

        if (!this.isRetryableError(lastError, attempt)) {
          break;
        }

        const delay = this.calculateBackoffDelay(attempt);
        this.logger.warn(
          `[${requestId}] ${providerConfig.provider} attempt ${attempt + 1} failed, retrying in ${delay}ms: ${lastError.message}`,
        );
        await this.sleep(delay);
      }
    }

    this.onProviderFailure(
      providerConfig.provider,
      requestId,
      Date.now() - startTime,
      lastError,
    );
    throw lastError ?? new Error("Unknown error during chat request");
  }

  /**
   * Execute the actual HTTP request to an LLM API.
   */
  private async executeChatRequest(
    providerConfig: LlmProviderConfig,
    messages: LlmChatMessage[],
    maxTokens: number,
    temperature: number,
    requestId: string,
  ): Promise<Omit<LlmChatResponse, "provider">> {
    const controller = new AbortController();
    const timeoutId = setTimeout(
      () => controller.abort(),
      providerConfig.timeoutMs,
    );

    try {
      const url = `${providerConfig.endpoint}/chat/completions`;

      const body = {
        model: providerConfig.model,
        messages,
        max_tokens: maxTokens,
        temperature,
      };

      const response = await fetch(url, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${providerConfig.apiKey}`,
        },
        body: JSON.stringify(body),
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        const errorText = await response.text().catch(() => "Unknown error");
        this.handleHttpError(response.status, errorText, requestId);
      }

      const data = (await response.json()) as {
        choices: Array<{
          message: { content: string };
          finish_reason: string;
        }>;
        usage?: {
          prompt_tokens: number;
          completion_tokens: number;
          total_tokens: number;
        };
        model: string;
      };

      const content = data.choices[0]?.message?.content?.trim() ?? "";
      const usage = data.usage ?? {
        prompt_tokens: 0,
        completion_tokens: 0,
        total_tokens: 0,
      };

      this.logger.debug(
        `[${requestId}] ${providerConfig.provider} response: ${content.length} chars, ` +
        `${usage.total_tokens} tokens, finish_reason=${data.choices[0]?.finish_reason}`,
      );

      return {
        content,
        usage: {
          promptTokens: usage.prompt_tokens,
          completionTokens: usage.completion_tokens,
          totalTokens: usage.total_tokens,
        },
        model: data.model ?? providerConfig.model,
        finishReason: data.choices[0]?.finish_reason ?? "stop",
      };
    } catch (error) {
      clearTimeout(timeoutId);

      if (error instanceof Error && error.name === "AbortError") {
        throw new Error(`Request timeout after ${providerConfig.timeoutMs}ms`);
      }

      throw error;
    }
  }

  /**
   * Handle HTTP error responses with specific error messages.
   * Uses `never` return type to signal this always throws.
   */
  private handleHttpError(
    status: number,
    errorText: string,
    requestId: string,
  ): never {
    this.logger.warn(
      `[${requestId}] LLM API error: ${status} - ${errorText.slice(0, 200)}`,
    );

    switch (status) {
      case 401:
        throw new Error(
          "LLM API authentication failed. Check your API keys in .env.",
        );
      case 403:
        throw new Error("LLM API access forbidden. Check your account permissions.");
      case 429:
        throw new Error("LLM API rate limit exceeded. Will retry or fall back.");
      case 500:
      case 502:
      case 503:
        throw new Error(
          `LLM API server error (${status}). Service may be temporarily unavailable.`,
        );
      default:
        throw new Error(`LLM API error: ${status} - ${errorText.slice(0, 100)}`);
    }
  }

  // ==================== Response Parsing ====================

  /**
   * Parse JSON from an LLM response, handling common formatting issues.
   */
  private parseJsonResponse<T>(content: string): T | null {
    if (!content || content.trim().length === 0) {
      return null;
    }

    // Try direct parse first
    try {
      return JSON.parse(content.trim()) as T;
    } catch {
      // Continue to fallback parsing
    }

    // Try extracting JSON from markdown code blocks
    const codeBlockMatch = content.match(/```(?:json)?\s*([\s\S]*?)```/);
    if (codeBlockMatch?.[1]) {
      try {
        return JSON.parse(codeBlockMatch[1].trim()) as T;
      } catch {
        // Continue to next fallback
      }
    }

    // Try finding JSON object or array in the response
    const jsonMatch = content.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
    if (jsonMatch?.[1]) {
      try {
        return JSON.parse(jsonMatch[1]) as T;
      } catch {
        // Give up
      }
    }

    this.logger.warn(
      `Failed to parse JSON from LLM response: ${content.slice(0, 100)}...`,
    );
    return null;
  }

  // ==================== Circuit Breaker ====================

  /**
   * Check if a specific provider is available (circuit breaker not open).
   */
  private isProviderAvailable(provider: LlmProvider): boolean {
    if (!provider) {
      return false;
    }

    const state = this.circuitBreakers.get(provider);
    if (!state || state.consecutiveFailures < this.circuitBreakerThreshold) {
      return true;
    }

    const timeSinceLastFailure = Date.now() - state.lastFailureTime;
    if (timeSinceLastFailure > this.circuitBreakerResetMs) {
      state.consecutiveFailures = 0;
      return true;
    }

    this.logger.debug(
      `Circuit breaker open for ${provider} (${state.consecutiveFailures} consecutive failures)`,
    );
    return false;
  }

  private onProviderSuccess(
    provider: LlmProvider,
    requestId: string,
    latencyMs: number,
  ): void {
    const state = this.circuitBreakers.get(provider);
    if (state) {
      state.consecutiveFailures = 0;
    }
    this.logger.debug(
      `[${requestId}] ${provider} request succeeded in ${latencyMs}ms`,
    );
  }

  private onProviderFailure(
    provider: LlmProvider,
    requestId: string,
    latencyMs: number,
    error: Error | null,
  ): void {
    let state = this.circuitBreakers.get(provider);
    if (!state) {
      state = { consecutiveFailures: 0, lastFailureTime: 0 };
      this.circuitBreakers.set(provider, state);
    }
    state.consecutiveFailures++;
    state.lastFailureTime = Date.now();

    this.logger.warn(
      `[${requestId}] ${provider} request failed after ${latencyMs}ms ` +
      `(${state.consecutiveFailures}/${this.circuitBreakerThreshold} failures): ${error?.message}`,
    );
  }

  // ==================== Utilities ====================

  /**
   * Check if an error is retryable.
   */
  private isRetryableError(error: Error, attempt: number): boolean {
    if (attempt >= this.retryConfig.maxRetries) {
      return false;
    }

    // Rate limit and server errors are retryable
    if (error.message.includes("rate limit") || error.message.includes("429")) {
      return true;
    }
    if (
      error.message.includes("server error") ||
      error.message.includes("502") ||
      error.message.includes("503")
    ) {
      return true;
    }
    if (error.message.includes("timeout")) {
      return true;
    }

    // Auth errors are never retryable
    if (
      error.message.includes("authentication") ||
      error.message.includes("401")
    ) {
      return false;
    }

    return false;
  }

  /**
   * Calculate exponential backoff delay with jitter.
   */
  private calculateBackoffDelay(attempt: number): number {
    const delay = this.retryConfig.baseDelayMs * Math.pow(2, attempt);
    const jitter = Math.random() * this.retryConfig.baseDelayMs;
    return Math.min(delay + jitter, this.retryConfig.maxDelayMs);
  }

  /**
   * Log usage metrics for monitoring and cost tracking.
   */
  private logUsageMetrics(metrics: LlmUsageMetrics): void {
    this.logger.log(
      `[${metrics.requestId}] ${metrics.provider}/${metrics.model} ` +
      `${metrics.totalTokens} tokens ` +
      `(${metrics.promptTokens}+${metrics.completionTokens}) ` +
      `${metrics.fallbackUsed ? "(fallback) " : ""}` +
      `success=${metrics.success}`,
    );
  }

  /**
   * Mask sensitive parts of the endpoint URL for logging.
   */
  private maskEndpoint(endpoint: string): string {
    try {
      const url = new URL(endpoint);
      return `${url.protocol}//${url.host}${url.pathname}`;
    } catch {
      return endpoint.slice(0, 30) + "...";
    }
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

/**
 * @fileoverview NL Slot Extractor Service - LLM-powered slot extraction.
 *
 * Uses the LLM provider to extract structured styling preferences from
 * natural language Chinese messages. Falls back to keyword-based extraction
 * when the LLM is unavailable.
 *
 * @module NlSlotExtractorService
 */

import { Injectable, Logger } from "@nestjs/common";

import { LlmProviderService } from "./llm-provider.service";
import { SLOT_EXTRACTION_PROMPT } from "./prompts/system-prompt";

// Import shared types
import {
  type ExtractedSlots,
  type ExtractionResult,
} from "./types";

/**
 * Valid values for slot fields.
 */
const VALID_OCCASIONS = [
  "interview",
  "work",
  "date",
  "travel",
  "party",
  "daily",
  "campus",
] as const;

const VALID_STYLES = [
  "极简",
  "韩系",
  "法式",
  "日系",
  "轻正式",
  "街头",
  "运动",
  "复古",
] as const;

const VALID_FIT_GOALS = [
  "显高",
  "显瘦",
  "修饰胯部",
  "平衡肩线",
  "利落专业",
  "减龄",
  "提气色",
] as const;

const VALID_COLORS = [
  "白色",
  "黑色",
  "灰色",
  "蓝色",
  "米色",
  "卡其",
  "粉色",
  "绿色",
  "酒红",
  "驼色",
  "焦糖",
  "藏青",
  "米白",
  "奶白",
];

/**
 * NL Slot Extractor Service
 *
 * Provides two extraction strategies:
 * 1. LLM-powered extraction (primary) - Uses the configured LLM to understand
 *    Chinese natural language and extract structured data
 * 2. Keyword-based extraction (fallback) - Uses regex patterns and keyword
 *    matching when LLM is unavailable
 *
 * @example
 * ```typescript
 * const result = await nlExtractor.extractFromMessage(
 *   "我要一套面试穿搭，极简风格，预算1000以内，想显高一点"
 * );
 * // result.slots = {
 * //   occasion: "interview",
 * //   preferredStyles: ["极简"],
 * //   fitGoals: ["显高"],
 * //   budgetMax: 1000,
 * // }
 * ```
 */
@Injectable()
export class NlSlotExtractorService {
  private readonly logger = new Logger(NlSlotExtractorService.name);

  constructor(private readonly llmProvider: LlmProviderService) {}

  /**
   * Extract structured slots from a user message using LLM.
   *
   * Falls back to keyword-based extraction if LLM is unavailable.
   */
  async extractFromMessage(
    message: string,
    existingSlots?: Partial<ExtractedSlots>,
  ): Promise<ExtractionResult> {
    if (!message?.trim()) {
      return {
        slots: {},
        rawResponse: null,
        usedLlm: false,
        confidence: 0,
      };
    }

    // Try LLM extraction first
    if (this.llmProvider.isConfigured) {
      try {
        const result = await this.extractWithLlm(message, existingSlots);
        if (result.confidence > 0.3) {
          return result;
        }

        this.logger.debug(
          `LLM extraction confidence too low (${result.confidence}), trying keyword fallback`,
        );
      } catch (error) {
        this.logger.warn(
          `LLM slot extraction failed, falling back to keywords: ${error instanceof Error ? error.message : String(error)}`,
        );
      }
    }

    // Keyword fallback
    return this.extractWithKeywords(message);
  }

  /**
   * Extract slots using LLM.
   */
  private async extractWithLlm(
    message: string,
    existingSlots?: Partial<ExtractedSlots>,
  ): Promise<ExtractionResult> {
    const contextParts: string[] = [];
    if (existingSlots) {
      const nonEmpty = Object.entries(existingSlots)
        .filter(([, value]) => {
          if (Array.isArray(value)) {
            return value.length > 0;
          }
          return value !== null && value !== undefined;
        })
        .map(([key, value]) => `${key}: ${JSON.stringify(value)}`);

      if (nonEmpty.length > 0) {
        contextParts.push(`之前已收集的信息：\n${nonEmpty.join("\n")}`);
      }
    }

    const userMessage = contextParts.length > 0
      ? `${contextParts.join("\n\n")}\n\n用户最新消息：${message}`
      : `用户消息：${message}`;

    const response = await this.llmProvider.chatStructured<ExtractedSlots>({
      messages: [
        { role: "system", content: SLOT_EXTRACTION_PROMPT },
        { role: "user", content: userMessage },
      ],
      maxTokens: 500,
      temperature: 0.1,
      requestId: `slot-extract-${Date.now()}`,
    });

    if (!response.parsed) {
      return {
        slots: {},
        rawResponse: response.raw.content,
        usedLlm: true,
        confidence: 0,
      };
    }

    const slots = this.validateAndNormalizeSlots(response.parsed as unknown as Record<string, unknown>);

    return {
      slots,
      rawResponse: response.raw.content,
      usedLlm: true,
      confidence: this.calculateConfidence(slots, message),
    };
  }

  /**
   * Extract slots using keyword matching (fallback).
   */
  private extractWithKeywords(message: string): ExtractionResult {
    const slots: Partial<ExtractedSlots> = {};

    const occasion = this.extractOccasion(message);
    if (occasion) {
      slots.occasion = occasion;
    }

    const styles = this.extractStyles(message);
    if (styles.length > 0) {
      slots.preferredStyles = styles;
    }

    const goals = this.extractFitGoals(message);
    if (goals.length > 0) {
      slots.fitGoals = goals;
    }

    const colors = this.extractColors(message);
    if (colors.length > 0) {
      slots.preferredColors = colors;
    }

    const budget = this.extractBudget(message);
    if (budget.max !== undefined) {
      slots.budgetMax = budget.max;
    }
    if (budget.min !== undefined) {
      slots.budgetMin = budget.min;
    }

    const avoidances = this.extractStyleAvoidances(message);
    if (avoidances.length > 0) {
      slots.styleAvoidances = avoidances;
    }

    slots.photoSkip = this.isPhotoSkipMessage(message);

    return {
      slots,
      rawResponse: null,
      usedLlm: false,
      confidence: this.calculateConfidence(slots, message),
    };
  }

  /**
   * Validate and normalize extracted slots against allowed values.
   */
  private validateAndNormalizeSlots(raw: Record<string, unknown>): Partial<ExtractedSlots> {
    const slots: Partial<ExtractedSlots> = {};

    // Validate occasion
    if (typeof raw.occasion === "string") {
      const normalizedOccasion = raw.occasion.toLowerCase().trim();
      if ((VALID_OCCASIONS as readonly string[]).includes(normalizedOccasion)) {
        slots.occasion = normalizedOccasion;
      }
    }

    // Validate preferred styles
    if (Array.isArray(raw.preferredStyles)) {
      slots.preferredStyles = raw.preferredStyles
        .filter((s: unknown) => typeof s === "string")
        .filter((s: string) => (VALID_STYLES as readonly string[]).includes(s));
    }

    // Validate fit goals
    if (Array.isArray(raw.fitGoals)) {
      slots.fitGoals = raw.fitGoals
        .filter((g: unknown) => typeof g === "string")
        .filter((g: string) => (VALID_FIT_GOALS as readonly string[]).includes(g));
    }

    // Validate colors (more lenient - accept any string)
    if (Array.isArray(raw.preferredColors)) {
      slots.preferredColors = raw.preferredColors
        .filter((c: unknown) => typeof c === "string" && c.trim().length > 0);
    }

    // Validate style avoidances
    if (Array.isArray(raw.styleAvoidances)) {
      slots.styleAvoidances = raw.styleAvoidances
        .filter((s: unknown) => typeof s === "string" && s.trim().length > 0);
    }

    // Validate budget
    if (typeof raw.budgetMax === "number" && raw.budgetMax > 0) {
      slots.budgetMax = raw.budgetMax;
    }
    if (typeof raw.budgetMin === "number" && raw.budgetMin > 0) {
      slots.budgetMin = raw.budgetMin;
    }

    // Validate weather
    if (typeof raw.weather === "string" && raw.weather.trim().length > 0) {
      slots.weather = raw.weather.trim();
    }

    // Validate photo skip
    if (typeof raw.photoSkip === "boolean") {
      slots.photoSkip = raw.photoSkip;
    }

    return slots;
  }

  /**
   * Calculate confidence score for extracted slots.
   */
  private calculateConfidence(
    slots: Partial<ExtractedSlots>,
    originalMessage: string,
  ): number {
    if (!originalMessage?.trim()) {
      return 0;
    }

    let score = 0;
    let maxScore = 0;

    // Message length factor (longer messages are more likely to contain useful info)
    const lengthFactor = Math.min(originalMessage.length / 20, 1);
    maxScore += 0.1;
    score += 0.1 * lengthFactor;

    // Occasion extraction
    maxScore += 0.25;
    if (slots.occasion) {
      score += 0.25;
    }

    // Style extraction
    maxScore += 0.2;
    if (slots.preferredStyles && slots.preferredStyles.length > 0) {
      score += 0.2;
    }

    // Fit goals extraction
    maxScore += 0.15;
    if (slots.fitGoals && slots.fitGoals.length > 0) {
      score += 0.15;
    }

    // Budget extraction
    maxScore += 0.15;
    if (slots.budgetMax !== undefined && slots.budgetMax !== null) {
      score += 0.15;
    }

    // Color extraction
    maxScore += 0.15;
    if (slots.preferredColors && slots.preferredColors.length > 0) {
      score += 0.15;
    }

    return maxScore > 0 ? score / maxScore : 0;
  }

  // ==================== Keyword-based extraction methods ====================

  private extractOccasion(message: string): string | null {
    const source = message.toLowerCase();
    const occasionMap: Array<[string, string]> = [
      ["面试", "interview"],
      ["求职", "interview"],
      ["职场", "work"],
      ["上班", "work"],
      ["通勤", "work"],
      ["约会", "date"],
      ["相亲", "date"],
      ["旅行", "travel"],
      ["出游", "travel"],
      ["旅游", "travel"],
      ["聚会", "party"],
      ["派对", "party"],
      ["逛街", "daily"],
      ["日常", "daily"],
      ["校园", "campus"],
      ["上学", "campus"],
    ];

    for (const [keyword, occasion] of occasionMap) {
      if (source.includes(keyword)) {
        return occasion;
      }
    }
    return null;
  }

  private extractStyles(message: string): string[] {
    const styleMap: Array<[string, string]> = [
      ["极简", "极简"],
      ["minimal", "极简"],
      ["韩系", "韩系"],
      ["法式", "法式"],
      ["日系", "日系"],
      ["轻正式", "轻正式"],
      ["通勤", "轻正式"],
      ["街头", "街头"],
      ["运动", "运动"],
      ["复古", "复古"],
    ];

    const normalized = message.toLowerCase();
    return [...new Set(
      styleMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    )];
  }

  private extractFitGoals(message: string): string[] {
    const goalMap: Array<[string, string]> = [
      ["显高", "显高"],
      ["拉长比例", "显高"],
      ["显瘦", "显瘦"],
      ["遮肉", "显瘦"],
      ["遮胯", "修饰胯部"],
      ["修肩", "平衡肩线"],
      ["利落", "利落专业"],
      ["正式", "利落专业"],
      ["减龄", "减龄"],
      ["提气色", "提气色"],
    ];

    const normalized = message.toLowerCase();
    return [...new Set(
      goalMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    )];
  }

  private extractColors(message: string): string[] {
    return VALID_COLORS.filter((color) => message.includes(color));
  }

  private extractBudget(message: string): { min?: number; max?: number } {
    const rangeMatch = message.match(/(\d{2,5})\s*(?:-|~|到|至)\s*(\d{2,5})/);
    if (rangeMatch) {
      const min = Number(rangeMatch[1]);
      const max = Number(rangeMatch[2]);
      return {
        min: Math.min(min, max),
        max: Math.max(min, max),
      };
    }

    const underMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:以内|以下)/i,
    );
    if (underMatch) {
      return { max: Number(underMatch[1]) };
    }

    const aroundMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:左右|上下)/i,
    );
    if (aroundMatch) {
      const center = Number(aroundMatch[1]);
      return {
        min: Math.max(center - 200, 0),
        max: center + 200,
      };
    }

    return {};
  }

  private extractStyleAvoidances(message: string): string[] {
    const avoidances: string[] = [];

    if (message.includes("不要太甜") || message.includes("别太甜")) {
      avoidances.push("甜美");
    }
    if (message.includes("不要太正式") || message.includes("别太正式")) {
      avoidances.push("正式");
    }
    if (message.includes("不要太成熟") || message.includes("别太成熟")) {
      avoidances.push("成熟");
    }

    return avoidances;
  }

  private isPhotoSkipMessage(message: string): boolean {
    return (
      message.includes("跳过") ||
      message.includes("先不要拍") ||
      message.includes("直接推荐") ||
      message.includes("不用了") ||
      message.includes("不需要照片")
    );
  }
}

import { Injectable, NotFoundException, Logger } from "@nestjs/common";
import { PhotoType } from "@prisma/client";

import { PhotosService } from "../../photos/photos.service";
import { LlmProviderService } from "../llm-provider.service";
import {
  STYLIST_SYSTEM_PROMPT,
  buildConversationContextPrompt,
} from "../prompts/system-prompt";
import type {
  ChatMessage,
  StylistAction,
  StylistSlots,
  StylistSessionState,
  ChatResult,
  StylistOutfitItem,
} from "../types";

import { AiStylistContextService } from "./context.service";
import { AiStylistSessionService } from "./session.service";
import type { StylistSession } from "./session.service";

const OCCASION_OPTIONS = ["通勤", "约会", "面试", "出游"];
const STYLE_OPTIONS = ["极简", "韩系", "法式", "轻正式"];

@Injectable()
export class AiStylistChatService {
  private readonly logger = new Logger(AiStylistChatService.name);

  constructor(
    private sessionService: AiStylistSessionService,
    private contextService: AiStylistContextService,
    private photosService: PhotosService,
    private llmProvider: LlmProviderService,
  ) {}

  async processChat(
    userId: string,
    message: string,
    conversationHistory: ChatMessage[] = [],
    buildSessionFn: (userId: string, context: import("../types").StylistContext) => StylistSession,
    processMessageFn: (session: StylistSession, message: string) => Promise<ChatResult>,
  ): Promise<ChatResult> {
    const trimmedMessage = message?.trim().slice(0, 2000);
    if (!trimmedMessage) {
      return {
        success: false,
        message: "消息不能为空",
        assistantMessage: "消息不能为空",
        timestamp: new Date().toISOString(),
        error: "INVALID_INPUT",
      };
    }

    const context = await this.contextService.buildUserContext(userId);
    const session = buildSessionFn(userId, context);
    for (const historyMessage of conversationHistory.slice(-10)) {
      if (historyMessage?.role && historyMessage?.content) {
        session.conversationHistory.push({
          role: historyMessage.role,
          content: historyMessage.content,
        });
        if (historyMessage.role === "user") {
          this.contextService.mergeSlots(
            session.state.slots,
            this.contextService.extractSlotUpdates(historyMessage.content),
          );
        }
      }
    }

    return processMessageFn(session, trimmedMessage);
  }

  async sendMessage(
    userId: string,
    sessionId: string,
    message: string,
    processMessageFn: (session: StylistSession, message: string) => Promise<ChatResult>,
  ): Promise<ChatResult> {
    const trimmedMessage = message?.trim().slice(0, 2000);
    if (!trimmedMessage) {
      return {
        success: false,
        message: "消息不能为空",
        assistantMessage: "消息不能为空",
        timestamp: new Date().toISOString(),
        sessionId,
        error: "INVALID_INPUT",
      };
    }

    const session = await this.sessionService.getSessionOrThrow(userId, sessionId);
    await this.contextService.syncPhotoAnalysis(session);
    const response = await processMessageFn(session, trimmedMessage);
    await this.sessionService.persistSession(session);
    return response;
  }

  async processMessageInSession(
    session: StylistSession,
    message: string,
    deriveOrchestrationFn: (session: StylistSession) => { nextAction: StylistAction; missingFields: string[] },
    composeAssistantMessageFn: (
      session: StylistSession,
      nextAction: StylistAction,
      slotUpdates: Partial<StylistSlots>,
      missingFields: string[],
      stage: string,
    ) => Promise<{ message: string; isFallback: boolean }>,
    buildChatResultFn: (
      session: StylistSession,
      assistantMessage: string,
      options?: Record<string, unknown>,
    ) => ChatResult,
  ): Promise<ChatResult> {
    const slotUpdates = this.contextService.extractSlotUpdates(message);

    if (this.isPhotoSkipMessage(message)) {
      session.state.photoSkipped = true;
      session.state.currentStage = "ready_to_resolve";
    }

    session.conversationHistory.push({ role: "user", content: message });
    this.contextService.mergeSlots(session.state.slots, slotUpdates);
    session.updatedAt = new Date().toISOString();

    const orchestration = deriveOrchestrationFn(session);
    const { message: assistantMessage, isFallback } =
      await composeAssistantMessageFn(
        session,
        orchestration.nextAction,
        slotUpdates,
        orchestration.missingFields,
        "message_turn",
      );

    session.conversationHistory.push({
      role: "assistant",
      content: assistantMessage,
    });

    return buildChatResultFn(session, assistantMessage, {
      nextAction: orchestration.nextAction,
      slotUpdates,
      missingFields: orchestration.missingFields,
      isFallback,
    });
  }

  async uploadSessionPhoto(
    userId: string,
    sessionId: string,
    file: Express.Multer.File,
    type: PhotoType = PhotoType.full_body,
    buildChatResultFn: (
      session: StylistSession,
      assistantMessage: string,
      options?: Record<string, unknown>,
    ) => ChatResult,
  ): Promise<ChatResult> {
    const session = await this.sessionService.getSessionOrThrow(userId, sessionId);
    const photo = await this.photosService.uploadPhoto(userId, file, type);

    session.state.lastPhotoId = photo.id;
    session.state.lastPhotoStatus = photo.status;
    session.state.photoRequested = true;
    session.state.photoSkipped = false;
    session.state.currentStage = "analysis_pending";
    session.updatedAt = new Date().toISOString();

    const assistantMessage = "照片已上传，我正在提取你的身材和色彩信息。";
    session.conversationHistory.push({
      role: "assistant",
      content: assistantMessage,
    });
    await this.sessionService.persistSession(session);

    return buildChatResultFn(session, assistantMessage, {
      nextAction: { type: "poll_analysis" },
      analysisStatus: photo.status,
      photoId: photo.id,
      missingFields: [],
    });
  }

  async attachExistingPhoto(
    userId: string,
    sessionId: string,
    photoId: string,
    deriveOrchestrationFn: (session: StylistSession) => { nextAction: StylistAction; missingFields: string[] },
    buildChatResultFn: (
      session: StylistSession,
      assistantMessage: string,
      options?: Record<string, unknown>,
    ) => ChatResult,
  ): Promise<ChatResult> {
    const session = await this.sessionService.getSessionOrThrow(userId, sessionId);
    const photo = await this.photosService.getPhotoById(photoId, userId);

    if (!photo) {
      throw new NotFoundException("照片不存在");
    }

    session.state.lastPhotoId = photo.id;
    session.state.lastPhotoStatus = photo.analysisStatus;
    session.state.photoRequested = true;
    session.state.photoSkipped = false;
    session.state.currentStage =
      photo.analysisStatus === "completed"
        ? "collecting_scene"
        : "analysis_pending";
    session.updatedAt = new Date().toISOString();

    await this.contextService.syncPhotoAnalysis(session);

    const orchestration = deriveOrchestrationFn(session);
    const assistantMessage =
      session.state.lastPhotoStatus === "completed"
        ? "我已经接入你最近上传的照片，身材分析结果也同步好了。接下来继续告诉我场景和风格偏好吧。"
        : "我已经接入你最近上传的照片，正在继续分析你的身材和色彩信息。";

    session.conversationHistory.push({
      role: "assistant",
      content: assistantMessage,
    });
    await this.sessionService.persistSession(session);

    return buildChatResultFn(session, assistantMessage, {
      nextAction: orchestration.nextAction,
      missingFields: orchestration.missingFields,
      analysisStatus: session.state.lastPhotoStatus,
      photoId: session.state.lastPhotoId,
      result: session.result,
    });
  }

  async getSessionStatus(
    userId: string,
    sessionId: string,
    deriveOrchestrationFn: (session: StylistSession) => { nextAction: StylistAction; missingFields: string[] },
    buildTemplateMessageFn: (session: StylistSession, nextAction: StylistAction) => string,
    buildChatResultFn: (
      session: StylistSession,
      assistantMessage: string,
      options?: Record<string, unknown>,
    ) => ChatResult,
  ): Promise<ChatResult> {
    const session = await this.sessionService.getSessionOrThrow(userId, sessionId);
    await this.contextService.syncPhotoAnalysis(session);

    const orchestration = deriveOrchestrationFn(session);
    const assistantMessage =
      session.state.lastPhotoStatus === "completed"
        ? "身材分析已完成，现在可以继续确认偏好或直接生成方案。"
        : buildTemplateMessageFn(session, orchestration.nextAction);

    await this.sessionService.persistSession(session);
    return buildChatResultFn(session, assistantMessage, {
      nextAction: orchestration.nextAction,
      missingFields: orchestration.missingFields,
      analysisStatus: session.state.lastPhotoStatus,
      result: session.result,
    });
  }

  async composeAssistantMessage(
    session: StylistSession,
    nextAction: StylistAction,
    slotUpdates: Partial<StylistSlots>,
    missingFields: string[],
    stage: string,
    buildTemplateMessageFn: (session: StylistSession, nextAction: StylistAction) => string,
  ): Promise<{ message: string; isFallback: boolean }> {
    const fallbackMessage = buildTemplateMessageFn(session, nextAction);

    if (!this.llmProvider.isConfigured) {
      return { message: fallbackMessage, isFallback: true };
    }

    try {
      const contextPrompt = buildConversationContextPrompt({
        slots: session.state.slots as unknown as Record<string, unknown>,
        bodyProfile: session.state.bodyProfile as unknown as Record<string, unknown>,
        conversationHistory: session.conversationHistory.slice(-6),
        stage,
      });

      const response = await this.llmProvider.chat({
        messages: [
          {
            role: "system",
            content: STYLIST_SYSTEM_PROMPT,
          },
          {
            role: "system",
            content: contextPrompt,
          },
          {
            role: "system",
            content:
              "请根据上面的上下文和当前状态，输出一句中文回复。不要 JSON，不要解释系统逻辑，控制在 80 字以内。直接给出你作为造型师对用户说的话。",
          },
          ...session.conversationHistory.slice(-4),
          {
            role: "user",
            content: JSON.stringify({
              stage,
              slotUpdates,
              nextAction,
              missingFields,
            }),
          },
        ],
        maxTokens: 200,
        temperature: 0.4,
        requestId: `stylist-compose-${Date.now()}`,
      });

      const content = response.content?.trim();
      if (!content) {
        return { message: fallbackMessage, isFallback: true };
      }
      return { message: content, isFallback: false };
    } catch (error) {
      const errorMessage =
        error instanceof Error ? error.message : "Unknown error";
      this.logger.warn(`Falling back to template copy: ${errorMessage}`);
      return { message: fallbackMessage, isFallback: true };
    }
  }

  buildTemplateMessage(
    session: StylistSession,
    nextAction: StylistAction,
    getOccasionNameFn: (occasion?: string) => string,
  ): string {
    const occasionName = getOccasionNameFn(session.state.slots.occasion);
    const budgetText = session.state.slots.budgetMax
      ? `，预算先按 ${session.state.slots.budgetMax} 元以内`
      : "";

    switch (nextAction.type) {
      case "ask_question":
        return "你这次更偏向通勤、约会、面试还是出游？";
      case "show_preference_buttons":
        return `收到${occasionName ? `，这次是${occasionName}场景` : ""}${budgetText}。你更想走哪种风格？`;
      case "request_photo_upload":
        return "为了把版型和显高显瘦建议做准，建议上传一张全身正面照。你也可以跳过，我先给你基础方案。";
      case "poll_analysis":
        return "照片已收到，我正在分析你的身材和色彩信息。";
      case "confirm_preferences":
        return "身材分析完成了。你更想强调利落通勤，还是柔和亲和？";
      case "generate_outfit":
        return "信息已经够了，现在可以直接为你生成穿搭方案。";
      case "show_outfit_cards":
        return "我已经整理好适合你的穿搭方案。";
      default:
        return "我已经整理好你的信息，继续下一步吧。";
    }
  }

  buildChatResult(
    session: StylistSession,
    assistantMessage: string,
    options: {
      nextAction?: StylistAction;
      slotUpdates?: Partial<StylistSlots>;
      missingFields?: string[];
      previewRecommendations?: StylistOutfitItem[];
      result?: import("../types").StylistResolution;
      photoId?: string;
      analysisStatus?: string;
      isFallback?: boolean;
    } = {},
    sessionTtlMs: number,
    buildProgressFn: (
      session: StylistSession,
      nextAction?: StylistAction,
      analysisStatus?: string,
      result?: import("../types").StylistResolution,
    ) => import("../types").StylistProgress,
  ): ChatResult {
    const progress = buildProgressFn(
      session,
      options.nextAction,
      options.analysisStatus,
      options.result,
    );

    return {
      success: true,
      message: assistantMessage,
      assistantMessage,
      timestamp: new Date().toISOString(),
      sessionId: session.id,
      nextAction: options.nextAction,
      sessionState: session.state,
      slotUpdates: options.slotUpdates,
      missingFields: options.missingFields || [],
      previewRecommendations: options.previewRecommendations || [],
      result: options.result,
      photoId: options.photoId,
      analysisStatus: options.analysisStatus,
      progress,
      sessionExpiresAt: new Date(
        new Date(session.updatedAt).getTime() + sessionTtlMs,
      ).toISOString(),
      isFallback: options.isFallback,
      isAIGenerated: true,
      aiDisclaimer: "本内容由AI生成，仅供参考，不构成专业建议。",
    };
  }

  buildProgress(
    session: StylistSession,
    nextAction?: StylistAction,
    analysisStatus?: string,
    result?: import("../types").StylistResolution,
  ): import("../types").StylistProgress {
    const effectiveAnalysisStatus =
      analysisStatus || session.state.lastPhotoStatus || "idle";

    if (
      effectiveAnalysisStatus === "pending" ||
      effectiveAnalysisStatus === "processing" ||
      nextAction?.type === "poll_analysis"
    ) {
      return {
        stage: "body_analysis",
        title: "正在分析身材与色彩",
        detail: "预计 10 到 20 秒，可先离开页面，稍后回来继续。",
        etaSeconds: 15,
        canLeaveAndResume: true,
        isWaiting: true,
      };
    }

    if (result || nextAction?.type === "show_outfit_cards") {
      return {
        stage: "resolved",
        title: "穿搭方案已准备好",
        detail: "你可以直接浏览单品卡片，继续调整预算或场景也可以。",
        canLeaveAndResume: true,
        isWaiting: false,
      };
    }

    if (nextAction?.type === "request_photo_upload") {
      return {
        stage: "awaiting_photo",
        title: "补一张照片，推荐会更准",
        detail: "显高、显瘦、比例优化这类诉求会更依赖身材判断。",
        canLeaveAndResume: true,
        isWaiting: false,
      };
    }

    if (nextAction?.type === "generate_outfit") {
      return {
        stage: "ready_to_resolve",
        title: "信息已基本齐全",
        detail: "现在可以直接生成穿搭方案，后续还可以继续微调。",
        etaSeconds: 5,
        canLeaveAndResume: true,
        isWaiting: false,
      };
    }

    if (nextAction?.type === "show_preference_buttons") {
      return {
        stage: "collecting_style",
        title: "正在确认风格偏好",
        detail: "再确认一下风格方向，我就能进入下一步。",
        canLeaveAndResume: true,
        isWaiting: false,
      };
    }

    if (nextAction?.type === "ask_question") {
      if (!session.state.sceneReady) {
        return {
          stage: "collecting_scene",
          title: "先告诉我你的使用场景",
          detail: "比如面试、通勤、约会或出游，我会先确定正式度。",
          canLeaveAndResume: true,
          isWaiting: false,
        };
      }

      return {
        stage: "collecting_style",
        title: "再补一点风格偏好",
        detail: "告诉我预算、颜色或想强调的效果，方案会更贴合。",
        canLeaveAndResume: true,
        isWaiting: false,
      };
    }

    return {
      stage: session.state.currentStage,
      title: "AI 正在整理你的需求",
      detail: "我会先抽取场景、预算和风格偏好，再决定下一步。",
      etaSeconds: 3,
      canLeaveAndResume: true,
      isWaiting: false,
    };
  }

  private isPhotoSkipMessage(message: string): boolean {
    return (
      message.includes("跳过") ||
      message.includes("先不要拍") ||
      message.includes("直接推荐")
    );
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { PhotoType } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";
import type {
  StylistContext,
  StylistSlots,
  StylistBodyProfile,
} from "../types";

import type { StylistSession, StylistContextInternal } from "./session.service";

const VALID_OCCASIONS = [
  "interview",
  "work",
  "date",
  "travel",
  "party",
  "daily",
  "campus",
] as const;
const VALID_STYLES = [
  "极简",
  "韩系",
  "法式",
  "日系",
  "轻正式",
  "街头",
  "运动",
  "复古",
] as const;
const VALID_FIT_GOALS = [
  "显高",
  "显瘦",
  "修饰胯部",
  "平衡肩线",
  "利落专业",
  "减龄",
  "提气色",
] as const;

type ValidOccasion = (typeof VALID_OCCASIONS)[number];
type ValidStyle = (typeof VALID_STYLES)[number];
type ValidFitGoal = (typeof VALID_FIT_GOALS)[number];

const COLOR_KEYWORDS = [
  "白色", "黑色", "灰色", "蓝色", "米色",
  "卡其", "粉色", "绿色", "酒红",
];

@Injectable()
export class AiStylistContextService {
  private readonly logger = new Logger(AiStylistContextService.name);

  constructor(private prisma: PrismaService) {}

  async buildUserContext(userId: string): Promise<StylistContextInternal> {
    const [profile, preferences, recentBehaviors] = await Promise.all([
      this.prisma.userProfile
        .findUnique({
          where: { userId },
          select: {
            bodyType: true,
            skinTone: true,
            faceShape: true,
            colorSeason: true,
            height: true,
            weight: true,
            stylePreferences: true,
          },
        })
        .catch(() => null),
      this.prisma.userPreferenceWeight
        .findMany({
          where: { userId },
          orderBy: { updatedAt: "desc" },
          take: 20,
          select: {
            category: true,
            key: true,
            weight: true,
          },
        })
        .catch(() => []),
      this.prisma.userBehaviorEvent
        .findMany({
          where: { userId },
          orderBy: { createdAt: "desc" },
          take: 10,
          select: {
            eventType: true,
            metadata: true,
          },
        })
        .catch(() => []),
    ]);

    return {
      userProfile: profile
        ? {
            bodyType: profile.bodyType ?? undefined,
            skinTone: profile.skinTone ?? undefined,
            faceShape: profile.faceShape ?? undefined,
            colorSeason: profile.colorSeason ?? undefined,
            height: profile.height ?? undefined,
            weight: profile.weight ?? undefined,
            stylePreferences: Array.isArray(profile.stylePreferences)
              ? (profile.stylePreferences as Array<{ name?: string } | string>)
              : undefined,
          }
        : null,
      preferences: (preferences as Array<{
        category: string | null;
        key: string | null;
        weight: number;
      }>).reduce(
        (acc: Record<string, Record<string, number>>, preference) => {
          const category = preference.category;
          const key = preference.key;
          if (!category || !key) {
            return acc;
          }
          if (!acc[category]) {
            acc[category] = {};
          }
          const bucket = acc[category];
          if (!bucket) {
            return acc;
          }
          bucket[key] = preference.weight;
          return acc;
        },
        {} as Record<string, Record<string, number>>,
      ),
      recentBehaviors: recentBehaviors.map(
        (behavior: { eventType: string; metadata: unknown }) => ({
          type: behavior.eventType,
          data: behavior.metadata,
        }),
      ),
    };
  }

  async syncPhotoAnalysis(session: StylistSession): Promise<void> {
    if (!session.state.lastPhotoId) {
      return;
    }

    const photo = await this.prisma.userPhoto.findFirst({
      where: {
        id: session.state.lastPhotoId,
        userId: session.userId,
      },
      select: {
        analysisStatus: true,
        analysisResult: true,
      },
    });

    if (!photo) {
      return;
    }

    session.state.lastPhotoStatus = photo.analysisStatus;
    if (
      photo.analysisStatus === "completed" &&
      photo.analysisResult &&
      typeof photo.analysisResult === "object"
    ) {
      const analysisResult = photo.analysisResult as Record<string, unknown>;
      session.state.bodyProfile = {
        ...session.state.bodyProfile,
        bodyType:
          typeof analysisResult.bodyType === "string"
            ? analysisResult.bodyType
            : session.state.bodyProfile.bodyType,
        skinTone:
          typeof analysisResult.skinTone === "string"
            ? analysisResult.skinTone
            : session.state.bodyProfile.skinTone,
        faceShape:
          typeof analysisResult.faceShape === "string"
            ? analysisResult.faceShape
            : session.state.bodyProfile.faceShape,
        colorSeason:
          typeof analysisResult.colorSeason === "string"
            ? analysisResult.colorSeason
            : session.state.bodyProfile.colorSeason,
        shapeFeatures: this.deduplicateStrings([
          ...session.state.bodyProfile.shapeFeatures,
          ...(typeof analysisResult.bodyType === "string"
            ? [analysisResult.bodyType]
            : []),
        ]),
      };
      session.state.bodyReady = this.hasBodyProfile(session.state.bodyProfile);
      if (session.state.bodyReady) {
        session.state.currentStage = "ready_to_resolve";
      }
    }
  }

  getInitialPreferredStyles(context: StylistContextInternal): string[] {
    const profileStyles = Array.isArray(context.userProfile?.stylePreferences)
      ? context.userProfile?.stylePreferences || []
      : [];
    const normalizedProfileStyles = profileStyles
      .map((item) => (typeof item === "string" ? item : item?.name || ""))
      .map((value) => this.normalizeStyle(value))
      .filter((value): value is string => Boolean(value));

    const weightedStyles = Object.entries(context.preferences?.style || {})
      .sort((a, b) => b[1] - a[1])
      .slice(0, 3)
      .map(([name]) => this.normalizeStyle(name))
      .filter((value): value is string => Boolean(value));

    return this.deduplicateStrings([
      ...normalizedProfileStyles,
      ...weightedStyles,
    ]);
  }

  extractSlotUpdates(message: string): Partial<StylistSlots> {
    const slotUpdates: Partial<StylistSlots> = {};
    const occasion = this.extractOccasion(message);
    const preferredStyles = this.extractStyles(message);
    const fitGoals = this.extractFitGoals(message);
    const preferredColors = this.extractColors(message);
    const budget = this.extractBudget(message);
    const styleAvoidances = this.extractStyleAvoidances(message);

    if (occasion && this.isValidOccasion(occasion)) {
      slotUpdates.occasion = occasion;
    }
    if (preferredStyles.length > 0) {
      slotUpdates.preferredStyles = this.filterValidStyles(preferredStyles);
    }
    if (fitGoals.length > 0) {
      slotUpdates.fitGoals = this.filterValidFitGoals(fitGoals);
    }
    if (preferredColors.length > 0) {
      slotUpdates.preferredColors = preferredColors;
    }
    if (styleAvoidances.length > 0) {
      slotUpdates.styleAvoidances = this.filterValidStyles(styleAvoidances);
    }
    if (budget.min !== undefined && budget.min >= 0) {
      slotUpdates.budgetMin = budget.min;
    }
    if (budget.max !== undefined && budget.max >= 0) {
      slotUpdates.budgetMax = budget.max;
    }

    return slotUpdates;
  }

  mergeSlots(current: StylistSlots, updates: Partial<StylistSlots>): void {
    if (updates.occasion) {
      current.occasion = updates.occasion;
    }
    if (updates.weather) {
      current.weather = updates.weather;
    }
    if (updates.budgetMin !== undefined) {
      current.budgetMin = updates.budgetMin;
    }
    if (updates.budgetMax !== undefined) {
      current.budgetMax = updates.budgetMax;
    }
    if (updates.preferredStyles?.length) {
      current.preferredStyles = this.deduplicateStrings([
        ...current.preferredStyles,
        ...updates.preferredStyles,
      ]);
    }
    if (updates.styleAvoidances?.length) {
      current.styleAvoidances = this.deduplicateStrings([
        ...current.styleAvoidances,
        ...updates.styleAvoidances,
      ]);
    }
    if (updates.fitGoals?.length) {
      current.fitGoals = this.deduplicateStrings([
        ...current.fitGoals,
        ...updates.fitGoals,
      ]);
    }
    if (updates.preferredColors?.length) {
      current.preferredColors = this.deduplicateStrings([
        ...current.preferredColors,
        ...updates.preferredColors,
      ]);
    }
  }

  deriveOrchestration(session: StylistSession): {
    nextAction: import("../types").StylistAction;
    missingFields: string[];
  } {
    const { slots, bodyProfile, photoSkipped, lastPhotoStatus } = session.state;
    const missingFields: string[] = [];

    session.state.sceneReady = Boolean(slots.occasion);
    session.state.styleReady = slots.preferredStyles.length > 0;
    session.state.bodyReady = this.hasBodyProfile(bodyProfile);

    if (session.result) {
      session.state.currentStage = "resolved";
      return {
        nextAction: { type: "show_outfit_cards" },
        missingFields,
      };
    }

    if (lastPhotoStatus === "processing" || lastPhotoStatus === "pending") {
      session.state.currentStage = "analysis_pending";
      return {
        nextAction: { type: "poll_analysis" },
        missingFields,
      };
    }

    if (!slots.occasion) {
      missingFields.push("occasion");
      session.state.currentStage = "collecting_scene";
      return {
        nextAction: {
          type: "ask_question",
          field: "occasion",
          options: ["通勤", "约会", "面试", "出游"],
        },
        missingFields,
      };
    }

    if (slots.preferredStyles.length === 0) {
      missingFields.push("style_preferences");
      session.state.currentStage = "collecting_style";
      return {
        nextAction: {
          type: "show_preference_buttons",
          options: ["极简", "韩系", "法式", "轻正式"],
        },
        missingFields,
      };
    }

    const shouldRequestPhoto =
      !photoSkipped &&
      !session.state.bodyReady &&
      this.needsPhotoForPrecision(session);
    if (shouldRequestPhoto) {
      missingFields.push("body_profile");
      session.state.currentStage = "awaiting_photo";
      session.state.photoRequested = true;
      return {
        nextAction: {
          type: "request_photo_upload",
          canSkip: true,
          photoType: PhotoType.full_body,
        },
        missingFields,
      };
    }

    session.state.currentStage = "ready_to_resolve";
    return {
      nextAction: { type: "generate_outfit" },
      missingFields,
    };
  }

  hasBodyProfile(profile?: StylistBodyProfile | null): boolean {
    return Boolean(
      profile?.bodyType || profile?.colorSeason || profile?.skinTone,
    );
  }

  normalizeOccasion(value: string): string {
    return this.extractOccasion(value) || value;
  }

  normalizeStyle(value: string): string | undefined {
    const normalized = value.trim().toLowerCase();
    const styleMap: Record<string, string> = {
      极简: "极简",
      minimalist: "极简",
      casual: "休闲",
      smart_casual: "轻正式",
      韩系: "韩系",
      korean: "韩系",
      法式: "法式",
      french: "法式",
      streetwear: "街头",
      运动: "运动",
      sporty: "运动",
    };

    return styleMap[value] || styleMap[normalized] || value.trim() || undefined;
  }

  getOccasionName(occasion?: string): string {
    const names: Record<string, string> = {
      interview: "面试",
      work: "通勤",
      date: "约会",
      travel: "出游",
      party: "聚会",
      daily: "日常",
      campus: "校园",
    };
    return occasion ? names[occasion] || occasion : "";
  }

  getBodyTypeName(type: string): string {
    const names: Record<string, string> = {
      rectangle: "H 型体型",
      triangle: "A 型体型",
      inverted_triangle: "Y 型体型",
      hourglass: "X 型体型",
      oval: "O 型体型",
    };
    return names[type] || type;
  }

  getColorSeasonName(season: string): string {
    const names: Record<string, string> = {
      spring: "春季型",
      summer: "夏季型",
      autumn: "秋季型",
      winter: "冬季型",
    };
    return names[season] || season;
  }

  private isValidOccasion(occasion: string): occasion is ValidOccasion {
    return VALID_OCCASIONS.includes(occasion as ValidOccasion);
  }

  private filterValidStyles(styles: string[]): string[] {
    return styles.filter((style) => VALID_STYLES.includes(style as ValidStyle));
  }

  private filterValidFitGoals(goals: string[]): string[] {
    return goals.filter((goal) =>
      VALID_FIT_GOALS.includes(goal as ValidFitGoal),
    );
  }

  private extractOccasion(message: string): string | undefined {
    const source = message.toLowerCase();
    const occasionMap: Array<[string, string]> = [
      ["面试", "interview"],
      ["求职", "interview"],
      ["职场", "work"],
      ["上班", "work"],
      ["通勤", "work"],
      ["约会", "date"],
      ["相亲", "date"],
      ["旅行", "travel"],
      ["出游", "travel"],
      ["旅游", "travel"],
      ["聚会", "party"],
      ["派对", "party"],
      ["逛街", "daily"],
      ["日常", "daily"],
      ["校园", "campus"],
      ["上学", "campus"],
    ];

    for (const [keyword, occasion] of occasionMap) {
      if (source.includes(keyword)) {
        return occasion;
      }
    }
    return undefined;
  }

  private extractStyles(message: string): string[] {
    const styleMap: Array<[string, string]> = [
      ["极简", "极简"],
      ["minimal", "极简"],
      ["韩系", "韩系"],
      ["法式", "法式"],
      ["日系", "日系"],
      ["轻正式", "轻正式"],
      ["通勤", "轻正式"],
      ["街头", "街头"],
      ["运动", "运动"],
      ["复古", "复古"],
    ];

    const normalized = message.toLowerCase();
    return this.deduplicateStrings(
      styleMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    );
  }

  private extractFitGoals(message: string): string[] {
    const goalMap: Array<[string, string]> = [
      ["显高", "显高"],
      ["拉长比例", "显高"],
      ["显瘦", "显瘦"],
      ["遮肉", "显瘦"],
      ["遮胯", "修饰胯部"],
      ["修肩", "平衡肩线"],
      ["利落", "利落专业"],
      ["正式", "利落专业"],
      ["减龄", "减龄"],
      ["提气色", "提气色"],
    ];

    const normalized = message.toLowerCase();
    return this.deduplicateStrings(
      goalMap
        .filter(([keyword]) => normalized.includes(keyword.toLowerCase()))
        .map(([, value]) => value),
    );
  }

  private extractColors(message: string): string[] {
    return COLOR_KEYWORDS.filter((color) => message.includes(color));
  }

  private extractStyleAvoidances(message: string): string[] {
    const avoidances: string[] = [];

    if (message.includes("不要太甜") || message.includes("别太甜")) {
      avoidances.push("甜美");
    }
    if (message.includes("不要太正式") || message.includes("别太正式")) {
      avoidances.push("正式");
    }
    if (message.includes("不要太成熟") || message.includes("别太成熟")) {
      avoidances.push("成熟");
    }

    return avoidances;
  }

  private extractBudget(message: string): {
    min?: number;
    max?: number;
  } {
    const rangeMatch = message.match(/(\d{2,5})\s*(?:-|~|到|至)\s*(\d{2,5})/);
    if (rangeMatch) {
      const min = Number(rangeMatch[1]);
      const max = Number(rangeMatch[2]);
      return {
        min: Math.min(min, max),
        max: Math.max(min, max),
      };
    }

    const underMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:以内|以下)/i,
    );
    if (underMatch) {
      return { max: Number(underMatch[1]) };
    }

    const aroundMatch = message.match(
      /(\d{2,5})\s*(?:元|块|rmb)?\s*(?:左右|上下)/i,
    );
    if (aroundMatch) {
      const center = Number(aroundMatch[1]);
      return {
        min: Math.max(center - 200, 0),
        max: center + 200,
      };
    }

    return {};
  }

  private needsPhotoForPrecision(session: StylistSession): boolean {
    const { fitGoals, occasion } = session.state.slots;
    return fitGoals.length > 0 || occasion === "interview";
  }

  deduplicateStrings(values: string[]): string[] {
    return [...new Set(values.filter(Boolean))];
  }
}

import { randomUUID } from "crypto";

import { Injectable, NotFoundException, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { Prisma } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";
import { RedisService } from "../../../common/redis/redis.service";
import type {
  ChatMessage,
  StylistSessionState,
  StylistResolution,
  StylistBodyProfile,
  StylistSlots,
  StylistContext,
} from "../types";

export interface StylistContextInternal {
  userProfile?: {
    bodyType?: string;
    skinTone?: string;
    faceShape?: string;
    colorSeason?: string;
    height?: number;
    weight?: number;
    stylePreferences?: Array<{ name?: string } | string>;
  } | null;
  recentBehaviors?: Array<{ type: string; data: unknown }>;
  preferences?: Record<string, Record<string, number>>;
}

export interface StylistSession {
  id: string;
  userId: string;
  createdAt: string;
  updatedAt: string;
  conversationHistory: ChatMessage[];
  state: StylistSessionState;
  result?: StylistResolution;
  feedback?: {
    likes: Array<{
      outfitIndex: number;
      itemId?: string;
      timestamp: string;
      rating?: number;
    }>;
    dislikes: Array<{
      outfitIndex: number;
      itemId?: string;
      timestamp: string;
      rating?: number;
      dislikeReason?: string;
      dislikeDetail?: string;
    }>;
  };
}

@Injectable()
export class AiStylistSessionService {
  private readonly logger = new Logger(AiStylistSessionService.name);
  private readonly sessionTtlMs = 30 * 60 * 1000;
  private readonly sessionCleanupThrottleMs = 5 * 60 * 1000;
  private readonly maxSessionMessages = 20;
  private readonly sessionConfigPrefix = "ai_stylist_session:";
  private readonly maxMemorySessions = 1000;
  private readonly sessionStore = new Map<string, StylistSession>();
  private readonly sessionAccessOrder: string[] = [];
  private lastStoreCleanupAt = 0;
  private readonly useRedis: boolean;

  constructor(
    private configService: ConfigService,
    private prisma: PrismaService,
    private redisService: RedisService,
  ) {
    this.useRedis = this.configService.get<string>("REDIS_URL") ? true : false;
  }

  async getSessionOrThrow(
    userId: string,
    sessionId: string,
  ): Promise<StylistSession> {
    await this.cleanupExpiredSessions();
    const key = this.getSessionKey(userId, sessionId);
    const cachedSession = this.sessionStore.get(key);

    if (cachedSession) {
      return cachedSession;
    }

    const storedSession = await this.loadPersistedSession(userId, sessionId);
    if (!storedSession) {
      throw new NotFoundException("AI 造型师会话不存在或已过期");
    }

    this.sessionStore.set(key, storedSession);
    return storedSession;
  }

  async persistSession(session: StylistSession): Promise<void> {
    await this.cleanupExpiredSessions();
    session.updatedAt = new Date().toISOString();
    session.conversationHistory = session.conversationHistory.slice(
      -this.maxSessionMessages,
    );
    const key = this.getSessionKey(session.userId, session.id);

    await this.writeSessionRecord(
      session,
      new Date(Date.now() + this.sessionTtlMs),
    );

    if (this.useRedis) {
      try {
        const redisKey = `stylist:session:${key}`;
        await this.redisService.setex(
          redisKey,
          Math.floor(this.sessionTtlMs / 1000),
          JSON.stringify(session),
        );
      } catch (error) {
        this.logger.warn(`Redis session persist failed, falling back to DB-only: ${error}`);
      }
    }

    this.updateSessionAccessOrder(key);
    while (this.sessionStore.size >= this.maxMemorySessions) {
      const lruKey = this.sessionAccessOrder.shift();
      if (lruKey) {
        this.sessionStore.delete(lruKey);
        this.logger.debug(`Evicted LRU session from memory: ${lruKey}`);
      } else {
        break;
      }
    }
    this.sessionStore.set(key, session);
  }

  async listSessions(
    userId: string,
    options?: { limit?: number; offset?: number },
  ): Promise<{
    sessions: Array<{
      id: string;
      createdAt: string;
      updatedAt: string;
      state: StylistSessionState;
      result?: StylistResolution;
    }>;
    total: number;
  }> {
    await this.cleanupExpiredSessions();

    const limit = options?.limit ?? 10;
    const offset = options?.offset ?? 0;

    const records = await this.prisma.aiStylistSession.findMany({
      where: { userId },
      orderBy: { updatedAt: "desc" },
      skip: offset,
      take: limit,
      select: {
        id: true,
        payload: true,
        updatedAt: true,
      },
    });

    const total = await this.prisma.aiStylistSession.count({
      where: { userId },
    });

    const sessions = records
      .map((record) => {
        try {
          const session = record.payload as unknown as StylistSession;
          return {
            id: session.id,
            createdAt: session.createdAt,
            updatedAt: session.updatedAt,
            state: session.state,
            result: session.result,
          };
        } catch (error) {
          this.logger.warn(
            `Failed to parse session record ${record.id}: ${error instanceof Error ? error.message : String(error)}. Record will be skipped.`,
          );
          return null;
        }
      })
      .filter((s): s is NonNullable<typeof s> => s !== null);

    return { sessions, total };
  }

  async deleteSession(
    userId: string,
    sessionId: string,
  ): Promise<{ success: boolean }> {
    const key = this.getSessionKey(userId, sessionId);
    this.sessionStore.delete(key);

    try {
      await this.prisma.aiStylistSession.delete({
        where: { id: sessionId },
      });
    } catch (primaryError) {
      this.logger.warn(
        `Failed to delete AI stylist session from primary table: ${primaryError instanceof Error ? primaryError.message : String(primaryError)}. Attempting fallback deletion.`,
      );
      try {
        await this.prisma.systemConfig.delete({
          where: { key: this.getSessionConfigKey(userId, sessionId) },
        });
      } catch (fallbackError) {
        this.logger.error(
          `Failed to delete session config from fallback table: ${fallbackError instanceof Error ? fallbackError.message : String(fallbackError)}. Session cleanup may be incomplete for userId=${userId}, sessionId=${sessionId}`,
        );
      }
    }

    return { success: true };
  }

  async loadPersistedSession(
    userId: string,
    sessionId: string,
  ): Promise<StylistSession | null> {
    const key = this.getSessionKey(userId, sessionId);

    if (this.useRedis) {
      try {
        const redisKey = `stylist:session:${key}`;
        const cached = await this.redisService.get(redisKey);
        if (cached) {
          const session = JSON.parse(cached) as StylistSession;
          if (!this.isSessionExpired(session.updatedAt)) {
            this.sessionStore.set(key, session);
            return session;
          }
        }
      } catch (error) {
        this.logger.warn(`Redis session load failed: ${error}`);
      }
    }

    return this.readSessionRecord(userId, sessionId);
  }

  private updateSessionAccessOrder(key: string): void {
    const existingIndex = this.sessionAccessOrder.indexOf(key);
    if (existingIndex > -1) {
      this.sessionAccessOrder.splice(existingIndex, 1);
    }
    this.sessionAccessOrder.push(key);
  }

  private async cleanupExpiredSessions(): Promise<void> {
    const now = Date.now();
    for (const [key, session] of this.sessionStore.entries()) {
      if (now - new Date(session.updatedAt).getTime() > this.sessionTtlMs) {
        this.sessionStore.delete(key);
      }
    }

    if (now - this.lastStoreCleanupAt < this.sessionCleanupThrottleMs) {
      return;
    }

    this.lastStoreCleanupAt = now;
    await this.deleteExpiredSessionRecords(new Date(now - this.sessionTtlMs));
  }

  getSessionKey(userId: string, sessionId: string): string {
    return `${userId}:${sessionId}`;
  }

  getSessionConfigKey(userId: string, sessionId: string): string {
    return `${this.sessionConfigPrefix}${this.getSessionKey(userId, sessionId)}`;
  }

  private isSessionExpired(updatedAt: string): boolean {
    return Date.now() - new Date(updatedAt).getTime() > this.sessionTtlMs;
  }

  private async writeSessionRecord(
    session: StylistSession,
    expiresAt: Date,
  ): Promise<void> {
    try {
      const sessionPayload = session as unknown as Prisma.InputJsonValue;

      await this.prisma.aiStylistSession.upsert({
        where: { id: session.id },
        update: {
          userId: session.userId,
          payload: sessionPayload,
          expiresAt,
        },
        create: {
          id: session.id,
          userId: session.userId,
          payload: sessionPayload,
          expiresAt,
        },
      });
      return;
    } catch (error: unknown) {
      this.logger.warn(
        `AiStylistSession 表写入失败，回退 SystemConfig: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    await this.prisma.systemConfig.upsert({
      where: {
        key: this.getSessionConfigKey(session.userId, session.id),
      },
      update: {
        value: JSON.stringify(session),
      },
      create: {
        key: this.getSessionConfigKey(session.userId, session.id),
        value: JSON.stringify(session),
      },
    });
  }

  private async deleteExpiredSessionRecords(
    expiredBefore: Date,
  ): Promise<void> {
    try {
      await this.prisma.aiStylistSession.deleteMany({
        where: {
          expiresAt: {
            lt: new Date(),
          },
        },
      });
      return;
    } catch (error: unknown) {
      this.logger.warn(
        `AiStylistSession 过期清理失败，回退 SystemConfig: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    await this.prisma.systemConfig.deleteMany({
      where: {
        key: { startsWith: this.sessionConfigPrefix },
        updatedAt: {
          lt: expiredBefore,
        },
      },
    });
  }

  private async readSessionRecord(
    userId: string,
    sessionId: string,
  ): Promise<StylistSession | null> {
    try {
      const record = await this.prisma.aiStylistSession.findUnique({
        where: { id: sessionId },
      });

      if (record) {
        if (record.userId !== userId || record.expiresAt < new Date()) {
          await this.prisma.aiStylistSession.delete({
            where: { id: sessionId },
          });
          return null;
        }

        return record.payload as unknown as StylistSession;
      }
    } catch (error: unknown) {
      this.logger.warn(
        `AiStylistSession 表读取失败，回退 SystemConfig: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    const record = await this.prisma.systemConfig.findUnique({
      where: {
        key: this.getSessionConfigKey(userId, sessionId),
      },
    });

    if (!record?.value) {
      return null;
    }

    try {
      const session = JSON.parse(record.value as string) as StylistSession;
      if (
        session.userId !== userId ||
        session.id !== sessionId ||
        this.isSessionExpired(session.updatedAt)
      ) {
        await this.prisma.systemConfig.delete({
          where: {
            key: this.getSessionConfigKey(userId, sessionId),
          },
        });
        return null;
      }

      return session;
    } catch (error: unknown) {
      this.logger.warn(
        `AI 造型师会话反序列化失败: ${error instanceof Error ? error.message : String(error)}`,
      );
      await this.prisma.systemConfig.delete({
        where: {
          key: this.getSessionConfigKey(userId, sessionId),
        },
      });
      return null;
    }
  }

  get sessionTtl(): number {
    return this.sessionTtlMs;
  }
}

﻿import { cpus } from "os";

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import { PrismaService } from "../../common/prisma/prisma.service";
import { RedisService } from "../../common/redis/redis.service";

export interface GitInfo {
