}

export interface SystemContextResult {
  timestamp: string;
  environment: string;
  git: GitInfo;
  database: DatabaseStats;
  services: ServiceHealthStatus;
  resources: SystemResources;
  projectFiles: ProjectFileInfo;
}

@Injectable()
export class SystemContextService implements OnModuleInit {
  private readonly logger = new Logger(SystemContextService.name);
  private startTime: number;
  private cachedContext: SystemContextResult | null = null;
  private cacheExpiry: number = 0;
  private readonly cacheTtlMs = 30_000;

  constructor(
    private configService: ConfigService,
    private prisma: PrismaService,
    private redisService: RedisService,
  ) {
    this.startTime = Date.now();
  }

  onModuleInit(): void {
    this.logger.log("SystemContextService initialized - AI can now query local environment");
  }

  async getFullContext(refresh = false): Promise<SystemContextResult> {
    const now = Date.now();
    if (!refresh && this.cachedContext && now < this.cacheExpiry) {
      return this.cachedContext;
    }

    const [git, database, services, resources, projectFiles] =
      await Promise.all([
        this.getGitInfo(),
        this.getDatabaseStats(),
        this.getServiceHealthStatus(),
        this.getSystemResources(),
        this.getProjectFileInfo(),
      ]);

    const context: SystemContextResult = {
      timestamp: new Date().toISOString(),
      environment: this.configService.get<string>("NODE_ENV", "development"),
      git,
      database,
      services,
      resources,
      projectFiles,
    };

    this.cachedContext = context;
    this.cacheExpiry = now + this.cacheTtlMs;
    return context;
  }

  async getGitInfo(): Promise<GitInfo> {
    const defaultInfo: GitInfo = {
      branch: "unknown",
      lastCommit: "unknown",
      lastCommitAuthor: "unknown",
      lastCommitDate: "unknown",
      lastCommitMessage: "no git info available",
      isCleanWorkingTree: true,
      changedFiles: 0,
      totalCommits: "0",
    };

    try {
      const { execSync } = await import("child_process");
      const cwd = this.configService.get<string>("PROJECT_ROOT", "C:\\xuno");

      const runCmd = (cmd: string): string => {
        try {
          return execSync(cmd, {
            cwd,
            encoding: "utf-8",
            timeout: 5000,
          }).trim();
        } catch {
          return "";
        }
      };

      const branch =
        runCmd('git rev-parse --abbrev-ref HEAD') || "unknown";
      const lastCommit = runCmd("git rev-parse --short HEAD") || "unknown";
      const lastCommitAuthor =
        runCmd('git log -1 --format="%an"') || "unknown";
      const lastCommitDate =
        runCmd('git log -1 --format="%ai"') || "unknown";
      const lastCommitMessage =
        runCmd('git log -1 --format="%s"') || "no commits";
      const statusOutput = runCmd("git status --porcelain");
      const changedFiles = statusOutput
        ? statusOutput.split("\n").filter(Boolean).length
        : 0;
      const totalCommits = runCmd('git rev-list --count HEAD') || "0";
      const remoteUrl = runCmd("git config --get remote.origin.url") || undefined;

      return {
        branch,
        lastCommit,
        lastCommitAuthor,
        lastCommitDate,
        lastCommitMessage,
        isCleanWorkingTree: changedFiles === 0,
        changedFiles,
        totalCommits,
        remoteUrl,
      };
    } catch (error) {
      this.logger.warn(`Failed to get Git info: ${error instanceof Error ? error.message : String(error)}`);
      return defaultInfo;
    }
  }

  async getDatabaseStats(): Promise<DatabaseStats> {
    const defaults: DatabaseStats = {
      totalUsers: 0,
      totalClothingItems: 0,
      activeClothingItems: 0,
      totalBrands: 0,
      totalCategories: 0,
      totalSessions: 0,
      activeSessions: 0,
      totalTryOns: 0,
      completedTryOns: 0,
      totalPhotos: 0,
      analyzedPhotos: 0,
      totalFeedbackRecords: 0,
      recentUsers24h: 0,
      recentTryOns24h: 0,
    };

    try {
      const yesterday = new Date(Date.now() - 86400000);

      const [
        totalUsers,
        totalClothingItems,
        activeClothingItems,
        totalBrands,
        totalCategories,
        totalSessions,
        activeSessions,
        totalTryOns,
        completedTryOns,
        totalPhotos,
        analyzedPhotos,
        totalFeedbackRecords,
        recentUsers24h,
        recentTryOns24h,
      ] = await Promise.all([
        this.prisma.user.count().catch(() => 0),
        this.prisma.clothingItem.count().catch(() => 0),
        this.prisma.clothingItem.count({ where: { isActive: true } }).catch(() => 0),
        this.prisma.brand.count().catch(() => 0),
        this.prisma.clothingItem
          .findMany({ select: { category: true }, distinct: ["category"] })
          .then((r: { category: unknown }[]) => r.length)
          .catch(() => 0),
        this.prisma.aiStylistSession.count().catch(() => 0),
        this.prisma.aiStylistSession
          .count({ where: { expiresAt: { gt: new Date() } } })
          .catch(() => 0),
        this.prisma.virtualTryOn.count().catch(() => 0),
        this.prisma.virtualTryOn
          .count({ where: { status: "completed" } })
          .catch(() => 0),
        this.prisma.userPhoto.count().catch(() => 0),
        this.prisma.userPhoto
          .count({ where: { analysisStatus: "completed" } })
          .catch(() => 0),
        this.prisma.rankingFeedback.count().catch(() => 0),
        this.prisma.user
          .count({ where: { createdAt: { gte: yesterday } } })
          .catch(() => 0),
        this.prisma.virtualTryOn
          .count({ where: { createdAt: { gte: yesterday } } })
          .catch(() => 0),
      ]);

      return {
        totalUsers,
        totalClothingItems,
        activeClothingItems,
        totalBrands,
        totalCategories,
        totalSessions,
        activeSessions,
        totalTryOns,
        completedTryOns,
        totalPhotos,
        analyzedPhotos,
        totalFeedbackRecords,
        recentUsers24h,
        recentTryOns24h,
      };
    } catch (error) {
      this.logger.warn(`Failed to get database stats: ${error instanceof Error ? error.message : String(error)}`);
      return defaults;
    }
  }

  async getServiceHealthStatus(): Promise<ServiceHealthStatus> {
    const uptimeMs = Date.now() - this.startTime;
    let version = "unknown";
    try {
      const fs = await import("fs/promises");
      const path = await import("path");
      const pkgPath = path.join(process.cwd(), "..", "..", "package.json");
      const pkgContent = await fs.readFile(pkgPath, "utf-8").catch(() => null);
      if (pkgContent) {
        const parsed = JSON.parse(pkgContent);
        version = parsed.version || "unknown";
      }
    } catch {
      // keep default
    }

    let postgresqlLatency = -1;
    try {
      const start = Date.now();
      await this.prisma.$queryRaw`SELECT 1`;
      postgresqlLatency = Date.now() - start;
    } catch {
      // keep -1
    }

    let redisLatency = -1;
    let redisConnectedClients: number | undefined;
    try {
      const start = Date.now();
      const client = this.redisService.getClient();
      await client.ping();
      redisLatency = Date.now() - start;
      try {
        const info = (await client.info("clients"));
        if (typeof info === "string") {
          const match = info.match(/connected_clients:(\d+)/);
          if (match?.[1]) {redisConnectedClients = parseInt(match[1], 10);}
        }
      } catch {
        // optional field, ignore
      }
    } catch {
      // keep -1
    }

    let minioLatency = -1;
    const minioEndpoint =
      this.configService.get<string>("MINIO_ENDPOINT", "localhost:9000") ||
      "localhost:9000";
    try {
      const start = Date.now();
      const response = await fetch(
        `http://${minioEndpoint}/minio/health/live`,
        { signal: AbortSignal.timeout(3000) },
      );
      minioLatency = response.ok ? Date.now() - start : -1;
    } catch {
      // keep -1
    }

    let qdrantLatency = -1;
    const qdrantHost =
      this.configService.get<string>("QDRANT_HOST", "localhost") ||
      "localhost";
    const qdrantPort = this.configService.get<number>("QDRANT_PORT", 6333);
    try {
      const start = Date.now();
      const response = await fetch(
        `http://${qdrantHost}:${qdrantPort}/`,
        { signal: AbortSignal.timeout(3000) },
      );
      qdrantLatency = response.ok ? Date.now() - start : -1;
    } catch {
      // keep -1
    }

    const llmKey = this.configService.get<string>("GLM_API_KEY", "") ||
      this.configService.get<string>("DEEPSEEK_API_KEY", "") ||
      this.configService.get<string>("AI_STYLIST_API_KEY", "");
    const llmProviderName = this.configService.get<string>(
      "AI_STYLIST_MODEL",
      this.configService.get<string>("GLM_MODEL", "glm-5"),
    );

    return {
      backend: {
        status: "up",
        uptimeMs,
        version: version,
      },
      postgresql: {
        status: postgresqlLatency >= 0 ? "up" : "down",
        latencyMs: Math.max(0, postgresqlLatency),
      },
      redis: {
        status: redisLatency >= 0 ? "up" : "down",
        latencyMs: Math.max(0, redisLatency),
        connectedClients: redisConnectedClients,
      },
      minio: {
        status: minioLatency >= 0 ? "up" : "down",
        latencyMs: Math.max(0, minioLatency),
      },
      qdrant: {
        status: qdrantLatency >= 0 ? "up" : "down",
        latencyMs: Math.max(0, qdrantLatency),
      },
      llmProvider: {
        provider: llmKey ? "configured" : "none",
        model: llmProviderName,
        status: llmKey ? "configured" : "not_configured",
      },
    };
  }

  async getSystemResources(): Promise<SystemResources> {
    const memUsage = process.memoryUsage();
    cpus();

    let cpuUsage = 0;
    try {
      const startUsage = process.cpuUsage();
      await new Promise((resolve) => setTimeout(resolve, 100));
      const endUsage = process.cpuUsage(startUsage);
      const totalMs = endUsage.user + endUsage.system;
      cpuUsage = Math.round((totalMs / 100000) * 100) / 100;
    } catch {
      cpuUsage = -1;
    }

    return {
      nodeVersion: process.version,
      platform: process.platform,
      arch: process.arch,
      memoryUsageMb: {
        rss: Math.round(memUsage.rss / 1024 / 1024 * 10) / 10,
        heapUsed: Math.round(memUsage.heapUsed / 1024 / 1024 * 10) / 10,
        heapTotal: Math.round(memUsage.heapTotal / 1024 / 1024 * 10) / 10,
        external: Math.round(memUsage.external / 1024 / 1024 * 10) / 10,
      },
      cpuUsage,
      uptimeSeconds: Math.round(process.uptime()),
      processId: process.pid,
      cwd: process.cwd(),
    };
  }

  async getProjectFileInfo(): Promise<ProjectFileInfo> {
    const defaults: ProjectFileInfo = {
      totalTypeScriptFiles: 0,
      totalPythonFiles: 0,
      backendModuleCount: 0,
      mlServiceCount: 0,
      packageJsonDeps: 0,
      prismaModels: 0,
    };

    try {
      const fs = await import("fs/promises");
      const path = await import("path");
      const rootDir = this.configService.get<string>("PROJECT_ROOT", "C:\\xuno");

      const [tsFiles, pythonFiles, backendModules, mlServices] =
        await Promise.all([
          this.countFiles(rootDir, "**/*.ts").catch(() => 0),
          this.countFiles(rootDir, "**/*.py").catch(() => 0),
          fs.readdir(path.join(rootDir, "apps/backend/src/modules"))
            .then((dirs) => dirs.length)
            .catch(() => 0),
          fs.readdir(path.join(rootDir, "ml/services"))
            .then((dirs) => dirs.length)
            .catch(() => 0),
        ]);

      let packageJsonDeps = 0;
      try {
        const pkgContent = await fs.readFile(
          path.join(rootDir, "package.json"),
          "utf-8",
        );
        const pkg = JSON.parse(pkgContent);
        packageJsonDeps =
          Object.keys(pkg.dependencies || {}).length +
          Object.keys(pkg.devDependencies || {}).length;
      } catch {
        // skip
      }

      let prismaModels = 0;
      try {
        const schemaPath = path.join(
          rootDir,
          "apps/backend/prisma/schema.prisma",
        );
        const schema = await fs.readFile(schemaPath, "utf-8");
        const modelMatches = schema.match(/^model\s+\w+/gm);
        prismaModels = modelMatches?.length || 0;
      } catch {
        // skip
      }

      return {
        totalTypeScriptFiles: tsFiles,
        totalPythonFiles: pythonFiles,
        backendModuleCount: backendModules,
        mlServiceCount: mlServices,
        packageJsonDeps,
        prismaModels,
      };
    } catch (error) {
      this.logger.warn(`Failed to get project file info: ${error instanceof Error ? error.message : String(error)}`);
      return defaults;
    }
  }

  private async countFiles(
    rootDir: string,
    pattern: string,
  ): Promise<number> {
    try {
      const fs = await import("fs/promises");
      const path = await import("path");

      async function walk(dir: string): Promise<string[]> {
        const entries = await fs.readdir(dir, { withFileTypes: true });
        const results: string[] = [];
        for (const entry of entries) {
          const fullPath = path.join(dir, entry.name);
          if (entry.isDirectory()) {
            if (
              !entry.name.startsWith(".") &&
              entry.name !== "node_modules" &&
              entry.name !== "dist"
            ) {
              results.push(...(await walk(fullPath)));
            }
          } else {
            results.push(fullPath);
          }
        }
        return results;
      }

      const allFiles = await walk(rootDir);
      const ext = pattern.includes(".ts") ? ".ts" : ".py";
      return allFiles.filter((f) => f.endsWith(ext)).length;
    } catch {
      return 0;
    }
  }

  getContextSummaryForPrompt(): Promise<string> {
    return this.getFullContext().then((ctx) => {
      const parts: string[] = [
        `## 系统环境快照 (${ctx.timestamp})`,
        ``,
        `### 项目信息`,
        `- 分支: ${ctx.git.branch} | 最近提交: ${ctx.git.lastCommit} (${ctx.git.lastCommitMessage.slice(0, 60)})`,
        `- 工作区: ${ctx.git.isCleanWorkingTree ? "干净" : `${ctx.git.changedFiles} 个文件未提交`}`,
        `- 环境: ${ctx.environment} | Node.js ${ctx.resources.nodeVersion}`,
        ``,
        `### 数据概况`,
        `- 用户: ${ctx.database.totalUsers} (今日+${ctx.database.recentUsers24h})`,
        `- 服装: ${ctx.database.totalClothingItems} 件 (${ctx.database.activeClothingItems} 活跃)`,
        `- 品牌: ${ctx.database.totalBrands} | 分类: ${ctx.database.totalCategories}`,
        `- 试衣: ${ctx.database.totalTryOns} 次 (${ctx.database.completedTryOns} 完成)`,
        `- AI会话: ${ctx.database.totalSessions} (${ctx.database.activeSessions} 活跃)`,
        ``,
        `### 服务状态`,
        `- PostgreSQL: ${ctx.services.postgresql.status} (${ctx.services.postgresql.latencyMs}ms)`,
        `- Redis: ${ctx.services.redis.status} (${ctx.services.redis.latencyMs}ms)`,
        `- Qdrant: ${ctx.services.qdrant.status} (${ctx.services.qdrant.latencyMs}ms)`,
        `- MinIO: ${ctx.services.minio.status} (${ctx.services.minio.latencyMs}ms)`,
        `- LLM: ${ctx.services.llmProvider.provider}/${ctx.services.llmProvider.model}`,
        ``,
        `### 系统资源`,
        `- 内存 RSS: ${ctx.resources.memoryUsageMb.rss}MB | Heap: ${ctx.resources.memoryUsageMb.heapUsed}/${ctx.resources.memoryUsageMb.heapTotal}MB`,
        `- 运行时间: ${Math.floor(ctx.resources.uptimeSeconds / 60)} 分钟 | PID: ${ctx.resources.processId}`,
      ];
      return parts.join("\n");
    });
  }
}

import { Injectable, Logger } from "@nestjs/common";

import {
  CloudCommunicationService,
  CloudTask,
} from "./cloud-communication.service";
import {
  HybridProcessingService,
  HybridProcessingRequest,
} from "./hybrid-processing.service";
import {
  UNetSegmentationService,
  SegmentationResult,
} from "./unet-segmentation.service";

export interface AlgorithmPipelineConfig {
  enableLocalProcessing: boolean;
  enableCloudProcessing: boolean;
  preferQuality: boolean;
  maxLatency: number;
  cacheResults: boolean;
}

export interface PipelineResult {
  success: boolean;
  data: unknown;
  algorithm: string;
  processingPath: "local" | "cloud" | "hybrid";
  latency: number;
  confidence: number;
  metadata: Record<string, unknown>;
}

export interface TryOnPipelineInput {
  userId: string;
  personImage: Buffer;
  garmentImage: Buffer;
  category: string;
  options?: Partial<AlgorithmPipelineConfig>;
}

export interface RecommendationPipelineInput {
  userId: string;
  context: {
    currentItemId?: string;
    category?: string;
    season?: string;
    occasion?: string;
  };
  options?: Partial<AlgorithmPipelineConfig>;
}

export interface SegmentationPipelineInput {
  image: Buffer;
  category: string;
  options?: Partial<AlgorithmPipelineConfig>;
}

export interface CompatibilityPipelineInput {
  items: Array<{
    id: string;
    features: number[];
    category: string;
  }>;
  options?: Partial<AlgorithmPipelineConfig>;
}

@Injectable()
export class AlgorithmOrchestratorService {
  private readonly logger = new Logger(AlgorithmOrchestratorService.name);

  private readonly defaultConfig: AlgorithmPipelineConfig = {
    enableLocalProcessing: true,
    enableCloudProcessing: true,
    preferQuality: false,
    maxLatency: 10000,
    cacheResults: true,
  };

  constructor(
    private unetSegmentation: UNetSegmentationService,
    private hybridProcessing: HybridProcessingService,
    private cloudCommunication: CloudCommunicationService,
  ) {}

  async executeTryOnPipeline(
    input: TryOnPipelineInput,
  ): Promise<PipelineResult> {
    const startTime = Date.now();
    const config = { ...this.defaultConfig, ...input.options };

    this.logger.log(`Starting try-on pipeline for user ${input.userId}`);

    try {
      const segmentationResult = await this.unetSegmentation.segmentClothing(
        input.personImage,
      );

      const hybridRequest: HybridProcessingRequest = {
        requestId: `tryon_${Date.now()}`,
        userId: input.userId,
        personImage: input.personImage,
        garmentImage: input.garmentImage,
        poseKeypoints: this.extractPoseKeypoints(segmentationResult),
        options: {
          useCloud: config.enableCloudProcessing && config.preferQuality,
          priority: config.preferQuality ? "quality" : "balanced",
          timeout: config.maxLatency,
        },
      };

      const hybridResult = await this.hybridProcessing.process(hybridRequest);

      const latency = Date.now() - startTime;

      return {
        success: true,
        data: hybridResult.result,
        algorithm: "diffusion_tryon",
        processingPath: hybridResult.processingPath,
        latency,
        confidence: hybridResult.confidence,
        metadata: {
          segmentationConfidence: segmentationResult.confidence,
          ...hybridResult.metadata,
        },
      };
    } catch (error) {
      const latency = Date.now() - startTime;
      this.logger.error("Try-on pipeline failed:", error);

      return {
        success: false,
        data: null,
        algorithm: "diffusion_tryon",
        processingPath: "local",
        latency,
        confidence: 0,
        metadata: {
          error: error instanceof Error ? error.message : String(error),
        },
      };
    }
  }

  async executeRecommendationPipeline(
    input: RecommendationPipelineInput,
  ): Promise<PipelineResult> {
    const startTime = Date.now();
    const config = { ...this.defaultConfig, ...input.options };

    this.logger.log(
      `Starting recommendation pipeline for user ${input.userId}`,
    );

    try {
      const taskType: CloudTask["type"] = "recommendation";

      if (config.enableCloudProcessing) {
        const taskId = await this.cloudCommunication.submitTask(
          taskType,
          {
            userId: input.userId,
            context: input.context,
          },
          "normal",
        );

        const result = await this.cloudCommunication.getTaskResult(
          taskId,
          config.maxLatency,
        );

        const latency = Date.now() - startTime;

        return {
          success: true,
          data: result,
          algorithm: "gnn_hypergraph_compatibility",
          processingPath: "cloud",
          latency,
          confidence: result?.confidence || 0.8,
          metadata: { taskId },
        };
      }

      throw new Error(
        "Recommendation pipeline requires cloud processing or a verified local recommender",
      );
    } catch (error) {
      const latency = Date.now() - startTime;
      this.logger.error("Recommendation pipeline failed:", error);

      return {
        success: false,
        data: null,
        algorithm: "gnn_hypergraph_compatibility",
        processingPath: "local",
        latency,
        confidence: 0,
        metadata: {
          error: error instanceof Error ? error.message : String(error),
        },
      };
    }
  }

  async executeSegmentationPipeline(
    input: SegmentationPipelineInput,
  ): Promise<PipelineResult> {
    const startTime = Date.now();
    const config = { ...this.defaultConfig, ...input.options };

    this.logger.log(
      `Starting segmentation pipeline for category ${input.category}`,
    );

    try {
      const result = await this.unetSegmentation.segmentClothing(input.image);

      const latency = Date.now() - startTime;

      return {
        success: true,
        data: {
          mask: result.mask,
          attributes: result.attributes,
          boundingBox: result.boundingBox,
        },
        algorithm: "unet_eca_attention",
        processingPath: "local",
        latency,
        confidence: result.confidence,
        metadata: {
          maskSize: result.mask.length,
        },
      };
    } catch (error) {
      const latency = Date.now() - startTime;
      this.logger.error("Segmentation pipeline failed:", error);

      return {
        success: false,
        data: null,
        algorithm: "unet_eca_attention",
        processingPath: "local",
        latency,
        confidence: 0,
        metadata: {
          error: error instanceof Error ? error.message : String(error),
        },
      };
    }
  }

  async executeCompatibilityPipeline(
    input: CompatibilityPipelineInput,
  ): Promise<PipelineResult> {
    const startTime = Date.now();
    const config = { ...this.defaultConfig, ...input.options };

    this.logger.log(
      `Starting compatibility pipeline for ${input.items.length} items`,
    );

    try {
      if (config.enableCloudProcessing) {
        const taskId = await this.cloudCommunication.submitTask(
          "compatibility",
          {
            items: input.items,
          },
          "normal",
        );

        const result = await this.cloudCommunication.getTaskResult(
          taskId,
          config.maxLatency,
        );

        const latency = Date.now() - startTime;

        return {
          success: true,
          data: result,
          algorithm: "gnn_hypergraph",
          processingPath: "cloud",
          latency,
          confidence: result?.confidence || 0.85,
          metadata: { taskId, itemCount: input.items.length },
        };
      }

      const compatibilityScore = this.calculateLocalCompatibility(input.items);

      const latency = Date.now() - startTime;

      return {
        success: true,
        data: { score: compatibilityScore, pairs: [] },
        algorithm: "gnn_hypergraph",
        processingPath: "local",
        latency,
        confidence: 0.7,
        metadata: { itemCount: input.items.length, mode: "local_heuristic" },
      };
    } catch (error) {
      const latency = Date.now() - startTime;
      this.logger.error("Compatibility pipeline failed:", error);

      return {
        success: false,
        data: null,
        algorithm: "gnn_hypergraph",
        processingPath: "local",
        latency,
        confidence: 0,
        metadata: {
          error: error instanceof Error ? error.message : String(error),
        },
      };
    }
  }

  private extractPoseKeypoints(segmentationResult: SegmentationResult): Array<{
    id: number;
    x: number;
    y: number;
    z: number;
    visibility: number;
  }> {
    const keypoints: Array<{
      id: number;
      x: number;
      y: number;
      z: number;
      visibility: number;
    }> = [];

    if (segmentationResult.boundingBox) {
      const { x, y, width, height } = segmentationResult.boundingBox;

      keypoints.push(
        { id: 0, x: x + width / 2, y: y, z: 0, visibility: 0.9 },
        { id: 1, x: x + width / 2, y: y + height / 3, z: 0, visibility: 0.9 },
        {
          id: 2,
          x: x + width / 2,
          y: y + (height * 2) / 3,
          z: 0,
          visibility: 0.9,
        },
        { id: 3, x: x + width / 2, y: y + height, z: 0, visibility: 0.9 },
        { id: 4, x: x, y: y + height / 2, z: 0, visibility: 0.8 },
        { id: 5, x: x + width, y: y + height / 2, z: 0, visibility: 0.8 },
      );
    }

    return keypoints;
  }

  private calculateLocalCompatibility(
    items: CompatibilityPipelineInput["items"],
  ): number {
    if (items.length < 2) {return 1.0;}

    let totalScore = 0;
    let pairCount = 0;

    for (let i = 0; i < items.length; i++) {
      for (let j = i + 1; j < items.length; j++) {
        const currentItem = items[i];
        const compareItem = items[j];
        if (!currentItem || !compareItem) {
          continue;
        }
        const similarity = this.cosineSimilarity(
          currentItem.features,
          compareItem.features,
        );
        const categoryBonus =
          currentItem.category !== compareItem.category ? 0.1 : -0.1;
        totalScore += similarity + categoryBonus;
        pairCount++;
      }
    }

    return Math.max(0, Math.min(1, totalScore / pairCount));
  }

  private cosineSimilarity(vec1: number[], vec2: number[]): number {
    if (vec1.length !== vec2.length) {return 0;}

    let dotProduct = 0;
    let norm1 = 0;
    let norm2 = 0;

    for (let i = 0; i < vec1.length; i++) {
      const value1 = vec1[i] ?? 0;
      const value2 = vec2[i] ?? 0;
      dotProduct += value1 * value2;
      norm1 += value1 * value1;
      norm2 += value2 * value2;
    }

    if (norm1 === 0 || norm2 === 0) {return 0;}

    return dotProduct / (Math.sqrt(norm1) * Math.sqrt(norm2));
  }

  async getSystemStatus(): Promise<{
    algorithms: Record<string, { status: string; lastUsed: Date | null }>;
    cloudConnection: boolean;
    queueStats: Record<string, number>;
  }> {
    const connectionStatus = this.cloudCommunication.getConnectionStatus();
    const queueStats = this.cloudCommunication.getQueueStats();

    return {
      algorithms: {
        unet_segmentation: { status: "ready", lastUsed: null },
        diffusion_tryon: { status: "ready", lastUsed: null },
        gnn_compatibility: { status: "ready", lastUsed: null },
        hypergraph_outfit: { status: "ready", lastUsed: null },
      },
      cloudConnection: connectionStatus.connected,
      queueStats: {
        total: queueStats.total,
        pending: queueStats.pending,
        processing: queueStats.processing,
        completed: queueStats.completed,
        failed: queueStats.failed,
      },
    };
  }

  async prefetchUserData(userId: string): Promise<void> {
    await this.cloudCommunication.prefetchUserData(userId);
    this.logger.log(`Prefetched data for user ${userId}`);
  }

  async batchProcess(
    tasks: Array<{
      type: "tryon" | "recommendation" | "segmentation" | "compatibility";
      input: TryOnPipelineInput | RecommendationPipelineInput | SegmentationPipelineInput | CompatibilityPipelineInput;
    }>,
  ): Promise<PipelineResult[]> {
    const results: PipelineResult[] = [];

    for (const task of tasks) {
      let result: PipelineResult;

      switch (task.type) {
        case "tryon":
          result = await this.executeTryOnPipeline(task.input as TryOnPipelineInput);
          break;
        case "recommendation":
          result = await this.executeRecommendationPipeline(task.input as RecommendationPipelineInput);
          break;
        case "segmentation":
          result = await this.executeSegmentationPipeline(task.input as SegmentationPipelineInput);
          break;
        case "compatibility":
          result = await this.executeCompatibilityPipeline(task.input as CompatibilityPipelineInput);
          break;
        default:
          result = {
            success: false,
            data: null,
            algorithm: "unknown",
            processingPath: "local",
            latency: 0,
            confidence: 0,
            metadata: { error: "Unknown task type" },
          };
      }

      results.push(result);
    }

    return results;
  }
}

import {
  Injectable,
  Logger,
  OnModuleInit,
  OnModuleDestroy,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import { RedisService } from "../../../common/redis/redis.service";

export interface CloudTask {
  taskId: string;
  type: "tryon" | "segmentation" | "recommendation" | "compatibility";
  payload: Record<string, unknown>;
  priority: "low" | "normal" | "high" | "urgent";
  status: "pending" | "processing" | "completed" | "failed";
  createdAt: Date;
  startedAt?: Date;
  completedAt?: Date;
  retryCount: number;
  maxRetries: number;
  result?: unknown;
  error?: string;
}

export interface TaskProgress {
  taskId: string;
  progress: number;
  stage: string;
  estimatedTimeRemaining?: number;
}

export interface CloudConnection {
  connected: boolean;
  latency: number;
  lastHeartbeat: Date;
  serverLoad: number;
}

export interface SyncMessage {
  type:
    | "sync_request"
    | "sync_response"
    | "delta_update"
    | "conflict_resolution";
  timestamp: Date;
  deviceId: string;
  data: Record<string, unknown>;
  checksum?: string;
}

export interface CommunicationProtocol {
  version: string;
  encoding: "json" | "protobuf" | "msgpack";
  compression: boolean;
  encryption: boolean;
  timeout: number;
  retryPolicy: {
    maxRetries: number;
    backoffMultiplier: number;
    initialDelay: number;
    maxDelay: number;
  };
}

@Injectable()
export class CloudCommunicationService
  implements OnModuleInit, OnModuleDestroy
{
  private readonly logger = new Logger(CloudCommunicationService.name);

  private readonly PROTOCOL: CommunicationProtocol = {
    version: "1.0.0",
    encoding: "json",
    compression: true,
    encryption: true,
    timeout: 30000,
    retryPolicy: {
      maxRetries: 3,
      backoffMultiplier: 2,
      initialDelay: 1000,
      maxDelay: 10000,
    },
  };

  private connectionStatus: CloudConnection = {
    connected: false,
    latency: 0,
    lastHeartbeat: new Date(),
    serverLoad: 0,
  };

  private taskQueue: Map<string, CloudTask> = new Map();
  private pendingCallbacks: Map<
    string,
    {
      resolve: (result: unknown) => void;
      reject: (error: Error) => void;
      timeout: NodeJS.Timeout;
    }
  > = new Map();

  private heartbeatInterval?: NodeJS.Timeout;
  private taskProcessorInterval?: NodeJS.Timeout;
  private readonly DEVICE_ID = `device_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

  constructor(
    private configService: ConfigService,
    private redisService: RedisService,
  ) {}

  async onModuleInit() {
    this.logger.log("Initializing Cloud Communication Service");
    await this.initializeConnection();
    this.startHeartbeat();
    this.startTaskProcessor();
  }

  async onModuleDestroy() {
    this.logger.log("Destroying Cloud Communication Service");
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
    if (this.taskProcessorInterval) {
      clearInterval(this.taskProcessorInterval);
    }
    await this.flushPendingTasks();
  }

  private async initializeConnection(): Promise<void> {
    this.logger.log("Establishing cloud connection...");

    try {
      const start = Date.now();
      await this.pingCloud();
      this.connectionStatus.latency = Date.now() - start;
      this.connectionStatus.connected = true;
      this.connectionStatus.lastHeartbeat = new Date();
      this.logger.log(
        `Cloud connection established. Latency: ${this.connectionStatus.latency}ms`,
      );
    } catch (error) {
      this.logger.error("Failed to establish cloud connection:", error);
      this.connectionStatus.connected = false;
    }
  }

  private startHeartbeat(): void {
    this.heartbeatInterval = setInterval(async () => {
      try {
        const start = Date.now();
        await this.pingCloud();
        this.connectionStatus.latency = Date.now() - start;
        this.connectionStatus.lastHeartbeat = new Date();
        this.connectionStatus.connected = true;
      } catch (error) {
        this.logger.warn("Heartbeat failed:", error);
        this.connectionStatus.connected = false;
      }
    }, 30000);
  }

  private startTaskProcessor(): void {
    this.taskProcessorInterval = setInterval(async () => {
      await this.processPendingTasks();
    }, 5000);
  }

  private async pingCloud(): Promise<void> {
    const client = this.redisService.getClient();
    const pingKey = `cloud:ping:${this.DEVICE_ID}`;
    await client.set(pingKey, Date.now().toString(), "EX", 60);
  }

  async submitTask(
    type: CloudTask["type"],
    payload: Record<string, any>,
    priority: CloudTask["priority"] = "normal",
  ): Promise<string> {
    const taskId = `task_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

    const task: CloudTask = {
      taskId,
      type,
      payload,
      priority,
      status: "pending",
      createdAt: new Date(),
      retryCount: 0,
      maxRetries: this.PROTOCOL.retryPolicy.maxRetries,
    };

    this.taskQueue.set(taskId, task);
    await this.persistTask(task);

    this.logger.log(
      `Task ${taskId} submitted: ${type} with priority ${priority}`,
    );
    return taskId;
  }

  async getTaskResult(taskId: string, timeout: number = 30000): Promise<any> {
    return new Promise((resolve, reject) => {
      const timeoutHandle = setTimeout(() => {
        this.pendingCallbacks.delete(taskId);
        reject(new Error(`Task ${taskId} timed out after ${timeout}ms`));
      }, timeout);

      this.pendingCallbacks.set(taskId, {
        resolve: (result) => {
          clearTimeout(timeoutHandle);
          this.pendingCallbacks.delete(taskId);
          resolve(result);
        },
        reject: (error) => {
          clearTimeout(timeoutHandle);
          this.pendingCallbacks.delete(taskId);
          reject(error);
        },
        timeout: timeoutHandle,
      });

      this.checkTaskCompletion(taskId);
    });
  }

  private async checkTaskCompletion(taskId: string): Promise<void> {
    const task = this.taskQueue.get(taskId);
    if (!task) {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error(`Task ${taskId} not found`));
      }
      return;
    }

    if (task.status === "completed") {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.resolve(task.result);
      }
    } else if (task.status === "failed") {
      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error(task.error || "Task failed"));
      }
    }
  }

  private async processPendingTasks(): Promise<void> {
    if (!this.connectionStatus.connected) {
      this.logger.debug("Cloud not connected, skipping task processing");
      return;
    }

    const pendingTasks = Array.from(this.taskQueue.values())
      .filter((t) => t.status === "pending")
      .sort(
        (a, b) =>
          this.getPriorityWeight(b.priority) -
          this.getPriorityWeight(a.priority),
      );

    for (const task of pendingTasks.slice(0, 5)) {
      await this.processTask(task);
    }
  }

  private getPriorityWeight(priority: CloudTask["priority"]): number {
    const weights = { urgent: 4, high: 3, normal: 2, low: 1 };
    return weights[priority];
  }

  private async processTask(task: CloudTask): Promise<void> {
    this.logger.log(`Processing task ${task.taskId}`);
    task.status = "processing";
    task.startedAt = new Date();
    await this.persistTask(task);

    try {
      const result = await this.executeOnCloud(task);
      task.status = "completed";
      task.completedAt = new Date();
      task.result = result;

      const callback = this.pendingCallbacks.get(task.taskId);
      if (callback) {
        callback.resolve(result);
      }
    } catch (error) {
      this.logger.error(`Task ${task.taskId} failed:`, error);
      task.retryCount++;

      if (task.retryCount >= task.maxRetries) {
        task.status = "failed";
        task.error = error instanceof Error ? error.message : String(error);

        const callback = this.pendingCallbacks.get(task.taskId);
        if (callback) {
          callback.reject(new Error(task.error));
        }
      } else {
        task.status = "pending";
        const delay = this.calculateBackoffDelay(task.retryCount);
        await this.delay(delay);
      }
    }

    await this.persistTask(task);
  }

  private calculateBackoffDelay(retryCount: number): number {
    const { initialDelay, backoffMultiplier, maxDelay } =
      this.PROTOCOL.retryPolicy;
    const delay = initialDelay * Math.pow(backoffMultiplier, retryCount - 1);
    return Math.min(delay, maxDelay);
  }

  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }

  private async executeOnCloud(task: CloudTask): Promise<any> {
    const client = this.redisService.getClient();
    const taskKey = `cloud:task:${task.taskId}`;
    const resultKey = `cloud:result:${task.taskId}`;

    await client.hset(taskKey, {
      type: task.type,
      payload: JSON.stringify(task.payload),
      priority: task.priority,
      deviceId: this.DEVICE_ID,
      createdAt: task.createdAt.toISOString(),
    });
    await client.expire(taskKey, 3600);

    await client.lpush("cloud:task:queue", task.taskId);

    const startTime = Date.now();
    const timeout = this.PROTOCOL.timeout;

    while (Date.now() - startTime < timeout) {
      const resultData = await client.get(resultKey);
      if (resultData) {
        await client.del(resultKey);
        return JSON.parse(resultData);
      }
      await this.delay(500);
    }

    throw new Error("Cloud task execution timed out");
  }

  private async persistTask(task: CloudTask): Promise<void> {
    const client = this.redisService.getClient();
    const key = `local:task:${task.taskId}`;
    await client.hset(key, {
      taskId: task.taskId,
      type: task.type,
      payload: JSON.stringify(task.payload),
      priority: task.priority,
      status: task.status,
      createdAt: task.createdAt.toISOString(),
      startedAt: task.startedAt?.toISOString() || "",
      completedAt: task.completedAt?.toISOString() || "",
      retryCount: task.retryCount.toString(),
      maxRetries: task.maxRetries.toString(),
      result: task.result ? JSON.stringify(task.result) : "",
      error: task.error || "",
    });
    await client.expire(key, 86400);
  }

  async getTaskProgress(taskId: string): Promise<TaskProgress | null> {
    const task = this.taskQueue.get(taskId);
    if (!task) {return null;}

    let progress = 0;
    let stage = "pending";

    if (task.status === "processing") {
      const elapsed = Date.now() - (task.startedAt?.getTime() || Date.now());
      const estimatedTotal = 5000;
      progress = Math.min(90, (elapsed / estimatedTotal) * 100);
      stage = this.getProcessingStage(task.type, progress);
    } else if (task.status === "completed") {
      progress = 100;
      stage = "completed";
    } else if (task.status === "failed") {
      stage = "failed";
    }

    return {
      taskId,
      progress,
      stage,
      estimatedTimeRemaining:
        task.status === "processing" ? 5000 * (1 - progress / 100) : undefined,
    };
  }

  private getProcessingStage(
    type: CloudTask["type"],
    progress: number,
  ): string {
    const stages: Record<CloudTask["type"], string[]> = {
      tryon: [
        "preprocessing",
        "pose_estimation",
        "garment_warping",
        "image_synthesis",
        "postprocessing",
      ],
      segmentation: [
        "image_loading",
        "feature_extraction",
        "mask_generation",
        "refinement",
      ],
      recommendation: [
        "user_profiling",
        "item_retrieval",
        "ranking",
        "diversification",
      ],
      compatibility: [
        "feature_extraction",
        "graph_construction",
        "gnn_propagation",
        "scoring",
      ],
    };

    const typeStages = stages[type] ?? ["queued"];
    const stageIndex = Math.floor((progress / 100) * typeStages.length);
    return typeStages[Math.min(stageIndex, typeStages.length - 1)] ?? "queued";
  }

  async cancelTask(taskId: string): Promise<boolean> {
    const task = this.taskQueue.get(taskId);
    if (!task) {return false;}

    if (task.status === "pending" || task.status === "processing") {
      task.status = "failed";
      task.error = "Cancelled by user";
      await this.persistTask(task);

      const callback = this.pendingCallbacks.get(taskId);
      if (callback) {
        callback.reject(new Error("Task cancelled"));
      }

      return true;
    }
    return false;
  }

  async syncData(message: SyncMessage): Promise<SyncMessage> {
    const client = this.redisService.getClient();
    const syncKey = `sync:${message.deviceId}:${Date.now()}`;

    await client.set(syncKey, JSON.stringify(message), "EX", 300);

    const response: SyncMessage = {
      type: "sync_response",
      timestamp: new Date(),
      deviceId: this.DEVICE_ID,
      data: { status: "acknowledged", originalMessageId: syncKey },
    };

    return response;
  }

  async requestDeltaSync(lastSyncTime: Date, dataType: string): Promise<any> {
    this.logger.log(
      `Requesting delta sync for ${dataType} since ${lastSyncTime.toISOString()}`,
    );

    const client = this.redisService.getClient();
    const deltaKey = `delta:${dataType}:${this.DEVICE_ID}`;

    const deltas = await client.lrange(deltaKey, 0, -1);
    return deltas.map((d) => JSON.parse(d));
  }

  getConnectionStatus(): CloudConnection {
    return { ...this.connectionStatus };
  }

  getProtocolInfo(): CommunicationProtocol {
    return { ...this.PROTOCOL };
  }

  getQueueStats(): {
    total: number;
    pending: number;
    processing: number;
    completed: number;
    failed: number;
  } {
    const tasks = Array.from(this.taskQueue.values());
    return {
      total: tasks.length,
      pending: tasks.filter((t) => t.status === "pending").length,
      processing: tasks.filter((t) => t.status === "processing").length,
      completed: tasks.filter((t) => t.status === "completed").length,
      failed: tasks.filter((t) => t.status === "failed").length,
    };
  }

  private async flushPendingTasks(): Promise<void> {
    this.logger.log("Flushing pending tasks...");

    for (const [_taskId, callback] of this.pendingCallbacks) {
      callback.reject(new Error("Service shutting down"));
    }
    this.pendingCallbacks.clear();

    for (const task of this.taskQueue.values()) {
      if (task.status === "processing") {
        task.status = "pending";
        await this.persistTask(task);
      }
    }
  }

  async prefetchUserData(userId: string): Promise<void> {
    this.logger.log(`Prefetching data for user: ${userId}`);

    const client = this.redisService.getClient();
    const prefetchKey = `prefetch:user:${userId}`;

    await client.set(
      prefetchKey,
      JSON.stringify({
        userId,
        timestamp: new Date().toISOString(),
        deviceId: this.DEVICE_ID,
      }),
      "EX",
      300,
    );
  }

  async batchSubmitTasks(
    tasks: Array<{
      type: CloudTask["type"];
      payload: Record<string, any>;
      priority?: CloudTask["priority"];
    }>,
  ): Promise<string[]> {
    const taskIds: string[] = [];

    for (const task of tasks) {
      const taskId = await this.submitTask(
        task.type,
        task.payload,
        task.priority,
      );
      taskIds.push(taskId);
    }

    return taskIds;
  }

  async getBatchResults(
    taskIds: string[],
    timeout: number = 60000,
  ): Promise<Map<string, any>> {
    const results = new Map<string, any>();
    const startTime = Date.now();

    while (Date.now() - startTime < timeout) {
      for (const taskId of taskIds) {
        if (!results.has(taskId)) {
          const task = this.taskQueue.get(taskId);
          if (task?.status === "completed") {
            results.set(taskId, task.result);
          } else if (task?.status === "failed") {
            results.set(taskId, { error: task.error });
          }
        }
      }

      if (results.size === taskIds.length) {
        break;
      }

      await this.delay(500);
    }

    return results;
  }
}

import {
  Injectable,
  Logger,
  ServiceUnavailableException,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { allowUnverifiedAiFallbacks } from "../../../common/config/runtime-flags";

export interface HybridProcessingRequest {
  requestId?: string;
  userId?: string;
  personImage: Buffer;
  garmentImage?: Buffer;
  type?: "tryon" | "recommendation" | "segmentation";
  context?: Record<string, unknown>;
  poseKeypoints?: PoseKeypoint[];
  options?: {
    useCloud?: boolean;
    priority?: "speed" | "quality" | "balanced";
    timeout?: number;
  };
}

export interface HybridProcessingResult {
  requestId: string;
  result: TryOnResult | RecommendationResult | SegmentationResult;
  processingPath: "local" | "cloud" | "hybrid";
  latency: number;
  confidence: number;
  metadata: {
    localLatency?: number;
    cloudLatency?: number;
    cacheHit?: boolean;
    modelVersion: string;
  };
}

export interface PoseKeypoint {
  id: number;
  x: number;
  y: number;
  z: number;
  visibility: number;
}

export interface TryOnResult {
  type: "tryon";
  image: string | Buffer;
  score: number;
}

export interface RecommendationResult {
  type: "recommendation";
  items: Array<{
    itemId: string;
    score: number;
    reasons: string[];
  }>;
}

export interface SegmentationResult {
  type: "segmentation";
  mask: number[][];
  attributes: Record<string, unknown>;
}

/**
 * API 返回的推荐商品项结构
 */
interface ApiRecommendationItem {
  id: string;
  score: number;
  reasons?: string[];
}

export interface NetworkQuality {
  bandwidth: number;
  latency: number;
  stability: number;
  score: number;
}

export interface ProcessingDecision {
  useCloud: boolean;
  reason: string;
  estimatedLatency: number;
  estimatedCost: number;
}

@Injectable()
export class HybridProcessingService {
  private readonly logger = new Logger(HybridProcessingService.name);
  private aiClient: AxiosInstance;
  private aiServiceAvailable = false;
  private readonly allowFallbacks: boolean;
  private readonly aiServiceUrl: string;

  private readonly thresholds = {
    complexity: 0.7,
    networkQuality: 0.5,
    cacheHit: 0.8,
    userPreference: 0.6,
    maxLocalLatency: 100,
    maxCloudLatency: 5000,
  };

  private readonly weights = {
    gnn: 0.35,
    hypergraph: 0.35,
    crossAttention: 0.3,
  };

  private cacheHits = 0;
  private totalRequests = 0;
  private networkLatencyHistory: number[] = [];

  constructor(private configService: ConfigService) {
    this.allowFallbacks = allowUnverifiedAiFallbacks(this.configService);

    this.aiServiceUrl = this.configService.get<string>(
      "AI_SERVICE_URL",
      "http://localhost:8001",
    );

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 30000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkAiServiceHealth();
  }

  private async checkAiServiceHealth(): Promise<void> {
    try {
      const start = Date.now();
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      const latency = Date.now() - start;

      if (response.data?.status === "healthy") {
        this.aiServiceAvailable = true;
        this.networkLatencyHistory.push(latency);
        this.logger.log(`AI Service connected (latency: ${latency}ms)`);
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `AI Service not available for hybrid processing (${this.aiServiceUrl}): ${errorMessage}`,
      );
      this.aiServiceAvailable = false;
    }
  }

  async process(
    request: HybridProcessingRequest,
  ): Promise<HybridProcessingResult> {
    const startTime = Date.now();
    const requestId = request.requestId || `hybrid_${Date.now()}`;
    this.totalRequests++;

    this.logger.log(`Processing request ${requestId}`);

    const networkQuality = await this.assessNetworkQuality();
    const imageComplexity = this.assessImageComplexity(
      request.personImage,
      request.garmentImage,
    );

    const decision = this.makeProcessingDecision(
      imageComplexity,
      networkQuality,
      request.options,
    );

    this.logger.log(
      `Decision for ${requestId}: ${decision.useCloud ? "cloud" : "local"} - ${decision.reason}`,
    );

    let result: TryOnResult | RecommendationResult | SegmentationResult;
    let localLatency: number | undefined;
    let cloudLatency: number | undefined;
    const cacheHit = false;

    if (decision.useCloud) {
      const cloudStart = Date.now();
      result = await this.processOnCloud(request);
      cloudLatency = Date.now() - cloudStart;
    } else {
      const localStart = Date.now();
      result = await this.processLocally(request);
      localLatency = Date.now() - localStart;
    }

    const totalLatency = Date.now() - startTime;

    return {
      requestId,
      result,
      processingPath: decision.useCloud ? "cloud" : "local",
      latency: totalLatency,
      confidence: this.calculateConfidence(result),
      metadata: {
        localLatency,
        cloudLatency,
        cacheHit,
        modelVersion: "1.0.0",
      },
    };
  }

  private async assessNetworkQuality(): Promise<NetworkQuality> {
    if (this.aiServiceAvailable && this.networkLatencyHistory.length > 0) {
      const recentLatencies = this.networkLatencyHistory.slice(-5);
      const avgLatency =
        recentLatencies.reduce((a, b) => a + b, 0) / recentLatencies.length;
      const latencyVariance =
        recentLatencies.reduce(
          (sum, l) => sum + Math.pow(l - avgLatency, 2),
          0,
        ) / recentLatencies.length;
      const stability = Math.max(
        0,
        1 - Math.sqrt(latencyVariance) / avgLatency,
      );

      const bandwidth = Math.max(1, 1000 / avgLatency);

      const score =
        (bandwidth / 100) * 0.4 +
        (1 - avgLatency / 500) * 0.3 +
        stability * 0.3;

      return { bandwidth, latency: avgLatency, stability, score };
    }

    return {
      bandwidth: 10,
      latency: 500,
      stability: 0.5,
      score: 0.3,
    };
  }

  private assessImageComplexity(
    personImage: Buffer,
    garmentImage?: Buffer,
  ): number {
    const personComplexity = this.calculateImageComplexity(personImage);
    const garmentComplexity = this.calculateImageComplexity(
      garmentImage ?? personImage,
    );

    return (personComplexity + garmentComplexity) / 2;
  }

  private calculateImageComplexity(image: Buffer): number {
    if (!image || image.length === 0) {
      return 0.5;
    }

    const size = image.length;
    const sizeScore = Math.min(size / (1024 * 1024), 1);

    let entropy = 0;
    const byteFreq = new Map<number, number>();
    const sampleSize = Math.min(image.length, 10000);
    const step = Math.max(1, Math.floor(image.length / sampleSize));

    for (let i = 0; i < image.length; i += step) {
      const byte = image[i];
      if (byte === undefined) {
        continue;
      }
      byteFreq.set(byte, (byteFreq.get(byte) || 0) + 1);
    }

    const totalSamples = Math.ceil(image.length / step);
    byteFreq.forEach((count) => {
      const p = count / totalSamples;
      entropy -= p * Math.log2(p);
    });

    const normalizedEntropy = entropy / 8;

    return 0.3 * sizeScore + 0.7 * normalizedEntropy;
  }

  private makeProcessingDecision(
    imageComplexity: number,
    networkQuality: NetworkQuality,
    options: HybridProcessingRequest["options"],
  ): ProcessingDecision {
    if (options?.useCloud !== undefined) {
      return {
        useCloud: options.useCloud,
        reason: "User specified processing path",
        estimatedLatency: options.useCloud ? 2000 : 80,
        estimatedCost: options.useCloud ? 0.01 : 0,
      };
    }

    const conditions = [
      imageComplexity > this.thresholds.complexity,
      networkQuality.score > this.thresholds.networkQuality,
    ];

    const useCloud = conditions.filter(Boolean).length >= 1;

    const reason = useCloud
      ? `Complexity: ${(imageComplexity * 100).toFixed(1)}%, Network: ${(networkQuality.score * 100).toFixed(1)}%`
      : "Local processing sufficient";

    return {
      useCloud,
      reason,
      estimatedLatency: useCloud ? 2000 : 80,
      estimatedCost: useCloud ? 0.01 : 0,
    };
  }

  private async processLocally(
    request: HybridProcessingRequest,
  ): Promise<TryOnResult | RecommendationResult | SegmentationResult> {
    this.logger.log("Processing locally with Python ML service");

    try {
      if (request.type === "tryon") {
        const response = await this.aiClient.post("/api/tryon", {
          person_image: request.personImage.toString("base64"),
          garment_image: request.garmentImage?.toString("base64"),
          mode: "local",
        });

        if (response.data?.success) {
          return {
            type: "tryon",
            image: response.data.data.result_image,
            score: response.data.data.confidence || 0.85,
          };
        }
      }

      if (request.type === "recommendation") {
        const response = await this.aiClient.post("/api/recommendations", {
          user_id: request.userId,
          context: request.context,
          count: 10,
        });

        if (response.data?.success) {
          return {
            type: "recommendation",
            items: response.data.data.items.map((item: ApiRecommendationItem) => ({
              itemId: item.id,
              score: item.score,
              reasons: item.reasons || [],
            })),
          };
        }
      }
    } catch (error: unknown) {
      this.logger.error(
        `Local hybrid processing failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (this.allowFallbacks) {
        return this.getFallbackResult(request);
      }
      throw new ServiceUnavailableException("Local hybrid processing failed");
    }

    if (this.allowFallbacks) {
      return this.getFallbackResult(request);
    }

    throw new ServiceUnavailableException(
      "Local hybrid processing did not produce a valid result",
    );
  }

  private async processOnCloud(
    request: HybridProcessingRequest,
  ): Promise<TryOnResult | RecommendationResult | SegmentationResult> {
    this.logger.log("Processing on cloud with enhanced AI models");

    try {
      if (request.type === "tryon") {
        const response = await this.aiClient.post("/api/tryon", {
          person_image: request.personImage.toString("base64"),
          garment_image: request.garmentImage?.toString("base64"),
          mode: "cloud",
          enhance: true,
        });

        if (response.data?.success) {
          return {
            type: "tryon",
            image: response.data.data.result_image,
            score: response.data.data.confidence || 0.92,
          };
        }
      }

      if (request.type === "recommendation") {
        const response = await this.aiClient.post(
          "/api/recommendations/advanced",
          {
            user_id: request.userId,
            context: request.context,
            count: 20,
            use_advanced_models: true,
          },
        );

        if (response.data?.success) {
          return {
            type: "recommendation",
            items: response.data.data.items.map((item: ApiRecommendationItem) => ({
              itemId: item.id,
              score: item.score,
              reasons: item.reasons || [],
            })),
          };
        }
      }
    } catch (error: unknown) {
      this.logger.warn(
        `Cloud processing failed, falling back to local: ${error instanceof Error ? error.message : String(error)}`,
      );
      return this.processLocally(request);
    }

    if (this.allowFallbacks) {
      return this.getFallbackResult(request);
    }

    throw new ServiceUnavailableException(
      "Cloud hybrid processing did not produce a valid result",
    );
  }

  private calculateConfidence(
    result: TryOnResult | RecommendationResult | SegmentationResult,
  ): number {
    if (result.type === "tryon") {
      return result.score;
    }
    if (result.type === "recommendation") {
      const scores = result.items.map((i) => i.score);
      return scores.length > 0
        ? scores.reduce((a, b) => a + b, 0) / scores.length
        : 0;
    }
    return 0.8;
  }

  async checkCache(_requestId: string): Promise<boolean> {
    return false;
  }

  async invalidateCache(pattern: string): Promise<void> {
    this.logger.log(`Invalidating cache for pattern: ${pattern}`);
  }

  getStatistics(): {
    totalRequests: number;
    cacheHitRate: number;
    averageLatency: number;
    cloudUsageRate: number;
  } {
    return {
      totalRequests: this.totalRequests,
      cacheHitRate:
        this.totalRequests > 0 ? this.cacheHits / this.totalRequests : 0,
      averageLatency: 500,
      cloudUsageRate: 0.6,
    };
  }

  async prefetchUserData(userId: string): Promise<void> {
    this.logger.log(`Prefetching data for user: ${userId}`);
  }

  async syncUserData(userId: string): Promise<void> {
    this.logger.log(`Syncing data for user: ${userId}`);
  }

  private getFallbackResult(
    request: HybridProcessingRequest,
  ): TryOnResult | RecommendationResult | SegmentationResult {
    if (request.type === "recommendation") {
      return {
        type: "recommendation",
        items: [],
      };
    }

    if (request.type === "segmentation") {
      return {
        type: "segmentation",
        mask: [],
        attributes: {},
      };
    }

    return {
      type: "tryon",
      image: request.personImage.toString("base64"),
      score: 0.5,
    };
  }
}

