@Injectable()
export class StyleUnderstandingService {
  private readonly logger = new Logger(StyleUnderstandingService.name);
  private mlClient!: AxiosInstance;
  private readonly mlServiceUrl: string;

  constructor(private configService: ConfigService) {
    this.mlServiceUrl = this.configService.get<string>(
      "ML_SERVICE_URL",
      "http://localhost:8001",
    );
  }

  async onModuleInit() {
    this.mlClient = axios.create({
      baseURL: this.mlServiceUrl,
      timeout: 60000,
      headers: {
        "Content-Type": "application/json",
      },
    });
  }

  async analyzeStyle(
    userInput: string,
    userProfile?: {
      gender?: string;
      age?: number;
      bodyType?: string;
      stylePreferences?: string[];
    },
  ): Promise<StyleAnalysisResult> {
    try {
      const response = await this.mlClient.post("/api/style/analyze", {
        user_input: userInput,
        user_profile: userProfile,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`风格分析失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackStyleAnalysis(userInput);
    }
  }

  async getStyleSuggestions(
    userInput: string,
    bodyType?: string,
    occasion?: string,
  ): Promise<StyleRecommendationResult> {
    try {
      const response = await this.mlClient.post("/api/style/suggestions", {
        user_input: userInput,
        body_type: bodyType,
        occasion: occasion,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取风格建议失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackSuggestions(userInput);
    }
  }

  async getRecommendations(
    userInput: string,
    options?: {
      userProfile?: Record<string, any>;
      occasion?: string;
      category?: string;
      topK?: number;
    },
  ): Promise<FullRecommendationResult> {
    try {
      const response = await this.mlClient.post("/api/recommendations", {
        user_input: userInput,
        user_profile: options?.userProfile,
        occasion: options?.occasion,
        category: options?.category,
        top_k: options?.topK || 10,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取推荐失败: ${this.getErrorMessage(error)}`);
      return this.getFallbackRecommendations(userInput);
    }
  }

  async getOutfitRecommendation(
    userInput: string,
    options?: {
      userProfile?: Record<string, any>;
      occasion?: string;
    },
  ): Promise<{
    outfit_id: string;
    style_analysis: StyleAnalysisResult;
    items: RecommendationItem[];
    compatibility_score: number;
    total_price?: number;
  }> {
    try {
      const response = await this.mlClient.post("/api/recommendations/outfit", {
        user_input: userInput,
        user_profile: options?.userProfile,
        occasion: options?.occasion,
      });

      return response.data;
    } catch (error) {
      this.logger.error(`获取搭配推荐失败: ${this.getErrorMessage(error)}`);
      return {
        outfit_id: `outfit_${Date.now()}`,
        style_analysis: this.getFallbackStyleAnalysis(userInput),
        items: [],
        compatibility_score: 0,
      };
    }
  }

  quickMatchStyle(userInput: string): { style: string; confidence: number } {
    const styleKeywords: Record<string, string[]> = {
      小红书同款: ["小红书", "网红", "爆款", "种草"],
      法式慵懒: ["法式", "慵懒", "巴黎", "French"],
      韩系: ["韩系", "韩国", "Korean", "韩风"],
      日系: ["日系", "日本", "Japanese", "文艺"],
      街头潮流: ["街头", "潮流", "嘻哈", "streetwear"],
      极简风: ["极简", "简约", "minimalist"],
      复古风: ["复古", "vintage", "怀旧"],
      运动风: ["运动", "健身", "sporty"],
    };

    for (const [style, keywords] of Object.entries(styleKeywords)) {
      for (const keyword of keywords) {
        if (userInput.includes(keyword)) {
          return { style, confidence: 0.9 };
        }
      }
    }

    return { style: "休闲风", confidence: 0.5 };
  }

  private getFallbackStyleAnalysis(userInput: string): StyleAnalysisResult {
    const quickMatch = this.quickMatchStyle(userInput);

    const styleData: Record<string, Partial<StyleAnalysisResult>> = {
      小红书同款: {
        core_elements: ["显瘦", "日常", "拍照好看"],
        key_items: ["白衬衫", "阔腿裤", "针织开衫"],
        color_palette: ["米白", "浅蓝", "卡其"],
        occasions: ["约会", "逛街", "拍照"],
      },
      法式慵懒: {
        core_elements: ["优雅", "随性", "浪漫"],
        key_items: ["条纹衫", "牛仔裤", "芭蕾舞鞋"],
        color_palette: ["海军蓝", "白色", "红色"],
        occasions: ["约会", "咖啡厅", "旅行"],
      },
      韩系: {
        core_elements: ["温柔", "甜美", "年轻"],
        key_items: ["针织背心", "百褶裙", "小白鞋"],
        color_palette: ["粉色", "米色", "浅蓝"],
        occasions: ["约会", "上学", "逛街"],
      },
    };

    const matchedData = styleData[quickMatch.style] || {};

    return {
      style_name: quickMatch.style,
      confidence: quickMatch.confidence,
      core_elements: matchedData.core_elements || ["日常", "舒适"],
      key_items: matchedData.key_items || ["T恤", "牛仔裤"],
      color_palette: matchedData.color_palette || ["白色", "蓝色"],
      patterns: ["纯色"],
      materials: ["棉", "牛仔"],
      occasions: matchedData.occasions || ["日常"],
      seasons: ["春", "秋"],
      body_type_suggestions: {},
      celebrity_references: [],
      brand_references: ["优衣库", "ZARA"],
      price_range: "100-500元",
      similar_styles: ["简约风", "休闲风"],
    };
  }

  private getFallbackSuggestions(userInput: string): StyleRecommendationResult {
    const analysis = this.getFallbackStyleAnalysis(userInput);

    return {
      style_analysis: analysis,
      outfit_suggestions: [
        {
          category: "tops",
          description: `${analysis.style_name}风格上衣`,
          style_tags: analysis.similar_styles,
          color_suggestions: analysis.color_palette.slice(0, 3),
          item_examples: analysis.key_items.slice(0, 2),
          pairing_tips: "选择合身版型，搭配高腰下装",
        },
        {
          category: "bottoms",
          description: `${analysis.style_name}风格下装`,
          style_tags: analysis.similar_styles,
          color_suggestions: analysis.color_palette.slice(0, 3),
          item_examples: ["阔腿裤", "A字裙"],
          pairing_tips: "高腰设计可以优化身材比例",
        },
      ],
      embedding_prompts: [],
      style_weights: {},
    };
  }

  private getFallbackRecommendations(
    userInput: string,
  ): FullRecommendationResult {
    return {
      style_analysis: this.getFallbackStyleAnalysis(userInput),
      recommendations: [],
      total: 0,
    };
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : "Unknown error";
  }
}

import {
  Injectable,
  Logger,
  ServiceUnavailableException,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { allowUnverifiedAiFallbacks } from "../../../common/config/runtime-flags";

export interface SegmentationResult {
  mask: number[][];
  attributes: ClothingAttributes;
  boundingBox: BoundingBox;
  confidence: number;
}

export interface ClothingAttributes {
  category: string;
  subcategory: string;
  colors: string[];
  patterns: string[];
  styles: string[];
  materials: string[];
  sleeveLength: string;
  neckline: string;
  length: string;
  fit: string;
}

export interface BoundingBox {
  x: number;
  y: number;
  width: number;
  height: number;
}

@Injectable()
export class UNetSegmentationService {
  private readonly logger = new Logger(UNetSegmentationService.name);
  private aiClient: AxiosInstance;
  private readonly aiServiceUrl: string;
  private serviceAvailable = false;
  private readonly allowFallbacks: boolean;

  constructor(private configService: ConfigService) {
    this.allowFallbacks = allowUnverifiedAiFallbacks(this.configService);
    this.aiServiceUrl = this.configService.get<string>(
      "AI_SERVICE_URL",
      "http://localhost:8001",
    );

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 60000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkServiceHealth();
  }

  private async checkServiceHealth(): Promise<void> {
    try {
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      if (response.data?.status === "healthy") {
        this.serviceAvailable = true;
        this.logger.log("Python AI Service connected successfully");
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `Python AI Service not available for segmentation (${this.aiServiceUrl}): ${errorMessage}. Will use fallback if enabled.`,
      );
      this.serviceAvailable = false;
    }
  }

  async segmentClothing(imageBuffer: Buffer): Promise<SegmentationResult> {
    this.logger.log("Starting clothing segmentation");

    if (!this.serviceAvailable) {
      if (this.allowFallbacks) {
        return this.segmentWithFallback();
      }

      throw new ServiceUnavailableException(
        "Python AI Service is unavailable for segmentation",
      );
    }

    try {
      return await this.segmentWithPythonService(imageBuffer);
    } catch (error: unknown) {
      this.logger.error(
        `Python segmentation failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (this.allowFallbacks) {
        return this.segmentWithFallback();
      }

      throw new ServiceUnavailableException("Clothing segmentation failed");
    }
  }

  private async segmentWithPythonService(
    imageBuffer: Buffer,
  ): Promise<SegmentationResult> {
    const base64 = imageBuffer.toString("base64");

    const response = await this.aiClient.post("/api/analyze/path", {
      image_base64: base64,
    });

    const data = response.data?.data;
    if (!data || !response.data?.success) {
      throw new Error("Invalid response from AI service");
    }

    const attributes = data.clothing || data;
    const mask = this.extractMask(data);

    if (mask.length === 0 || mask[0]?.length === 0) {
      throw new Error("AI service did not return a valid segmentation mask");
    }

    return {
      mask,
      attributes: {
        category: attributes.category || "tops",
        subcategory: this.inferSubcategory(
          attributes.category,
          attributes.style,
        ),
        colors: attributes.colors || [],
        patterns: this.extractPatterns(attributes),
        styles: attributes.style || [],
        materials: this.extractMaterials(attributes),
        sleeveLength: this.extractSleeveLength(attributes),
        neckline: this.extractNeckline(attributes),
        length: this.extractLength(attributes),
        fit: this.extractFit(attributes),
      },
      boundingBox: this.extractBoundingBox(mask),
      confidence: attributes.confidence || 0.85,
    };
  }

  private segmentWithFallback(): Promise<SegmentationResult> {
    this.logger.debug("Using fallback segmentation (rule-based)");

    const size = 512;
    const mask: number[][] = [];

    for (let y = 0; y < size; y++) {
      const row: number[] = [];
      for (let x = 0; x < size; x++) {
        const inCenter =
          x > size * 0.2 && x < size * 0.8 && y > size * 0.1 && y < size * 0.9;
        row.push(inCenter ? 1 : 0);
      }
      mask.push(row);
    }

    return Promise.resolve({
      mask,
      attributes: {
        category: "tops",
        subcategory: "t_shirt",
        colors: ["black"],
        patterns: ["solid"],
        styles: ["casual"],
        materials: ["cotton"],
        sleeveLength: "short",
        neckline: "round",
        length: "regular",
        fit: "regular",
      },
      boundingBox: {
        x: size * 0.2,
        y: size * 0.1,
        width: size * 0.6,
        height: size * 0.8,
      },
      confidence: 0.5,
    });
  }

  private extractMask(data: unknown): number[][] {
    if (
      typeof data === "object" &&
      data !== null &&
      "mask" in data &&
      Array.isArray((data as { mask?: unknown[] }).mask)
    ) {
      const rawMask = (data as { mask?: unknown[] }).mask || [];
      const normalizedMask = rawMask
        .filter((row): row is unknown[] => Array.isArray(row))
        .map((row) =>
          row.map((value) =>
            typeof value === "number" ? Number(value) : Number(Boolean(value)),
          ),
        );

      if (normalizedMask.length > 0) {
        return normalizedMask;
      }
    }

    return [];
  }

  private inferSubcategory(category: string, styles: string[] = []): string {
    const subcategories: Record<string, string[]> = {
      tops: ["t_shirt", "shirt", "blouse", "sweater", "hoodie"],
      bottoms: ["jeans", "trousers", "shorts", "skirt"],
      dresses: ["mini_dress", "midi_dress", "maxi_dress"],
      outerwear: ["jacket", "coat", "blazer", "cardigan"],
      footwear: ["sneakers", "boots", "heels", "flats"],
      accessories: ["bag", "hat", "scarf", "jewelry"],
    };

    const options = subcategories[category] ?? ["other"];
    return options[0] ?? "other";
  }

  private extractPatterns(attributes: Record<string, unknown>): string[] {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.pattern) {
      const pattern = attrs.pattern as Record<string, unknown>;
      if (pattern.type && typeof pattern.type === 'string') {
        return [pattern.type];
      }
    }
    return ["solid"];
  }

  private extractMaterials(attributes: Record<string, unknown>): string[] {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.material) {
      const material = attrs.material as Record<string, unknown>;
      if (material.type && typeof material.type === 'string') {
        return [material.type];
      }
    }
    return ["cotton"];
  }

  private extractSleeveLength(attributes: Record<string, unknown>): string {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.sleeve) {
      const sleeve = attrs.sleeve as Record<string, unknown>;
      if (sleeve.type && typeof sleeve.type === 'string') {
        return sleeve.type;
      }
    }
    return "short";
  }

  private extractNeckline(attributes: Record<string, unknown>): string {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.neckline) {
      const neckline = attrs.neckline as Record<string, unknown>;
      if (neckline.type && typeof neckline.type === 'string') {
        return neckline.type;
      }
    }
    return "round";
  }

  private extractLength(attributes: Record<string, unknown>): string {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.length) {
      const length = attrs.length as Record<string, unknown>;
      if (length.type && typeof length.type === 'string') {
        return length.type;
      }
    }
    return "regular";
  }

  private extractFit(attributes: Record<string, unknown>): string {
    const attrs = attributes.attributes as Record<string, unknown> | undefined;
    if (attrs?.fit) {
      const fit = attrs.fit as Record<string, unknown>;
      if (fit.type && typeof fit.type === 'string') {
        return fit.type;
      }
    }
    return "regular";
  }

  private extractBoundingBox(mask: number[][]): BoundingBox {
    const height = mask.length;
    const width = mask[0]?.length || 0;

    let minX = width,
      maxX = 0,
      minY = height,
      maxY = 0;

    for (let y = 0; y < height; y++) {
      for (let x = 0; x < width; x++) {
        const row = mask[y];
        if ((row?.[x] ?? 0) > 0) {
          minX = Math.min(minX, x);
          maxX = Math.max(maxX, x);
          minY = Math.min(minY, y);
          maxY = Math.max(maxY, y);
        }
      }
    }

    return {
      x: minX === width ? 0 : minX,
      y: minY === height ? 0 : minY,
      width: maxX - minX || width,
      height: maxY - minY || height,
    };
  }

  async extractFeatureVector(imageBuffer: Buffer): Promise<number[]> {
    if (this.serviceAvailable) {
      try {
        const base64 = imageBuffer.toString("base64");
        const response = await this.aiClient.post("/api/analyze/path", {
          image_base64: base64,
        });

        const embedding = response.data?.data?.embedding;
        if (embedding && Array.isArray(embedding)) {
          return embedding;
        }
      } catch (error: unknown) {
        this.logger.error(
          `Failed to extract embedding: ${error instanceof Error ? error.message : String(error)}`,
        );
      }
    }

    if (this.allowFallbacks) {
      return this.generateDeterministicVector(imageBuffer.toString("base64"));
    }

    throw new ServiceUnavailableException(
      "AI embedding service is unavailable for segmentation features",
    );
  }

  async batchSegment(imageBuffers: Buffer[]): Promise<SegmentationResult[]> {
    return Promise.all(
      imageBuffers.map((buffer) => this.segmentClothing(buffer)),
    );
  }

  isServiceAvailable(): boolean {
    return this.serviceAvailable;
  }

  private generateDeterministicVector(seed: string): number[] {
    const vectorSize = 512;
    const vector: number[] = [];
    let current = this.simpleHash(seed);

    for (let i = 0; i < vectorSize; i++) {
      current = (current * 1103515245 + 12345) % 2147483648;
      vector.push(((current % 2000) - 1000) / 1000);
    }

    const norm = Math.sqrt(
      vector.reduce((sum, value) => sum + value * value, 0),
    );
    return norm === 0 ? vector : vector.map((value) => value / norm);
  }

  private simpleHash(value: string): number {
    let hash = 0;
    for (let i = 0; i < value.length; i++) {
      hash = (hash << 5) - hash + value.charCodeAt(i);
      hash = hash & hash;
    }

    return Math.abs(hash);
  }
}

import { ApiProperty, ApiPropertyOptional } from "@nestjs/swagger";
import { IsObject, IsArray, IsString, IsNumber, IsDateString, IsOptional } from "class-validator";

export class BehaviorProfileDto {
  @ApiProperty({ description: "用户偏好", type: Object })
