import { Module, forwardRef } from "@nestjs/common";

import { BrandsModule } from "../brands.module";
import { BrandsService } from "../brands.service";

import { BrandPortalController } from "./brand-portal.controller";
import { BrandPortalService } from "./brand-portal.service";

@Module({
  imports: [forwardRef(() => BrandsModule)],
  controllers: [BrandPortalController],
  providers: [BrandPortalService, BrandsService],
  exports: [BrandPortalService],
})
export class BrandPortalModule {}

import { Controller, Get, Post, Patch, Param, Query, Body, UseGuards, Request } from "@nestjs/common";
import { ApiTags, ApiOperation, ApiResponse, ApiQuery, ApiParam, ApiBearerAuth } from "@nestjs/swagger";
import { ClothingCategory, PriceRange } from "@prisma/client";

import { MerchantAuthGuard } from "../merchant/guards/merchant-auth.guard";

import { BrandsService } from "./brands.service";
import { GenerateQRCodeDto, BatchGenerateQRCodeDto } from "./dto/qr-code.dto";

@ApiTags("brands")
@Controller("brands")
export class BrandsController {
  constructor(private brandsService: BrandsService) {}

  @Get()
  @ApiOperation({ summary: "获取所有品牌列表" })
  @ApiResponse({ status: 200, description: "获取成功" })
  @ApiQuery({ name: "category", enum: ClothingCategory, required: false })
  @ApiQuery({ name: "priceRange", enum: PriceRange, required: false })
  @ApiQuery({ name: "page", type: Number, required: false })
  @ApiQuery({ name: "limit", type: Number, required: false })
  async getAllBrands(
    @Query("category") category?: ClothingCategory,
    @Query("priceRange") priceRange?: PriceRange,
    @Query("page") page?: string,
    @Query("limit") limit?: string,
  ) {
    return this.brandsService.getAllBrands({
      category,
      priceRange,
      page: page ? parseInt(page, 10) : 1,
      limit: limit ? parseInt(limit, 10) : 20,
    });
  }

  @Get("featured")
  @ApiOperation({ summary: "获取推荐品牌" })
  @ApiResponse({ status: 200, description: "获取成功" })
  @ApiQuery({ name: "limit", type: Number, required: false })
  async getFeaturedBrands(@Query("limit") limit?: string) {
    return this.brandsService.getFeaturedBrands(
      limit ? parseInt(limit, 10) : 10,
    );
  }

  @Get("price-ranges")
  @ApiOperation({ summary: "获取价格区间统计" })
  @ApiResponse({ status: 200, description: "获取成功" })
  async getPriceRangeStats() {
    return this.brandsService.getPriceRangeStats();
  }

  @Get("category/:category")
  @ApiOperation({ summary: "按分类获取品牌" })
  @ApiResponse({ status: 200, description: "获取成功" })
  @ApiParam({ name: "category", enum: ClothingCategory, description: "服装分类" })
  async getBrandsByCategory(@Param("category") category: ClothingCategory) {
    return this.brandsService.getBrandsByCategory(category);
  }

  // ==================== QR Code Scan (Public) ====================

  @Get("qr-codes/:code")
  @ApiOperation({ summary: "扫码获取商品信息（公开）", description: "扫描品牌二维码获取关联的商品数据，无需认证" })
  @ApiParam({ name: "code", description: "二维码编码" })
  @ApiResponse({ status: 200, description: "商品信息" })
  @ApiResponse({ status: 404, description: "二维码不存在" })
  async scanQRCode(
    @Param("code") code: string,
  ) {
    const qrCode = await this.brandsService.getQRCodeByCode(code);
    if (!qrCode?.isActive) {
      return { success: false, error: "二维码无效或已停用" };
    }
    return {
      success: true,
      brand: qrCode.brand,
      product: qrCode.payload,
      qrCodeId: qrCode.id,
    };
  }

  @Post("qr-codes/:code/scan")
  @ApiOperation({ summary: "记录扫码并导入衣橱", description: "记录扫码事件，已登录用户可自动导入到衣橱" })
  @ApiParam({ name: "code", description: "二维码编码" })
  @ApiResponse({ status: 200, description: "扫码成功" })
  async recordScanAndImport(
    @Param("code") code: string,
    @Body() body: { userId?: string; platform?: string },
  ) {
    const qrCode = await this.brandsService.getQRCodeByCode(code);
    if (!qrCode?.isActive) {
      return { success: false, error: "二维码无效或已停用" };
    }

    await this.brandsService.recordScan(qrCode.id, body.userId, body.platform);

    return {
      success: true,
      imported: !!body.userId,
      product: qrCode.payload,
    };
  }

  // ==================== QR Code Management (Merchant Auth) ====================

  @Post("qr-codes")
  @UseGuards(MerchantAuthGuard)
  @ApiBearerAuth()
  @ApiOperation({ summary: "生成品牌二维码（商家）", description: "为品牌商品生成专属二维码" })
  @ApiResponse({ status: 201, description: "二维码生成成功" })
  async generateQRCode(
    @Request() req: { merchant: { brandId: string } },
    @Body() dto: GenerateQRCodeDto,
  ) {
    return this.brandsService.generateQRCode(req.merchant.brandId, dto.productId, {
      productName: dto.productName,
      sku: dto.sku,
      color: dto.color,
      size: dto.size,
      material: dto.material,
      price: dto.price,
    });
  }

  @Get("manage/qr-codes")
  @UseGuards(MerchantAuthGuard)
  @ApiBearerAuth()
  @ApiOperation({ summary: "获取品牌二维码列表（商家）" })
  @ApiQuery({ name: "page", type: Number, required: false })
  @ApiQuery({ name: "limit", type: Number, required: false })
  async getBrandQRCodes(
    @Request() req: { merchant: { brandId: string } },
    @Query("page") page?: string,
    @Query("limit") limit?: string,
  ) {
    return this.brandsService.getBrandQRCodes(
      req.merchant.brandId,
      page ? parseInt(page, 10) : 1,
      limit ? parseInt(limit, 10) : 20,
    );
  }

  @Patch("manage/qr-codes/:id/deactivate")
  @UseGuards(MerchantAuthGuard)
  @ApiBearerAuth()
  @ApiOperation({ summary: "停用二维码（商家）" })
  @ApiParam({ name: "id", description: "二维码ID" })
  async deactivateQRCode(
    @Request() req: { merchant: { brandId: string } },
    @Param("id") qrCodeId: string,
  ) {
    return this.brandsService.deactivateQRCode(qrCodeId, req.merchant.brandId);
  }

  @Get(":slug")
  @ApiOperation({ summary: "获取品牌详情" })
  @ApiResponse({ status: 200, description: "获取成功" })
  @ApiResponse({ status: 404, description: "品牌不存在" })
  @ApiParam({ name: "slug", description: "品牌标识" })
  async getBrandBySlug(@Param("slug") slug: string) {
    return this.brandsService.getBrandBySlug(slug);
  }

  @Get(":slug/products")
  @ApiOperation({ summary: "获取品牌商品" })
  @ApiQuery({ name: "category", enum: ClothingCategory, required: false })
  @ApiQuery({ name: "minPrice", type: Number, required: false })
  @ApiQuery({ name: "maxPrice", type: Number, required: false })
  @ApiQuery({
    name: "sortBy",
    enum: ["price", "createdAt", "viewCount"],
    required: false,
  })
  @ApiQuery({ name: "sortOrder", enum: ["asc", "desc"], required: false })
  @ApiQuery({ name: "page", type: Number, required: false })
  @ApiQuery({ name: "limit", type: Number, required: false })
  async getBrandProducts(
    @Param("slug") slug: string,
    @Query("category") category?: ClothingCategory,
    @Query("minPrice") minPrice?: string,
    @Query("maxPrice") maxPrice?: string,
    @Query("sortBy") sortBy?: "price" | "createdAt" | "viewCount",
    @Query("sortOrder") sortOrder?: "asc" | "desc",
    @Query("page") page?: string,
    @Query("limit") limit?: string,
  ) {
    return this.brandsService.getBrandProducts(slug, {
      category,
      minPrice: minPrice ? parseFloat(minPrice) : undefined,
      maxPrice: maxPrice ? parseFloat(maxPrice) : undefined,
      sortBy,
      sortOrder,
      page: page ? parseInt(page, 10) : 1,
      limit: limit ? parseInt(limit, 10) : 20,
    });
  }
}

import { Module, forwardRef } from "@nestjs/common";

import { EncryptionModule } from "../../common/encryption/encryption.module";
import { PrismaModule } from "../../common/prisma/prisma.module";

import { BrandPortalModule } from "./brand-portal/brand-portal.module";
import { BrandsController } from "./brands.controller";
import { BrandsService } from "./brands.service";

@Module({
  imports: [
    PrismaModule,
    EncryptionModule,
    forwardRef(() => BrandPortalModule),
  ],
  controllers: [BrandsController],
  providers: [BrandsService],
  exports: [BrandsService],
})
export class BrandsModule {}

import { Test, TestingModule } from "@nestjs/testing";
import { PriceRange, ClothingCategory } from "@prisma/client";

import { EncryptionService } from "../../common/encryption/encryption.service";
import { PrismaService } from "../../common/prisma/prisma.service";

import { BrandsService } from "./brands.service";

describe("BrandsService", () => {
  let service: BrandsService;
  let prisma: PrismaService;

  const mockPrismaService = {
    brand: {
      findMany: jest.fn(),
      findUnique: jest.fn(),
      count: jest.fn(),
      groupBy: jest.fn(),
      create: jest.fn(),
      update: jest.fn(),
    },
    clothingItem: {
      findMany: jest.fn(),
      count: jest.fn(),
    },
    brandMerchant: {
      findFirst: jest.fn(),
    },
  };

  const mockEncryptionService = {
    encrypt: jest.fn((value: string) => `enc:${value}`),
    decrypt: jest.fn((value: string) => value.replace(/^enc:/, "")),
    hash: jest.fn((value: string) => `hash:${value}`),
    verifyHash: jest.fn((value: string, hash: string) => hash === `hash:${value}`),
    isEncrypted: jest.fn((value: string) => value?.startsWith("enc:")),
  };

  const mockBrand = {
    id: "brand-id",
    name: "测试品牌",
    slug: "test-brand",
    logo: "https://example.com/logo.jpg",
    description: "这是一个测试品牌",
    website: "https://example.com",
    categories: [ClothingCategory.tops],
    priceRange: PriceRange.mid_range,
    isActive: true,
    _count: { products: 10 },
  };

  const mockClothingItem = {
    id: "item-id",
    name: "测试商品",
    price: 199,
    brandId: "brand-id",
    isActive: true,
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        BrandsService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: EncryptionService,
          useValue: mockEncryptionService,
        },
      ],
    }).compile();

    service = module.get<BrandsService>(BrandsService);
    prisma = module.get<PrismaService>(PrismaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe("getAllBrands", () => {
    it("应该返回品牌列表", async () => {
      mockPrismaService.brand.findMany.mockResolvedValue([mockBrand]);
      mockPrismaService.brand.count.mockResolvedValue(1);

      const result = await service.getAllBrands();
      const firstItem = result.items[0];

      expect(result.items).toHaveLength(1);
      expect(firstItem?.name).toBe("测试品牌");
      expect(firstItem?.productCount).toBe(10);
      expect(result.total).toBe(1);
    });

    it("应该按价格范围过滤", async () => {
      mockPrismaService.brand.findMany.mockResolvedValue([]);
      mockPrismaService.brand.count.mockResolvedValue(0);

      await service.getAllBrands({ priceRange: PriceRange.luxury });

      expect(mockPrismaService.brand.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({
            priceRange: PriceRange.luxury,
          }),
        }),
      );
    });

    it("应该按分类过滤", async () => {
      mockPrismaService.brand.findMany.mockResolvedValue([]);
      mockPrismaService.brand.count.mockResolvedValue(0);

      await service.getAllBrands({ category: ClothingCategory.tops });

      expect(mockPrismaService.brand.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({
            categories: { has: ClothingCategory.tops },
          }),
        }),
      );
    });

    it("应该支持分页", async () => {
      mockPrismaService.brand.findMany.mockResolvedValue([]);
      mockPrismaService.brand.count.mockResolvedValue(50);

      const result = await service.getAllBrands({ page: 2, limit: 10 });

      expect(result.page).toBe(2);
      expect(result.limit).toBe(10);
      expect(result.totalPages).toBe(5);
    });
  });

  describe("getBrandBySlug", () => {
    it("应该返回品牌详情", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(mockBrand);

      const result = await service.getBrandBySlug("test-brand");

      expect(result).not.toBeNull();
      expect(result?.slug).toBe("test-brand");
      expect(result?.productCount).toBe(10);
    });

    it("应该返回 null 当品牌不存在", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(null);

      const result = await service.getBrandBySlug("non-existent");

      expect(result).toBeNull();
    });
  });

  describe("getBrandProducts", () => {
    it("应该返回品牌商品列表", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(mockBrand);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        mockClothingItem,
      ]);
      mockPrismaService.clothingItem.count.mockResolvedValue(1);

      const result = await service.getBrandProducts("test-brand");

      expect(result).not.toBeNull();
      expect(result?.brand.name).toBe("测试品牌");
      expect(result?.items).toHaveLength(1);
    });

    it("应该返回 null 当品牌不存在", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(null);

      const result = await service.getBrandProducts("non-existent");

      expect(result).toBeNull();
    });

    it("应该按价格范围过滤", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(mockBrand);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([]);
      mockPrismaService.clothingItem.count.mockResolvedValue(0);

      await service.getBrandProducts("test-brand", {
        minPrice: 100,
        maxPrice: 500,
      });

      expect(mockPrismaService.clothingItem.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({
            price: { gte: 100, lte: 500 },
          }),
        }),
      );
    });

    it("应该支持排序", async () => {
      mockPrismaService.brand.findUnique.mockResolvedValue(mockBrand);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([]);
      mockPrismaService.clothingItem.count.mockResolvedValue(0);

      await service.getBrandProducts("test-brand", {
        sortBy: "price",
        sortOrder: "asc",
      });

