import { StorageModule } from '../../common/storage/storage.module';
import { AdminCommunityController } from '../admin/admin-community.controller';
import { QueueModule } from '../queue/queue.module';

import { CommunityController } from './community.controller';
import { CommunityService } from './community.service';
import { ContentModerationService, CONTENT_MODERATION_QUEUE } from './content-moderation.service';


@Module({
  imports: [
    PrismaModule,
    StorageModule,
    RedisModule,
    forwardRef(() => QueueModule),
    BullModule.registerQueue({ name: CONTENT_MODERATION_QUEUE }),
  ],
  controllers: [CommunityController, AdminCommunityController],
  providers: [CommunityService, ContentModerationService],
  exports: [CommunityService, ContentModerationService],
})
export class CommunityModule {}

import { Injectable, Logger, NotFoundException, ConflictException, ForbiddenException, Inject, Optional } from "@nestjs/common";
import { Cron } from "@nestjs/schedule";
import { Prisma } from "@prisma/client";
import Redis from "ioredis";

import { PrismaService } from "../../common/prisma/prisma.service";
import { REDIS_CLIENT, RedisKeyBuilder } from "../../common/redis/redis.service";
import { StorageService } from "../../common/storage/storage.service";

import { ContentModerationService } from "./content-moderation.service";
import {
  CreatePostDto,
  UpdatePostDto,
  PostQueryDto,
  CreateCommentDto,
  LikePostDto,
  BookmarkPostDto,
  CreateReportDto,
  ReportQueryDto,
  TrendingQueryDto,
} from "./dto/community.dto";

@Injectable()
export class CommunityService {
  private readonly logger = new Logger(CommunityService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly storage: StorageService,
    @Inject(REDIS_CLIENT) private readonly redis: Redis,
    @Optional() private readonly contentModerationService: ContentModerationService,
  ) {}

  async createPost(userId: string, dto: CreatePostDto) {
    const post = await this.prisma.communityPost.create({
      data: {
        authorId: userId,
        title: dto.title,
        content: dto.content,
        images: dto.images || [],
        tags: dto.tags || [],
        category: dto.category,
      },
      include: {
        author: {
          select: {
            id: true,
            nickname: true,
            avatar: true,
          },
        },
        _count: {
          select: {
            likes: true,
            comments: true,
          },
        },
      },
    });

    if (dto.relatedItemIds && dto.relatedItemIds.length > 0) {
      await this.prisma.communityPostItem.createMany({
        data: dto.relatedItemIds.map((itemId) => ({
          postId: post.id,
          itemId,
        })),
        skipDuplicates: true,
      });
    }

    await this.prisma.userBehaviorEvent.create({
      data: {
        userId,
        sessionId: "default",
        eventType: "post_create",
        category: "community",
        action: "create",
        targetType: "community_post",
        targetId: post.id,
        metadata: { category: dto.category },
      },
    });

    if (this.contentModerationService) {
      await this.contentModerationService.moderateContent(
        'post',
        post.id,
        post.content,
        post.images as string[] | undefined,
      ).catch((err) => {
        this.logger.warn(`Content moderation failed for post ${post.id}: ${err.message}`);
      });
    }

    return post;
  }

  async getPosts(query: PostQueryDto, userId?: string, adminMode = false) {
    const {
      page = 1,
      pageSize = 20,
      category,
      tags,
      authorId,
      sortBy = "latest",
    } = query;

    const where: Prisma.CommunityPostWhereInput = { isDeleted: false };

    if (!adminMode) {
      where.moderationStatus = "approved";
    }

    if (category) {
      where.category = category;
    }

    if (tags && tags.length > 0) {
      where.tags = { hasSome: tags };
    }

    if (authorId) {
      where.authorId = authorId;
    }

    let orderBy: Prisma.CommunityPostOrderByWithRelationInput | Prisma.CommunityPostOrderByWithRelationInput[] = { createdAt: "desc" };

    switch (sortBy) {
      case "popular":
        orderBy = [{ likeCount: "desc" }, { viewCount: "desc" }];
        break;
      case "trending":
        orderBy = [
          { commentCount: "desc" },
          { likeCount: "desc" },
          { createdAt: "desc" },
        ];
        break;
      case "latest":
      default:
        orderBy = { createdAt: "desc" };
    }

    if (sortBy === "trending") {
      const cached = await this.redis.get("community:trending");
      if (cached) {
        const trendingIds = (JSON.parse(cached) as Array<{ id: string }>).map((p) => p.id);
        if (trendingIds.length > 0) {
          const skip = (page - 1) * pageSize;
          const pagedIds = trendingIds.slice(skip, skip + pageSize);
          if (pagedIds.length > 0) {
            const posts = await this.prisma.communityPost.findMany({
              where: { id: { in: pagedIds }, ...where },
              include: {
                author: {
                  select: { id: true, nickname: true, avatar: true },
                },
                relatedItems: {
                  select: {
                    item: {
                      select: { id: true, name: true, mainImage: true, price: true },
                    },
                  },
                  take: 3,
                },
                _count: {
                  select: { likes: true, comments: true },
                },
              },
            });

            const sortedPosts = pagedIds
              .map((id) => posts.find((p) => p.id === id))
              .filter(Boolean);

            const bookmarkedIds = userId
              ? (
                  await this.prisma.postBookmark.findMany({
                    where: { userId, postId: { in: pagedIds } },
                    select: { postId: true },
                  })
                ).map((b) => b.postId)
              : [];

            return {
              data: sortedPosts.map((post) => ({
                ...post!,
                relatedItems: post!.relatedItems.map((ri) => ri.item),
                isBookmarked: bookmarkedIds.includes(post!.id),
              })),
              meta: {
                total: trendingIds.length,
                page,
                pageSize,
                totalPages: Math.ceil(trendingIds.length / pageSize),
              },
            };
          }
        }
      }
    }

    const [posts, total] = await Promise.all([
      this.prisma.communityPost.findMany({
        where,
        orderBy,
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          author: {
            select: {
              id: true,
              nickname: true,
              avatar: true,
            },
          },
          relatedItems: {
            select: {
              item: {
                select: {
                  id: true,
                  name: true,
                  mainImage: true,
                  price: true,
                },
              },
            },
            take: 3,
          },
          _count: {
            select: {
              likes: true,
              comments: true,
            },
          },
        },
      }),
      this.prisma.communityPost.count({ where }),
    ]);

    const postIds = posts.map((p) => p.id);
    const bookmarkedIds = userId
      ? (
          await this.prisma.postBookmark.findMany({
            where: { userId, postId: { in: postIds } },
            select: { postId: true },
          })
        ).map((b) => b.postId)
      : [];

    return {
      data: posts.map((post) => ({
        ...post,
        relatedItems: post.relatedItems.map((ri) => ri.item),
        isBookmarked: bookmarkedIds.includes(post.id),
      })),
      meta: {
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      },
    };
  }

  async getPostById(postId: string, userId?: string, adminMode = false) {
    const post = await this.prisma.communityPost.findUnique({
      where: { id: postId },
      include: {
        author: {
          select: {
            id: true,
            nickname: true,
            avatar: true,
            bio: true,
            followerCount: true,
            isVerified: true,
          },
        },
        relatedItems: {
          select: {
            item: {
              select: {
                id: true,
                name: true,
                mainImage: true,
                price: true,
                brand: {
                  select: { name: true },
                },
              },
            },
          },
        },
        _count: {
          select: {
            likes: true,
            comments: true,
          },
        },
      },
    });

    if (!post) {
      throw new NotFoundException("帖子不存在");
    }

    if (post.isDeleted) {
      throw new NotFoundException("帖子不存在");
    }

    if (!adminMode && post.moderationStatus !== "approved") {
      throw new NotFoundException("帖子不存在");
    }

    await this.prisma.communityPost.update({
      where: { id: postId },
      data: { viewCount: { increment: 1 } },
    });

    let isLiked = false;
    let isFollowing = false;
    let isBookmarked = false;

    if (userId) {
      const likeRecord = await this.prisma.postLike.findUnique({
        where: {
          userId_postId: { userId, postId },
        },
      });
      isLiked = !!likeRecord;

      const followRecord = await this.prisma.userFollow.findUnique({
        where: {
          followerId_followingId: {
            followerId: userId,
            followingId: post.authorId,
          },
        },
      });
      isFollowing = !!followRecord;

      const bookmarkRecord = await this.prisma.postBookmark.findUnique({
        where: { userId_postId: { userId, postId } },
      });
      isBookmarked = !!bookmarkRecord;
    }

    const relatedItems = (post as any).relatedItems?.map((ri: any) => ri.item) ?? [];

    return {
      ...post,
      relatedItems,
      isLiked,
      isFollowing,
      isBookmarked,
    };
  }

  async updatePost(userId: string, postId: string, dto: UpdatePostDto) {
    const existingPost = await this.prisma.communityPost.findFirst({
      where: { id: postId, authorId: userId, isDeleted: false },
    });

    if (!existingPost) {
      throw new NotFoundException("帖子不存在或无权编辑");
    }

    return this.prisma.communityPost.update({
      where: { id: postId },
      data: {
        title: dto.title,
        content: dto.content,
        images: dto.images,
        tags: dto.tags,
        category: dto.category,
      },
      include: {
        author: {
          select: {
            id: true,
            nickname: true,
            avatar: true,
          },
        },
      },
    });
  }

  async deletePost(userId: string, postId: string) {
    const existingPost = await this.prisma.communityPost.findFirst({
      where: { id: postId, authorId: userId, isDeleted: false },
    });

    if (!existingPost) {
      throw new NotFoundException("帖子不存在或无权删除");
    }

    await this.prisma.communityPost.update({
      where: { id: postId },
      data: { isDeleted: true, deletedAt: new Date() },
    });

    return { success: true };
  }

  async likePost(userId: string, postId: string) {
    return this.prisma.$transaction(async (tx) => {
      const existingLike = await tx.postLike.findUnique({
        where: {
          userId_postId: { userId, postId },
        },
      });

      if (existingLike) {
        await tx.postLike.delete({
          where: {
            userId_postId: { userId, postId },
          },
        });

        await tx.communityPost.update({
          where: { id: postId },
          data: { likeCount: { decrement: 1 } },
        });

        this.logger.debug(`User ${userId} unliked post ${postId}`);
        return { liked: false };
      } else {
        const post = await tx.communityPost.findUnique({
          where: { id: postId },
          select: { authorId: true },
        });

        if (!post) {
          throw new NotFoundException("帖子不存在");
        }

        await tx.postLike.create({
          data: { userId, postId },
        });

        await tx.communityPost.update({
          where: { id: postId },
          data: { likeCount: { increment: 1 } },
        });

        if (post.authorId !== userId) {
          await tx.notification.create({
            data: {
              userId: post.authorId,
              type: "like",
              title: "收到新的点赞",
              content: "有人赞了你的帖子",
              data: { postId, likerId: userId },
            },
          });
        }

        this.logger.debug(`User ${userId} liked post ${postId}`);
        return { liked: true };
      }
    });
  }

  async createComment(userId: string, postId: string, dto: CreateCommentDto) {
    const post = await this.prisma.communityPost.findUnique({
      where: { id: postId, isDeleted: false },
    });

    if (!post) {
      throw new NotFoundException("帖子不存在");
    }

    const comment = await this.prisma.postComment.create({
      data: {
        authorId: userId,
        postId,
        parentId: dto.parentId,
        content: dto.content,
        images: dto.images || [],
      },
      include: {
        author: {
          select: {
            id: true,
            nickname: true,
            avatar: true,
          },
        },
      },
    });

    await this.prisma.communityPost.update({
      where: { id: postId },
      data: { commentCount: { increment: 1 } },
    });

    if (dto.parentId) {
      const parentComment = await this.prisma.postComment.findUnique({
        where: { id: dto.parentId },
      });
      if (parentComment && parentComment.authorId !== userId) {
        await this.prisma.notification.create({
          data: {
            userId: parentComment.authorId,
            type: "comment",
            title: "收到新的回复",
            content: dto.content.substring(0, 50),
            data: { postId, commentId: comment.id },
          },
        });
      }
    } else if (post.authorId !== userId) {
      await this.prisma.notification.create({
        data: {
          userId: post.authorId,
          type: "comment",
          title: "收到新的评论",
          content: dto.content.substring(0, 50),
          data: { postId, commentId: comment.id },
        },
      });
    }

    if (this.contentModerationService) {
      await this.contentModerationService.moderateContent(
        'comment',
        comment.id,
        dto.content,
      ).catch((err) => {
        this.logger.warn(`Content moderation failed for comment ${comment.id}: ${err.message}`);
      });
    }

    return comment;
  }

  async getComments(postId: string, page = 1, pageSize = 20, repliesLimit = 2) {
    const [comments, total] = await Promise.all([
      this.prisma.postComment.findMany({
        where: { postId, parentId: null, isDeleted: false },
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          author: {
            select: {
              id: true,
              nickname: true,
              avatar: true,
            },
          },
          replies: {
            where: { isDeleted: false },
            take: repliesLimit,
            orderBy: { createdAt: "asc" },
            include: {
              author: {
                select: {
                  id: true,
                  nickname: true,
                  avatar: true,
                },
              },
            },
          },
          _count: {
            select: { replies: true },
          },
