  @ApiBody({ type: CalculateQuoteDto })
  @ApiResponse({ status: 200, description: "报价计算成功" })
  @ApiResponse({ status: 404, description: "设计不存在" })
  async calculateQuote(
    @CurrentUser("id") userId: string,
    @Param("id") designId: string,
