  // ==================== Original CRUD Endpoints ====================

  @Post()
  @ApiOperation({ summary: "创建定制需求", description: "创建新的服装定制需求，支持指定定制类型、描述和参考图片。" })
  @ApiBody({
    schema: {
      type: "object",
      properties: {
        type: { type: "string", enum: ["ALTERATION", "CUSTOM_MADE", "BESPOKE"], description: "定制类型" },
        title: { type: "string", description: "定制需求标题" },
        description: { type: "string", description: "定制需求详细描述" },
        referenceImages: { type: "array", items: { type: "string" }, description: "参考图片URL列表" },
        preferences: { type: "object", description: "定制偏好设置" },
      },
      required: ["type", "description"],
    },
  })
  @ApiResponse({ status: 201, description: "定制需求创建成功" })
  @ApiResponse({ status: 400, description: "请求参数错误" })
  async createRequest(
    @CurrentUser("id") userId: string,
    @Body()
    body: {
      type: CustomizationType;
      title?: string;
      description: string;
      referenceImages?: string[];
      preferences?: Record<string, any>;
    },
  ) {
    return this.customizationService.createRequest(userId, body);
  }

  @Post(":id/submit")
  @ApiOperation({ summary: "提交定制需求", description: "将草稿状态的定制需求提交审核。" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  @ApiResponse({ status: 200, description: "提交成功" })
  async submitRequest(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
  ) {
    return this.customizationService.submitRequest(requestId, userId);
  }

  @Get()
  @ApiOperation({ summary: "获取定制需求列表", description: "获取当前用户的定制需求列表，支持按状态筛选和分页。" })
  @ApiQuery({ name: "status", required: false, enum: CustomizationStatus, description: "按状态筛选" })
  @ApiQuery({ name: "page", required: false, type: Number, description: "页码" })
  @ApiQuery({ name: "limit", required: false, type: Number, description: "每页数量" })
  async getRequests(
    @CurrentUser("id") userId: string,
    @Query("status") status?: CustomizationStatus,
    @Query("page") page?: string,
    @Query("limit") limit?: string,
  ) {
    return this.customizationService.getUserRequests(
      userId,
      status,
      page ? parseInt(page, 10) : 1,
      limit ? parseInt(limit, 10) : 10,
    );
  }

  @Get(":id")
  @ApiOperation({ summary: "获取定制需求详情", description: "根据ID获取定制需求的详细信息。" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async getRequestById(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
  ) {
    return this.customizationService.getRequestById(requestId, userId);
  }

  @Put(":id")
  @ApiOperation({ summary: "更新定制需求", description: "更新草稿状态的定制需求信息。" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async updateRequest(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
    @Body()
    body: {
      title?: string;
      description?: string;
      referenceImages?: string[];
      preferences?: Record<string, any>;
    },
  ) {
    return this.customizationService.updateRequest(requestId, userId, body);
  }

  @Post(":id/select-quote")
  @ApiOperation({ summary: "选择报价", description: "从定制需求的报价列表中选择一个报价。" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async selectQuote(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
    @Body() body: { quoteId: string },
  ) {
    return this.customizationService.selectQuote(
      requestId,
      userId,
      body.quoteId,
    );
  }

  @Post(":id/cancel")
  @ApiOperation({ summary: "取消定制需求", description: "取消指定的定制需求。" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async cancelRequest(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
  ) {
    return this.customizationService.cancelRequest(requestId, userId);
  }

  // ==================== Payment + Production ====================

  @Post(":id/pay")
  @ApiOperation({ summary: "定制需求付款", description: "为已确认的定制需求发起支付" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  @ApiBody({
    schema: {
      type: "object",
      properties: {
        paymentMethod: { type: "string", description: "支付方式 (alipay/wechat)" },
      },
      required: ["paymentMethod"],
    },
  })
  async payForCustomization(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
    @Body() body: { paymentMethod: string },
  ) {
    const payResult = await this.customizationService.confirmAndPay(
      requestId,
      userId,
      body.paymentMethod,
    );

    // Simulate payment callback success
    await this.customizationService.handlePaymentCallback(requestId, {
      success: true,
      paymentId: payResult.paymentId,
    });

    return payResult;
  }

  @Get(":id/production-status")
  @ApiOperation({ summary: "获取生产状态", description: "查询定制商品的生产和物流状态" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async getProductionStatus(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
  ) {
    return this.customizationService.getProductionStatus(requestId, userId);
  }

  @Post(":id/confirm-delivery")
  @ApiOperation({ summary: "确认收货", description: "用户确认收到定制商品" })
  @ApiParam({ name: "id", description: "定制需求ID", type: String, format: "uuid" })
  async confirmDelivery(
    @CurrentUser("id") userId: string,
    @Param("id") requestId: string,
  ) {
    return this.customizationService.confirmDelivery(requestId, userId);
  }
}

import { NotFoundException, BadRequestException } from "@nestjs/common";
import { Test, TestingModule } from "@nestjs/testing";
import { CustomizationType, CustomizationStatus, ProductTemplateType } from "@prisma/client";

import { PrismaService } from "../../common/prisma/prisma.service";

import { CustomizationService } from "./customization.service";
import { PODService } from "./pod/pod-service";

describe("CustomizationService", () => {
  let service: CustomizationService;
  let prisma: PrismaService;

  const mockPrismaService = {
    customizationRequest: {
      create: jest.fn(),
      findFirst: jest.fn(),
      findUnique: jest.fn(),
      findMany: jest.fn(),
      update: jest.fn(),
      count: jest.fn(),
    },
    customizationQuote: {
      findUnique: jest.fn(),
      create: jest.fn(),
      update: jest.fn(),
    },
    customizationDesign: {
      create: jest.fn(),
      findFirst: jest.fn(),
      update: jest.fn(),
    },
    customizationDesignLayer: {
      deleteMany: jest.fn(),
      createMany: jest.fn(),
    },
    customizationTemplate: {
      findUnique: jest.fn(),
    },
  };

  const mockPODService = {
    submitToProduction: jest.fn(),
    checkProductionStatus: jest.fn(),
  };

  const mockRequest = {
    id: "request-id",
    userId: "test-user-id",
    type: CustomizationType.tailored,
    title: "测试定制需求",
    description: "这是一个测试定制需求",
    referenceImages: ["https://example.com/img1.jpg"],
    preferences: { color: "blue", style: "casual" },
    status: CustomizationStatus.draft,
    quotes: [],
    designId: null,
    templateId: null,
    podOrderId: null,
    trackingNumber: null,
    carrier: null,
    estimatedDeliveryDate: null,
    paymentId: null,
    selectedQuoteId: null,
    createdAt: new Date(),
  };

  const mockQuote = {
    id: "quote-id",
    requestId: "request-id",
    price: 500,
    description: "测试报价",
    createdAt: new Date(),
  };

  const mockTemplate = {
    id: "template-1",
    name: "T恤模板",
    type: ProductTemplateType.tshirt,
    createdAt: new Date(),
  };

  const mockDesign = {
    id: "design-1",
    userId: "test-user-id",
    templateId: "template-1",
    canvasData: { layers: [] },
    previewUrl: null,
    template: mockTemplate,
    layers: [],
    createdAt: new Date(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        CustomizationService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: PODService,
          useValue: mockPODService,
        },
      ],
    }).compile();

    service = module.get<CustomizationService>(CustomizationService);
    prisma = module.get<PrismaService>(PrismaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe("createRequest", () => {
    it("应该成功创建定制请求", async () => {
      mockPrismaService.customizationRequest.create.mockResolvedValue(
        mockRequest,
      );

      const result = await service.createRequest("test-user-id", {
        type: CustomizationType.tailored,
        description: "这是一个测试定制需求",
      });

      expect(result.id).toBe("request-id");
      expect(result.status).toBe(CustomizationStatus.draft);
      expect(
        mockPrismaService.customizationRequest.create,
      ).toHaveBeenCalledWith({
        data: expect.objectContaining({
          userId: "test-user-id",
          type: CustomizationType.tailored,
          status: CustomizationStatus.draft,
        }),
      });
    });

    it("应该处理可选参数", async () => {
      mockPrismaService.customizationRequest.create.mockResolvedValue(
        mockRequest,
      );

      await service.createRequest("test-user-id", {
        type: CustomizationType.tailored,
        description: "描述",
        title: "标题",
        referenceImages: ["img1.jpg"],
        preferences: { key: "value" },
