    it("应该抛出 NotFoundException 当请求不存在或状态不允许修改", async () => {
      mockPrismaService.customizationRequest.findFirst.mockResolvedValue(null);

      await expect(
        service.updateRequest("request-id", "test-user-id", {
          title: "新标题",
