@Injectable()
export class MetricsService {
  // HTTP 请求记录方法
  recordHttpRequest(
    method: string,
    route: string,
    statusCode: number,
    duration: number,
  ) {
    httpRequestsTotal.labels(method, route, statusCode.toString()).inc();
    httpRequestDuration
      .labels(method, route, statusCode.toString())
      .observe(duration);
  }

  // 数据库连接更新
  updateDbConnections(active: number, idle: number) {
    dbConnectionsActive.set(active);
    dbConnectionsIdle.set(idle);
  }

  // Redis 连接更新
  updateRedisConnections(active: number) {
    redisConnectionsActive.set(active);
  }

  // 缓存命中/未命中
  recordCacheHit() {
    redisCacheHits.inc();
  }

  recordCacheMiss() {
    redisCacheMisses.inc();
  }

  // 用户注册
  recordUserRegistration(source: string = 'email') {
    userRegistrations.labels(source).inc();
  }

  // 用户登录
  recordUserLogin(method: string = 'password') {
    userLogins.labels(method).inc();
  }

  // 活跃用户
  setActiveUsers(count: number) {
    activeUsersGauge.set(count);
  }

  // 风格档案创建
  recordStyleProfileCreated() {
    styleProfilesCreated.inc();
  }

  // 照片上传
  recordPhotoUpload(type: string = 'user') {
    photosUploaded.labels(type).inc();
  }

  // 服装添加
  recordClothingAdded(category: string = 'unknown') {
    clothingItemsAdded.labels(category).inc();
  }

  // 收藏添加
  recordFavoriteAdded(itemType: string) {
    favoritesAdded.labels(itemType).inc();
  }

  // 推荐服务
  recordRecommendationServed(type: string = 'style') {
    recommendationsServed.labels(type).inc();
  }

  recordRecommendationClicked(type: string = 'style') {
    recommendationsClicked.labels(type).inc();
  }

  // 虚拟试穿
  recordTryOnRequest() {
    tryOnRequests.inc();
  }

  recordTryOnCompleted(duration?: number) {
    tryOnCompleted.inc();
    if (duration) {
      tryOnDuration.observe(duration);
    }
  }

  recordTryOnError(errorType: string = 'unknown') {
    tryOnErrors.labels(errorType).inc();
  }

  // AI 造型师
  recordAIStylistConversation() {
    aiStylistConversations.inc();
  }

  recordAIStylistMessage(direction: 'user' | 'ai') {
    aiStylistMessages.labels(direction).inc();
  }

  // 风格分析
  recordStyleAnalysis(type: string = 'photo') {
    styleAnalysisTotal.labels(type).inc();
  }

  // 订单
  recordOrderCreated(status: string = 'pending', value?: number) {
    ordersCreated.labels(status).inc();
    if (value) {
      orderValue.observe(value);
    }
  }

  recordOrderFailed(reason: string = 'unknown') {
    ordersFailed.labels(reason).inc();
  }

  // 支付
  recordPaymentInitiated(method: string = 'credit_card') {
    paymentsInitiated.labels(method).inc();
  }

  recordPaymentCompleted(method: string = 'credit_card') {
    paymentsCompleted.labels(method).inc();
  }

  recordPaymentFailed(method: string, reason: string = 'unknown') {
    paymentsFailed.labels(method, reason).inc();
  }

  // 订阅
  recordSubscriptionCreated(plan: string = 'basic') {
    subscriptionsCreated.labels(plan).inc();
  }

  recordSubscriptionCanceled(plan: string, reason: string = 'user_request') {
    subscriptionsCanceled.labels(plan, reason).inc();
  }

  setActiveSubscriptions(plan: string, count: number) {
    subscriptionActiveTotal.labels(plan).set(count);
  }

  // 营收
  recordRevenue(amount: number, source: string = 'subscription') {
    revenueTotal.labels(source).inc(amount);
  }

  // AI 服务
  recordAIServiceCall(endpoint: string) {
    aiServiceCalls.labels(endpoint).inc();
  }

  recordAIServiceError(endpoint: string, errorType: string = 'unknown') {
    aiServiceErrors.labels(endpoint, errorType).inc();
  }

  recordAIServiceDuration(endpoint: string, duration: number) {
    aiServiceDuration.labels(endpoint).observe(duration);
  }

  // 向量搜索
  recordVectorSearch(collection: string, duration: number) {
    vectorSearchTotal.labels(collection).inc();
    vectorSearchDuration.labels(collection).observe(duration);
  }

  // 文件存储
  recordStorageUpload(bucket: string, type: string, bytes: number) {
    storageUploads.labels(bucket, type).inc();
    storageUploadBytes.labels(bucket).inc(bytes);
  }

  updateGpuMemory(device: string, usedBytes: number, totalBytes: number) {
    gpuMemoryUsedBytes.labels(device).set(usedBytes);
    gpuMemoryTotalBytes.labels(device).set(totalBytes);
  }

  updateModelLoaded(model: string, loaded: boolean) {
    gpuModelLoaded.labels(model).set(loaded ? 1 : 0);
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { OnEvent } from "@nestjs/event-emitter";

import {
  PAYMENT_EVENTS,
  PaymentSucceededPayload,
  PaymentFailedPayload,
  PaymentRefundedPayload,
} from "../../payment/events";
import { NotificationService } from "../services/notification.service";

/**
 * Payment Event Listener for Notification Module
 * Listens to payment events and sends appropriate notifications
 * This decouples Notification from Payment module using event-driven architecture
 */
@Injectable()
export class PaymentNotificationListener {
  private readonly logger = new Logger(PaymentNotificationListener.name);

  constructor(private readonly notificationService: NotificationService) {}

  /**
   * Send notification when payment succeeds
   */
  @OnEvent(PAYMENT_EVENTS.PAYMENT_SUCCEEDED)
  async handlePaymentSucceeded(payload: PaymentSucceededPayload): Promise<void> {
    this.logger.log(
      `Sending payment success notification to user ${payload.userId}`,
    );

    try {
      await this.notificationService.sendToUser(payload.userId, {
        type: "subscription_activated" as any,
        title: "支付成功",
        content: `您的订单 ${payload.orderId} 已支付成功，金额 ¥${payload.amount.toFixed(2)}。`,
        targetType: "payment",
        targetId: payload.paymentRecordId,
      });
    } catch (error) {
      this.logger.error(
        `Failed to send payment success notification: ${this.getErrorMessage(error)}`,
      );
    }
  }

  /**
   * Send notification when payment fails
   */
  @OnEvent(PAYMENT_EVENTS.PAYMENT_FAILED)
  async handlePaymentFailed(payload: PaymentFailedPayload): Promise<void> {
    this.logger.log(
      `Sending payment failure notification to user ${payload.userId}`,
    );

    try {
      await this.notificationService.sendToUser(payload.userId, {
        type: "system_update" as any,
        title: "支付失败",
        content: `您的订单 ${payload.orderId} 支付失败${payload.reason ? `: ${payload.reason}` : ""}，请重试或联系客服。`,
        targetType: "payment",
        targetId: payload.paymentRecordId,
      });
    } catch (error) {
      this.logger.error(
        `Failed to send payment failure notification: ${this.getErrorMessage(error)}`,
      );
    }
  }

  /**
   * Send notification when payment is refunded
   */
  @OnEvent(PAYMENT_EVENTS.PAYMENT_REFUNDED)
  async handlePaymentRefunded(payload: PaymentRefundedPayload): Promise<void> {
    this.logger.log(
      `Sending refund notification to user ${payload.userId}`,
    );

    try {
      await this.notificationService.sendToUser(payload.userId, {
        type: "system_update" as any,
        title: "退款通知",
        content: `您的订单 ${payload.orderId} 已退款 ¥${payload.amount.toFixed(2)}${payload.reason ? `，原因: ${payload.reason}` : ""}。`,
        targetType: "payment",
        targetId: payload.paymentRecordId,
      });
    } catch (error) {
      this.logger.error(
        `Failed to send refund notification: ${this.getErrorMessage(error)}`,
      );
    }
  }

  private getErrorMessage(error: unknown): string {
    return error instanceof Error ? error.message : String(error);
  }
}

import {
  Controller,
  Get,
  Post,
  Delete,
  Query,
  Param,
  Body,
  UseGuards,
  Request,
} from "@nestjs/common";
import {
  ApiTags,
  ApiOperation,
  ApiResponse,
  ApiBearerAuth,
  ApiQuery,
  ApiParam,
} from "@nestjs/swagger";

import { RequestWithUser } from "../../common/types/common.types";
import { AuthGuard } from "../auth/guards/auth.guard";

import { RegisterDeviceTokenDto, DeregisterDeviceTokenDto } from "./dto/push-notification.dto";
import { NotificationService, UpdateNotificationSettingsDto } from "./services/notification.service";
import { PushNotificationService } from "./services/push-notification.service";

@ApiTags("notification")
@ApiBearerAuth()
@Controller("notifications")
@UseGuards(AuthGuard)
export class NotificationController {
  constructor(
    private readonly notificationService: NotificationService,
    private readonly pushNotificationService: PushNotificationService,
  ) {}

  /**
   * 获取通知列表
   */
  @Get()
  @ApiOperation({ summary: "获取通知列表", description: "分页获取当前用户的通知列表，支持筛选未读通知" })
  @ApiResponse({ status: 200, description: "成功返回通知列表" })
  @ApiResponse({ status: 401, description: "未授权" })
  @ApiQuery({ name: "limit", required: false, description: "每页数量，默认20", type: Number })
  @ApiQuery({ name: "offset", required: false, description: "偏移量，默认0", type: Number })
  @ApiQuery({ name: "unreadOnly", required: false, description: "仅未读通知", type: Boolean })
  async getNotifications(
    @Request() req: RequestWithUser,
    @Query("limit") limit?: string,
    @Query("offset") offset?: string,
    @Query("unreadOnly") unreadOnly?: string,
  ) {
    return this.notificationService.getUserNotifications(req.user.id, {
      limit: limit ? parseInt(limit) : 20,
      offset: offset ? parseInt(offset) : 0,
      unreadOnly: unreadOnly === "true",
    });
  }

  /**
   * 标记为已读
   */
  @Post(":id/read")
  @ApiOperation({ summary: "标记通知为已读", description: "将指定通知标记为已读状态" })
  @ApiResponse({ status: 200, description: "标记成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  @ApiResponse({ status: 404, description: "通知不存在" })
  @ApiParam({ name: "id", description: "通知ID" })
  async markAsRead(@Request() req: RequestWithUser, @Param("id") id: string) {
    return this.notificationService.markAsRead(req.user.id, id);
  }

  /**
   * 标记全部已读
   */
  @Post("read-all")
  @ApiOperation({ summary: "标记全部已读", description: "将当前用户所有未读通知标记为已读" })
  @ApiResponse({ status: 200, description: "标记成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  async markAllAsRead(@Request() req: RequestWithUser) {
    return this.notificationService.markAllAsRead(req.user.id);
  }

  /**
   * 删除通知
   */
  @Delete(":id")
  @ApiOperation({ summary: "删除通知", description: "删除指定的通知" })
  @ApiResponse({ status: 200, description: "删除成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  @ApiResponse({ status: 404, description: "通知不存在" })
  @ApiParam({ name: "id", description: "通知ID" })
  async delete(@Request() req: RequestWithUser, @Param("id") id: string) {
    return this.notificationService.delete(req.user.id, id);
  }

  /**
   * 获取通知设置
   */
  @Get("settings")
  @ApiOperation({ summary: "获取通知设置", description: "获取当前用户的通知偏好设置" })
  @ApiResponse({ status: 200, description: "成功返回通知设置" })
  @ApiResponse({ status: 401, description: "未授权" })
  async getSettings(@Request() req: RequestWithUser) {
    return this.notificationService.getUserSettings(req.user.id);
  }

  /**
   * 更新通知设置
   */
  @Post("settings")
  @ApiOperation({ summary: "更新通知设置", description: "更新当前用户的通知偏好设置" })
  @ApiResponse({ status: 200, description: "更新成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  @ApiResponse({ status: 400, description: "请求参数错误" })
  async updateSettings(
    @Request() req: RequestWithUser,
    @Body() settings: UpdateNotificationSettingsDto,
  ) {
    return this.notificationService.updateUserSettings(req.user.id, settings);
  }

  // ==================== Device Token Management ====================

  /**
   * Register a device push token
   */
  @Post("device-token")
  @ApiOperation({ summary: "注册设备推送令牌", description: "注册或更新设备的FCM/APNs推送令牌" })
  @ApiResponse({ status: 201, description: "注册成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  async registerDeviceToken(
    @Request() req: RequestWithUser,
    @Body() dto: RegisterDeviceTokenDto,
  ) {
    return this.pushNotificationService.registerDeviceToken(
      req.user.id,
      dto.token,
      dto.platform,
      dto.appId,
    );
  }

  /**
   * Deregister a device push token
   */
  @Delete("device-token/:token")
  @ApiOperation({ summary: "注销设备推送令牌", description: "注销指定的设备推送令牌" })
  @ApiResponse({ status: 200, description: "注销成功" })
  @ApiResponse({ status: 401, description: "未授权" })
  @ApiParam({ name: "token", description: "设备推送令牌" })
  async deregisterDeviceToken(
    @Request() req: RequestWithUser,
    @Param("token") token: string,
  ) {
    return this.pushNotificationService.deregisterDeviceToken(req.user.id, token);
  }

  /**
   * List user's registered devices
   */
  @Get("device-tokens")
  @ApiOperation({ summary: "获取已注册设备列表", description: "获取当前用户所有已注册推送的设备列表" })
  @ApiResponse({ status: 200, description: "成功返回设备列表" })
  @ApiResponse({ status: 401, description: "未授权" })
  async getDeviceTokens(@Request() req: RequestWithUser) {
    return this.pushNotificationService.getUserDevices(req.user.id);
  }
}

import { Test, TestingModule } from "@nestjs/testing";

import { NotificationService as WebSocketNotificationService } from "../../../common/gateway/notification.service";
import { PrismaService } from "../../../common/prisma/prisma.service";

import { NotificationTemplateService } from "./notification-template.service";
import {
  NotificationService,
  CreateNotificationDto,
} from "./notification.service";
import { PushNotificationService } from "./push-notification.service";

describe("NotificationService", () => {
  let service: NotificationService;
  let prisma: PrismaService;

  const mockPrismaService = {
    notification: {
      create: jest.fn(),
      createMany: jest.fn(),
      findMany: jest.fn(),
      count: jest.fn(),
      updateMany: jest.fn(),
      deleteMany: jest.fn(),
    },
    userNotificationSetting: {
      findUnique: jest.fn(),
      upsert: jest.fn(),
    },
  };

  const mockWebSocketNotificationService = {
    sendCustomNotification: jest.fn().mockResolvedValue(undefined),
  };

  const mockPushNotificationService = {
    sendToUser: jest.fn().mockResolvedValue(undefined),
  };

  const mockNotificationTemplateService = {
    render: jest.fn().mockReturnValue(null),
  };

  const mockNotification = {
    id: "notification-id",
    userId: "user-id",
    type: "system_update" as any,
    title: "Test Notification",
    content: "This is a test notification",
    isRead: false,
    readAt: null,
    createdAt: new Date(),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        NotificationService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: WebSocketNotificationService,
          useValue: mockWebSocketNotificationService,
        },
        {
          provide: PushNotificationService,
          useValue: mockPushNotificationService,
        },
        {
          provide: NotificationTemplateService,
          useValue: mockNotificationTemplateService,
        },
      ],
    }).compile();

    service = module.get<NotificationService>(NotificationService);
    prisma = module.get<PrismaService>(PrismaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe("send", () => {
    const createDto: CreateNotificationDto = {
      type: "system_update" as any,
      title: "Test Notification",
      content: "This is a test notification",
    };

    it("应该成功创建通知", async () => {
      mockPrismaService.notification.create.mockResolvedValue(mockNotification);

      const result = await service.send("user-id", createDto);

      expect(result).toEqual(mockNotification);
      expect(mockPrismaService.notification.create).toHaveBeenCalledWith({
        data: {
          userId: "user-id",
          ...createDto,
        },
      });
    });
  });

  describe("sendBatch", () => {
    const createDto: CreateNotificationDto = {
      type: "system_update" as any,
      title: "Batch Notification",
      content: "This is a batch notification",
    };

    it("应该批量创建通知", async () => {
      const userIds = ["user-1", "user-2", "user-3"];
      mockPrismaService.notification.createMany.mockResolvedValue({ count: 3 });

      const result = await service.sendBatch(userIds, createDto);

      expect(result.count).toBe(3);
      expect(mockPrismaService.notification.createMany).toHaveBeenCalledWith({
        data: userIds.map((userId) => ({
          userId,
          ...createDto,
        })),
      });
    });
  });

  describe("getUserNotifications", () => {
    it("应该获取用户通知列表", async () => {
      mockPrismaService.notification.findMany.mockResolvedValue([
        mockNotification,
      ]);
      mockPrismaService.notification.count.mockResolvedValue(5);

      const result = await service.getUserNotifications("user-id");

      expect(result.notifications).toHaveLength(1);
      expect(result.unreadCount).toBe(5);
      expect(result.hasMore).toBe(false);
    });

    it("应该只获取未读通知", async () => {
      mockPrismaService.notification.findMany.mockResolvedValue([
        mockNotification,
      ]);
      mockPrismaService.notification.count.mockResolvedValue(5);

      await service.getUserNotifications("user-id", { unreadOnly: true });

      expect(mockPrismaService.notification.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { userId: "user-id", isRead: false },
        }),
      );
    });

    it("应该支持分页", async () => {
      mockPrismaService.notification.findMany.mockResolvedValue([
        mockNotification,
      ]);
      mockPrismaService.notification.count.mockResolvedValue(0);

      await service.getUserNotifications("user-id", { limit: 10, offset: 20 });

      expect(mockPrismaService.notification.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          take: 10,
          skip: 20,
        }),
      );
    });
  });

  describe("markAsRead", () => {
    it("应该标记通知为已读", async () => {
      mockPrismaService.notification.updateMany.mockResolvedValue({ count: 1 });

      await service.markAsRead("user-id", "notification-id");

      expect(mockPrismaService.notification.updateMany).toHaveBeenCalledWith({
        where: { id: "notification-id", userId: "user-id" },
        data: { isRead: true, readAt: expect.any(Date) },
      });
    });
  });

  describe("markAllAsRead", () => {
    it("应该标记所有通知为已读", async () => {
      mockPrismaService.notification.updateMany.mockResolvedValue({ count: 5 });

      const result = await service.markAllAsRead("user-id");

      expect(result.count).toBe(5);
      expect(mockPrismaService.notification.updateMany).toHaveBeenCalledWith({
        where: { userId: "user-id", isRead: false },
        data: { isRead: true, readAt: expect.any(Date) },
      });
    });
  });

  describe("delete", () => {
    it("应该删除通知", async () => {
      mockPrismaService.notification.deleteMany.mockResolvedValue({ count: 1 });

      await service.delete("user-id", "notification-id");

      expect(mockPrismaService.notification.deleteMany).toHaveBeenCalledWith({
        where: { id: "notification-id", userId: "user-id" },
      });
    });
  });

  describe("getUserSettings", () => {
    it("应该获取用户通知设置", async () => {
      const mockSettings = {
        id: "settings-id",
        userId: "user-id",
        email: { marketing: true, transactional: true },
        push: { order: true, recommendation: true, community: true, system: true, quietHoursEnabled: false, quietHoursStart: "22:00", quietHoursEnd: "08:00" },
        inApp: { all: true },
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      mockPrismaService.userNotificationSetting.findUnique.mockResolvedValue(
        mockSettings,
      );

      const result = await service.getUserSettings("user-id");

      expect(result).toEqual(mockSettings);
    });

    it("应该返回默认设置如果用户没有设置", async () => {
      mockPrismaService.userNotificationSetting.findUnique.mockResolvedValue(
        null,
      );

      const result = await service.getUserSettings("user-id");

