const GenderValues = ["male", "female", "other"] as const;
const AgeRangeValues = ["under_18", "18_24", "25_34", "35_44", "45_54", "55_plus"] as const;
const SkipStepValues = ["PHOTO", "STYLE_TEST"] as const;
