import {
  Injectable,
  NotFoundException,
  BadRequestException,
  Logger,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { EventEmitter2 } from "@nestjs/event-emitter";
import { Cron } from "@nestjs/schedule";
import { PrismaClient, OrderStatus } from "@prisma/client";

import { StructuredLoggerService, ContextualLogger } from "../../common/logging";
import { PrismaService } from "../../common/prisma/prisma.service";
import { RedisService } from "../../common/redis/redis.service";

import {
  CreatePaymentDto,
  PaymentMethod,
  RefundPaymentDto,
  PaymentStatusResponseDto,
  RefundResponseDto,
  PaymentRecordDto,
  PaymentListResponseDto,
  PaymentStatus,
} from "./dto";
import {
  PAYMENT_EVENTS,
  PaymentSucceededPayload,
  PaymentFailedPayload,
  PaymentRefundedPayload,
  SubscriptionActivationPayload,
} from "./events";
import { AlipayProvider } from "./providers/alipay.provider";
import {
  PaymentProviderInterface,
  PaymentProvider,
  CreatePaymentOptions,
  PaymentResult,
  PaymentCallbackData,
  RefundOptions,
} from "./providers/payment-provider.interface";
import { WechatProvider } from "./providers/wechat.provider";
import {
  PaymentOrderMetadata,
  PaymentRecordMetadata,
  PaymentRawCallbackData,
} from "./types/common.types";


const PAYMENT_IDEMPOTENCY_PREFIX = "payment:idempotency:";
const IDEMPOTENCY_TTL_SECONDS = 300;

@Injectable()
export class PaymentService {
  private readonly logger = new Logger(PaymentService.name);
  private readonly providers: Map<PaymentProvider, PaymentProviderInterface>;

  constructor(
    private readonly prisma: PrismaService,
    private readonly configService: ConfigService,
    private readonly alipayProvider: AlipayProvider,
    private readonly wechatProvider: WechatProvider,
    private readonly redisService: RedisService,
    private readonly eventEmitter: EventEmitter2,
  ) {
    this.providers = new Map<PaymentProvider, PaymentProviderInterface>([
      ["alipay", alipayProvider as PaymentProviderInterface],
      ["wechat", wechatProvider as PaymentProviderInterface],
    ]);
  }

  /**
   * 创建支付订单
   */
  async createPayment(
    userId: string,
    dto: CreatePaymentDto,
  ): Promise<PaymentResult> {
    this.logger.log("创建支付订单", {
      userId,
      provider: dto.provider,
      amount: dto.amount,
      orderId: dto.orderId,
    });

    const provider = this.getProvider(dto.provider as PaymentProvider);

    // 检查是否已存在未支付的订单
    const existingOrder = await this.prisma.paymentRecord.findFirst({
      where: {
        userId,
        status: "pending",
        expiredAt: { gt: new Date() },
      },
    });

    if (existingOrder) {
      // 返回已存在的订单信息
      const queryResult = await provider.queryPayment(existingOrder.orderId);
      if (queryResult.status === "pending") {
        return {
          success: true,
          orderId: existingOrder.orderId,
          qrCode: existingOrder.qrCode || undefined,
          expireAt: existingOrder.expiredAt ?? undefined,
        };
      }
    }

    // 获取订单信息（从订阅模块或自定义订单）
    const orderInfo = await this.getOrderInfo(dto.orderId, userId);

    // 创建支付记录
    const expireMinutes = dto.expireMinutes || 30;
    const expiredAt = new Date();
    expiredAt.setMinutes(expiredAt.getMinutes() + expireMinutes);

    const paymentRecord = await this.prisma.paymentRecord.create({
      data: {
        orderId: dto.orderId,
        userId,
        provider: dto.provider,
        amount: dto.amount || orderInfo.amount,
        currency: "CNY",
        status: "pending",
        expiredAt,
        metadata: {
          subject: dto.subject || orderInfo.subject,
          body: dto.body,
          originalOrderId: dto.orderId,
        },
      },
    });

    // 调用支付提供商创建支付
    const options: CreatePaymentOptions = {
      orderId: paymentRecord.orderId,
      amount: paymentRecord.amount.toNumber(),
      subject: dto.subject || orderInfo.subject || "寻裳会员订阅",
      body: dto.body,
      method: dto.method,
      clientIp: dto.clientIp,
      expireMinutes,
      notifyUrl: this.getNotifyUrl(dto.provider),
    };

    const result = await provider.createPayment(options);

    if (result.success) {
      // 更新支付记录
      await this.prisma.paymentRecord.update({
        where: { id: paymentRecord.id },
        data: {
          qrCode: result.qrCode,
          tradeNo: result.tradeNo,
        },
      });

      this.logger.log("支付订单创建成功", {
        orderId: dto.orderId,
        provider: dto.provider,
        amount: paymentRecord.amount.toNumber(),
        userId,
      });
    } else {
      // 更新状态为失败
      await this.prisma.paymentRecord.update({
        where: { id: paymentRecord.id },
        data: {
          status: "failed",
          failedReason: result.error?.message,
        },
      });

      this.logger.error("支付订单创建失败", undefined, {
        orderId: dto.orderId,
        provider: dto.provider,
        error: result.error?.message,
        userId,
      });
    }

    return result;
  }

  /**
   * 查询支付状态
   */
  async queryPayment(
    userId: string,
    orderId: string,
  ): Promise<PaymentStatusResponseDto> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    // 如果状态是 pending，查询最新状态
    if (record.status === "pending") {
      const provider = this.getProvider(record.provider as PaymentProvider);
      const queryResult = await provider.queryPayment(orderId);

      if (
        queryResult.status !== "pending" &&
        (queryResult.status as string) !== record.status
      ) {
        // 状态发生变化，更新记录
        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: queryResult.status,
            tradeNo: queryResult.tradeNo,
            paidAt: queryResult.paidAt,
          },
        });

        return {
          orderId,
          tradeNo: queryResult.tradeNo,
          amount: queryResult.amount ?? 0,
          status: queryResult.status as PaymentStatus,
          paidAt: queryResult.paidAt,
        };
      }
    }

    return {
      orderId,
      tradeNo: record.tradeNo || undefined,
      amount: record.amount.toNumber(),
      status: record.status as PaymentStatus,
      paidAt: record.paidAt || undefined,
    };
  }

  /**
   * 处理支付回调
   */
  async handleCallback(
    providerName: PaymentProvider,
    callbackData: PaymentRawCallbackData,
  ): Promise<{ success: boolean; message: string }> {
    this.logger.log("收到支付回调", { provider: providerName });

    const provider = this.getProvider(providerName);

    // 验证签名
    if (!provider.verifyCallbackSign(callbackData)) {
      this.logger.warn("支付回调签名验证失败", { provider: providerName });
      return { success: false, message: "Invalid signature" };
    }

    // 解析回调数据
    const parsedData = await provider.handleCallback(callbackData);
    const { orderId, tradeNo, amount, status, paidAt } = parsedData;

    // 幂等性保护：使用 Redis 分布式锁
    const lockKey = `${PAYMENT_IDEMPOTENCY_PREFIX}${orderId}`;
    const lockValue = `${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    
    const lockAcquired = await this.redisService.getClient().set(
      lockKey,
      lockValue,
      "PX",
      IDEMPOTENCY_TTL_SECONDS * 1000,
      "NX"
    );

    if (!lockAcquired) {
      this.logger.log("订单正在处理中", { orderId });
      return { success: true, message: "Order is being processed" };
    }

    try {
      // 查找支付记录
      const record = await this.prisma.paymentRecord.findUnique({
        where: { orderId },
      });

      if (!record) {
        this.logger.warn("支付记录不存在", { orderId });
        return { success: false, message: "Order not found" };
      }

      // 检查订单状态
      if (record.status !== "pending") {
        this.logger.log("订单已处理", { orderId, status: record.status });
        return { success: true, message: "Order already processed" };
      }

      // 金额校验
      if (Math.abs(record.amount.toNumber() - amount) > 0.01) {
        this.logger.warn("支付金额不匹配", {
          orderId,
          expected: record.amount.toNumber(),
          actual: amount,
        });
        return { success: false, message: "Amount mismatch" };
      }

      // 使用事务更新状态
      await this.prisma.$transaction(async (tx) => {
        // 更新支付记录
        await tx.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: status === "paid" ? "paid" : "failed",
            tradeNo,
            paidAt,
            notifyData: JSON.parse(JSON.stringify(callbackData)),
          },
        });

        // 如果支付成功，激活订阅
        if (status === "paid") {
          await this.activateSubscription(record.userId, record.orderId);

          // 更新关联的 Order 状态为 paid
          await tx.order.updateMany({
            where: {
              id: record.orderId,
              status: OrderStatus.pending,
            },
            data: {
              status: OrderStatus.paid,
              paymentTime: new Date(),
            },
          });
        }
      });

      this.logger.log("支付回调处理成功", {
        orderId,
        status,
        userId: record.userId,
        amount: record.amount.toNumber(),
      });

      // Emit events for decoupled notification and subscription handling
      if (status === "paid") {
        const paymentOrder = await this.prisma.paymentOrder.findUnique({
          where: { id: orderId },
        });

        // Emit payment succeeded event
        const successPayload: PaymentSucceededPayload = {
          userId: record.userId,
          orderId,
          paymentRecordId: record.id,
          amount: record.amount.toNumber(),
          currency: record.currency,
          provider: record.provider,
          tradeNo,
          paidAt,
          metadata: paymentOrder?.metadata as PaymentOrderMetadata | undefined,
        };
        this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_SUCCEEDED, successPayload);
      }

      return { success: true, message: "Success" };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error("支付回调处理失败", errorStack, {
        orderId,
        error: errorMessage,
      });
      return { success: false, message: "Processing failed" };
    } finally {
      // 释放锁（使用 Lua 脚本确保原子性）
      const releaseScript = `
        if redis.call("get", KEYS[1]) == ARGV[1] then
          return redis.call("del", KEYS[1])
        else
          return 0
        end
      `;
      await this.redisService.getClient().eval(releaseScript, 1, lockKey, lockValue);
    }
  }

  /**
   * 申请退款
   */
  async refund(
    userId: string,
    dto: RefundPaymentDto,
  ): Promise<RefundResponseDto> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId: dto.orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    if (record.status !== "paid") {
      throw new BadRequestException("Only paid orders can be refunded");
    }

    if (dto.amount > record.amount.toNumber()) {
      throw new BadRequestException(
        "Refund amount cannot exceed payment amount",
      );
    }

    const refundId = `refund_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    const provider = this.getProvider(record.provider as PaymentProvider);

    // 创建退款记录
    const refundRecord = await this.prisma.refundRecord.create({
      data: {
        id: refundId,
        paymentRecordId: record.id,
        amount: dto.amount,
        reason: dto.reason,
        status: "processing",
      },
    });

    // 调用支付提供商退款
    const options: RefundOptions = {
      orderId: dto.orderId,
      refundId,
      amount: dto.amount,
      reason: dto.reason,
    };

    const result = await provider.refund(options);

    // 更新退款记录
    await this.prisma.refundRecord.update({
      where: { id: refundId },
      data: {
        status: result.success ? "success" : "failed",
        refundNo: result.refundNo,
        failedReason: result.error?.message,
      },
    });

    if (result.success) {
      // 如果是全额退款，更新支付记录状态
      if (dto.amount >= record.amount.toNumber()) {
        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: { status: "refunded", refundedAt: new Date() },
        });
      }

      // Emit refund event for notification
      const refundPayload: PaymentRefundedPayload = {
        userId: record.userId,
        orderId: dto.orderId,
        paymentRecordId: record.id,
        refundId,
        amount: dto.amount,
        reason: dto.reason,
      };
      this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_REFUNDED, refundPayload);
    }

    return result;
  }

  /**
   * 关闭订单
   */
  async closeOrder(userId: string, orderId: string): Promise<boolean> {
    const record = await this.prisma.paymentRecord.findFirst({
      where: { orderId, userId },
    });

    if (!record) {
      throw new NotFoundException("Payment record not found");
    }

    if (record.status !== "pending") {
      throw new BadRequestException("Only pending orders can be closed");
    }

    const provider = this.getProvider(record.provider as PaymentProvider);
    const success = await provider.closeOrder(orderId);

    if (success) {
      await this.prisma.paymentRecord.update({
        where: { id: record.id },
        data: { status: "closed" },
      });
    }

    return success;
  }

  /**
   * 获取支付记录列表
   */
  async getPaymentRecords(
    userId: string,
    page: number = 1,
    pageSize: number = 10,
  ): Promise<PaymentListResponseDto> {
    const where = { userId };

    const [records, total] = await Promise.all([
      this.prisma.paymentRecord.findMany({
        where,
        orderBy: { createdAt: "desc" },
        skip: (page - 1) * pageSize,
        take: pageSize,
      }),
      this.prisma.paymentRecord.count({ where }),
    ]);

    return {
      items: records.map((record) => ({
        id: record.id,
        orderId: record.orderId,
        userId: record.userId,
        provider: record.provider,
        amount: record.amount.toNumber(),
        currency: record.currency,
        status: record.status,
        tradeNo: record.tradeNo || undefined,
        paidAt: record.paidAt || undefined,
        createdAt: record.createdAt,
        expiredAt: record.expiredAt || undefined,
      })),
      total,
      page,
      pageSize,
    };
  }

  /**
   * 轮询支付状态（用于前端）
   */
  async pollPaymentStatus(
    userId: string,
    orderId: string,
  ): Promise<{ paid: boolean; status: string }> {
    const result = await this.queryPayment(userId, orderId);
    return {
      paid: result.status === "paid",
      status: result.status,
    };
  }

  // ==================== 私有方法 ====================

  /**
   * 获取支付提供商
   */
  private getProvider(name: PaymentProvider): PaymentProviderInterface {
    const provider = this.providers.get(name);
    if (!provider) {
      throw new BadRequestException(`Unsupported payment provider: ${name}`);
    }
    return provider;
  }

  /**
   * 获取回调 URL
   */
  private getNotifyUrl(provider: PaymentProvider): string {
    const baseUrl =
      this.configService.get<string>("BACKEND_URL") || "http://localhost:3001";
    return `${baseUrl}/api/v1/payment/callback/${provider}`;
  }

  /**
   * 获取订单信息
   */
  private async getOrderInfo(
    orderId: string,
    userId: string,
  ): Promise<{ amount: number; subject: string }> {
    // 检查是否是订阅订单
    const paymentOrder = await this.prisma.paymentOrder.findUnique({
      where: { id: orderId },
    });

    if (paymentOrder) {
      const metadata = paymentOrder.metadata as PaymentOrderMetadata;
      const amount =
        typeof paymentOrder.amount === "number"
          ? paymentOrder.amount
          : (paymentOrder.amount as { toNumber?: () => number }).toNumber?.() ||
            Number(paymentOrder.amount);
      return {
        amount,
        subject: `寻裳 ${metadata?.planName || "会员"}订阅`,
      };
    }

    // 默认返回
    return {
      amount: 0,
      subject: "寻裳服务",
    };
  }

  /**
   * 激活订阅 - 通过事件驱动
   */
  private async activateSubscription(
    userId: string,
    orderId: string,
  ): Promise<void> {
    const paymentOrder = await this.prisma.paymentOrder.findUnique({
      where: { id: orderId },
    });

    if (paymentOrder) {
      const metadata = paymentOrder.metadata as PaymentOrderMetadata;
      if (metadata?.planId) {
        // Emit event instead of direct service call
        const payload: SubscriptionActivationPayload = {
          userId,
          orderId,
          planId: metadata.planId,
          paymentRecordId: orderId,
          metadata,
        };
        this.eventEmitter.emit(
          PAYMENT_EVENTS.SUBSCRIPTION_ACTIVATION_REQUIRED,
          payload,
        );
      }
    }
  }

  // FIX-CODE-007: 支付宝签名验证方法 (修复时间: 2026-03-19)
  async verifyAlipaySignature(body: PaymentRawCallbackData): Promise<boolean> {
    try {
      const provider = this.getProvider("alipay");
      if ('verifyCallbackSign' in provider && typeof provider.verifyCallbackSign === 'function') {
        return provider.verifyCallbackSign(body);
      }
      this.logger.warn("支付宝Provider未实现签名验证方法");
      return false;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error("支付宝签名验证失败", undefined, { error: errorMessage });
      return false;
    }
  }

  /**
   * 自动关闭超时未支付订单（每5分钟执行）
   */
  @Cron("*/5 * * * *")
  async handleCloseExpiredPayments(): Promise<void> {
    const expiredThreshold = new Date();
    expiredThreshold.setMinutes(expiredThreshold.getMinutes() - 30);

    const expiredRecords = await this.prisma.paymentRecord.findMany({
      where: {
        status: "pending",
        expiredAt: { lt: new Date() },
        createdAt: { lt: expiredThreshold },
      },
      take: 50,
    });

    if (expiredRecords.length === 0) {
      return;
    }

    this.logger.log(`Found ${expiredRecords.length} expired payment records to close`);

    for (const record of expiredRecords) {
      try {
        const provider = this.getProvider(record.provider as PaymentProvider);
        await provider.closeOrder(record.orderId);

        await this.prisma.paymentRecord.update({
          where: { id: record.id },
          data: {
            status: "closed",
            cancelledAt: new Date(),
          },
        });

        await this.prisma.order.updateMany({
          where: {
            id: record.orderId,
            status: OrderStatus.pending,
          },
          data: {
            status: OrderStatus.cancelled,
          },
        });

        const orderWithItems = await this.prisma.order.findUnique({
          where: { id: record.orderId },
          include: { items: true },
        });

        if (orderWithItems && orderWithItems.items.length > 0) {
          await this.prisma.$transaction(
            orderWithItems.items.map((item) =>
              this.prisma.clothingItem.update({
                where: { id: item.itemId },
                data: { stock: { increment: item.quantity } },
              }),
            ),
          );
        }

        this.eventEmitter.emit(PAYMENT_EVENTS.PAYMENT_CLOSED, {
          userId: record.userId,
          orderId: record.orderId,
          paymentRecordId: record.id,
        });

        this.logger.log(`Closed expired payment: ${record.orderId}`);
      } catch (error) {
        const message = error instanceof Error ? error.message : String(error);
        this.logger.error(
          `Failed to close expired payment ${record.orderId}: ${message}`,
        );
      }
    }
  }
}

import * as crypto from "crypto";
import * as fs from "fs";
import * as https from "https";
import * as path from "path";

import { Injectable, Logger, OnModuleInit } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";

import {
  PaymentRawCallbackData,
} from "../types/common.types";
import {
  WechatV3CreatePaymentResponse,
  WechatV3QueryResponse,
  WechatV3RefundResponse,
  WechatCallbackData,
  WechatCallbackPayload,
  WechatDecryptedResource,
  WechatV3RequestData,
  WechatApiResponse,
} from "../types/wechat.types";

import {
  PaymentProviderInterface,
  PaymentProvider,
  CreatePaymentOptions,
  PaymentResult,
  PaymentCallbackData,
  RefundOptions,
  RefundResult,
  PaymentQueryResult,
} from "./payment-provider.interface";


@Injectable()
export class WechatProvider implements PaymentProviderInterface, OnModuleInit {
  private readonly logger = new Logger(WechatProvider.name);
  readonly name: PaymentProvider = "wechat";

  private appId!: string;
  private mchId!: string;
  private apiKey!: string;
  private notifyUrl!: string;
  private certPath!: string;
  private keyPath!: string;
  private apiV3Key!: string;
  private serialNo!: string;

  // API 端点
  private readonly gateway = "https://api.mch.weixin.qq.com";
  private readonly v3Gateway = "https://api.mch.weixin.qq.com/v3";

  constructor(private readonly configService: ConfigService) {}

  onModuleInit() {
    this.appId = this.configService.get<string>("WECHAT_APP_ID") || "";
    this.mchId = this.configService.get<string>("WECHAT_MCH_ID") || "";
    this.apiKey = this.configService.get<string>("WECHAT_API_KEY") || "";
    this.apiV3Key = this.configService.get<string>("WECHAT_API_V3_KEY") || "";
    this.notifyUrl = this.configService.get<string>("WECHAT_NOTIFY_URL") || "";
    this.certPath = this.configService.get<string>("WECHAT_CERT_PATH") || "";
    this.keyPath = this.configService.get<string>("WECHAT_KEY_PATH") || "";
    this.serialNo = this.configService.get<string>("WECHAT_SERIAL_NO") || "";

    if (!this.appId || !this.mchId || !this.apiKey) {
      this.logger.warn(
        "Wechat Pay configuration is incomplete. Payment will not work.",
      );
    }
  }

  /**
   * 创建支付订单（使用 V3 API）
   */
  async createPayment(options: CreatePaymentOptions): Promise<PaymentResult> {
    try {
      const {
        orderId,
        amount,
        subject,
        body,
        method,
        expireMinutes = 30,
      } = options;

      const expireAt = new Date();
      expireAt.setMinutes(expireAt.getMinutes() + expireMinutes);

      // 使用 V3 API
      const endpoint = this.getV3Endpoint(method);
      const requestData = this.buildV3RequestData(
        orderId,
        amount,
        subject,
        method,
        expireMinutes,
      );

      const response = await this.v3Request("POST", endpoint, requestData);

      if (!response.code) {
        // 请求成功
        const createResponse = response as WechatV3CreatePaymentResponse;
        const result: PaymentResult = {
          success: true,
          orderId,
          tradeNo: createResponse.prepay_id,
          expireAt,
          rawData: response as unknown as PaymentRawCallbackData,
        };

        switch (method) {
          case "qrcode":
          case "native":
            // Native 支付返回 code_url
            result.qrCode = createResponse.code_url;
            break;
          case "h5":
            // H5 支付返回 h5_url
            result.h5Url = createResponse.h5_url;
            break;
          case "app":
            // APP 支付返回 prepay_id，需要二次签名
            result.appPayload = this.buildAppPayload(createResponse.prepay_id || "");
            break;
        }

        return result;
      }

      return {
        success: false,
        orderId,
        error: {
          code: response.code,
          message: response.message || "创建支付失败",
          detail: response.detail,
        },
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to create wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        success: false,
        orderId: options.orderId,
        error: {
          code: "CREATE_PAYMENT_FAILED",
          message: "创建支付订单失败",
          detail: errorMessage,
        },
      };
    }
  }

  /**
   * 查询支付状态
   */
  async queryPayment(orderId: string): Promise<PaymentQueryResult> {
    try {
      const endpoint = `/v3/pay/transactions/out-trade-no/${orderId}?mchid=${this.mchId}`;
      const response = await this.v3Request("GET", endpoint);

      if (response.code) {
        return {
          orderId,
          status: "failed",
          rawData: response as unknown as PaymentRawCallbackData,
        };
      }

      const queryResponse = response as WechatV3QueryResponse;
      const statusMap: Record<string, PaymentQueryResult["status"]> = {
        NOTPAY: "pending",
        SUCCESS: "paid",
        CLOSED: "closed",
        REFUND: "refunded",
      };

      const tradeState = queryResponse.trade_state || "";
      return {
        orderId,
        tradeNo: queryResponse.transaction_id,
        amount: queryResponse.amount?.total ? queryResponse.amount.total / 100 : 0,
        status: statusMap[tradeState] || "failed",
        paidAt: queryResponse.success_time
          ? new Date(queryResponse.success_time)
          : undefined,
        rawData: response as unknown as PaymentRawCallbackData,
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to query wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        orderId,
        status: "failed",
        rawData: { error: errorMessage },
      };
    }
  }

  /**
   * 处理支付回调
   */
  async handleCallback(
    callbackData: PaymentRawCallbackData,
  ): Promise<PaymentCallbackData> {
    const actualBody = (callbackData.body ?? callbackData) as WechatCallbackData;
    const resource = actualBody.resource;
    const decryptedData = this.decryptResource(resource);

    const statusMap: Record<string, PaymentCallbackData["status"]> = {
      SUCCESS: "paid",
      CLOSED: "cancelled",
      PAYERROR: "failed",
    };

    return {
      orderId: decryptedData.out_trade_no,
      tradeNo: decryptedData.transaction_id,
      amount: decryptedData.amount?.total
        ? decryptedData.amount.total / 100
        : 0,
      status: statusMap[decryptedData.trade_state] || "failed",
      paidAt: decryptedData.success_time
        ? new Date(decryptedData.success_time)
        : new Date(),
      rawData: callbackData,
    };
  }

  /**
   * 验证回调签名
   */
  verifyCallbackSign(callbackData: PaymentRawCallbackData): boolean {
    try {
      // 检查 callbackData 是否包含 WechatCallbackPayload 所需的结构
      const payload = callbackData as unknown as WechatCallbackPayload;
      const { headers, body } = payload;

      if (!headers || !body) {
        return false;
      }

      const timestamp = headers["wechatpay-timestamp"];
      const nonce = headers["wechatpay-nonce"];
      const signature = headers["wechatpay-signature"];
      const serial = headers["wechatpay-serial"];

      if (!timestamp || !nonce || !signature) {
        return false;
      }

      // 构建验签字符串
      const message = `${timestamp}\n${nonce}\n${body}\n`;

      // 使用微信支付平台公钥验证签名
      return this.verifySignature(message, signature, serial);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(
        `Failed to verify wechat callback sign: ${errorMessage}`,
      );
      return false;
    }
  }

  /**
   * 申请退款
   */
  async refund(options: RefundOptions): Promise<RefundResult> {
    try {
      const { orderId, refundId, amount, reason } = options;

      // 先查询原订单获取总金额
      const queryResult = await this.queryPayment(orderId);
      const totalAmount = (queryResult.amount ?? 0) * 100; // 转换为分

      const requestData = {
        out_trade_no: orderId,
        out_refund_no: refundId,
        reason: reason || "用户申请退款",
        amount: {
          refund: Math.round(amount * 100),
          total: Math.round(totalAmount),
          currency: "CNY",
        },
      };

      const response = await this.v3Request(
        "POST",
        "/v3/refund/domestic/refunds",
        requestData as unknown as WechatV3RequestData,
      );

      if (response.code) {
        return {
          success: false,
          refundId,
          status: "failed",
          error: {
            code: response.code,
            message: response.message || "退款失败",
            detail: response.detail,
          },
        };
      }

      const refundResponse = response as WechatV3RefundResponse;
      const statusMap: Record<string, RefundResult["status"]> = {
        SUCCESS: "success",
        PROCESSING: "processing",
        CLOSED: "failed",
      };

      const refundStatus = refundResponse.status || "";
      return {
        success: true,
        refundId,
        refundNo: refundResponse.refund_id,
        status: statusMap[refundStatus] || "processing",
      };
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to refund wechat payment: ${errorMessage}`,
        errorStack,
      );
      return {
        success: false,
        refundId: options.refundId,
        status: "failed",
        error: {
          code: "REFUND_ERROR",
          message: "退款异常",
          detail: errorMessage,
        },
      };
    }
  }

  /**
   * 关闭订单
   */
  async closeOrder(orderId: string): Promise<boolean> {
    try {
      const endpoint = `/v3/pay/transactions/out-trade-no/${orderId}/close`;
      const requestData = {
        mchid: this.mchId,
      };

      const response = await this.v3Request("POST", endpoint, requestData as unknown as WechatV3RequestData);
      return !response.code;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      const errorStack = error instanceof Error ? error.stack : undefined;
      this.logger.error(
        `Failed to close wechat order: ${errorMessage}`,
        errorStack,
      );
      return false;
    }
  }

  // ==================== 私有方法 ====================

  /**
   * 获取 V3 API 端点
   */
  private getV3Endpoint(method: string): string {
    const endpointMap: Record<string, string> = {
      qrcode: "/v3/pay/transactions/native",
      native: "/v3/pay/transactions/native",
      h5: "/v3/pay/transactions/h5",
      app: "/v3/pay/transactions/app",
    };
    return endpointMap[method] || "/v3/pay/transactions/native";
  }

  /**
   * 构建 V3 请求数据
   */
  private buildV3RequestData(
    orderId: string,
    amount: number,
    description: string,
    method: string,
    expireMinutes: number,
  ): WechatV3RequestData {
    const baseData: WechatV3RequestData = {
      appid: this.appId,
      mchid: this.mchId,
      description,
      out_trade_no: orderId,
      notify_url: this.notifyUrl,
      amount: {
        total: Math.round(amount * 100), // 转换为分
        currency: "CNY",
      },
    };

    // 设置过期时间
    const expireTime = new Date();
    expireTime.setMinutes(expireTime.getMinutes() + expireMinutes);
    baseData.time_expire = expireTime.toISOString();

    // 根据支付方式添加额外参数
    if (method === "h5") {
      (baseData as WechatV3RequestData & { scene_info: unknown }).scene_info = {
        payer_client_ip: "127.0.0.1",
        h5_info: {
          type: "Wap",
        },
      };
    }

    return baseData;
  }

  /**
   * 构建 APP 支付参数
   */
  private buildAppPayload(prepayId: string): string {
    const timestamp = Math.floor(Date.now() / 1000).toString();
    const nonceStr = crypto.randomBytes(16).toString("hex");
    const packageStr = `prepay_id=${prepayId}`;

    const message = `${this.appId}\n${timestamp}\n${nonceStr}\n${packageStr}\n`;
    const signature = this.signV3(message);

    const params = {
      appid: this.appId,
      partnerid: this.mchId,
      prepayid: prepayId,
      package: "Sign=WXPay",
      noncestr: nonceStr,
      timestamp,
      sign: signature,
    };

    return JSON.stringify(params);
  }

  /**
   * V3 API 请求
   */
  private async v3Request(
    method: string,
    endpoint: string,
    data?: WechatV3RequestData,
  ): Promise<WechatApiResponse> {
    const url = `${this.v3Gateway}${endpoint}`;
    const timestamp = Math.floor(Date.now() / 1000).toString();
    const nonceStr = crypto.randomBytes(16).toString("hex");

    let bodyStr = "";
    if (data && method !== "GET") {
      bodyStr = JSON.stringify(data);
    }

    const message = `${method}\n${endpoint}\n${timestamp}\n${nonceStr}\n${bodyStr}\n`;
    const signature = this.signV3(message);

    const authorization = `WECHATPAY2-SHA256-RSA2048 mchid="${this.mchId}",nonce_str="${nonceStr}",timestamp="${timestamp}",serial_no="${this.serialNo}",signature="${signature}"`;

    const headers: Record<string, string> = {
      "Content-Type": "application/json",
      Accept: "application/json",
      Authorization: authorization,
    };

    try {
      const https = await import("https");
      const agent = this.getHttpsAgent();

      return new Promise((resolve, reject) => {
        const req = https.request(
          url,
          {
            method,
            headers,
            agent,
          },
          (res) => {
            let responseData = "";
            res.on("data", (chunk) => (responseData += chunk));
            res.on("end", () => {
              try {
                resolve(JSON.parse(responseData) as WechatApiResponse);
              } catch (parseError) {
                // WeChat API may return non-JSON responses in some cases
                // Log this for debugging but continue with raw response
                this.logger.debug(
                  `WeChat API returned non-JSON response (status: ${res.statusCode}). Response (truncated): ${responseData.substring(0, 200)}`,
                );
                resolve({ raw: responseData } as unknown as WechatApiResponse);
              }
            });
          },
        );

        req.on("error", reject);

        if (bodyStr) {
          req.write(bodyStr);
        }
        req.end();
      });
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`V3 request error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * V3 签名
   */
  private signV3(message: string): string {
    try {
      const sign = crypto.createSign("RSA-SHA256");
      sign.update(message);

      const privateKey = this.getPrivateKey();
      return sign.sign(privateKey, "base64");
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`V3 sign error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * 验证签名
   */
  private verifySignature(
    message: string,
    signature: string,
    serial: string,
  ): boolean {
    try {
      const platformCert = this.configService.get<string>(
        "WECHAT_PLATFORM_CERT",
      );
      if (!platformCert) {
        this.logger.error(
          "SECURITY ALERT: Platform certificate not configured. " +
            "Callback signature verification is DISABLED. " +
            "This is a critical security risk - configure WECHAT_PLATFORM_CERT immediately.",
        );
        return false;
      }

      const verify = crypto.createVerify("RSA-SHA256");
      verify.update(message);

      const cert = this.formatCertificate(platformCert);
      const isValid = verify.verify(cert, signature, "base64");

      if (!isValid) {
        this.logger.error(
          `Signature verification failed for serial: ${serial}. ` +
            "Possible callback forgery attempt detected.",
        );
      }

      return isValid;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(
        `Verify signature error: ${errorMessage}. ` +
          "Rejecting callback for security reasons.",
      );
      return false;
    }
  }

  /**
   * 解密回调数据
   */
  private decryptResource(resource: WechatCallbackData["resource"]): WechatDecryptedResource {
    try {
      const { ciphertext, nonce, associated_data } = resource;
      const key = Buffer.from(this.apiV3Key, "utf8");
      const iv = Buffer.from(nonce, "utf8");
      const authTag = Buffer.from(ciphertext.slice(-16), "base64");
      const data = Buffer.from(ciphertext.slice(0, -16), "base64");

      const decipher = crypto.createDecipheriv("aes-256-gcm", key, iv);
      decipher.setAuthTag(authTag);
      decipher.setAAD(Buffer.from(associated_data || "", "utf8"));

      let decrypted = decipher.update(data, undefined, "utf8");
      decrypted += decipher.final("utf8");

      return JSON.parse(decrypted) as WechatDecryptedResource;
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : "未知错误";
      this.logger.error(`Decrypt resource error: ${errorMessage}`);
      throw error;
    }
  }

  /**
   * 获取私钥
   */
  private getPrivateKey(): string {
    if (this.keyPath) {
      // 实际应该从文件读取
      return this.formatPrivateKey(this.keyPath);
    }
    return this.formatPrivateKey(
      this.configService.get<string>("WECHAT_PRIVATE_KEY") || "",
    );
  }

  /**
   * 获取 HTTPS Agent（包含证书）
   */
  private getHttpsAgent(): https.Agent | undefined {
    try {
      const certFilePath = this.certPath;
      const keyFilePath = this.keyPath;

      if (certFilePath && keyFilePath) {
        if (fs.existsSync(certFilePath) && fs.existsSync(keyFilePath)) {
          const cert = fs.readFileSync(certFilePath);
          const key = fs.readFileSync(keyFilePath);

          return new https.Agent({
            cert,
            key,
            rejectUnauthorized: true,
          });
        }

        this.logger.warn(
          `WeChat certificate files not found: cert=${certFilePath}, key=${keyFilePath}`,
        );
      }

      const certEnv = this.configService.get<string>("WECHAT_CERT_CONTENT");
      const keyEnv = this.configService.get<string>("WECHAT_KEY_CONTENT");

      if (certEnv && keyEnv) {
        return new https.Agent({
          cert: Buffer.from(certEnv, "utf8"),
          key: Buffer.from(keyEnv, "utf8"),
          rejectUnauthorized: true,
        });
      }

      this.logger.warn(
        "WeChat merchant certificate not configured. " +
          "Set WECHAT_CERT_PATH/WECHAT_KEY_PATH or WECHAT_CERT_CONTENT/WECHAT_KEY_CONTENT. " +
          "Using default Agent (some V3 API calls may fail).",
      );
      return undefined;
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to create HTTPS agent: ${message}`);
      return undefined;
    }
  }

  /**
   * 格式化私钥
   */
  private formatPrivateKey(key: string): string {
    if (key.includes("-----BEGIN")) {
      return key;
    }
    return `-----BEGIN PRIVATE KEY-----\n${key}\n-----END PRIVATE KEY-----`;
  }

  /**
   * 格式化证书
   */
  private formatCertificate(cert: string): string {
    if (cert.includes("-----BEGIN")) {
      return cert;
    }
    return `-----BEGIN CERTIFICATE-----\n${cert}\n-----END CERTIFICATE-----`;
  }
}

import {
  Body,
  Controller,
  Logger,
  Post,
  UploadedFile,
  UseGuards,
  UseInterceptors,
} from "@nestjs/common";
import { FileInterceptor } from "@nestjs/platform-express";
import {
  ApiBearerAuth,
  ApiBody,
  ApiConsumes,
  ApiOperation,
  ApiResponse,
  ApiTags,
} from "@nestjs/swagger";

import { SensitiveDataInterceptor } from "../../common/interceptors/sensitive-data.interceptor";
import { CurrentUser } from "../auth/decorators/current-user.decorator";
import { JwtAuthGuard } from "../auth/guards/jwt-auth.guard";

import { EnhanceRequestDto } from "./dto/quality-report.dto";
import { PhotoQualityService } from "./services/photo-quality.service";

@ApiTags("photo-quality")
@ApiBearerAuth()
@UseGuards(JwtAuthGuard)
@UseInterceptors(SensitiveDataInterceptor)
@Controller("photo-quality")
export class PhotoQualityController {
  private readonly logger = new Logger(PhotoQualityController.name);

  constructor(private readonly photoQualityService: PhotoQualityService) {}

  @Post("quality-check")
  @ApiOperation({ summary: "上传图片质量检测", description: "上传照片进行质量分析，返回清晰度、亮度、构图等维度的评分和改进建议。" })
  @ApiConsumes("multipart/form-data")
