  @Post("enhance")
  @ApiOperation({ summary: "自动增强照片质量", description: "上传照片进行自动增强处理，可指定需要修复的问题（如亮度、对比度、锐度等）。" })
  @ApiConsumes("multipart/form-data")
  @ApiBody({
    schema: {
      type: "object",
      properties: {
