          type: true,
          url: true,
          thumbnailUrl: true,
          originalName: true,
          mimeType: true,
          size: true,
          analysisResult: true,
          analysisStatus: true,
          analyzedAt: true,
          createdAt: true,
        },
      });
    });

    it("应该按类型筛选照片", async () => {
