      expect(mockPrismaService.userPhoto.findMany).toHaveBeenCalledWith({
        where: { userId: "test-user-id", type: PhotoType.full_body },
        orderBy: { createdAt: "desc" },
        select: {
          id: true,
          userId: true,
          type: true,
          url: true,
          thumbnailUrl: true,
          originalName: true,
          mimeType: true,
          size: true,
          analysisResult: true,
          analysisStatus: true,
          analyzedAt: true,
          createdAt: true,
        },
      });
    });
