});

import crypto from "crypto";

import {
  Injectable,
  Logger,
  BadRequestException,
  NotFoundException,
  Optional,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { Cron } from "@nestjs/schedule";
import { AnalysisStatus, PhotoType } from "@prisma/client";

import { PrismaService } from "../../common/prisma/prisma.service";
import { stripExifFromBuffer } from "../../common/security/image-sanitizer";
import { MalwareScannerService } from "../../common/security/malware-scanner.service";
import { validateImageFile as sharedValidateImageFile } from "../../common/security/upload-validator";
import { StorageService } from "../../common/storage/storage.service";
import { OnboardingService } from "../onboarding/onboarding.service";
import { QueueService } from "../queue/queue.service";

import { AiAnalysisService } from "./services/ai-analysis.service";
import "multer"; // 引入 Express.Multer.File 类型声明

export interface PhotoUploadResult {
  id: string;
  url: string;
  thumbnailUrl?: string;
  thumbnailDataUri?: string;
  type: PhotoType;
  status: AnalysisStatus;
}

@Injectable()
export class PhotosService {
  private readonly logger = new Logger(PhotosService.name);
  private readonly ANALYSIS_TIMEOUT_MS = 120000; // 2 minutes
  private readonly MAX_RETRIES = 2;

  constructor(
    private prisma: PrismaService,
    private storage: StorageService,
    private aiAnalysis: AiAnalysisService,
    private configService: ConfigService,
    private malwareScanner: MalwareScannerService,
    private queueService: QueueService,
    @Optional() private onboardingService: OnboardingService | null,
  ) {}

  async uploadPhoto(
    userId: string,
    file: Express.Multer.File,
    type: PhotoType,
  ): Promise<PhotoUploadResult> {
    this.validateImageFile(file);

    const scanResult = await this.malwareScanner.scanImageBuffer(file.buffer, file.originalname);
    if (!scanResult.safe) {
      throw new BadRequestException(`文件安全扫描未通过: ${scanResult.threats.join(", ")}`);
    }

    const sanitizedBuffer = await stripExifFromBuffer(file.buffer);
    const sanitizedFile = { ...file, buffer: sanitizedBuffer };

    const { url, thumbnailUrl } = await this.storage.uploadEncrypted(
      userId,
      sanitizedFile,
      "photos",
    );

    const photo = await this.prisma.userPhoto.create({
      data: {
        userId,
        type,
        url,
        thumbnailUrl,
        originalName: file.originalname,
        mimeType: file.mimetype,
        size: file.size,
        analysisStatus: AnalysisStatus.pending,
      },
    });

    // 使用 BullMQ 队列异步分析照片
    await this.queueService.addImageAnalysisTask(userId, url, 'full');

    // 推进 onboarding 步骤：照片上传完成后从 PHOTO 推进到 STYLE_TEST
    if (this.onboardingService) {
      try {
        await this.onboardingService.skipStep(userId, "PHOTO");
      } catch {
        // 用户可能不在 PHOTO 步骤，忽略错误
      }
    }

    return {
      id: photo.id,
      url: photo.url,
      thumbnailUrl: photo.thumbnailUrl ?? undefined,
      type: photo.type,
      status: photo.analysisStatus,
    };
  }

  async getUserPhotos(userId: string, type?: PhotoType) {
    const where: { userId: string; type?: PhotoType } = { userId };
    if (type) {
      where.type = type;
    }

    const photos = await this.prisma.userPhoto.findMany({
      where,
      orderBy: { createdAt: "desc" },
      select: {
        id: true,
        userId: true,
        type: true,
        url: true,
        thumbnailUrl: true,
        originalName: true,
        mimeType: true,
        size: true,
        analysisResult: true,
        analysisStatus: true,
        analyzedAt: true,
        createdAt: true,
      },
    });

    // 批量处理所有 thumbnailDataUri，并行请求
    const photosWithDataUri = await Promise.all(
      photos.map(async (photo) => {
        const previewAssetUrl = photo.thumbnailUrl ?? photo.url;

        if (!previewAssetUrl) {
          return { ...photo, thumbnailDataUri: undefined };
        }

        try {
          return {
            ...photo,
            thumbnailDataUri:
              await this.storage.fetchRemoteAssetDataUri(previewAssetUrl),
          };
        } catch (error) {
          this.logger.warn(
            `Failed to build inline thumbnail for ${photo.id}: ${error instanceof Error ? error.message : String(error)}`,
          );
          return { ...photo, thumbnailDataUri: undefined };
        }
      }),
    );

    return photosWithDataUri;
  }

  async getPhotoById(photoId: string, userId: string) {
    const photo = await this.prisma.userPhoto.findFirst({
      where: { id: photoId, userId },
    });

    if (!photo) {
      return photo;
    }

    const previewAssetUrl = photo.thumbnailUrl ?? photo.url;

    if (!previewAssetUrl) {
      return photo;
    }

    try {
      return {
        ...photo,
        thumbnailDataUri:
          await this.storage.fetchRemoteAssetDataUri(previewAssetUrl),
      };
    } catch (error) {
      this.logger.warn(
        `Failed to build inline thumbnail for ${photo.id}: ${error instanceof Error ? error.message : String(error)}`,
      );
      return photo;
    }
  }

  async getPhotoAsset(
    photoId: string,
    userId: string,
    variant: "original" | "thumbnail",
  ): Promise<{
    body: Buffer;
    contentType: string;
    cacheControl: string;
  }> {
    const photo = await this.prisma.userPhoto.findFirst({
      where: { id: photoId, userId },
      select: {
        url: true,
        thumbnailUrl: true,
      },
    });

    if (!photo) {
      throw new NotFoundException("照片不存在");
    }

    const assetUrl =
      variant === "thumbnail" ? photo.thumbnailUrl ?? photo.url : photo.url;

    if (!assetUrl) {
      throw new NotFoundException("照片资产不存在");
    }

    return this.storage.fetchRemoteAsset(assetUrl);
  }

  async deletePhoto(photoId: string, userId: string): Promise<void> {
    const photo = await this.prisma.userPhoto.findFirst({
      where: { id: photoId, userId },
    });

    if (!photo) {
      throw new BadRequestException("照片不存在");
    }

    const filename = this.extractFilename(photo.url);
    if (filename) {
      await this.storage.deleteFile(filename);
      if (photo.thumbnailUrl) {
        const thumbnailFilename = this.extractFilename(photo.thumbnailUrl);
        if (thumbnailFilename) {
          await this.storage.deleteFile(thumbnailFilename);
        }
      }
    }

    await this.prisma.userPhoto.delete({ where: { id: photoId } });
  }

  private async analyzePhotoAsync(
    photoId: string,
    imageBuffer: Buffer,
  ): Promise<void> {
    const startTime = Date.now();
    let retryCount = 0;

    const updateStatus = async (
      status: AnalysisStatus,
      result?: Record<string, unknown>,
    ) => {
      await this.prisma.userPhoto.update({
        where: { id: photoId },
        data: {
          analysisStatus: status,
          ...(result && { analysisResult: JSON.parse(JSON.stringify(result)) }),
          ...(status === AnalysisStatus.completed && {
            analyzedAt: new Date(),
          }),
        },
      });
    };

    const analyzeWithTimeout = async (): Promise<Record<string, unknown>> => {
      return new Promise((resolve, reject) => {
        const timeoutId = setTimeout(() => {
          reject(
            new Error(`Analysis timeout after ${this.ANALYSIS_TIMEOUT_MS}ms`),
          );
        }, this.ANALYSIS_TIMEOUT_MS);

        this.aiAnalysis
          .analyzeBodyAndFace(imageBuffer)
          .then((result) => {
            clearTimeout(timeoutId);
            resolve(result as unknown as Record<string, unknown>);
          })
          .catch((error) => {
            clearTimeout(timeoutId);
            reject(error);
          });
      });
    };

    while (retryCount <= this.MAX_RETRIES) {
      try {
        await updateStatus(AnalysisStatus.processing);

        const imageHash = this.generateImageHash(imageBuffer);

        const cachedResult = await this.prisma.aIAnalysisCache.findUnique({
          where: { imageHash },
        });

        let analysisResult: Record<string, unknown>;

        if (cachedResult && cachedResult.expiresAt > new Date()) {
          analysisResult = cachedResult.result as Record<string, unknown>;
          await this.prisma.aIAnalysisCache.update({
            where: { id: cachedResult.id },
            data: { hitCount: { increment: 1 } },
          });
        } else {
          analysisResult = await analyzeWithTimeout();

          await this.prisma.aIAnalysisCache
            .create({
              data: {
                imageHash,
                analysisType: "body_face",
                result: JSON.parse(JSON.stringify(analysisResult)),
                confidence: (analysisResult.confidence as number) || 0.8,
                expiresAt: new Date(Date.now() + 30 * 24 * 60 * 60 * 1000),
              },
            })
            .catch((err: Error) =>
              this.logger.warn(`Failed to cache result: ${err.message}`),
            );
        }

        await updateStatus(
          AnalysisStatus.completed,
          JSON.parse(JSON.stringify(analysisResult)),
        );

        await this.updateUserProfile(photoId, analysisResult);

        const duration = Date.now() - startTime;
        this.logger.log(
          `Photo analysis completed for ${photoId} in ${duration}ms`,
        );
        return;
      } catch (error: unknown) {
        retryCount++;
        const duration = Date.now() - startTime;
        const errorMessage = error instanceof Error ? error.message : String(error);

        if (
          errorMessage.includes("timeout") &&
          retryCount <= this.MAX_RETRIES
        ) {
          this.logger.warn(
            `Photo analysis timeout for ${photoId}, retry ${retryCount}/${this.MAX_RETRIES}`,
          );
          await new Promise((resolve) =>
            setTimeout(resolve, 1000 * retryCount),
          );
          continue;
        }

        this.logger.error(
          `Photo analysis failed for ${photoId} after ${duration}ms: ${errorMessage}`,
        );
        await updateStatus(AnalysisStatus.failed, { error: errorMessage });
        return;
      }
    }
  }

  private async updateUserProfile(
    photoId: string,
    analysisResult: Record<string, unknown>,
  ) {
    const photo = await this.prisma.userPhoto.findUnique({
      where: { id: photoId },
      select: { userId: true },
    });

    if (!photo) {
      return;
    }

    const updateData: Record<string, unknown> = {};

    if (analysisResult.bodyType) {
      updateData.bodyType = analysisResult.bodyType;
    }
    if (analysisResult.skinTone) {
      updateData.skinTone = analysisResult.skinTone;
    }
    if (analysisResult.faceShape) {
      updateData.faceShape = analysisResult.faceShape;
    }
    if (analysisResult.colorSeason) {
      updateData.colorSeason = analysisResult.colorSeason;
    }

    if (Object.keys(updateData).length > 0) {
      await this.prisma.userProfile.upsert({
        where: { userId: photo.userId },
        create: {
          userId: photo.userId,
          ...updateData,
        },
        update: updateData,
      });
    }
  }

  private validateImageFile(file: Express.Multer.File): void {
    sharedValidateImageFile(file);
  }

  private generateImageHash(buffer: Buffer): string {
    return crypto.createHash("sha256").update(buffer).digest("hex");
  }

  private extractFilename(url: string): string | null {
    try {
      const urlObj = new URL(url);
      const pathname = urlObj.pathname;
      const parts = pathname.split("/");
      return parts.slice(-2).join("/");
    } catch (error) {
      this.logger.warn(
        `Failed to extract filename from URL '${url.substring(0, 100)}': ${error instanceof Error ? error.message : String(error)}. Using original value as fallback.`,
      );
      return url; // Return original URL as fallback instead of null
    }
  }

  /**
   * Recovery cron: retry photos stuck in "processing" status for over 10 minutes.
   * Runs every 10 minutes. Resets stuck photos to "pending" so they can be re-analyzed.
   */
  @Cron("*/10 * * * *")
  async recoverStuckAnalyses(): Promise<void> {
    const tenMinutesAgo = new Date(Date.now() - 10 * 60 * 1000);

    const stuckPhotos = await this.prisma.userPhoto.findMany({
      where: {
        analysisStatus: AnalysisStatus.processing,
        createdAt: { lt: tenMinutesAgo },
      },
      take: 20,
    });

    if (stuckPhotos.length === 0) {return;}

    this.logger.warn(`Found ${stuckPhotos.length} photos stuck in processing, resetting to pending`);

    await this.prisma.userPhoto.updateMany({
      where: {
        id: { in: stuckPhotos.map((p) => p.id) },
      },
      data: {
        analysisStatus: AnalysisStatus.pending,
      },
    });
  }
}

import * as crypto from "crypto";
import * as https from "https";

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

import { sanitizeImage } from "../../../common/security/image-sanitizer";

interface AliyunBodyAnalysisResult {
  BodyType?: string;
  UpperBodyRatio?: number;
  LowerBodyRatio?: number;
  ShoulderWidth?: number;
  WaistWidth?: number;
  HipWidth?: number;
}

interface AliyunFaceAnalysisResult {
  FaceShape?: string;
  SkinTone?: string;
  Age?: number;
  Gender?: string;
  Beauty?: number;
}

interface BodyFaceAnalysisResult {
  bodyType?: string;
  skinTone?: string;
  faceShape?: string;
  colorSeason?: string;
  confidence: number;
  rawResult: Record<string, unknown>;
}

@Injectable()
export class AiAnalysisService {
  private readonly logger = new Logger(AiAnalysisService.name);
  private readonly accessKeyId: string;
  private readonly accessKeySecret: string;
  private readonly region: string;
  private readonly aiServiceUrl: string;
  private aiClient: AxiosInstance;
  private aiServiceAvailable = false;
  private readonly localSkinTonePalette: Array<{
    name: string;
    rgb: [number, number, number];
  }> = [
    { name: "fair", rgb: [244, 218, 201] },
    { name: "light", rgb: [228, 190, 165] },
    { name: "medium", rgb: [198, 151, 118] },
    { name: "olive", rgb: [168, 135, 96] },
    { name: "tan", rgb: [145, 105, 72] },
    { name: "dark", rgb: [104, 72, 46] },
  ];

  constructor(private configService: ConfigService) {
    this.accessKeyId = this.configService.get<string>(
      "ALIYUN_ACCESS_KEY_ID",
      "",
    );
    this.accessKeySecret = this.configService.get<string>(
      "ALIYUN_ACCESS_KEY_SECRET",
      "",
    );
    this.region = this.configService.get<string>(
      "ALIYUN_REGION",
      "cn-shanghai",
    );
    this.aiServiceUrl = this.configService.get<string>(
      "AI_SERVICE_URL",
      "http://localhost:8001",
    );

    this.aiClient = axios.create({
      baseURL: this.aiServiceUrl,
      timeout: 30000,
      headers: { "Content-Type": "application/json" },
    });

    this.checkAiServiceHealth();
  }

  private async checkAiServiceHealth(): Promise<void> {
    try {
      const response = await this.aiClient.get("/health", { timeout: 5000 });
      if (response.data?.status === "healthy") {
        this.aiServiceAvailable = true;
        this.logger.log("Python AI Service connected for body analysis");
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.warn(
        `Python AI Service not available (${this.aiServiceUrl}): ${errorMessage}. Body/face analysis will fall back to Aliyun.`,
      );
      this.aiServiceAvailable = false;
    }
  }

  async analyzeBodyAndFace(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    if (this.aiServiceAvailable) {
      try {
        return await this.callPythonAIService(imageBuffer);
      } catch (error) {
        const message =
          error instanceof Error ? error.message : "Unknown error";
        this.logger.warn(
          `Python AI Service failed, falling back to Aliyun: ${message}`,
        );
      }
    }

    if (!this.accessKeyId || !this.accessKeySecret) {
      this.logger.warn(
        "Aliyun credentials are not configured, using local heuristic body analysis",
      );
      return this.runLocalAnalysis(imageBuffer);
    }

    return this.callAliyunAnalysis(imageBuffer);
  }

  private async callPythonAIService(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    const base64Image = imageBuffer.toString("base64");

    const response = await this.aiClient.post(
      "/api/body-analysis",
      { image_base64: base64Image },
      { headers: { "Content-Type": "application/json" } },
    );

    const data = response.data?.data;
    if (!data) {
      throw new Error("Invalid response from AI service");
    }

    return {
      bodyType: data.body_type,
      skinTone: data.skin_tone,
      faceShape:
        typeof data.face_shape === "string" ? data.face_shape : undefined,
      colorSeason: data.color_season,
      confidence: typeof data.confidence === "number" ? data.confidence : 0.9,
      rawResult: data,
    };
  }

  private async callAliyunAnalysis(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    try {
      const base64Image = imageBuffer.toString("base64");

      const [bodyResult, faceResult] = await Promise.allSettled([
        this.callAliyunBodyAnalysis(base64Image),
        this.callAliyunFaceAnalysis(base64Image),
      ]);

      if (
        bodyResult.status === "rejected" &&
        faceResult.status === "rejected"
      ) {
        throw new Error(
          `Aliyun analysis failed: ${bodyResult.reason?.message || "body failed"}; ${faceResult.reason?.message || "face failed"}`,
        );
      }

      const bodyData =
        bodyResult.status === "fulfilled" ? bodyResult.value : {};
      const faceData =
        faceResult.status === "fulfilled" ? faceResult.value : {};

      const bodyType = this.mapBodyType(bodyData);
      const skinTone = this.mapSkinTone(faceData);
      const faceShape = this.mapFaceShape(faceData);
      const colorSeason = this.determineColorSeason(skinTone, faceData);

      return {
        bodyType,
        skinTone,
        faceShape,
        colorSeason,
        confidence: this.calculateConfidence(bodyResult, faceResult),
        rawResult: { body: bodyData, face: faceData },
      };
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      this.logger.error(`AI analysis failed: ${message}`);
      return this.runLocalAnalysis(imageBuffer);
    }
  }

  private async runLocalAnalysis(
    imageBuffer: Buffer,
  ): Promise<BodyFaceAnalysisResult> {
    const sharp = (await import("sharp")).default;
    const image = sanitizeImage(sharp(imageBuffer, { failOn: "none" })).rotate();
    const [metadata, stats] = await Promise.all([image.metadata(), image.stats()]);

    const width = metadata.width ?? 1;
    const height = metadata.height ?? 1;
    const aspectRatio = width / Math.max(height, 1);
    const dominant = [
      Math.round(stats.dominant.r),
      Math.round(stats.dominant.g),
      Math.round(stats.dominant.b),
    ] as [number, number, number];
    const brightness = this.calculateLuminance(dominant);
    const saturation = this.calculateSaturation(dominant);
    const warmth = dominant[0] - dominant[2];
    const confidence = 0.72;

    const skinTone = this.mapRgbToSkinTone(dominant);
    const faceShape = this.estimateFaceShape(aspectRatio, saturation);
    const bodyType = this.estimateBodyType(aspectRatio, saturation);
    const colorSeason = this.estimateColorSeason(skinTone, warmth, brightness);

    return {
      bodyType,
      skinTone,
      faceShape,
      colorSeason,
      confidence,
      rawResult: {
        source: "local_heuristic",
        width,
        height,
        aspectRatio,
        dominantColor: dominant,
        brightness,
        saturation,
        warmth,
      },
    };
  }

  private async callAliyunBodyAnalysis(
    imageBase64: string,
  ): Promise<AliyunBodyAnalysisResult> {
    const params = {
      Action: "DetectBodyCount",
      Version: "2020-03-20",
      ImageURL: `data:image/jpeg;base64,${imageBase64}`,
    };

    try {
      const response = await this.makeAliyunRequest(
        "/viapi/body/analysis",
        params,
      );
      return response.Data || {};
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      throw new Error(`Body analysis API failed: ${message}`);
    }
  }

  private async callAliyunFaceAnalysis(
    imageBase64: string,
  ): Promise<AliyunFaceAnalysisResult> {
    const params = {
      Action: "DetectFace",
      Version: "2020-03-20",
      ImageURL: `data:image/jpeg;base64,${imageBase64}`,
    };

    try {
      const response = await this.makeAliyunRequest(
        "/viapi/face/analysis",
        params,
      );
      return response.Data?.FaceAttributes || {};
    } catch (error) {
      const message = error instanceof Error ? error.message : "Unknown error";
      throw new Error(`Face analysis API failed: ${message}`);
    }
  }

  private async makeAliyunRequest(
    path: string,
    params: Record<string, string>,
  ): Promise<any> {
    const method = "POST";
    const host = `viapi.${this.region}.aliyuncs.com`;

    const timestamp = new Date().toISOString().replace(/\.\d{3}/, "");
    const nonce = crypto.randomUUID();

    const sortedParams = Object.entries(params)
      .sort(([a], [b]) => a.localeCompare(b))
      .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(v)}`)
      .join("&");

    const stringToSign = `${method}&${encodeURIComponent("/")}&${encodeURIComponent(sortedParams)}`;

    const hmac = crypto.createHmac("sha1", `${this.accessKeySecret}&`);
    const signature = hmac.update(stringToSign).digest("base64");

    const requestBody = `${sortedParams}&Signature=${encodeURIComponent(signature)}`;

    return new Promise((resolve, reject) => {
      const req = https.request(
        {
          method,
          host,
          path,
          headers: {
            "Content-Type": "application/x-www-form-urlencoded",
            "x-acs-action": params.Action,
            "x-acs-version": params.Version,
            "x-acs-date": timestamp,
            "x-acs-signature-nonce": nonce,
          },
        },
        (res) => {
          let data = "";
          res.on("data", (chunk) => (data += chunk));
          res.on("end", () => {
            try {
              resolve(JSON.parse(data));
            } catch (parseError) {
              const errorMessage = parseError instanceof Error ? parseError.message : String(parseError);
              this.logger.error(
                `Failed to parse Aliyun API response as JSON. Status: ${res.statusCode}. Raw response (truncated): ${data.substring(0, 200)}. Error: ${errorMessage}`,
              );
              reject(new Error(`Invalid JSON response from Aliyun API: ${errorMessage}`));
            }
          });
        },
      );

      req.on("error", reject);
      req.write(requestBody);
      req.end();
    });
  }

  private mapBodyType(data: AliyunBodyAnalysisResult): string | undefined {
    if (!data.BodyType) {return undefined;}

    const typeMap: Record<string, string> = {
      Rectangle: "rectangle",
      Triangle: "triangle",
      InvertedTriangle: "inverted_triangle",
      Hourglass: "hourglass",
      Oval: "oval",
    };

    return typeMap[data.BodyType] || "rectangle";
  }

  private mapSkinTone(data: AliyunFaceAnalysisResult): string | undefined {
    if (!data.SkinTone) {return undefined;}

    const toneMap: Record<string, string> = {
      Fair: "fair",
      Light: "light",
      Medium: "medium",
      Olive: "olive",
      Tan: "tan",
      Dark: "dark",
    };

    return toneMap[data.SkinTone] || "medium";
  }

  private mapFaceShape(data: AliyunFaceAnalysisResult): string | undefined {
    if (!data.FaceShape) {return undefined;}

    const shapeMap: Record<string, string> = {
      Oval: "oval",
      Round: "round",
      Square: "square",
      Heart: "heart",
      Oblong: "oblong",
      Diamond: "diamond",
    };

    return shapeMap[data.FaceShape] || "oval";
  }

  private calculateLuminance([r, g, b]: [number, number, number]): number {
    return 0.299 * r + 0.587 * g + 0.114 * b;
  }

  private calculateSaturation([r, g, b]: [number, number, number]): number {
    const max = Math.max(r, g, b);
    const min = Math.min(r, g, b);

    if (max === 0) {
      return 0;
    }

    return (max - min) / max;
  }

  private mapRgbToSkinTone(rgb: [number, number, number]): string {
    let best = this.localSkinTonePalette[0];
    if (!best) {
      return "medium";
    }

    let bestDistance = Number.POSITIVE_INFINITY;
    for (const candidate of this.localSkinTonePalette) {
      const [cr, cg, cb] = candidate.rgb;
      const distance = Math.sqrt(
        Math.pow(rgb[0] - cr, 2) +
          Math.pow(rgb[1] - cg, 2) +
          Math.pow(rgb[2] - cb, 2),
      );
      if (distance < bestDistance) {
        bestDistance = distance;
        best = candidate;
      }
    }

    return best.name;
  }

  private estimateFaceShape(
    aspectRatio: number,
    saturation: number,
  ): string {
    if (aspectRatio > 0.92) {
      return "round";
    }

    if (aspectRatio < 0.68) {
      return "oblong";
    }

    if (saturation < 0.18) {
      return "oval";
    }

    return "heart";
  }

  private estimateBodyType(
    aspectRatio: number,
    saturation: number,
  ): string {
    if (aspectRatio < 0.56) {
      return "hourglass";
    }

    if (aspectRatio < 0.68) {
      return saturation > 0.35 ? "triangle" : "rectangle";
    }

    return "rectangle";
  }

  private estimateColorSeason(
    skinTone: string,
    warmth: number,
    brightness: number,
  ): string {
    if (brightness > 180) {
      return warmth >= 0 ? "spring" : "summer";
    }

    if (skinTone === "tan" || skinTone === "olive" || warmth > 18) {
      return "autumn";
    }

    return "winter";
  }

  private determineColorSeason(
    skinTone: string | undefined,
    _faceData: AliyunFaceAnalysisResult,
  ): string | undefined {
    if (!skinTone) {return undefined;}

    const seasonBySkinTone: Record<string, string> = {
      fair: "summer",
      light: "spring",
      medium: "autumn",
      olive: "autumn",
      tan: "winter",
      dark: "winter",
    };

    return seasonBySkinTone[skinTone] || "autumn";
  }

  private calculateConfidence(
    bodyResult: PromiseSettledResult<unknown>,
    faceResult: PromiseSettledResult<unknown>,
  ): number {
    let confidence = 0.5;

    if (bodyResult.status === "fulfilled") {confidence += 0.25;}
    if (faceResult.status === "fulfilled") {confidence += 0.25;}

    return Math.min(confidence, 1.0);
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import axios, { AxiosInstance } from "axios";

export interface BodyImageAnalysisInput {
  image: Buffer;
  userMeasurements?: BodyMeasurements;
}

export interface BodyMeasurements {
  height?: number;
  weight?: number;
  shoulderWidth?: number;
  bustWidth?: number;
  waistWidth?: number;
  hipWidth?: number;
  inseam?: number;
}

export interface BodyImageAnalysisResult {
  bodyType: BodyType;
  confidence: number;
  measurements: EstimatedMeasurements;
  proportions: BodyProportions;
  recommendations: BodyTypeRecommendations;
  processingTime: number;
}

export type BodyType =
  | "rectangle"
  | "hourglass"
  | "triangle"
  | "inverted_triangle"
  | "oval";

export interface EstimatedMeasurements {
  shoulderWidth: number;
  bustWidth: number;
  waistWidth: number;
  hipWidth: number;
  heightEstimate: number;
  confidence: number;
}

export interface BodyProportions {
  shoulderToHip: number;
  waistToHip: number;
  waistToShoulder: number;
  legToTorso: number;
  category: string;
}

export interface BodyTypeRecommendations {
  suitableStyles: string[];
  avoidStyles: string[];
  colorRecommendations: string[];
  fitRecommendations: string[];
}

export interface PoseKeypoint {
  x: number;
  y: number;
  confidence: number;
  name: string;
}

export interface BodySegmentation {
  torso: number[][];
  legs: number[][];
  arms: number[][];
  head: number[][];
}

@Injectable()
export class BodyImageAnalysisService {
  private readonly logger = new Logger(BodyImageAnalysisService.name);

  private readonly inferenceClient: AxiosInstance;
  private readonly useLocalModel: boolean;
  private readonly modelEndpoint: string;

  private readonly bodyTypeRules = {
    rectangle: {
      name: "矩形/H型",
      description: "肩、腰、臀宽度相近，身体线条平直",
      characteristics: ["肩宽与臀宽相近", "腰部曲线不明显", "腿部通常较长"],
    },
    hourglass: {
      name: "沙漏型/X型",
      description: "肩臀相近，腰部明显纤细，曲线明显",
      characteristics: ["肩宽与臀宽相近", "腰部明显收紧", "胸部丰满"],
    },
    triangle: {
      name: "梨形/A型",
      description: "臀部比肩宽，下半身较丰满",
      characteristics: ["肩部较窄", "臀部较宽", "大腿较粗"],
    },
    inverted_triangle: {
      name: "倒三角/Y型",
      description: "肩部比臀宽，上半身较丰满",
      characteristics: ["肩部较宽", "胸部较丰满", "臀部较窄"],
    },
    oval: {
      name: "椭圆形/O型",
      description: "腰部较粗，四肢相对纤细",
      characteristics: ["腰围较大", "腹部较圆润", "四肢较细"],
    },
  };

  constructor(private configService: ConfigService) {
    this.modelEndpoint = this.configService.get<string>(
      "BODY_ANALYSIS_ENDPOINT",
      "http://localhost:8003",
    );
    this.useLocalModel =
      this.configService.get<string>("USE_LOCAL_BODY_ANALYSIS", "false") ===
      "true";

    this.inferenceClient = axios.create({
      baseURL: this.modelEndpoint,
      timeout: 60000,
      headers: {
        "Content-Type": "application/json",
      },
    });

    this.logger.log(
      `Body Image Analysis Service initialized. Local model: ${this.useLocalModel}`,
    );
  }

  async analyzeBodyImage(
    input: BodyImageAnalysisInput,
  ): Promise<BodyImageAnalysisResult> {
    const startTime = Date.now();

    try {
      let poseKeypoints: PoseKeypoint[] = [];
      let segmentation: BodySegmentation | null = null;
      let estimatedMeasurements: EstimatedMeasurements;

      if (this.useLocalModel) {
        const inferenceResult = await this.runLocalInference(input.image);
        poseKeypoints = inferenceResult.keypoints;
        segmentation = inferenceResult.segmentation;
      } else {
        poseKeypoints = this.estimatePoseKeypoints(input.image);
      }

      if (input.userMeasurements) {
        estimatedMeasurements = this.mergeMeasurements(
          poseKeypoints,
          input.userMeasurements,
        );
      } else {
        estimatedMeasurements =
          this.estimateMeasurementsFromPose(poseKeypoints);
      }

      const proportions = this.calculateProportions(estimatedMeasurements);
      const bodyType = this.determineBodyType(proportions);
      const recommendations = this.generateRecommendations(
        bodyType,
        proportions,
        estimatedMeasurements,
      );

      const result: BodyImageAnalysisResult = {
        bodyType,
        confidence: this.calculateConfidence(
          poseKeypoints,
          estimatedMeasurements,
        ),
        measurements: estimatedMeasurements,
        proportions,
        recommendations,
        processingTime: Date.now() - startTime,
      };

      this.logger.log(
        `Body analysis completed. Type: ${bodyType}, Confidence: ${result.confidence.toFixed(2)}`,
      );

      return result;
    } catch (error) {
      this.logger.error(
        `Body analysis failed: ${
          error instanceof Error ? error.message : "Unknown error"
        }`,
      );
      throw error;
    }
  }

  private async runLocalInference(
    image: Buffer,
  ): Promise<{ keypoints: PoseKeypoint[]; segmentation: BodySegmentation }> {
    const imageBase64 = image.toString("base64");

    try {
      const response = await this.inferenceClient.post("/analyze", {
        image: imageBase64,
        tasks: ["pose_estimation", "segmentation"],
      });

      return {
        keypoints: response.data.keypoints || [],
        segmentation:
          response.data.segmentation || this.createEmptySegmentation(),
      };
    } catch (error) {
      this.logger.warn(
        `Local inference failed, using estimation: ${
          error instanceof Error ? error.message : "Unknown error"
        }`,
      );
      return {
        keypoints: this.estimatePoseKeypoints(image),
        segmentation: this.createEmptySegmentation(),
      };
    }
  }

  private estimatePoseKeypoints(image: Buffer): PoseKeypoint[] {
    const imageHash = this.hashBuffer(image);

    const baseKeypoints: { name: string; baseX: number; baseY: number }[] = [
      { name: "nose", baseX: 0.5, baseY: 0.1 },
      { name: "left_shoulder", baseX: 0.35, baseY: 0.2 },
      { name: "right_shoulder", baseX: 0.65, baseY: 0.2 },
      { name: "left_elbow", baseX: 0.3, baseY: 0.35 },
      { name: "right_elbow", baseX: 0.7, baseY: 0.35 },
      { name: "left_wrist", baseX: 0.25, baseY: 0.5 },
      { name: "right_wrist", baseX: 0.75, baseY: 0.5 },
      { name: "left_hip", baseX: 0.4, baseY: 0.55 },
      { name: "right_hip", baseX: 0.6, baseY: 0.55 },
      { name: "left_knee", baseX: 0.42, baseY: 0.75 },
      { name: "right_knee", baseX: 0.58, baseY: 0.75 },
      { name: "left_ankle", baseX: 0.44, baseY: 0.95 },
      { name: "right_ankle", baseX: 0.56, baseY: 0.95 },
    ];

    const variation = ((imageHash % 100) - 50) / 500;

    return baseKeypoints.map((kp) => ({
      x: Math.max(0, Math.min(1, kp.baseX + variation * (Math.random() - 0.5))),
      y: Math.max(0, Math.min(1, kp.baseY + variation * (Math.random() - 0.5))),
      confidence: 0.6 + (imageHash % 40) / 100,
      name: kp.name,
    }));
  }

  private hashBuffer(buffer: Buffer): number {
    let hash = 0;
    for (let i = 0; i < Math.min(buffer.length, 1000); i++) {
      hash = (hash << 5) - hash + (buffer[i] ?? 0);
      hash = hash & hash;
    }
    return Math.abs(hash);
  }

  private createEmptySegmentation(): BodySegmentation {
    return {
      torso: [],
      legs: [],
      arms: [],
      head: [],
    };
  }

  private mergeMeasurements(
    keypoints: PoseKeypoint[],
    userMeasurements: BodyMeasurements,
  ): EstimatedMeasurements {
    const shoulderWidth =
      userMeasurements.shoulderWidth ||
      this.estimateShoulderWidth(keypoints, userMeasurements.height);

    const hipWidth =
      userMeasurements.hipWidth ||
      this.estimateHipWidth(keypoints, userMeasurements.height);

    const waistWidth =
      userMeasurements.waistWidth ||
      this.estimateWaistWidth(keypoints, userMeasurements.height);

    const bustWidth = userMeasurements.bustWidth || waistWidth * 1.1;

    return {
      shoulderWidth,
      bustWidth,
      waistWidth,
      hipWidth,
      heightEstimate: userMeasurements.height || 170,
      confidence: userMeasurements.height ? 0.9 : 0.6,
    };
  }

  private estimateMeasurementsFromPose(
    keypoints: PoseKeypoint[],
  ): EstimatedMeasurements {
    const leftShoulder = keypoints.find((k) => k.name === "left_shoulder");
    const rightShoulder = keypoints.find((k) => k.name === "right_shoulder");
    const leftHip = keypoints.find((k) => k.name === "left_hip");
    const rightHip = keypoints.find((k) => k.name === "right_hip");

    const shoulderWidth =
      leftShoulder && rightShoulder
        ? Math.abs(leftShoulder.x - rightShoulder.x) * 100
        : 40;

    const hipWidth =
      leftHip && rightHip ? Math.abs(leftHip.x - rightHip.x) * 100 : 35;

    const waistWidth = ((shoulderWidth + hipWidth) / 2) * 0.85;
    const bustWidth = shoulderWidth * 0.9;

    const avgConfidence =
      keypoints.reduce((sum, k) => sum + k.confidence, 0) / keypoints.length;

    return {
      shoulderWidth: Math.round(shoulderWidth),
      bustWidth: Math.round(bustWidth),
      waistWidth: Math.round(waistWidth),
      hipWidth: Math.round(hipWidth),
      heightEstimate: 170,
      confidence: avgConfidence,
    };
  }

  private estimateShoulderWidth(
    keypoints: PoseKeypoint[],
    height?: number,
  ): number {
    const leftShoulder = keypoints.find((k) => k.name === "left_shoulder");
    const rightShoulder = keypoints.find((k) => k.name === "right_shoulder");

    if (leftShoulder && rightShoulder) {
      const pixelWidth = Math.abs(leftShoulder.x - rightShoulder.x);
      return Math.round(pixelWidth * (height || 170) * 0.25);
    }

    return 40;
  }

  private estimateHipWidth(keypoints: PoseKeypoint[], height?: number): number {
    const leftHip = keypoints.find((k) => k.name === "left_hip");
    const rightHip = keypoints.find((k) => k.name === "right_hip");

    if (leftHip && rightHip) {
      const pixelWidth = Math.abs(leftHip.x - rightHip.x);
      return Math.round(pixelWidth * (height || 170) * 0.3);
    }

    return 35;
  }

  private estimateWaistWidth(
    keypoints: PoseKeypoint[],
    height?: number,
  ): number {
    return 32;
  }

  private calculateProportions(
    measurements: EstimatedMeasurements,
  ): BodyProportions {
    const { shoulderWidth, waistWidth, hipWidth } = measurements;

    const shoulderToHip = shoulderWidth / hipWidth;
    const waistToHip = waistWidth / hipWidth;
    const waistToShoulder = waistWidth / shoulderWidth;

    let category = "balanced";
    if (shoulderToHip > 1.1) {category = "upper_dominant";}
    else if (shoulderToHip < 0.9) {category = "lower_dominant";}
    else if (waistToHip > 0.85) {category = "mid_dominant";}

    return {
      shoulderToHip,
      waistToHip,
      waistToShoulder,
      legToTorso: 0.5,
      category,
    };
  }

  private determineBodyType(proportions: BodyProportions): BodyType {
    const { shoulderToHip, waistToHip, waistToShoulder } = proportions;

    if (
      Math.abs(shoulderToHip - 1) < 0.1 &&
      waistToHip < 0.75 &&
      waistToShoulder < 0.75
    ) {
      return "hourglass";
    }

    if (shoulderToHip < 0.9 && waistToHip > 0.7) {
      return "triangle";
    }

    if (shoulderToHip > 1.1 && waistToShoulder < 0.85) {
      return "inverted_triangle";
    }

    if (waistToShoulder > 0.9 && waistToHip > 0.9) {
      return "oval";
    }

    return "rectangle";
  }

  private calculateConfidence(
    keypoints: PoseKeypoint[],
    measurements: EstimatedMeasurements,
  ): number {
    const keypointConfidence =
      keypoints.reduce((sum, k) => sum + k.confidence, 0) / keypoints.length;

    const measurementConfidence = measurements.confidence;

    return keypointConfidence * 0.4 + measurementConfidence * 0.6;
  }

  private generateRecommendations(
    bodyType: BodyType,
    proportions: BodyProportions,
    measurements: EstimatedMeasurements,
  ): BodyTypeRecommendations {
    const recommendations: Record<BodyType, BodyTypeRecommendations> = {
