      email: "test@example.com",
      profile: {
        bodyType: "hourglass",
        colorSeason: "spring_warm",
        stylePreferences: ["casual", "elegant"],
      },
    }),
    getBodyAnalysis: jest.fn().mockResolvedValue({
      bodyType: "hourglass",
      bodyTypeName: "X型（沙漏）体型",
      description: "您的肩部和臀部宽度相近",
      recommendations: [
        { category: "上衣", advice: "突出腰线的款式", examples: ["收腰衬衫"] },
      ],
      idealStyles: ["收腰设计", "高腰裤", "裹身裙"],
      avoidStyles: ["过于宽松的款式"],
    }),
    getColorAnalysis: jest.fn().mockResolvedValue({
      colorSeason: "spring_warm",
      colorSeasonName: "春季暖型",
      bestColors: ["珊瑚色", "桃色", "杏色"],
      neutralColors: ["暖米色", "驼色"],
      avoidColors: ["纯黑色"],
      metalPreference: "金色饰品",
    }),
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        PosterGeneratorService,
        {
          provide: PrismaService,
          useValue: {},
        },
        {
          provide: StorageService,
          useValue: mockStorageService,
        },
        {
          provide: RedisService,
          useValue: mockRedisService,
        },
        {
          provide: ProfileService,
          useValue: mockProfileService,
        },
      ],
    }).compile();

    service = module.get<PosterGeneratorService>(PosterGeneratorService);
    storage = module.get<StorageService>(StorageService);
    redis = module.get<RedisService>(RedisService);
    profileService = module.get<ProfileService>(ProfileService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe("generateProfilePoster", () => {
    it("应该成功生成海报并返回 URL", async () => {
      mockRedisService.get.mockResolvedValue(null);

      const result = await service.generateProfilePoster("user-id");

      expect(result).toHaveProperty("id");
      expect(result).toHaveProperty("url");
      expect(result).toHaveProperty("createdAt");
      expect(mockProfileService.getProfile).toHaveBeenCalledWith("user-id");
      expect(mockProfileService.getBodyAnalysis).toHaveBeenCalledWith("user-id");
      expect(mockProfileService.getColorAnalysis).toHaveBeenCalledWith("user-id");
      expect(mockStorageService.uploadBuffer).toHaveBeenCalled();
      expect(mockRedisService.setWithTtl).toHaveBeenCalled();
    });

    it("同一天内应返回缓存", async () => {
      const cachedResult = JSON.stringify({
        id: "cached-poster-id",
        url: "https://storage.example.com/posters/cached.png",
        createdAt: new Date().toISOString(),
      });
      mockRedisService.get.mockResolvedValue(cachedResult);

      const result = await service.generateProfilePoster("user-id");

      expect(result.id).toBe("cached-poster-id");
      expect(result.url).toBe("https://storage.example.com/posters/cached.png");
      expect(mockStorageService.uploadBuffer).not.toHaveBeenCalled();
    });

    it("用户不存在应抛出 NotFoundException", async () => {
      mockRedisService.get.mockResolvedValue(null);
      mockProfileService.getProfile.mockResolvedValueOnce(null);

      await expect(service.generateProfilePoster("non-existent-user")).rejects.toThrow(
        NotFoundException,
      );
    });
  });

  describe("getPoster", () => {
    it("应该从缓存返回已生成的海报", async () => {
      const cachedResult = JSON.stringify({
        id: "poster-id",
        url: "https://storage.example.com/posters/test.png",
        createdAt: new Date().toISOString(),
      });
      mockRedisService.get.mockResolvedValue(cachedResult);

      const result = await service.getPoster("user-id", "poster-id");

      expect(result.id).toBe("poster-id");
      expect(result.url).toBe("https://storage.example.com/posters/test.png");
    });

    it("缓存未命中时应从 MinIO 获取海报", async () => {
      mockRedisService.get.mockResolvedValue(null);
      mockStorageService.fileExists.mockResolvedValue(true);
      mockStorageService.getFileUrl.mockResolvedValue("https://storage.example.com/posters/test.png");

      const result = await service.getPoster("user-id", "poster-id");

      expect(result.id).toBe("poster-id");
      expect(result.url).toBe("https://storage.example.com/posters/test.png");
      expect(mockStorageService.fileExists).toHaveBeenCalledWith("posters/user-id/poster-id.png");
    });

    it("海报不存在应抛出 NotFoundException", async () => {
      mockRedisService.get.mockResolvedValue(null);
      mockStorageService.fileExists.mockResolvedValue(false);

      await expect(service.getPoster("user-id", "non-existent-id")).rejects.toThrow(
        NotFoundException,
      );
    });
  });
});

import { Injectable, Logger, NotFoundException } from "@nestjs/common";
import { ColorSeason } from "@prisma/client";
import { createCanvas, Image, CanvasRenderingContext2D } from "canvas";
import * as QRCode from "qrcode";
import { v4 as uuidv4 } from "uuid";

import { PrismaService } from "../../../common/prisma/prisma.service";
import { RedisService, RedisKeyBuilder } from "../../../common/redis/redis.service";
import { StorageService } from "../../../common/storage/storage.service";
import { ProfileService, BodyAnalysisResult, ColorAnalysisResult } from "../profile.service";
import { getTemplateByColorSeason, PosterTemplate, ColorSeasonConfig } from "../templates";

const COLOR_SEASON_DISPLAY_NAMES: Record<ColorSeason, string> = {
  [ColorSeason.spring_warm]: "春季暖型",
  [ColorSeason.spring_light]: "春季清型",
  [ColorSeason.summer_cool]: "夏季冷型",
  [ColorSeason.summer_light]: "夏季清型",
  [ColorSeason.autumn_warm]: "秋季暖型",
  [ColorSeason.autumn_deep]: "秋季深型",
  [ColorSeason.winter_cool]: "冬季冷型",
  [ColorSeason.winter_deep]: "冬季深型",
};

const QR_CODE_CONTENT = "https://xuno.app/download";
const FONT_FAMILY = "sans-serif";

@Injectable()
export class PosterGeneratorService {
  private readonly logger = new Logger(PosterGeneratorService.name);

  constructor(
    private prisma: PrismaService,
    private storageService: StorageService,
    private redisService: RedisService,
    private profileService: ProfileService,
  ) {}

  async generateProfilePoster(userId: string): Promise<{
    id: string;
    url: string;
    createdAt: Date;
  }> {
    const today = new Date().toISOString().slice(0, 10);
    const cacheKey = RedisKeyBuilder.cache("poster", `${userId}:${today}`);

    const cached = await this.redisService.get(cacheKey);
    if (cached) {
      try {
        return JSON.parse(cached);
      } catch {
        this.logger.warn(`Failed to parse cached poster for user ${userId}`);
      }
    }

    const [profile, bodyAnalysis, _colorAnalysis] = await Promise.all([
      this.profileService.getProfile(userId),
      this.profileService.getBodyAnalysis(userId),
      this.profileService.getColorAnalysis(userId),
    ]);

    if (!profile) {
      throw new NotFoundException("用户不存在");
    }

    const colorSeason = profile.profile?.colorSeason ?? null;
    const seasonConfig = getTemplateByColorSeason(colorSeason);
    const template = seasonConfig.template;

    const canvas = createCanvas(template.width, template.height);
    const ctx = canvas.getContext("2d");

    this.drawBackground(ctx, template);
    this.drawHeader(ctx, template, colorSeason);
    this.drawStyleTags(ctx, template, bodyAnalysis, seasonConfig);
    this.drawColorPalette(ctx, template, seasonConfig);
    this.drawBodyAdvice(ctx, template, bodyAnalysis);
    await this.drawQrCode(ctx, template);
    this.drawFooter(ctx, template);

    const buffer = canvas.toBuffer("image/png");

    const posterId = uuidv4();
    const filename = `posters/${userId}/${posterId}.png`;

    await this.storageService.uploadBuffer(filename, buffer, "image/png");

    const url = await this.storageService.getFileUrl(filename);

    const result = {
      id: posterId,
      url,
      createdAt: new Date(),
    };

    const now = new Date();
    const endOfDay = new Date(now.getFullYear(), now.getMonth(), now.getDate() + 1);
    const ttlMs = endOfDay.getTime() - now.getTime();

    await this.redisService.setWithTtl(cacheKey, JSON.stringify(result), ttlMs);

    return result;
  }

  async getPoster(userId: string, posterId: string): Promise<{
    id: string;
    url: string;
    createdAt: Date;
  }> {
    const today = new Date().toISOString().slice(0, 10);
    const cacheKey = RedisKeyBuilder.cache("poster", `${userId}:${today}`);

    const cached = await this.redisService.get(cacheKey);
    if (cached) {
      try {
        const parsed = JSON.parse(cached);
        if (parsed.id === posterId) {
          return parsed;
        }
      } catch {
        this.logger.warn(`Failed to parse cached poster for user ${userId}`);
      }
    }

    const filename = `posters/${userId}/${posterId}.png`;
    const exists = await this.storageService.fileExists(filename);
    if (!exists) {
      throw new NotFoundException(`海报不存在: ${posterId}`);
    }

    const url = await this.storageService.getFileUrl(filename);

    return {
      id: posterId,
      url,
      createdAt: new Date(),
    };
  }

  private drawBackground(ctx: CanvasRenderingContext2D, template: PosterTemplate): void {
    ctx.fillStyle = template.background;
    ctx.fillRect(0, 0, template.width, template.height);
  }

  private drawHeader(
    ctx: CanvasRenderingContext2D,
    template: PosterTemplate,
    colorSeason: ColorSeason | null,
  ): void {
    const { header } = template;

    this.drawRoundedRect(ctx, 0, header.y, template.width, header.height, 0, header.backgroundColor);
    ctx.fill();

    ctx.fillStyle = header.titleColor;
    ctx.font = `bold ${header.titleFontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "center";
    ctx.textBaseline = "middle";
    ctx.fillText("我的风格画像", template.width / 2, header.y + header.height * 0.4);

    const seasonName = colorSeason
      ? COLOR_SEASON_DISPLAY_NAMES[colorSeason]
      : "春季型";
    ctx.fillStyle = header.subtitleColor;
    ctx.font = `${header.subtitleFontSize}px ${FONT_FAMILY}`;
    ctx.fillText(seasonName, template.width / 2, header.y + header.height * 0.65);
  }

  private drawStyleTags(
    ctx: CanvasRenderingContext2D,
    template: PosterTemplate,
    bodyAnalysis: BodyAnalysisResult,
    seasonConfig: ColorSeasonConfig,
  ): void {
    const { bodySection, styleTags } = template;
    const tags = bodyAnalysis.idealStyles.length > 0
      ? bodyAnalysis.idealStyles
      : ["待完善"];

    const sectionY = bodySection.y;
    const cardX = bodySection.paddingX;
    const cardWidth = template.width - bodySection.paddingX * 2;

    ctx.fillStyle = bodySection.cardBackgroundColor;
    this.drawRoundedRect(
      ctx,
      cardX,
      sectionY,
      cardWidth,
      this.calculateStyleTagsHeight(tags, template),
      bodySection.cardBorderRadius,
      bodySection.cardBackgroundColor,
    );
    ctx.fill();

    ctx.fillStyle = bodySection.labelColor;
    ctx.font = `bold ${bodySection.labelFontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("风格标签", cardX + bodySection.cardPadding, sectionY + bodySection.cardPadding);

    const tagsStartY = sectionY + bodySection.cardPadding + bodySection.labelFontSize + 12;
    const maxTagsPerRow = 3;
    const tagBackgroundColor = seasonConfig.template.header.backgroundColor;

    let currentX = cardX + bodySection.cardPadding;
    let currentY = tagsStartY;

    for (let i = 0; i < tags.length; i++) {
      const tagText = tags[i]!;
      ctx.font = `${styleTags.tagFontSize}px ${FONT_FAMILY}`;
      const textWidth = ctx.measureText(tagText).width;
      const tagWidth = textWidth + styleTags.tagPaddingH * 2;

      if (i > 0 && i % maxTagsPerRow === 0) {
        currentX = cardX + bodySection.cardPadding;
        currentY += styleTags.tagHeight + styleTags.tagGap;
      }

      ctx.fillStyle = tagBackgroundColor;
      this.drawRoundedRect(
        ctx,
        currentX,
        currentY,
        tagWidth,
        styleTags.tagHeight,
        styleTags.tagBorderRadius,
        tagBackgroundColor,
      );
      ctx.fill();

      ctx.fillStyle = "#FFFFFF";
      ctx.font = `${styleTags.tagFontSize}px ${FONT_FAMILY}`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText(tagText, currentX + tagWidth / 2, currentY + styleTags.tagHeight / 2);

      currentX += tagWidth + styleTags.tagGap;
    }
  }

  private calculateStyleTagsHeight(tags: string[], template: PosterTemplate): number {
    const { bodySection, styleTags } = template;
    const maxTagsPerRow = 3;
    const rows = Math.ceil(tags.length / maxTagsPerRow);
    const tagsStartY = bodySection.cardPadding + bodySection.labelFontSize + 12;
    const tagsHeight = rows * styleTags.tagHeight + (rows - 1) * styleTags.tagGap;
    return tagsStartY + tagsHeight + bodySection.cardPadding;
  }

  private drawColorPalette(
    ctx: CanvasRenderingContext2D,
    template: PosterTemplate,
    seasonConfig: ColorSeasonConfig,
  ): void {
    const { bodySection, colorPalette } = template;
    const { colorHexes, colorNames } = seasonConfig;

    const styleTagsHeight = this.calculateStyleTagsHeight(
      seasonConfig.colorNames,
      template,
    );
    const sectionY = bodySection.y + styleTagsHeight + bodySection.sectionGap;

    const cardX = bodySection.paddingX;
    const cardWidth = template.width - bodySection.paddingX * 2;
    const cardHeight = bodySection.cardPadding + bodySection.labelFontSize + 12 + colorPalette.swatchSize + 20 + bodySection.cardPadding;

    ctx.fillStyle = bodySection.cardBackgroundColor;
    this.drawRoundedRect(
      ctx,
      cardX,
      sectionY,
      cardWidth,
      cardHeight,
      bodySection.cardBorderRadius,
      bodySection.cardBackgroundColor,
    );
    ctx.fill();

    ctx.fillStyle = bodySection.labelColor;
    ctx.font = `bold ${bodySection.labelFontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("色彩调色板", cardX + bodySection.cardPadding, sectionY + bodySection.cardPadding);

    const swatchesStartY = sectionY + bodySection.cardPadding + bodySection.labelFontSize + 12;
    const totalSwatchesWidth = colorHexes.length * colorPalette.swatchSize + (colorHexes.length - 1) * colorPalette.swatchGap;
    let swatchX = cardX + (cardWidth - totalSwatchesWidth) / 2;

    for (let i = 0; i < colorHexes.length; i++) {
      const centerX = swatchX + colorPalette.swatchSize / 2;
      const centerY = swatchesStartY + colorPalette.swatchSize / 2;
      const radius = colorPalette.swatchSize / 2;

      ctx.beginPath();
      ctx.arc(centerX, centerY, radius, 0, Math.PI * 2);
      ctx.fillStyle = colorHexes[i]!;
      ctx.fill();

      ctx.strokeStyle = "rgba(0, 0, 0, 0.08)";
      ctx.lineWidth = 1;
      ctx.stroke();

      ctx.fillStyle = colorPalette.labelColor;
      ctx.font = `18px ${FONT_FAMILY}`;
      ctx.textAlign = "center";
      ctx.textBaseline = "top";
      ctx.fillText(colorNames[i]!, centerX, swatchesStartY + colorPalette.swatchSize + 4);

      swatchX += colorPalette.swatchSize + colorPalette.swatchGap;
    }
  }

  private drawBodyAdvice(
    ctx: CanvasRenderingContext2D,
    template: PosterTemplate,
    bodyAnalysis: BodyAnalysisResult,
  ): void {
    const { bodySection, bodyAdvice, colorPalette } = template;

    const styleTagsHeight = this.calculateStyleTagsHeight(
      bodyAnalysis.idealStyles.length > 0 ? bodyAnalysis.idealStyles : ["待完善"],
      template,
    );
    const colorCardHeight = bodySection.cardPadding + bodySection.labelFontSize + 12 + colorPalette.swatchSize + 20 + bodySection.cardPadding;
    const sectionY = bodySection.y + styleTagsHeight + bodySection.sectionGap + colorCardHeight + bodySection.sectionGap;

    const recommendations = bodyAnalysis.recommendations.length > 0
      ? bodyAnalysis.recommendations
      : [];

    const cardX = bodySection.paddingX;
    const cardWidth = template.width - bodySection.paddingX * 2;
    const cardHeight = bodySection.cardPadding + bodySection.labelFontSize + 12 +
      (recommendations.length > 0
        ? recommendations.length * bodyAdvice.lineHeight
        : bodyAdvice.lineHeight) +
      bodySection.cardPadding;

    ctx.fillStyle = bodySection.cardBackgroundColor;
    this.drawRoundedRect(
      ctx,
      cardX,
      sectionY,
      cardWidth,
      cardHeight,
      bodySection.cardBorderRadius,
      bodySection.cardBackgroundColor,
    );
    ctx.fill();

    ctx.fillStyle = bodySection.labelColor;
    ctx.font = `bold ${bodySection.labelFontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "left";
    ctx.textBaseline = "top";
    ctx.fillText("体型适配建议", cardX + bodySection.cardPadding, sectionY + bodySection.cardPadding);

    const adviceStartY = sectionY + bodySection.cardPadding + bodySection.labelFontSize + 12;

    if (recommendations.length > 0) {
      for (let i = 0; i < recommendations.length; i++) {
        const rec = recommendations[i]!;
        const textY = adviceStartY + i * bodyAdvice.lineHeight;

        ctx.fillStyle = bodyAdvice.color;
        ctx.font = `${bodyAdvice.fontSize}px ${FONT_FAMILY}`;
        ctx.textAlign = "left";
        ctx.textBaseline = "top";

        const label = `${rec.category}：`;
        const labelWidth = ctx.measureText(label).width;
        ctx.fillText(label, cardX + bodySection.cardPadding, textY);

        ctx.fillStyle = bodyAdvice.color;
        ctx.fillText(rec.advice, cardX + bodySection.cardPadding + labelWidth, textY);
      }
    } else {
      ctx.fillStyle = bodyAdvice.color;
      ctx.font = `${bodyAdvice.fontSize}px ${FONT_FAMILY}`;
      ctx.textAlign = "left";
      ctx.textBaseline = "top";
      ctx.fillText("请先完善体型信息以获取适配建议", cardX + bodySection.cardPadding, adviceStartY);
    }
  }

  private async drawQrCode(
    ctx: CanvasRenderingContext2D,
    template: PosterTemplate,
  ): Promise<void> {
    const { qrCode } = template;

    try {
      const qrDataUrl = await QRCode.toDataURL(QR_CODE_CONTENT, {
        width: qrCode.size,
        margin: 1,
        color: {
          dark: "#333333",
          light: "#FFFFFF",
        },
      });

      const base64Data = qrDataUrl.replace(/^data:image\/png;base64,/, "");
      const qrBuffer = Buffer.from(base64Data, "base64");

      const img = new Image();
      img.src = qrBuffer;

      const qrX = (template.width - qrCode.size) / 2;
      ctx.drawImage(img, qrX, qrCode.y, qrCode.size, qrCode.size);
    } catch (error: unknown) {
      const errorMessage = error instanceof Error ? error.message : String(error);
      this.logger.error(`Failed to generate QR code: ${errorMessage}`);

      const qrX = (template.width - qrCode.size) / 2;
      ctx.fillStyle = "#F0F0F0";
      ctx.fillRect(qrX, qrCode.y, qrCode.size, qrCode.size);
      ctx.fillStyle = "#999999";
      ctx.font = `${qrCode.labelFontSize}px ${FONT_FAMILY}`;
      ctx.textAlign = "center";
      ctx.textBaseline = "middle";
      ctx.fillText("扫码下载", qrX + qrCode.size / 2, qrCode.y + qrCode.size / 2);
    }

    ctx.fillStyle = qrCode.labelColor;
    ctx.font = `${qrCode.labelFontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "center";
    ctx.textBaseline = "top";
    ctx.fillText("扫码下载寻裳App", template.width / 2, qrCode.y + qrCode.size + 8);
  }

  private drawFooter(ctx: CanvasRenderingContext2D, template: PosterTemplate): void {
    const { footer } = template;

    ctx.fillStyle = footer.color;
    ctx.font = `${footer.fontSize}px ${FONT_FAMILY}`;
    ctx.textAlign = "center";
    ctx.textBaseline = "bottom";
    ctx.fillText("寻裳 · AI 造型师", template.width / 2, footer.y);
  }

  private drawRoundedRect(
    ctx: CanvasRenderingContext2D,
    x: number,
    y: number,
    width: number,
    height: number,
    radius: number,
    _fillColor: string,
  ): void {
    ctx.beginPath();
    if (radius === 0) {
      ctx.rect(x, y, width, height);
    } else {
      ctx.moveTo(x + radius, y);
      ctx.lineTo(x + width - radius, y);
      ctx.arcTo(x + width, y, x + width, y + radius, radius);
      ctx.lineTo(x + width, y + height - radius);
      ctx.arcTo(x + width, y + height, x + width - radius, y + height, radius);
      ctx.lineTo(x + radius, y + height);
      ctx.arcTo(x, y + height, x, y + height - radius, radius);
      ctx.lineTo(x, y + radius);
      ctx.arcTo(x, y, x + radius, y, radius);
    }
    ctx.closePath();
  }
}

import { ProfileCompletenessService, CompletenessResult } from "./profile-completeness.service";

describe("ProfileCompletenessService", () => {
  let service: ProfileCompletenessService;

  beforeEach(() => {
    service = new ProfileCompletenessService();
  });

  it("should be defined", () => {
    expect(service).toBeDefined();
  });

  describe("calculateCompleteness", () => {
    it("should return 0% with all fields missing", () => {
      const result = service.calculateCompleteness({});

      expect(result.percentage).toBe(0);
      expect(result.missingFields).toContain("性别");
      expect(result.missingFields).toContain("出生日期");
      expect(result.missingFields).toContain("昵称");
      expect(result.missingFields).toContain("身材数据");
      expect(result.missingFields).toContain("色彩分析");
      expect(result.missingFields).toContain("个人照片");
    });

    it("should return 100% when all fields are filled", () => {
      const result = service.calculateCompleteness({
        gender: "female",
        birthDate: new Date("1995-01-01"),
        nickname: "TestUser",
        height: 165,
        weight: 55,
        bodyType: "hourglass",
        colorSeason: "spring_warm",
        styleProfiles: [{ id: "1" }],
        stylePreferences: ["casual"],
        colorPreferences: ["red"],
        photos: [{ id: "photo1" }],
      });

      expect(result.percentage).toBe(100);
      expect(result.missingFields).toHaveLength(0);
    });

    it("should calculate basic info at 30% weight", () => {
      const result = service.calculateCompleteness({
        gender: "female",
        birthDate: new Date("1995-01-01"),
        nickname: "TestUser",
      });

      expect(result.percentage).toBe(30);
    });

    it("should calculate body data at 25% weight", () => {
      const result = service.calculateCompleteness({
        height: 165,
        weight: 55,
        bodyType: "hourglass",
      });

      expect(result.percentage).toBe(25);
    });

    it("should calculate style preferences at 20% weight", () => {
      const result = service.calculateCompleteness({
        styleProfiles: [{ id: "1" }],
        stylePreferences: ["casual"],
      });

      expect(result.percentage).toBe(20);
    });

    it("should calculate color preferences at 15% weight", () => {
      const result = service.calculateCompleteness({
        colorSeason: "spring_warm",
        colorPreferences: ["red"],
      });

      expect(result.percentage).toBe(15);
    });

    it("should calculate photos at 10% weight", () => {
      const result = service.calculateCompleteness({
        photos: [{ id: "photo1" }],
      });

      expect(result.percentage).toBe(10);
    });

    it("should handle partial fields correctly", () => {
      const result = service.calculateCompleteness({
        gender: "female",
        nickname: "TestUser",
        height: 165,
        photos: [{ id: "p1" }],
      });

      // gender (10) + nickname (10) + height (8) + photos (10) = 38
      expect(result.percentage).toBe(38);
    });

    it("should not list missing field if at least one sub-field is filled", () => {
      const result = service.calculateCompleteness({
        height: 165,
      });

      // Body data has height filled, so "身材数据" should NOT be in missing
      expect(result.missingFields).not.toContain("身材数据");
    });

    it("should report missingFields with Chinese labels", () => {
      const result = service.calculateCompleteness({});

      expect(result.missingFields).toEqual(
        expect.arrayContaining([
          expect.stringMatching(/[\u4e00-\u9fff]/), // Contains Chinese characters
        ]),
      );
    });
  });
});

import { Injectable, Logger, Inject } from "@nestjs/common";

import { RedisService } from "../../../common/redis/redis.service";

/**
 * ProfileEventEmitter publishes profile change events to Redis Pub/Sub channels.
 * Enables real-time notifications and cache invalidation across service instances.
 */
@Injectable()
export class ProfileEventEmitter {
  private readonly logger = new Logger(ProfileEventEmitter.name);

  private static readonly CHANNEL_PROFILE_UPDATED = "profile:updated";
  private static readonly CHANNEL_QUIZ_COMPLETED = "quiz:completed";

  constructor(private readonly redisService: RedisService) {}

  /**
   * Emit a profile:updated event with changed fields.
   */
  async emitProfileUpdated(userId: string, changedFields: string[]): Promise<void> {
    const message = JSON.stringify({
      userId,
      changedFields,
      timestamp: Date.now(),
    });

    await this.redisService.publish(
      ProfileEventEmitter.CHANNEL_PROFILE_UPDATED,
      message,
    );

    this.logger.debug(`Emitted profile:updated for user ${userId}, fields: ${changedFields.join(",")}`);
  }

  /**
   * Emit a quiz:completed event with quiz identification.
   */
  async emitQuizResultSaved(userId: string, quizId: string): Promise<void> {
    const message = JSON.stringify({
      userId,
      quizId,
      timestamp: Date.now(),
    });

    await this.redisService.publish(
      ProfileEventEmitter.CHANNEL_QUIZ_COMPLETED,
      message,
    );

    this.logger.debug(`Emitted quiz:completed for user ${userId}, quiz: ${quizId}`);
  }
}

import { Injectable, Logger } from "@nestjs/common";
import { Prisma } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";
import { PrismaUpdateData } from "../../../common/types/common.types";
import { BehaviorTrackerService } from "../../analytics/services/behavior-tracker.service";
import {
  BodyImageAnalysisService,
  BodyType,
} from "../../photos/services/body-image-analysis.service";
import { SASRecService } from "../../recommendations/services/sasrec.service";

export interface UserBodyProfile {
  userId: string;
  bodyType: BodyType;
  measurements: {
    shoulderWidth: number;
    bustWidth: number;
    waistWidth: number;
    hipWidth: number;
    heightEstimate: number;
  };
  proportions: {
    shoulderToHip: number;
    waistToHip: number;
    waistToShoulder: number;
  };
  stylePreferences: string[];
  colorPreferences: string[];
  priceRange: {
    min: number | null;
    max: number | null;
  };
  updatedAt: Date;
}

export interface PersonalizedRecommendation {
  itemId: string;
  score: number;
  reasons: string[];
  bodyTypeMatch: boolean;
  styleMatch: boolean;
  priceMatch: boolean;
}

export interface UserProfileSummary {
  bodyProfile: UserBodyProfile | null;
  behaviorStats: {
    totalViews: number;
    totalLikes: number;
    totalPurchases: number;
    preferredCategories: string[];
    preferredBrands: string[];
  };
  recommendations: PersonalizedRecommendation[];
  preferences: {
    styles: Array<{ key: string; weight: number; trend: string }>;
    colors: Array<{ key: string; weight: number; trend: string }>;
    brands: Array<{ key: string; weight: number; trend: string }>;
    priceRange: {
      min: number | null;
      max: number | null;
      primaryRange: string;
    };
  };
}

export interface UpdateProfileDto {
  stylePreferences?: string[];
  colorPreferences?: string[];
  priceRangeMin?: number;
  priceRangeMax?: number;
  bodyType?: BodyType;
  height?: number;
  weight?: number;
}

@Injectable()
export class UserProfileService {
  private readonly logger = new Logger(UserProfileService.name);

  constructor(
    private prisma: PrismaService,
    private bodyAnalysisService: BodyImageAnalysisService,
    private sasrecService: SASRecService,
    private behaviorTracker: BehaviorTrackerService,
  ) {}

  async analyzeAndSaveBodyProfile(
    userId: string,
    image: Buffer,
    measurements?: {
      height?: number;
      weight?: number;
      shoulderWidth?: number;
      bustWidth?: number;
      waistWidth?: number;
      hipWidth?: number;
    },
  ): Promise<UserBodyProfile> {
    this.logger.log(`Analyzing body profile for user ${userId}`);

    const analysisResult = await this.bodyAnalysisService.analyzeBodyImage({
      image,
      userMeasurements: measurements,
    });

    const profile: UserBodyProfile = {
      userId,
      bodyType: analysisResult.bodyType,
      measurements: analysisResult.measurements,
      proportions: analysisResult.proportions,
      stylePreferences: [],
      colorPreferences: [],
      priceRange: {
        min: null,
        max: null,
      },
      updatedAt: new Date(),
    };

    await this.saveBodyProfile(userId, profile);

    this.logger.log(
      `Body profile saved for user ${userId}: ${analysisResult.bodyType}`,
    );

    return profile;
  }

  private async saveBodyProfile(
    userId: string,
    profile: UserBodyProfile,
  ): Promise<void> {
    await this.prisma.userProfile.upsert({
      where: { userId },
      create: {
        userId,
        bodyType: profile.bodyType,
        shoulder: profile.measurements.shoulderWidth,
        bust: profile.measurements.bustWidth,
        waist: profile.measurements.waistWidth,
        hip: profile.measurements.hipWidth,
        height: profile.measurements.heightEstimate,
        stylePreferences: profile.stylePreferences,
        colorPreferences: profile.colorPreferences,
        priceRangeMin: profile.priceRange.min,
        priceRangeMax: profile.priceRange.max,
      },
      update: {
        bodyType: profile.bodyType,
        shoulder: profile.measurements.shoulderWidth,
        bust: profile.measurements.bustWidth,
        waist: profile.measurements.waistWidth,
        hip: profile.measurements.hipWidth,
        height: profile.measurements.heightEstimate,
        stylePreferences: profile.stylePreferences,
        colorPreferences: profile.colorPreferences,
        priceRangeMin: profile.priceRange.min,
        priceRangeMax: profile.priceRange.max,
        updatedAt: new Date(),
      },
    });
  }

  async getBodyProfile(userId: string): Promise<UserBodyProfile | null> {
    const profile = await this.prisma.userProfile.findUnique({
      where: { userId },
    });

    if (!profile) {return null;}

    return {
      userId: profile.userId,
      bodyType: (profile.bodyType as BodyType) || "rectangle",
      measurements: {
        shoulderWidth: profile.shoulder || 0,
        bustWidth: profile.bust || 0,
        waistWidth: profile.waist || 0,
        hipWidth: profile.hip || 0,
        heightEstimate: profile.height || 0,
      },
      proportions: {
        shoulderToHip:
          profile.shoulder && profile.hip ? profile.shoulder / profile.hip : 1,
        waistToHip:
          profile.waist && profile.hip ? profile.waist / profile.hip : 0.7,
        waistToShoulder:
          profile.waist && profile.shoulder
            ? profile.waist / profile.shoulder
            : 0.7,
      },
      stylePreferences: (profile.stylePreferences as string[]) || [],
      colorPreferences: (profile.colorPreferences as string[]) || [],
      priceRange: {
        min: profile.priceRangeMin,
        max: profile.priceRangeMax,
      },
      updatedAt: profile.updatedAt,
    };
  }

  async getPersonalizedRecommendations(
    userId: string,
    topK: number = 20,
  ): Promise<PersonalizedRecommendation[]> {
    const bodyProfile = await this.getBodyProfile(userId);
    const sequenceRecs = await this.sasrecService.getSequenceRecommendations(
      userId,
      topK * 2,
    );

    const itemIds = sequenceRecs.recommendations.map((rec) => rec.itemId);

    const items = await this.prisma.clothingItem.findMany({
      where: {
        id: { in: itemIds },
      },
      select: {
        id: true,
        category: true,
        tags: true,
        attributes: true,
        price: true,
        originalPrice: true,
      },
    });

    const itemMap = new Map(items.map((item) => [item.id, item]));

    const recommendations: PersonalizedRecommendation[] = [];

    for (const rec of sequenceRecs.recommendations) {
      const item = itemMap.get(rec.itemId);

      if (!item) {continue;}

      const { bodyTypeMatch, styleMatch, priceMatch, reasons } = this.evaluateItemMatch(
        item,
        bodyProfile,
      );

      recommendations.push({
        itemId: rec.itemId,
        score:
          rec.score * (bodyTypeMatch ? 1.2 : 1.0) * (styleMatch ? 1.1 : 1.0) * (priceMatch ? 1.05 : 1.0),
        reasons: [rec.reason, ...reasons].filter(Boolean),
        bodyTypeMatch,
        styleMatch,
        priceMatch,
      });
    }

    return recommendations.sort((a, b) => b.score - a.score).slice(0, topK);
  }

  private evaluateItemMatch(
    item: {
      id: string;
      category: string;
      tags: string[];
      attributes: Prisma.JsonValue | null;
      price: Prisma.Decimal;
      originalPrice: Prisma.Decimal | null;
    },
    bodyProfile: UserBodyProfile | null,
  ): { bodyTypeMatch: boolean; styleMatch: boolean; priceMatch: boolean; reasons: string[] } {
    const reasons: string[] = [];
    let bodyTypeMatch = false;
    let styleMatch = false;
    let priceMatch = false;

    if (bodyProfile) {
      const bodyTypeRecommendations = this.getBodyTypeRecommendations(
        bodyProfile.bodyType,
      );

      const itemTags = item.tags || [];
      const suitableStyles = bodyTypeRecommendations.suitableStyles || [];

      const hasMatchingTag = itemTags.some((tag: string) =>
        suitableStyles.some(
          (style) => tag.includes(style) || style.includes(tag),
        ),
      );

      if (hasMatchingTag) {
        bodyTypeMatch = true;
        reasons.push(
          `适合您的${this.getBodyTypeName(bodyProfile.bodyType)}身材`,
        );
      }

      const avoidStyles = bodyTypeRecommendations.avoidStyles || [];
      const hasAvoidTag = itemTags.some((tag: string) =>
        avoidStyles.some((style) => tag.includes(style) || style.includes(tag)),
      );

      if (hasAvoidTag) {
        bodyTypeMatch = false;
      }
    }

    if (
      bodyProfile?.stylePreferences &&
      bodyProfile.stylePreferences.length > 0
    ) {
      const itemTags = item.tags || [];
      styleMatch = itemTags.some((tag: string) =>
        bodyProfile.stylePreferences.includes(tag),
      );

      if (styleMatch) {
        reasons.push("符合您的风格偏好");
      }
    }

    // 价格匹配检查
    if (bodyProfile?.priceRange) {
      const itemPrice = Number(item.price) || Number(item.originalPrice) || 0;
      const { min, max } = bodyProfile.priceRange;
      
      if (min !== null && max !== null) {
        if (itemPrice >= min && itemPrice <= max) {
          priceMatch = true;
          reasons.push("符合您的价格偏好");
        }
      } else if (min !== null && itemPrice >= min) {
        priceMatch = true;
        reasons.push("符合您的价格偏好");
      } else if (max !== null && itemPrice <= max) {
        priceMatch = true;
        reasons.push("符合您的价格偏好");
      }
    }

    return { bodyTypeMatch, styleMatch, priceMatch, reasons };
  }

  private getBodyTypeRecommendations(bodyType: BodyType): {
    suitableStyles: string[];
    avoidStyles: string[];
  } {
    const recommendations: Record<
      BodyType,
      { suitableStyles: string[]; avoidStyles: string[] }
    > = {
      rectangle: {
        suitableStyles: ["收腰", "V领", "A字", "高腰", "层次"],
        avoidStyles: ["直筒", "无腰身", "宽松"],
      },
      hourglass: {
        suitableStyles: ["收腰", "铅笔裙", "高腰", "裹身", "紧身"],
        avoidStyles: ["直筒", "宽松", "超大号"],
      },
      triangle: {
        suitableStyles: ["垫肩", "荷叶边", "亮色上衣", "A字", "阔腿"],
        avoidStyles: ["紧身裤", "短裙", "浅色下装", "包臀"],
      },
      inverted_triangle: {
        suitableStyles: ["V领", "深色上衣", "阔腿", "A字", "百褶"],
        avoidStyles: ["垫肩", "泡泡袖", "紧身", "亮色上衣"],
      },
      oval: {
        suitableStyles: ["V领", "深色", "直筒", "A字", "垂感"],
        avoidStyles: ["紧身", "亮色大面积", "横条纹", "腰部装饰"],
      },
    };

    return recommendations[bodyType] || recommendations.rectangle;
  }

  private getBodyTypeName(bodyType: BodyType): string {
    const names: Record<BodyType, string> = {
      rectangle: "矩形",
      hourglass: "沙漏型",
      triangle: "梨形",
      inverted_triangle: "倒三角",
      oval: "椭圆形",
    };
    return names[bodyType] || "标准";
  }

  async getUserProfileSummary(userId: string): Promise<UserProfileSummary> {
    const bodyProfile = await this.getBodyProfile(userId);

    const behaviors = await this.prisma.userBehavior.groupBy({
      by: ["type"],
      where: { userId },
      _count: true,
    });

    const behaviorStats = {
      totalViews: behaviors.find((b) => b.type === "view")?._count || 0,
      totalLikes: behaviors.find((b) => b.type === "like")?._count || 0,
      totalPurchases: behaviors.find((b) => b.type === "purchase")?._count || 0,
      preferredCategories: [],
      preferredBrands: [],
    };

    const recommendations = await this.getPersonalizedRecommendations(
      userId,
      10,
    );

    // 从行为追踪服务获取偏好数据
    let preferences: UserProfileSummary["preferences"] = {
      styles: [],
      colors: [],
      brands: [],
      priceRange: {
        min: bodyProfile?.priceRange.min ?? null,
        max: bodyProfile?.priceRange.max ?? null,
        primaryRange: "mid_range",
      },
    };

    try {
      const behaviorProfile = await this.behaviorTracker.getUserBehaviorProfile(userId);
      preferences = {
        styles: behaviorProfile.preferences.styles.slice(0, 10),
        colors: behaviorProfile.preferences.colors.slice(0, 10),
        brands: behaviorProfile.preferences.brands.slice(0, 10),
        priceRange: {
          min: bodyProfile?.priceRange.min ?? null,
          max: bodyProfile?.priceRange.max ?? null,
          primaryRange: this.getPriceRangeLabel(bodyProfile?.priceRange.min, bodyProfile?.priceRange.max),
        },
      };
    } catch (error) {
      this.logger.warn(`Failed to get behavior profile for user ${userId}: ${error}`);
    }

    return {
      bodyProfile,
      behaviorStats,
      recommendations,
      preferences,
    };
  }

  private getPriceRangeLabel(min: number | null | undefined, max: number | null | undefined): string {
    if (min === null && max === null) {
      return "未设置";
    }
    const maxVal = max ?? null;
    if (maxVal !== null && maxVal < 100) {
      return "预算型";
    }
    if (maxVal !== null && maxVal < 300) {
      return "平价";
    }
    if (maxVal !== null && maxVal < 800) {
      return "中档";
    }
    if (maxVal !== null && maxVal < 2000) {
      return "高档";
    }
    if (maxVal !== null && maxVal < 5000) {
      return "奢侈";
    }
    return "超奢侈";
  }

  async updateStylePreferences(
    userId: string,
    preferences: string[],
  ): Promise<void> {
    await this.prisma.userProfile.update({
      where: { userId },
      data: {
        stylePreferences: preferences,
        updatedAt: new Date(),
      },
    });

    this.logger.log(`Updated style preferences for user ${userId}`);
  }

  async updateColorPreferences(
    userId: string,
    preferences: string[],
  ): Promise<void> {
    await this.prisma.userProfile.update({
      where: { userId },
      data: {
        colorPreferences: preferences,
        updatedAt: new Date(),
      },
    });

    this.logger.log(`Updated color preferences for user ${userId}`);
  }

  async updatePriceRange(
    userId: string,
    min: number | null,
    max: number | null,
  ): Promise<void> {
    await this.prisma.userProfile.update({
      where: { userId },
      data: {
        priceRangeMin: min,
        priceRangeMax: max,
        updatedAt: new Date(),
      },
    });

    this.logger.log(`Updated price range for user ${userId}: ${min}-${max}`);
  }

  async updateProfile(
    userId: string,
    dto: UpdateProfileDto,
  ): Promise<UserBodyProfile | null> {
    const updateData: Prisma.UserProfileUpdateInput = { updatedAt: new Date() };

    if (dto.stylePreferences !== undefined) {
      updateData.stylePreferences = dto.stylePreferences;
    }
    if (dto.colorPreferences !== undefined) {
      updateData.colorPreferences = dto.colorPreferences;
    }
    if (dto.priceRangeMin !== undefined) {
      updateData.priceRangeMin = dto.priceRangeMin;
    }
    if (dto.priceRangeMax !== undefined) {
      updateData.priceRangeMax = dto.priceRangeMax;
    }
    if (dto.bodyType !== undefined) {
      updateData.bodyType = dto.bodyType;
    }
    if (dto.height !== undefined) {
      updateData.height = dto.height;
    }
    if (dto.weight !== undefined) {
      updateData.weight = dto.weight;
    }

    await this.prisma.userProfile.upsert({
      where: { userId },
      create: {
        userId,
        stylePreferences: dto.stylePreferences ?? [],
        colorPreferences: dto.colorPreferences ?? [],
        priceRangeMin: dto.priceRangeMin ?? null,
        priceRangeMax: dto.priceRangeMax ?? null,
        bodyType: dto.bodyType ?? "rectangle",
        height: dto.height ?? null,
        weight: dto.weight ?? null,
      },
      update: updateData,
    });

    this.logger.log(`Updated profile for user ${userId}`);
    return this.getBodyProfile(userId);
  }

  /**
   * 从用户行为自动更新画像
   * 基于用户的历史行为数据推断偏好
   */
  async updateProfileFromBehavior(userId: string): Promise<void> {
    try {
      const behaviorProfile = await this.behaviorTracker.getUserBehaviorProfile(userId);
      
      // 从行为偏好中提取风格偏好
      const stylePrefs = behaviorProfile.preferences.styles
        .filter(s => s.weight > 0.3)
        .map(s => s.key);
      
      // 从行为偏好中提取颜色偏好
      const colorPrefs = behaviorProfile.preferences.colors
        .filter(c => c.weight > 0.3)
        .map(c => c.key);

      // 更新画像
      if (stylePrefs.length > 0 || colorPrefs.length > 0) {
        await this.prisma.userProfile.upsert({
          where: { userId },
          create: {
            userId,
            stylePreferences: stylePrefs,
            colorPreferences: colorPrefs,
          },
          update: {
            stylePreferences: stylePrefs.length > 0 ? stylePrefs : undefined,
            colorPreferences: colorPrefs.length > 0 ? colorPrefs : undefined,
            updatedAt: new Date(),
          },
        });

        this.logger.log(`Auto-updated profile from behavior for user ${userId}`);
      }
    } catch (error) {
      this.logger.error(`Failed to update profile from behavior: ${error}`);
    }
  }
}

