import { JobType, JobStatus } from './queue.constants';

export interface BaseJobData {
  jobId: string;
  userId: string;
  type: JobType;
  createdAt: string;
  priority?: number;
  callbackUrl?: string;
}

export interface StyleAnalysisJobData extends BaseJobData {
  type: 'style_analysis';
  userInput: string;
  userProfile?: {
    bodyType?: string;
    skinTone?: string;
    colorSeason?: string;
    stylePreferences?: string[];
    occasionPreferences?: string[];
  };
}

export interface VirtualTryOnJobData extends BaseJobData {
  type: 'virtual_tryon';
  photoId: string;
  userPhotoUrl: string;
  itemId: string;
  clothingImageUrl: string;
  category?: string;
}

export interface WardrobeMatchJobData extends BaseJobData {
  type: 'wardrobe_match';
  wardrobeItems: string[];
  targetStyle?: string;
  occasion?: string;
  season?: string;
}

export interface ImageAnalysisJobData extends BaseJobData {
  type: 'image_analysis';
  imagePath: string;
  analysisType: 'full' | 'color' | 'style' | 'body';
}

export interface BodyAnalysisJobData extends BaseJobData {
  type: 'body_analysis';
  imagePath: string;
}

export interface RecommendationJobData extends BaseJobData {
  type: 'recommendation';
  userInput: string;
  userProfile?: Record<string, any>;
  occasion?: string;
  category?: string;
  topK?: number;
}

export type AITaskJobData =
  | StyleAnalysisJobData
  | VirtualTryOnJobData
  | WardrobeMatchJobData
  | ImageAnalysisJobData
  | BodyAnalysisJobData
  | RecommendationJobData;

export interface JobResult<T = any> {
  jobId: string;
  status: JobStatus;
  result?: T;
  error?: string;
  processedAt?: string;
  duration?: number;
}

