    };
  }

  /**
   * Add a body analysis task to the queue
   */
  async addBodyAnalysisTask(
    userId: string,
    imagePath: string,
  ): Promise<TaskCreatedResponse> {
    const jobId = uuidv4();
    const jobData: BodyAnalysisJobData = {
      jobId,
