@ApiTags("recommendations")
@Controller("recommendations")
export class RecommendationsController {
  constructor(
    private recommendationsService: RecommendationsService,
    private advancedRecommendationService: AdvancedRecommendationService,
    private outfitCompletionService: OutfitCompletionService,
    private behaviorTrackingService: BehaviorTrackingService,
    private feedService: RecommendationFeedService,
  ) {}

  @UseGuards(JwtAuthGuard)
  @Get()
  @CacheKey("recommendations:personalized")
  @CacheTTL(180)
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取个性化推荐",
    description:
      "根据用户画像和行为数据，返回个性化服装推荐。支持按分类、场合、季节筛选。",
  })
  @ApiQuery({
    name: "category",
    required: false,
    enum: ClothingCategory,
    description: "服装分类筛选",
  })
  @ApiQuery({
    name: "occasion",
    required: false,
    type: String,
    description: "场合筛选（如：daily、work、party、date）",
    example: "daily",
  })
  @ApiQuery({
    name: "season",
    required: false,
    type: String,
    description: "季节筛选（spring、summer、autumn、winter）",
    example: "spring",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认20",
    example: 20,
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: RecommendationsResponseDto,
  })
  @ApiResponse({
    status: 401,
    description: "未授权，需要提供有效的 Access Token",
  })
  async getRecommendations(
    @CurrentUser("id") userId: string,
    @Query("category") category?: ClothingCategory,
    @Query("occasion") occasion?: string,
    @Query("season") season?: string,
    @Query("limit") limit?: string,
  ) {
    const result = await this.recommendationsService.getPersonalizedRecommendations(
      userId,
      {
        category,
        occasion,
        season,
        limit: limit ? parseInt(limit) : 20,
      },
    );
    return { items: result, total: result.length };
  }

  @UseGuards(JwtAuthGuard)
  @Get("feed")
  @CacheKey("recommendations:feed")
  @CacheTTL(180)
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取推荐 Feed（分页）",
    description:
      "获取分页推荐 Feed，支持 daily/occasion/trending/explore 四种分类。返回包含 colorHarmony 和 matchReason 的 FeedItem。",
  })
  @ApiResponse({ status: 200, description: "获取成功" })
  async getFeed(
    @CurrentUser("id") userId: string,
    @Query() dto: GetFeedDto,
  ) {
    return this.feedService.getFeed(
      userId,
      (dto.category as "daily" | "occasion" | "trending" | "explore") || "daily",
      dto.subCategory,
      dto.page || 1,
      dto.pageSize || 10,
    );
  }

  @UseGuards(JwtAuthGuard)
  @Get("advanced")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取高级个性化推荐（多策略融合）",
    description:
      "使用多种推荐策略（协同过滤、内容推荐、热门推荐等）融合生成推荐结果，提供更精准的个性化推荐。",
  })
  @ApiQuery({
    name: "occasion",
    required: false,
    type: String,
    description: "场合筛选",
    example: "work",
  })
  @ApiQuery({
    name: "season",
    required: false,
    type: String,
    description: "季节筛选",
    example: "spring",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认20",
    example: 20,
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: AdvancedRecommendationsResponseDto,
  })
  @ApiResponse({
    status: 401,
    description: "未授权，需要提供有效的 Access Token",
  })
  async getAdvancedRecommendations(
    @CurrentUser("id") userId: string,
    @Query("occasion") occasion?: string,
    @Query("season") season?: string,
    @Query("limit") limit?: string,
  ) {
    return this.advancedRecommendationService.getPersonalizedRecommendations(
      userId,
      { occasion, season },
      limit ? parseInt(limit) : 20,
    );
  }

  @UseGuards(JwtAuthGuard)
  @Get("daily")
  @ApiBearerAuth()
  @ApiOperation({ summary: "获取每日穿搭推荐" })
  @ApiResponse({ status: 200, description: "每日穿搭推荐" })
  async getDailyOutfit(@CurrentUser("id") userId: string) {
    return this.advancedRecommendationService.getDailyOutfitRecommendation(
      userId,
    );
  }

  @UseGuards(JwtAuthGuard)
  @Get("occasion")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取场合推荐",
    description:
      "根据特定场合（面试、约会、派对等）返回适合的服装推荐和穿搭建议。",
  })
  @ApiQuery({
    name: "type",
    required: true,
    type: String,
    description: "场合类型（daily、interview、date、party、workout、travel）",
    example: "interview",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认10",
    example: 10,
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: OccasionRecommendationsResponseDto,
  })
  @ApiResponse({
    status: 401,
    description: "未授权，需要提供有效的 Access Token",
  })
  async getOccasionRecommendations(
    @CurrentUser("id") userId: string,
    @Query("type") occasion: string,
    @Query("limit") limit?: string,
  ) {
    return this.advancedRecommendationService.getOccasionRecommendations(
      userId,
      occasion || "daily",
      limit ? parseInt(limit) : 10,
    );
  }

  @Public()
  @Throttle({ default: { limit: 20, ttl: 60000 } })
  @Get("trending")
  @CacheKey("recommendations:trending")
  @CacheTTL(180)
  @ApiOperation({
    summary: "获取热门趋势推荐",
    description:
      "获取当前热门服装趋势和流行单品，无需登录即可访问。数据基于全平台用户行为统计。",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认20",
    example: 20,
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: TrendingResponseDto,
  })
  @ApiResponse({
    status: 429,
    description: "请求过于频繁，每分钟最多20次",
  })
  async getTrendingRecommendations(@Query("limit") limit?: string) {
    return this.advancedRecommendationService.getTrendingRecommendations(
      limit ? parseInt(limit) : 20,
    );
  }

  @UseGuards(JwtAuthGuard)
  @Get("style-guide")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取风格指南",
    description:
      "根据用户画像生成个人风格指南，包含风格分析、推荐单品和穿搭技巧。",
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: StyleGuideResponseDto,
  })
  @ApiResponse({
    status: 401,
    description: "未授权，需要提供有效的 Access Token",
  })
  async getStyleGuide(@CurrentUser("id") userId: string) {
    return this.recommendationsService.getStyleGuide(userId);
  }

  @UseGuards(OptionalAuthGuard)
  @Get("discover")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "发现页面推荐",
    description:
      "发现页面推荐接口。已登录用户返回个性化推荐，未登录用户返回热门推荐。",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认20",
    example: 20,
  })
  @ApiResponse({
    status: 200,
    description: "获取成功",
    type: DiscoverResponseDto,
  })
  async getDiscoverRecommendations(
    @CurrentUser("id") userId?: string,
    @Query("limit") limit?: string,
  ) {
    // 如果用户已登录，返回个性化推荐
    // 否则返回热门推荐
    if (userId) {
      return this.advancedRecommendationService.getPersonalizedRecommendations(
        userId,
        {},
        limit ? parseInt(limit) : 20,
      );
    } else {
      return this.advancedRecommendationService.getTrendingRecommendations(
        limit ? parseInt(limit) : 20,
      );
    }
  }

  @UseGuards(JwtAuthGuard)
  @Get("complete-the-look/:clothingId")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取搭配推荐（Complete the Look）",
    description:
      "基于选中的服装，推荐互补的搭配单品（上装/下装/鞋/配饰），包含色彩和谐度评分。",
  })
  @ApiResponse({
    status: 200,
    description: "搭配推荐结果",
  })
  async getCompleteTheLook(
    @CurrentUser("id") userId: string,
    @Param("clothingId") clothingId: string,
  ) {
    return this.outfitCompletionService.getCompleteTheLook(clothingId, userId);
  }

  @UseGuards(JwtAuthGuard)
  @Post("feedback")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "提交推荐反馈",
    description:
      "用户对推荐结果进行反馈（like/dislike/ignore），反馈将用于改进后续推荐质量。",
  })
  @ApiResponse({
    status: 200,
    description: "反馈已记录",
  })
  async submitFeedback(
    @CurrentUser("id") userId: string,
    @Body() dto: SubmitFeedbackDto,
  ) {
    const actionMap: Record<string, BehaviorAction> = {
      like: "like",
      dislike: "dislike",
      ignore: "click",
    };

    await this.behaviorTrackingService.track({
      userId,
      action: actionMap[dto.action] || "click",
      clothingId: dto.clothingId,
      context: {
        recommendationId: dto.recommendationId,
        source: "recommendation_feedback",
      },
    });

    return { success: true, message: "反馈已记录" };
  }

  @UseGuards(JwtAuthGuard)
  @Post("feedback/batch")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "批量提交推荐反馈",
    description: "批量提交多条推荐反馈，适用于滑动推荐等场景。",
  })
  @ApiResponse({
    status: 200,
    description: "批量反馈已记录",
  })
  async submitBatchFeedback(
    @CurrentUser("id") userId: string,
    @Body() dto: SubmitBatchFeedbackDto,
  ) {
    const actionMap: Record<string, BehaviorAction> = {
      like: "like",
      dislike: "dislike",
      ignore: "click",
    };

    await this.behaviorTrackingService.trackBatch(
      dto.items.map((item) => ({
        userId,
        action: actionMap[item.action] || "click" as BehaviorAction,
        clothingId: item.clothingId,
        context: {
          recommendationId: item.recommendationId,
          source: "recommendation_feedback_batch",
        },
      })),
    );

    return { success: true, message: `已记录 ${dto.items.length} 条反馈` };
  }

  @UseGuards(JwtAuthGuard)
  @Get("cold-start")
  @ApiBearerAuth()
  @ApiOperation({
    summary: "获取冷启动推荐",
    description:
      "为新用户提供的推荐接口，基于 onboarding style quiz 结果生成初始推荐，无需历史行为数据。",
  })
  @ApiQuery({
    name: "limit",
    required: false,
    type: Number,
    description: "返回数量，默认20",
  })
  async getColdStartRecommendations(
    @CurrentUser("id") userId: string,
    @Query("limit") limit?: string,
  ) {
    return this.recommendationsService.getPersonalizedRecommendations(
      userId,
      { limit: limit ? parseInt(limit) : 20 },
    );
  }
}

/**
 * Recommendations Module - Refactored Architecture
 *
 * This module is organized into submodules by algorithm type:
 * - CollaborativeSubmodule: User behavior-based algorithms
 * - ContentSubmodule: Item attribute-based algorithms
 * - KnowledgeSubmodule: Knowledge graph and theory-based algorithms
 *
 * The RecommendationOrchestrator provides a unified facade for all operations.
 */

import { Module, forwardRef } from "@nestjs/common";
import { ConfigModule } from "@nestjs/config";

import { PrismaModule } from "../../common/prisma/prisma.module";
import { RedisModule } from "../../common/redis/redis.module";
import { AIModule } from "../ai/ai.module";
import { AiStylistModule } from "../ai-stylist/ai-stylist.module";
import { CacheModule } from "../cache/cache.module";

import { RecommendationOrchestrator } from "./orchestrator";
import { RecommendationsController } from "./recommendations.controller";
import { RecommendationsService } from "./recommendations.service";
import { AdvancedRecommendationService } from "./services/advanced-recommendation.service";
import { BehaviorTrackingService } from "./services/behavior-tracking.service";
import { Neo4jService } from "./services/neo4j.service";
import { OutfitCompletionService } from "./services/outfit-completion.service";
import { ProfileEventSubscriberService } from "./services/profile-event-subscriber.service";
import { QdrantService } from "./services/qdrant.service";
import { RecommendationCacheService } from "./services/recommendation-cache.service";
import { RecommendationExplainerService } from "./services/recommendation-explainer.service";
import { RecommendationFeedService } from "./services/recommendation-feed.service";
import { SASRecClientService } from "./services/sasrec-client.service";
import { UnifiedRecommendationEngine } from "./services/unified-recommendation.engine";
import {
  CollaborativeSubmodule,
  ContentSubmodule,
  KnowledgeSubmodule,
} from "./submodules";

@Module({
  imports: [
    PrismaModule,
    ConfigModule,
    AIModule,
    forwardRef(() => AiStylistModule),
    RedisModule,
    CacheModule,
    // Algorithm submodules
    CollaborativeSubmodule,
    ContentSubmodule,
    KnowledgeSubmodule,
  ],
  controllers: [RecommendationsController],
  providers: [
    // Facade
    RecommendationOrchestrator,
    // Main service (backwards compatible)
    RecommendationsService,
    // Advanced service
    AdvancedRecommendationService,
    // Unified engine
    UnifiedRecommendationEngine,
    // Explainer
    RecommendationExplainerService,
    // Outfit completion
    OutfitCompletionService,
    // Behavior tracking
    BehaviorTrackingService,
    // Profile event subscriber
    ProfileEventSubscriberService,
    // Neo4j knowledge graph
    Neo4jService,
    // Vector search
    QdrantService,
    // Recommendation cache
    RecommendationCacheService,
    // SASRec client
    SASRecClientService,
    // Feed service
    RecommendationFeedService,
  ],
  exports: [
    // Primary exports - use orchestrator for new code
    RecommendationOrchestrator,
    RecommendationsService,
    // Advanced exports
    AdvancedRecommendationService,
    UnifiedRecommendationEngine,
    // Explainer
    RecommendationExplainerService,
    // Outfit completion
    OutfitCompletionService,
    // Behavior tracking
    BehaviorTrackingService,
    // Neo4j knowledge graph
    Neo4jService,
    // Vector search
    QdrantService,
    // Recommendation cache
    RecommendationCacheService,
    // SASRec client
    SASRecClientService,
    // Feed service
    RecommendationFeedService,
  ],
})
export class RecommendationsModule {}

import { Test, TestingModule } from "@nestjs/testing";
import {
  BodyType,
  SkinTone,
  ColorSeason,
  ClothingCategory,
} from "@prisma/client";

import { PrismaService } from "../../common/prisma/prisma.service";
import { CacheService } from "../cache/cache.service";

import { RecommendationsService } from "./recommendations.service";


describe("RecommendationsService", () => {
  let service: RecommendationsService;
  let prisma: PrismaService;

  const mockPrismaService = {
    userProfile: {
      findUnique: jest.fn(),
    },
    clothingItem: {
      findMany: jest.fn(),
    },
  };

  const mockCacheService = {
    get: jest.fn(),
    set: jest.fn(),
    del: jest.fn(),
    delPattern: jest.fn(),
    getOrSet: jest.fn().mockImplementation(async (key, fetcher) => fetcher()),
    ttl: jest.fn(),
    exists: jest.fn(),
    refresh: jest.fn(),
  };

  const mockProfile = {
    userId: "test-user-id",
    bodyType: BodyType.hourglass,
    skinTone: SkinTone.medium,
    colorSeason: ColorSeason.autumn_warm,
    stylePreferences: ["casual", "elegant"],
    colorPreferences: ["blue", "black"],
  };

  const mockClothingItem = {
    id: "item-id",
    name: "测试服装",
    price: 199,
    colors: ["olive", "mustard"],
    viewCount: 150,
    likeCount: 80,
    attributes: {
      bodyTypeFit: [BodyType.hourglass],
      colorSeasons: [ColorSeason.autumn_warm],
      style: ["casual"],
      season: ["fall"],
      occasions: ["daily"],
    },
    brand: {
      id: "brand-id",
      name: "测试品牌",
      logo: "https://example.com/logo.jpg",
    },
  };

  beforeEach(async () => {
    const module: TestingModule = await Test.createTestingModule({
      providers: [
        RecommendationsService,
        {
          provide: PrismaService,
          useValue: mockPrismaService,
        },
        {
          provide: CacheService,
          useValue: mockCacheService,
        },
      ],
    }).compile();

    service = module.get<RecommendationsService>(RecommendationsService);
    prisma = module.get<PrismaService>(PrismaService);
  });

  afterEach(() => {
    jest.clearAllMocks();
  });

  describe("getPersonalizedRecommendations", () => {
    it("应该返回个性化推荐", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        mockClothingItem,
      ]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      // Service returns RecommendedItem[] directly (not wrapped in { items: [...] })
      expect(result.length).toBeGreaterThan(0);
      expect(result[0]).toHaveProperty("item");
      expect(result[0]).toHaveProperty("score");
      expect(result[0]).toHaveProperty("matchReasons");
    });

    it("应该返回热门商品当没有用户档案时", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(null);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        mockClothingItem,
      ]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");
      const firstRecommendation = result[0];

      expect(firstRecommendation?.score).toBe(60);
      expect(firstRecommendation?.matchReasons).toContain("热门单品");
    });

    it("应该按分类筛选", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        mockClothingItem,
      ]);

      await service.getPersonalizedRecommendations("test-user-id", {
        category: ClothingCategory.tops,
      });

      expect(mockPrismaService.clothingItem.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({
            category: ClothingCategory.tops,
          }),
        }),
      );
    });

    it("应该限制返回数量", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        mockClothingItem,
      ]);

      await service.getPersonalizedRecommendations("test-user-id", {
        limit: 5,
      });

      // Service optimized: uses pageSize * 1.5 instead of limit * 3
      expect(mockPrismaService.clothingItem.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          take: 15, // pageSize * 1.5 = 15
        }),
      );
    });
  });

  describe("getStyleGuide", () => {
    it("应该返回风格指南", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);

      const result = await service.getStyleGuide("test-user-id");

      expect(result.bodyType).toBe("X型");
      expect(result.colorSeason).toBe("秋季暖型");
      expect(result.recommendations.length).toBeGreaterThan(0);
    });

    it("应该返回默认提示当没有用户档案时", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue(null);

      const result = await service.getStyleGuide("test-user-id");

      expect(result.bodyType).toBeNull();
      expect(result.skinTone).toBeNull();
      expect(result.colorSeason).toBeNull();
      expect(result.recommendations).toContain("请先完善您的形象档案");
    });

    it("应该返回矩形体型推荐", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue({
        ...mockProfile,
        bodyType: BodyType.rectangle,
        colorSeason: null,
      });

      const result = await service.getStyleGuide("test-user-id");

      expect(result.bodyType).toBe("H型");
      expect(result.recommendations).toContain("选择有腰线的款式来创造曲线感");
    });

    it("应该返回春季型色彩推荐", async () => {
      mockPrismaService.userProfile.findUnique.mockResolvedValue({
        ...mockProfile,
        bodyType: null,
        colorSeason: ColorSeason.spring_warm,
      });

      const result = await service.getStyleGuide("test-user-id");

      expect(result.colorSeason).toBe("春季暖型");
      expect(result.recommendations.some((r) => r.includes("暖色调"))).toBe(
        true,
      );
    });
  });

  describe("匹配分数计算", () => {
    it("应该为匹配体型的服装加分", async () => {
      const itemWithBodyTypeFit = {
        ...mockClothingItem,
        attributes: {
          ...mockClothingItem.attributes,
          bodyTypeFit: [BodyType.hourglass, BodyType.rectangle],
        },
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        itemWithBodyTypeFit,
      ]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      // 体型匹配应该获得加分
      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("应该为匹配色彩季型的服装加分", async () => {
      const itemWithColorSeason = {
        ...mockClothingItem,
        attributes: {
          ...mockClothingItem.attributes,
          colorSeasons: [ColorSeason.autumn_warm, ColorSeason.winter_cool],
        },
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        itemWithColorSeason,
      ]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("应该为匹配肤色的服装颜色加分", async () => {
      const itemWithFlatteringColor = {
        ...mockClothingItem,
        colors: ["olive", "mustard", "burgundy"],
        attributes: {},
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        itemWithFlatteringColor,
      ]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      expect(result[0]!.score).toBeGreaterThanOrEqual(50);
    });

    it("应该为匹配风格的服装加分", async () => {
      const itemWithStyle = {
        ...mockClothingItem,
        attributes: {
          bodyTypeFit: [BodyType.hourglass],
        },
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([itemWithStyle]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("应该为匹配季节的服装加分", async () => {
      const itemWithSeason = {
        ...mockClothingItem,
        attributes: {
          seasons: ["fall", "winter"],
        },
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([itemWithSeason]);

      const result = await service.getPersonalizedRecommendations(
        "test-user-id",
        { season: "fall" },
      );

      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("应该为匹配场合的服装加分", async () => {
      const itemWithOccasion = {
        ...mockClothingItem,
        attributes: {
          styleTags: ["business", "formal"],
        },
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([
        itemWithOccasion,
      ]);

      const result = await service.getPersonalizedRecommendations(
        "test-user-id",
        { occasion: "work" },
      );

      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("应该为高浏览量的服装加分", async () => {
      const popularItem = {
        ...mockClothingItem,
        viewCount: 500,
        likeCount: 200,
        attributes: {},
      };

      mockPrismaService.userProfile.findUnique.mockResolvedValue(mockProfile);
      mockPrismaService.clothingItem.findMany.mockResolvedValue([popularItem]);

      const result =
        await service.getPersonalizedRecommendations("test-user-id");

      expect(result[0]!.score).toBeGreaterThan(50);
    });

    it("分数不应该超过100", async () => {
      const perfectItem = {
        ...mockClothingItem,
        viewCount: 10000,
        likeCount: 5000,
        attributes: {
