import {
  Injectable,
  Logger,
  ServiceUnavailableException,
} from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import type { ClothingCategory } from "@prisma/client";
import axios from "axios";

import { allowUnverifiedAiFallbacks } from "../../common/config/runtime-flags";
import { PrismaService } from "../../common/prisma/prisma.service";
import { QdrantService } from "../recommendations/services/qdrant.service";

import {
  type ClothingItemWhereInput,
  type ClothingItemOrderByWithRelationInput,
  type MLSimilarItemResult,
  type MLAnalysisResponse,
  type ClothingAttributes,
  type ScoredSearchResult,
  type PaginatedSearchResult,
  type ClothingItemWithBrand,
  type SearchSuggestionsResult,
  buildSearchWhereClause,
  buildOrderByClause,
  getClothingAttributes,
} from "./types/search.types";

@Injectable()
export class SearchService {
  private readonly logger = new Logger(SearchService.name);
  private readonly mlServiceUrl: string;
  private readonly allowFallbacks: boolean;

  constructor(
    private prisma: PrismaService,
    private configService: ConfigService,
    private qdrantService: QdrantService,
  ) {
    this.allowFallbacks = allowUnverifiedAiFallbacks(this.configService);
    this.mlServiceUrl = this.configService.get<string>(
      "ML_SERVICE_URL",
      "http://localhost:8001",
    );
  }

  /**
   * Hybrid search using Reciprocal Rank Fusion (RRF).
   * Combines text search (Prisma), vector search (Qdrant), and popularity signals.
   * RRF formula: score = sum(1 / (k + rank_i)) for each ranking, k=60.
   */
  async hybridSearch(
    query: string,
    options: {
      category?: string;
      minPrice?: number;
      maxPrice?: number;
      page?: number;
      limit?: number;
    } = {},
  ): Promise<PaginatedSearchResult<ScoredSearchResult>> {
    const {
      category,
      minPrice,
      maxPrice,
      page = 1,
      limit = 20,
    } = options;

    const candidateLimit = limit * 3; // Fetch more candidates for RRF fusion
    const rrfK = 60; // Standard RRF constant

    // Step 1: Text search via Prisma (ranking 1)
    const textWhere: ClothingItemWhereInput = buildSearchWhereClause({
      query,
      category,
      minPrice,
      maxPrice,
    });
    const textItems = await this.prisma.clothingItem.findMany({
      where: textWhere,
      include: { brand: { select: { id: true, name: true, logo: true } } },
      take: candidateLimit,
    });
    const textRanks = new Map<string, number>();
    textItems.forEach((item, idx) => {
      textRanks.set(item.id, idx + 1);
    });

    // Step 2: Vector search via Qdrant (ranking 2)
    const vectorRanks = new Map<string, number>();
    try {
      // Get query embedding from ML service
      const embedResponse = await axios.post<{ embedding: number[] }>(
        `${this.mlServiceUrl}/embed/text`,
        { text: query },
        { timeout: 10000 },
      );
      const queryVector = embedResponse.data.embedding;
      if (queryVector && queryVector.length > 0) {
        const vectorResults = await this.qdrantService.searchSimilar(
          queryVector,
          { topK: candidateLimit, minScore: 0.3 },
        );
        vectorResults.forEach((result, idx) => {
          vectorRanks.set(result.id, idx + 1);
        });
      }
    } catch (error: unknown) {
      this.logger.warn(
        `Vector search unavailable for hybrid: ${error instanceof Error ? error.message : String(error)}`,
      );
    }

    // Step 3: Collect all candidate IDs
    const allIds = new Set([...textRanks.keys(), ...vectorRanks.keys()]);
    if (allIds.size === 0) {
      return {
        items: [],
        page,
        limit,
        total: 0,
        totalPages: 0,
        query,
      };
    }

    // Step 4: Fetch popularity data for all candidates
    const candidates = await this.prisma.clothingItem.findMany({
      where: {
        id: { in: Array.from(allIds) },
        isActive: true,
      },
      include: { brand: { select: { id: true, name: true, logo: true } } },
    });

    // Step 5: Compute RRF scores
    // Weight: text 40%, vector 40%, popularity 20%
    const scored = candidates.map((item) => {
      let rrfScore = 0;

      // Text contribution (40% weight)
      const textRank = textRanks.get(item.id);
      if (textRank !== undefined) {
        rrfScore += 0.4 / (rrfK + textRank);
      }

      // Vector contribution (40% weight)
      const vectorRank = vectorRanks.get(item.id);
      if (vectorRank !== undefined) {
        rrfScore += 0.4 / (rrfK + vectorRank);
      }

      // Popularity contribution (20% weight, normalized)
      const popularityScore = Math.min(
        1,
        (item.viewCount * 0.5 + item.likeCount) / 1000,
      );
      rrfScore += 0.2 * popularityScore;

      return {
        ...item,
        similarityScore: rrfScore,
        matchReasons: this.generateHybridReasons(
          textRank !== undefined,
          vectorRank !== undefined,
          item.viewCount,
        ),
      };
    });

    // Sort by RRF score descending
    scored.sort((a, b) => b.similarityScore - a.similarityScore);

    const total = scored.length;
    const paginated = scored.slice((page - 1) * limit, page * limit);

    return {
      items: paginated,
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit),
      query,
    };
  }

  private generateHybridReasons(
    hasTextMatch: boolean,
    hasVectorMatch: boolean,
    viewCount: number,
  ): string[] {
    const reasons: string[] = [];
    if (hasTextMatch) {
      reasons.push("关键词匹配");
    }
    if (hasVectorMatch) {
      reasons.push("语义相似");
    }
    if (viewCount > 100) {
      reasons.push("热门商品");
    }
    return reasons.length > 0 ? reasons : ["综合推荐"];
  }

  async searchItems(
    query: string,
    options: {
      category?: string;
      minPrice?: number;
      maxPrice?: number;
      sortBy?: "relevance" | "price_asc" | "price_desc" | "popular";
      page?: number;
      limit?: number;
    } = {},
  ): Promise<PaginatedSearchResult<ClothingItemWithBrand>> {
    const {
      category,
      minPrice,
      maxPrice,
      sortBy = "relevance",
      page = 1,
      limit = 20,
    } = options;

    // 使用类型安全的 where 条件构建函数
    const where: ClothingItemWhereInput = buildSearchWhereClause({
      query,
      category,
      minPrice,
      maxPrice,
    });

    // 使用类型安全的排序构建函数
    const orderBy: ClothingItemOrderByWithRelationInput =
      buildOrderByClause(sortBy);

    const skip = (page - 1) * limit;

    const [items, total] = await Promise.all([
      this.prisma.clothingItem.findMany({
        where,
        include: {
          brand: { select: { id: true, name: true, logo: true } },
        },
        orderBy,
        skip,
        take: limit,
      }),
      this.prisma.clothingItem.count({ where }),
    ]);

    return {
      items,
      page,
      limit,
      total,
      totalPages: Math.ceil(total / limit),
      query,
    };
  }

  async searchByImage(
    imageUrl: string,
    limit: number = 20,
  ): Promise<ScoredSearchResult[]> {
    try {
      const mlResponse = await axios.post<{
        results: MLSimilarItemResult[];
      }>(
        `${this.mlServiceUrl}/search/similar`,
        {
          image_url: imageUrl,
          top_k: limit * 2,
        },
        { timeout: 30000 },
      );

      const similarItems = mlResponse.data.results || [];

      if (similarItems.length === 0) {
        if (!this.allowFallbacks) {
          throw new ServiceUnavailableException("图像搜索服务未返回结果");
        }
        return this.fallbackSearch(limit);
      }

      const itemIds = similarItems.map((item) => item.id);
      const items = await this.prisma.clothingItem.findMany({
        where: {
          id: { in: itemIds },
          isActive: true,
        },
        include: {
          brand: { select: { id: true, name: true, logo: true } },
        },
      });

      const itemMap = new Map(items.map((item) => [item.id, item]));

      return similarItems
        .filter((sim) => itemMap.has(sim.id))
        .map((sim) => {
          const item = itemMap.get(sim.id);
          if (!item) {
            throw new Error(`Item ${sim.id} not found in map`);
          }
          return {
            ...item,
            similarityScore: sim.similarity,
            matchReasons: sim.reasons || [],
          };
        })
        .slice(0, limit);
    } catch (error: unknown) {
      this.logger.error(
        `ML service error: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (!this.allowFallbacks) {
        throw new ServiceUnavailableException("图像搜索服务不可用");
      }
      return this.attributeBasedSearch(imageUrl, limit);
    }
  }

  private async fallbackSearch(
    limit: number,
  ): Promise<ScoredSearchResult[]> {
    const items = await this.prisma.clothingItem.findMany({
      where: { isActive: true },
      include: {
        brand: { select: { id: true, name: true, logo: true } },
      },
      orderBy: { viewCount: "desc" },
      take: limit,
    });

    return items.map((item) => ({
      ...item,
      similarityScore: 0,
      matchReasons: ["热门推荐"],
    }));
  }

  private async attributeBasedSearch(
    imageUrl: string,
    limit: number,
  ): Promise<ScoredSearchResult[]> {
    try {
      const analysisResponse = await axios.post<MLAnalysisResponse>(
        `${this.mlServiceUrl}/analyze`,
        { image_url: imageUrl },
        { timeout: 30000 },
      );

      const analysis = analysisResponse.data;
      const { category, style, colors } = analysis.clothing || {};

      const where: ClothingItemWhereInput = { isActive: true };

      if (category) {
        where.category = category as ClothingCategory;
      }

      const candidates = await this.prisma.clothingItem.findMany({
        where,
        include: {
          brand: { select: { id: true, name: true, logo: true } },
        },
        take: limit * 3,
      });

      const scoredItems = candidates.map((item) => {
        let score = 30;

        const attrs = getClothingAttributes(item.attributes);
        if (style && attrs?.style) {
          const styleMatch = attrs.style.filter((s) =>
            style.some((qs) => s.toLowerCase() === qs.toLowerCase()),
          );
          score += styleMatch.length * 15;
        }

        if (colors && item.colors) {
          const colorMatch = item.colors.filter((c) =>
            colors.some(
              (qc) =>
                c.toLowerCase().includes(qc.toLowerCase()) ||
                qc.toLowerCase().includes(c.toLowerCase()),
            ),
          );
          score += colorMatch.length * 10;
        }

        score += Math.min(item.viewCount / 100, 10);
        score += Math.min(item.likeCount / 50, 10);

        return {
          ...item,
          similarityScore: Math.min(score, 100),
          matchReasons: this.generateMatchReasons(attrs, colors, item.colors),
        };
      });

      scoredItems.sort((a, b) => b.similarityScore - a.similarityScore);

      return scoredItems.slice(0, limit);
    } catch (error: unknown) {
      this.logger.error(
        `Attribute search failed: ${error instanceof Error ? error.message : String(error)}`,
      );
      if (!this.allowFallbacks) {
        throw new ServiceUnavailableException("图像属性搜索服务不可用");
      }
      return this.fallbackSearch(limit);
    }
  }

  private generateMatchReasons(
    attrs: ClothingAttributes | null,
    queryColors: string[] | undefined,
    itemColors: string[],
  ): string[] {
    const reasons: string[] = [];

    if (attrs?.style && attrs.style.length > 0) {
      reasons.push(`${attrs.style[0]}风格`);
    }

    if (queryColors && itemColors.length > 0) {
      const matchedColor = itemColors.find((ic) =>
        queryColors.some(
          (qc) =>
            ic.toLowerCase().includes(qc.toLowerCase()) ||
            qc.toLowerCase().includes(ic.toLowerCase()),
        ),
      );
      if (matchedColor) {
        reasons.push(`包含${matchedColor}色调`);
      }
    }

    return reasons.length > 0 ? reasons : ["相似推荐"];
  }

  async getSearchSuggestions(
    query: string,
    limit: number = 10,
  ): Promise<SearchSuggestionsResult> {
    // Escape special ILIKE pattern characters to prevent pattern injection
    const escapedQuery = query.replace(/[%_\\]/g, "\\$&");
    const pattern = `%${escapedQuery}%`;

    const items = await this.prisma.clothingItem.findMany({
      where: {
        isActive: true,
        name: { contains: query, mode: "insensitive" },
      },
      select: { name: true },
      take: limit,
    });

    const tags = await this.prisma.$queryRaw<{ tag: string }[]>`
      SELECT DISTINCT unnest(tags) as tag
      FROM "ClothingItem"
      WHERE "isActive" = true
        AND unnest(tags) ILIKE ${pattern}
      LIMIT ${limit}
    `;

    return {
      itemNames: items.map((i) => i.name),
      tags: tags.map((t) => t.tag),
    };
  }

  /**
   * Enhanced search with multi-dimension filters + sales sort.
   */
  async searchWithFilters(
    query: string,
    options: {
      category?: string;
      minPrice?: number;
      maxPrice?: number;
      sortBy?: "relevance" | "price_asc" | "price_desc" | "popular" | "sales";
      page?: number;
      limit?: number;
      brandIds?: string[];
      colors?: string[];
      sizes?: string[];
      styleTags?: string[];
    } = {},
  ): Promise<PaginatedSearchResult<ClothingItemWithBrand>> {
    const {
      category,
      minPrice,
      maxPrice,
      sortBy = "relevance",
      page = 1,
      limit = 20,
      brandIds,
      colors,
      sizes,
      styleTags,
    } = options;

    const where: ClothingItemWhereInput = buildSearchWhereClause({
      query,
      category,
      minPrice,
      maxPrice,
    });

    // Add multi-dimension filters
    if (brandIds && brandIds.length > 0) {
      (where as Record<string, unknown>).brandId = { in: brandIds };
    }
    if (colors && colors.length > 0) {
      (where as Record<string, unknown>).colors = { hasSome: colors };
    }
    if (sizes && sizes.length > 0) {
      (where as Record<string, unknown>).sizes = { hasSome: sizes };
    }
    if (styleTags && styleTags.length > 0) {
      (where as Record<string, unknown>).tags = { hasSome: styleTags };
    }

    let orderBy: ClothingItemOrderByWithRelationInput;

    if (sortBy === "sales") {
      // For sales sort, fetch items and join with ProductSalesStats
      const skip = (page - 1) * limit;
      const [items, total] = await Promise.all([
        this.prisma.clothingItem.findMany({
          where,
          include: {
            brand: { select: { id: true, name: true, logo: true } },
            salesStats: {
              where: { date: { gte: new Date(Date.now() - 30 * 24 * 60 * 60 * 1000) } },
              select: { purchases: true },
            },
          },
          skip,
          take: limit,
        }),
        this.prisma.clothingItem.count({ where }),
      ]);

      // Sort by total purchases descending
      const sorted = items
        .map((item) => ({
          ...item,
          totalPurchases: (item as Record<string, unknown>).salesStats
            ? ((item as Record<string, unknown>).salesStats as Array<{ purchases: number }>)
                .reduce((sum: number, s: { purchases: number }) => sum + s.purchases, 0)
            : 0,
        }))
        .sort((a, b) => b.totalPurchases - a.totalPurchases);

      return { items: sorted, page, limit, total, totalPages: Math.ceil(total / limit), query };
    }

    orderBy = buildOrderByClause("popular");
    const skip = (page - 1) * limit;

    const [items, total] = await Promise.all([
      this.prisma.clothingItem.findMany({
        where,
        include: {
          brand: { select: { id: true, name: true, logo: true } },
        },
        orderBy,
        skip,
        take: limit,
      }),
      this.prisma.clothingItem.count({ where }),
    ]);

    return { items, page, limit, total, totalPages: Math.ceil(total / limit), query };
  }

  /**
   * Get available filter options for search context.
   */
  async getFilterOptions(category?: string) {
    const where: Record<string, unknown> = { isActive: true, isDeleted: false };
    if (category) {
      where.category = category;
    }

    const [brands, priceAgg] = await Promise.all([
      this.prisma.brand.findMany({
        where: { products: { some: where as never } },
        select: { id: true, name: true, _count: { select: { products: { where: where as never } } } },
        orderBy: { name: "asc" },
      }),
      this.prisma.clothingItem.aggregate({
        where: where as never,
        _min: { price: true },
        _max: { price: true },
      }),
    ]);

    // Get distinct colors and sizes
    const colorItems = await this.prisma.clothingItem.findMany({
      where: where as never,
      select: { colors: true },
    });
    const sizeItems = await this.prisma.clothingItem.findMany({
      where: where as never,
      select: { sizes: true },
    });

    const colorCounts: Record<string, number> = {};
    for (const item of colorItems) {
      for (const c of item.colors) {
        colorCounts[c] = (colorCounts[c] || 0) + 1;
      }
    }

    const sizeCounts: Record<string, number> = {};
    for (const item of sizeItems) {
      for (const s of item.sizes) {
        sizeCounts[s] = (sizeCounts[s] || 0) + 1;
      }
    }

    return {
      brands: brands.map((b) => ({ id: b.id, name: b.name, count: b._count.products })),
      colors: Object.entries(colorCounts)
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => b.count - a.count),
      sizes: Object.entries(sizeCounts)
        .map(([value, count]) => ({ value, count }))
        .sort((a, b) => b.count - a.count),
      priceRange: {
        min: priceAgg._min.price ? Number(priceAgg._min.price) : 0,
        max: priceAgg._max.price ? Number(priceAgg._max.price) : 0,
      },
    };
  }
}

import { Injectable } from "@nestjs/common";
import type { Prisma, ClothingCategory } from "@prisma/client";

import { PrismaService } from "../../../common/prisma/prisma.service";
import {
  type ClothingItemWhereInput,
  type ClothingAttributes,
  type ClothingItemWithBrand,
  getClothingAttributes,
} from "../types/search.types";

import { AIAnalysisResult, AIImageService } from "./ai-image.service";

export interface VisualSearchResult {
  id: string;
  name: string;
  images: string[];
  price: number;
  currency: string;
  category: string;
  subcategory?: string | null;
  colors: string[];
  tags: string[];
  createdAt: Date;
  updatedAt: Date;
  brand?: {
    id: string;
    name: string;
    logo?: string | null;
  } | null;
  similarityScore: number;
  matchReasons: string[];
}

export interface ImageFeatures {
  colorHistogram: number[];
  dominantColors: string[];
  textureFeatures: number[];
  embedding?: number[];
  labels?: string[];
  style?: string;
  category?: string;
}

/**
 * 带品牌信息的服装商品（用于内部计算）
 */
interface ClothingItemCandidate extends ClothingItemWithBrand {
  viewCount: number;
  likeCount: number;
  brandId: string | null;
}

@Injectable()
export class VisualSearchService {
  constructor(
    private prisma: PrismaService,
    private aiImageService: AIImageService,
  ) {}

  async searchByImage(
    imageBuffer: Buffer,
    options: {
      category?: string;
      minPrice?: number;
      maxPrice?: number;
      limit?: number;
    } = {},
  ): Promise<VisualSearchResult[]> {
    const { category, minPrice, maxPrice, limit = 20 } = options;

    // 提取图像特征
    const features = await this.extractFeatures(imageBuffer);

    // 获取候选商品
    const candidates = await this.getCandidateItems(
      category || features.category,
      minPrice,
      maxPrice,
      limit * 3,
    );

    // 计算相似度并排序
    const scoredItems = await Promise.all(
      candidates.map(async (item) => {
        const similarity = await this.calculateSimilarity(features, item);
        const matchReasons = this.generateMatchReasons(
          features,
          item,
          similarity,
        );
        return {
          ...item,
          similarityScore: similarity,
          matchReasons,
        };
      }),
    );

    // 按相似度排序并返回 top N
    scoredItems.sort((a, b) => b.similarityScore - a.similarityScore);

    return scoredItems.slice(0, limit).map((item) => ({
      id: item.id,
      name: item.name,
      images: item.images,
      price: Number(item.price),
      currency: item.currency,
      category: item.category,
      subcategory: item.subcategory,
      colors: item.colors ?? [],
      tags: item.tags ?? [],
      createdAt: item.createdAt,
      updatedAt: item.updatedAt,
      brand: item.brand,
      similarityScore: item.similarityScore,
      matchReasons: item.matchReasons,
    }));
  }

  async extractFeatures(imageBuffer: Buffer): Promise<ImageFeatures> {
    const analysis = await this.aiImageService.analyzeImage(imageBuffer);
    return this.mapAnalysisToFeatures(analysis);
  }

  private async getCandidateItems(
    category?: string,
    minPrice?: number,
    maxPrice?: number,
    limit?: number,
  ): Promise<ClothingItemCandidate[]> {
    const where: ClothingItemWhereInput = { isActive: true };

    if (category) {
      where.category = category as ClothingCategory;
    }

    if (minPrice !== undefined || maxPrice !== undefined) {
      where.price = {};
      if (minPrice !== undefined) {
        (where.price as { gte?: number }).gte = minPrice;
      }
      if (maxPrice !== undefined) {
        (where.price as { lte?: number }).lte = maxPrice;
      }
    }

    return this.prisma.clothingItem.findMany({
      where,
      include: {
        brand: {
          select: {
            id: true,
            name: true,
            logo: true,
          },
        },
      },
      take: limit,
    }) as Promise<ClothingItemCandidate[]>;
  }

  private async calculateSimilarity(
    queryFeatures: ImageFeatures,
    item: ClothingItemCandidate,
  ): Promise<number> {
    let score = 50; // 基础分

    // 颜色相似度
    if (item.colors && item.colors.length > 0) {
      const colorMatch = this.calculateColorMatch(
        queryFeatures.dominantColors,
        item.colors,
      );
      score += colorMatch * 20;
    }

    // 基于商品属性的相似度
    const attrs = getClothingAttributes(item.attributes);
    if (attrs) {
      // 风格匹配
      if (attrs.style) {
        score += 5;
      }

      // 图案匹配
      if (attrs.patterns && attrs.patterns.length > 0) {
        score += 5;
      }

      if (
        queryFeatures.style &&
        Array.isArray(attrs.style) &&
        attrs.style.some(
          (style) =>
            style.toLowerCase() === queryFeatures.style?.toLowerCase(),
        )
      ) {
        score += 10;
      }
    }

    // 热度加成
    score += Math.min(item.viewCount / 200, 5);
    score += Math.min(item.likeCount / 100, 5);

    return Math.min(score, 100);
  }

  private calculateColorMatch(
    queryColors: string[],
    itemColors: string[],
  ): number {
    if (!queryColors.length || !itemColors.length) {return 0;}

    let matchCount = 0;
    const colorMappings: Record<string, string[]> = {
      red: ["red", "crimson", "scarlet", "maroon", "burgundy", "wine"],
      orange: ["orange", "coral", "peach", "rust", "terracotta"],
      yellow: ["yellow", "gold", "mustard", "amber", "cream"],
      green: ["green", "olive", "emerald", "mint", "forest", "sage"],
      blue: ["blue", "navy", "azure", "teal", "cyan", "indigo"],
      purple: ["purple", "violet", "lavender", "plum", "magenta"],
      pink: ["pink", "rose", "blush", "fuchsia"],
      brown: ["brown", "tan", "beige", "camel", "chocolate", "coffee"],
      black: ["black", "charcoal", "ebony", "jet"],
      white: ["white", "ivory", "cream", "snow"],
      gray: ["gray", "grey", "silver", "slate", "ash"],
    };

    for (const qc of queryColors) {
      const qcLower = qc.toLowerCase();
      for (const ic of itemColors) {
        const icLower = ic.toLowerCase();

        // 直接匹配
        if (
          qcLower === icLower ||
          icLower.includes(qcLower) ||
          qcLower.includes(icLower)
        ) {
          matchCount++;
          break;
        }

        // 通过映射匹配
        for (const [, variants] of Object.entries(colorMappings)) {
          if (
            variants.some((v) => qcLower.includes(v)) &&
            variants.some((v) => icLower.includes(v))
          ) {
            matchCount += 0.8;
            break;
          }
        }
      }
    }

    return Math.min(matchCount / queryColors.length, 1);
  }

  private generateMatchReasons(
    features: ImageFeatures,
    item: ClothingItemCandidate,
    similarity: number,
  ): string[] {
    const reasons: string[] = [];

    if (similarity > 80) {
      reasons.push("高度相似的款式");
    } else if (similarity > 60) {
      reasons.push("风格相近");
    }

    // 颜色匹配原因
    if (
      item.colors &&
      item.colors.length > 0 &&
      features.dominantColors.length > 0
    ) {
      const matchedColor = this.findMatchedColor(
        features.dominantColors,
        item.colors,
      );
      if (matchedColor) {
        reasons.push(`包含${matchedColor}色调`);
      }
    }

    // 属性匹配
    const attrs = getClothingAttributes(item.attributes);
    if (attrs) {
      if (attrs.style && attrs.style.length > 0) {
        reasons.push(`${attrs.style[0] ?? ""}风格`);
      }
      if (attrs.occasions && attrs.occasions.length > 0) {
        reasons.push(`适合${attrs.occasions[0] ?? ""}`);
      }
    }

    // 品牌推荐
    if (item.brand) {
      reasons.push(`${item.brand.name}品牌商品`);
    }

    return reasons.slice(0, 3);
  }

  private findMatchedColor(
    queryColors: string[],
    itemColors: string[],
  ): string | null {
    for (const qc of queryColors) {
      const qcLower = qc.toLowerCase();
      for (const ic of itemColors) {
        const icLower = ic.toLowerCase();
        if (icLower.includes(qcLower) || qcLower.includes(icLower)) {
          return ic;
        }
      }
    }
    return itemColors[0] ?? null;
  }

  private mapAnalysisToFeatures(analysis: AIAnalysisResult): ImageFeatures {
    return {
      colorHistogram: [],
      dominantColors: analysis.colors || [],
      textureFeatures: [],
      embedding: analysis.embedding,
      labels: analysis.labels,
      style: analysis.style,
      category: analysis.category,
    };
  }

  async findSimilarItems(
    itemId: string,
    limit: number = 10,
  ): Promise<VisualSearchResult[]> {
    const item = await this.prisma.clothingItem.findUnique({
      where: { id: itemId },
      include: {
        brand: {
          select: {
            id: true,
            name: true,
            logo: true,
          },
        },
      },
    });

    if (!item) {
      return [];
    }

    // 基于商品属性查找相似商品
    const similarItems = await this.prisma.clothingItem.findMany({
      where: {
        isActive: true,
        id: { not: itemId },
        category: item.category,
      },
      include: {
        brand: {
          select: {
            id: true,
            name: true,
            logo: true,
          },
        },
      },
      take: limit * 2,
    });

    // 计算相似度
    const scoredItems = similarItems.map((similar) => {
      let score = 50;

      // 同品牌加成
      if (similar.brandId === item.brandId) {
        score += 10;
      }

      // 颜色匹配
      if (item.colors && similar.colors) {
        const commonColors = item.colors.filter((c) =>
          similar.colors.some((sc) =>
            sc.toLowerCase().includes(c.toLowerCase()),
          ),
        );
        score += commonColors.length * 10;
      }

      // 属性匹配
      const itemAttrs = getClothingAttributes(item.attributes);
      const similarAttrs = getClothingAttributes(similar.attributes);

      if (itemAttrs?.style && similarAttrs?.style) {
        const similarStyles = similarAttrs.style;
        const commonStyles = itemAttrs.style.filter((s) =>
          similarStyles.includes(s),
        );
        score += commonStyles.length * 5;
      }

      return {
        id: similar.id,
        name: similar.name,
        images: similar.images,
        price: Number(similar.price),
        currency: similar.currency,
        category: similar.category,
        subcategory: similar.subcategory,
        colors: similar.colors ?? [],
        tags: similar.tags ?? [],
        createdAt: similar.createdAt,
        updatedAt: similar.updatedAt,
        brand: similar.brand,
        similarityScore: Math.min(score, 100),
        matchReasons: this.generateSimilarItemReasons(item, similar),
      };
    });

    scoredItems.sort((a, b) => b.similarityScore - a.similarityScore);

    return scoredItems.slice(0, limit);
  }

  private generateSimilarItemReasons(
    original: Prisma.ClothingItemGetPayload<{
      include: {
        brand: {
          select: {
            id: true;
            name: true;
            logo: true;
          };
        };
      };
    }>,
    similar: Prisma.ClothingItemGetPayload<{
      include: {
        brand: {
          select: {
            id: true;
            name: true;
            logo: true;
          };
        };
      };
    }>,
  ): string[] {
    const reasons: string[] = ["相似款式"];

    if (original.brandId === similar.brandId && similar.brand) {
      reasons.push(`同品牌 ${similar.brand.name}`);
    }

    if (original.colors && similar.colors) {
      const commonColors = original.colors.filter((c) =>
        similar.colors.some((sc) =>
          sc.toLowerCase().includes(c.toLowerCase()),
        ),
      );
      if (commonColors.length > 0) {
        reasons.push(`相同${commonColors[0] ?? ""}色系`);
      }
    }

    return reasons;
  }
}

/**
 * Search Module Type Definitions
 * 搜索模块类型定义 - 消除 any 类型，提供类型安全
 */

import type { Prisma, ClothingCategory } from "@prisma/client";

// ============================================================================
// Prisma Where 条件类型
// ============================================================================

/**
 * 服装商品搜索 Where 条件
 * 用于 searchItems 和相关查询
 */
export type ClothingItemWhereInput = Prisma.ClothingItemWhereInput;

/**
 * 服装商品价格范围条件
 */
export interface PriceRangeFilter {
  gte?: number;
  lte?: number;
}

/**
 * 构建搜索 where 条件的输入参数
 */
export interface SearchWhereBuilderInput {
  query?: string;
  category?: ClothingCategory | string;
  minPrice?: number;
  maxPrice?: number;
}

// ============================================================================
// Prisma OrderBy 类型
// ============================================================================

/**
 * 服装商品排序选项
 */
export type ClothingItemOrderByWithRelationInput =
  Prisma.ClothingItemOrderByWithRelationInput;

/**
 * 排序方式枚举
 */
export type SortByOption =
  | "relevance"
  | "price_asc"
  | "price_desc"
  | "popular";

// ============================================================================
// ML 服务响应类型
// ============================================================================

/**
 * ML 服务相似商品响应项
 */
export interface MLSimilarItemResult {
  id: string;
  similarity: number;
  reasons?: string[];
}

/**
 * ML 服务相似商品搜索响应
 */
export interface MLSimilarItemsResponse {
  results: MLSimilarItemResult[];
}

/**
 * ML 服务图像分析响应 - 服装属性
 */
export interface MLAnalysisClothingData {
  category?: string;
  style?: string[];
  colors?: string[];
}

/**
 * ML 服务图像分析响应
 */
export interface MLAnalysisResponse {
  clothing?: MLAnalysisClothingData;
}

// ============================================================================
// 服装属性类型
// ============================================================================

/**
 * 服装商品属性结构
 * 对应 Prisma schema 中的 attributes Json 字段
 */
export interface ClothingAttributes {
  style?: string[];
  patterns?: string[];
  occasions?: string[];
  materials?: string[];
  season?: string[];
  fit?: string;
  [key: string]: string | string[] | number | boolean | undefined;
}

/**
 * 服装属性类型守卫
 */
export function isClothingAttributes(value: unknown): value is ClothingAttributes {
  if (typeof value !== "object" || value === null) {
    return false;
  }
  const obj = value as Record<string, unknown>;
  // 检查可选字段类型
  if (obj.style !== undefined && !Array.isArray(obj.style)) {
    return false;
  }
  if (obj.patterns !== undefined && !Array.isArray(obj.patterns)) {
    return false;
  }
  if (obj.occasions !== undefined && !Array.isArray(obj.occasions)) {
    return false;
  }
  return true;
}

// ============================================================================
// 搜索结果类型
// ============================================================================

/**
 * 带品牌信息的服装商品
 */
export interface ClothingItemWithBrand {
  id: string;
  name: string;
  description: string | null;
  category: string;
  subcategory: string | null;
  colors: string[];
  sizes: string[];
  tags: string[];
  price: Prisma.Decimal;
  originalPrice: Prisma.Decimal | null;
  currency: string;
  images: string[];
  mainImage: string | null;
  attributes: Prisma.JsonValue | null;
  isActive: boolean;
  viewCount: number;
  likeCount: number;
  createdAt: Date;
  updatedAt: Date;
  brandId: string | null;
  brand: {
    id: string;
    name: string;
    logo: string | null;
  } | null;
}

/**
 * 带相似度分数的搜索结果项
 */
export interface ScoredSearchResult extends ClothingItemWithBrand {
  similarityScore: number;
  matchReasons: string[];
}

/**
 * 分页搜索结果
 */
export interface PaginatedSearchResult<T> {
  items: T[];
  page: number;
  limit: number;
  total: number;
  totalPages: number;
  query: string;
}

/**
 * 搜索建议结果
 */
export interface SearchSuggestionsResult {
  itemNames: string[];
  tags: string[];
}

// ============================================================================
// AI 图像分析类型
// ============================================================================

/**
 * 阿里云图像分析响应样式项
 */
export interface AliyunStyleItem {
  Style?: string;
}

/**
 * 阿里云图像分析响应颜色项
 */
export interface AliyunColorItem {
  ColorName?: string;
}

/**
 * 阿里云图像分析响应数据
 */
export interface AliyunAnalysisData {
  Styles?: AliyunStyleItem[];
  Colors?: AliyunColorItem[];
}

/**
 * 阿里云图像分析完整响应
 */
export interface AliyunAnalysisResponse {
  Data?: AliyunAnalysisData;
}

/**
 * 百度图像分析结果项
 */
export interface BaiduAnalysisResultItem {
  keyword?: string;
}

/**
 * 百度图像分析响应
 */
export interface BaiduAnalysisResponse {
  result?: BaiduAnalysisResultItem[];
  color_result?: Array<{ color_name?: string }>;
}

/**
 * OpenAI 图像分析响应
 */
export interface OpenAIAnalysisContent {
  labels?: string[];
  colors?: string[];
  style?: string;
  category?: string;
}

// ============================================================================
// 辅助函数类型
// ============================================================================

/**
 * 构建 Prisma where 条件
 */
export function buildSearchWhereClause(
  input: SearchWhereBuilderInput,
): ClothingItemWhereInput {
  const where: ClothingItemWhereInput = { isActive: true };

  if (input.query) {
    where.OR = [
      { name: { contains: input.query, mode: "insensitive" } },
      { description: { contains: input.query, mode: "insensitive" } },
      { tags: { hasSome: [input.query] } },
      { brand: { name: { contains: input.query, mode: "insensitive" } } },
    ];
  }

  if (input.category) {
    where.category = input.category as ClothingCategory;
  }

  if (input.minPrice !== undefined || input.maxPrice !== undefined) {
    where.price = {};
    if (input.minPrice !== undefined) {
      (where.price as PriceRangeFilter).gte = input.minPrice;
    }
    if (input.maxPrice !== undefined) {
      (where.price as PriceRangeFilter).lte = input.maxPrice;
    }
  }

  return where;
}

/**
 * 构建排序条件
 */
export function buildOrderByClause(
  sortBy: SortByOption,
): ClothingItemOrderByWithRelationInput {
  switch (sortBy) {
    case "price_asc":
      return { price: "asc" };
    case "price_desc":
      return { price: "desc" };
    case "popular":
      return { viewCount: "desc" };
    default:
      return { createdAt: "desc" };
  }
}

/**
 * 安全获取服装属性
 */
export function getClothingAttributes(
  attributes: Prisma.JsonValue | null,
): ClothingAttributes | null {
  if (attributes === null || attributes === undefined) {
    return null;
  }
  if (isClothingAttributes(attributes)) {
    return attributes;
  }
  return null;
}

import { ConfigService } from "@nestjs/config";
import { EventEmitter2 } from "@nestjs/event-emitter";
import { Test, TestingModule } from "@nestjs/testing";

import { ContentFilterService } from "./content-filter.service";

jest.mock("fs", () => ({
  readFileSync: jest.fn(() =>
    [
      "# Violence",
      "kill",
      "murder",
      "bomb",
      "# Hate Speech",
      "hate speech",
      "slur",
      "# Sexual Content",
      "porn",
      "nude",
      "# Fraud",
      "phishing",
      "fake ID",
      "# Illegal Activity",
