  const mockProfile = {
    userId: "user-1",
    height: 165,
    weight: 60,
    bust: 86,
    waist: 68,
    hip: 94,
    bodyType: "hourglass",
    fitPreference: null,
    colorSeason: null,
    stylePreferences: [],
    colorPreferences: [],
  };

  const mockItem = {
    id: "item-1",
    name: "Test Dress",
    sizes: ["S", "M", "L", "XL"],
    brandId: "brand-1",
    brand: { id: "brand-1", name: "Test Brand" },
