  describe("applyFitPreference (via getRecommendation)", () => {
    it("tight preference shifts measurements by -2cm", async () => {
      // M bust range: 84-88. With bust=88 (top of M), tight offset = 86 → still in M
      const tightProfile = {
        ...mockProfile,
