      mockPrismaService.wardrobeCollectionItem.count.mockResolvedValue(1);
      mockPrismaService.communityPost.findMany.mockResolvedValue([
        { id: "post-1", title: "Post 1" },
      ]);
      mockPrismaService.outfit.findMany.mockResolvedValue([]);
      mockPrismaService.virtualTryOn.findMany.mockResolvedValue([]);

      const result = await service.getCollectionItems("user-1", "col-1", {});

      expect(result.data).toHaveLength(1);
      expect(result.meta.total).toBe(1);
    });
  });

  describe("reorderCollectionItems", () => {
    it("should reorder items using transaction", async () => {
      mockPrismaService.wardrobeCollection.findUnique.mockResolvedValue({
        id: "col-1",
        userId: "user-1",
      });
      mockPrismaService.wardrobeCollectionItem.updateMany.mockResolvedValue({ count: 1 });
      mockPrismaService.$transaction.mockImplementation(async (fns) => Promise.all(fns));

      const result = await service.reorderCollectionItems("user-1", "col-1", {
        itemIds: ["ci-2", "ci-1"],
      });

      expect(result.success).toBe(true);
      expect(mockPrismaService.$transaction).toHaveBeenCalled();
    });
  });
});

import { Injectable, Logger, NotFoundException, ForbiddenException } from "@nestjs/common";
import { Prisma } from "@prisma/client";

import { PrismaService } from "../../common/prisma/prisma.service";

import {
  CreateWardrobeCollectionDto,
  UpdateWardrobeCollectionDto,
  WardrobeCollectionQueryDto,
  CreateCollectionItemDto,
  BatchCreateCollectionItemsDto,
  UpdateCollectionItemDto,
  CollectionItemQueryDto,
  ReorderCollectionItemsDto,
  CollectionItemType,
} from "./dto/wardrobe-collection.dto";

@Injectable()
export class WardrobeCollectionService {
  private readonly logger = new Logger(WardrobeCollectionService.name);

  constructor(private readonly prisma: PrismaService) {}

  // ==================== 分类 CRUD ====================

  async createCollection(userId: string, dto: CreateWardrobeCollectionDto) {
    const collection = await this.prisma.wardrobeCollection.create({
      data: {
        userId,
        name: dto.name,
        icon: dto.icon,
        coverImage: dto.coverImage,
        sortOrder: dto.sortOrder ?? 0,
        isDefault: dto.isDefault ?? false,
      },
      include: {
        _count: {
          select: { items: true },
        },
      },
    });

    this.logger.log(`User ${userId} created wardrobe collection ${collection.id}`);
    return collection;
  }

  async getCollections(userId: string, query: WardrobeCollectionQueryDto) {
    const { page = 1, pageSize = 20 } = query;

    const [collections, total] = await Promise.all([
      this.prisma.wardrobeCollection.findMany({
        where: { userId },
        orderBy: [{ sortOrder: "asc" }, { createdAt: "desc" }],
        skip: (page - 1) * pageSize,
        take: pageSize,
        include: {
          _count: {
            select: { items: true },
          },
        },
      }),
      this.prisma.wardrobeCollection.count({ where: { userId } }),
    ]);

    return {
      data: collections,
      meta: {
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      },
    };
  }

  async getCollectionById(userId: string, collectionId: string) {
    const collection = await this.prisma.wardrobeCollection.findUnique({
      where: { id: collectionId },
      include: {
        _count: {
          select: { items: true },
        },
      },
    });

    if (!collection) {
      throw new NotFoundException("分类不存在");
    }

    if (collection.userId !== userId) {
      throw new ForbiddenException("无权访问此分类");
    }

    return collection;
  }

  async updateCollection(
    userId: string,
    collectionId: string,
    dto: UpdateWardrobeCollectionDto,
  ) {
    await this.verifyOwnership(userId, collectionId);

    return this.prisma.wardrobeCollection.update({
      where: { id: collectionId },
      data: {
        name: dto.name,
        icon: dto.icon,
        coverImage: dto.coverImage,
        sortOrder: dto.sortOrder,
        isDefault: dto.isDefault,
      },
      include: {
        _count: {
          select: { items: true },
        },
      },
    });
  }

  async deleteCollection(userId: string, collectionId: string) {
    const collection = await this.verifyOwnership(userId, collectionId);

    if (collection.isDefault) {
      throw new ForbiddenException("默认分类不可删除");
    }

    await this.prisma.wardrobeCollection.delete({
      where: { id: collectionId },
    });

    this.logger.log(`User ${userId} deleted wardrobe collection ${collectionId}`);
    return { success: true };
  }

  // ==================== 分类项 CRUD ====================

  async addCollectionItem(
    userId: string,
    collectionId: string,
    dto: CreateCollectionItemDto,
  ) {
    await this.verifyOwnership(userId, collectionId);

    await this.validateItemReference(dto.itemType, dto.itemId);

    const item = await this.prisma.wardrobeCollectionItem.create({
      data: {
        collectionId,
        userId,
        itemType: dto.itemType,
        itemId: dto.itemId,
        sortOrder: dto.sortOrder ?? 0,
      },
    });

    await this.updateCollectionCoverImage(collectionId, dto.itemType, dto.itemId);

    return item;
  }

  async batchAddCollectionItems(
    userId: string,
    collectionId: string,
    dto: BatchCreateCollectionItemsDto,
  ) {
    await this.verifyOwnership(userId, collectionId);

    // 逐个校验引用项是否存在
    for (const item of dto.items) {
      await this.validateItemReference(item.itemType, item.itemId);
    }

    const result = await this.prisma.wardrobeCollectionItem.createMany({
      data: dto.items.map((item) => ({
        collectionId,
        userId,
        itemType: item.itemType,
        itemId: item.itemId,
        sortOrder: item.sortOrder ?? 0,
      })),
      skipDuplicates: true,
    });

    this.logger.log(
      `User ${userId} added ${result.count} items to collection ${collectionId}`,
    );

    return { count: result.count };
  }

  async getCollectionItems(
    userId: string,
    collectionId: string,
    query: CollectionItemQueryDto,
  ) {
    await this.verifyOwnership(userId, collectionId);

    const { itemType, page = 1, pageSize = 20 } = query;

    const where: Prisma.WardrobeCollectionItemWhereInput = { collectionId };
    if (itemType) {
      where.itemType = itemType;
    }

    const [items, total] = await Promise.all([
      this.prisma.wardrobeCollectionItem.findMany({
        where,
        orderBy: [{ sortOrder: "asc" }, { createdAt: "desc" }],
        skip: (page - 1) * pageSize,
        take: pageSize,
      }),
      this.prisma.wardrobeCollectionItem.count({ where }),
    ]);

    // 附加引用项详情 - 批量查询避免 N+1 问题
    const itemsWithDetails = await this.batchGetItemDetails(items);

    return {
      data: itemsWithDetails,
      meta: {
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      },
    };
  }

  async updateCollectionItem(
    userId: string,
    collectionId: string,
    itemId: string,
    dto: UpdateCollectionItemDto,
  ) {
    await this.verifyCollectionItemOwnership(userId, collectionId, itemId);

    return this.prisma.wardrobeCollectionItem.update({
      where: { id: itemId },
      data: {
        sortOrder: dto.sortOrder,
      },
    });
  }

  async removeCollectionItem(
    userId: string,
    collectionId: string,
    itemId: string,
  ) {
    await this.verifyCollectionItemOwnership(userId, collectionId, itemId);

    await this.prisma.wardrobeCollectionItem.delete({
      where: { id: itemId },
    });

    return { success: true };
  }

  async reorderCollectionItems(
    userId: string,
    collectionId: string,
    dto: ReorderCollectionItemsDto,
  ) {
    await this.verifyOwnership(userId, collectionId);

    // 使用事务批量更新排序
    await this.prisma.$transaction(
      dto.itemIds.map((itemId, index) =>
        this.prisma.wardrobeCollectionItem.updateMany({
          where: { id: itemId, collectionId },
          data: { sortOrder: index },
        }),
      ),
    );

    return { success: true };
  }

  // ==================== 私有方法 ====================

  /**
   * 验证分类归属权
   */
  private async verifyOwnership(userId: string, collectionId: string) {
    const collection = await this.prisma.wardrobeCollection.findUnique({
      where: { id: collectionId },
    });

    if (!collection) {
      throw new NotFoundException("分类不存在");
    }

    if (collection.userId !== userId) {
      throw new ForbiddenException("无权操作此分类");
    }

    return collection;
  }

  /**
   * 验证分类项归属权
   */
  private async verifyCollectionItemOwnership(
    userId: string,
    collectionId: string,
    itemId: string,
  ) {
    const item = await this.prisma.wardrobeCollectionItem.findUnique({
      where: { id: itemId },
    });

    if (item?.collectionId !== collectionId) {
      throw new NotFoundException("分类项不存在");
    }

    await this.verifyOwnership(userId, collectionId);
    return item;
  }

  /**
   * 验证多态引用项是否存在
   */
  private async validateItemReference(itemType: string, itemId: string) {
    let exists = false;

    switch (itemType) {
      case CollectionItemType.POST: {
        const post = await this.prisma.communityPost.findUnique({
          where: { id: itemId },
        });
        exists = !!post;
        break;
      }
      case CollectionItemType.OUTFIT: {
        const outfit = await this.prisma.outfit.findUnique({
          where: { id: itemId },
        });
        exists = !!outfit;
        break;
      }
      case CollectionItemType.TRY_ON: {
        const tryOn = await this.prisma.virtualTryOn.findUnique({
          where: { id: itemId },
        });
        exists = !!tryOn;
        break;
      }
      default:
        throw new ForbiddenException(`不支持的引用类型: ${itemType}`);
    }

    if (!exists) {
      throw new NotFoundException(`引用的${this.getItemTypeName(itemType)}不存在`);
    }
  }

  /**
   * 批量获取引用项详情 - 避免 N+1 查询问题
   * 按类型分组后批量查询，将 N 次数据库查询降为 3 次（最多3种类型）
   */
  private async batchGetItemDetails(
    items: { id: string; itemType: string; itemId: string; sortOrder: number; createdAt: Date }[],
  ) {
    // 按类型分组收集 ID
    const postIds: string[] = [];
    const outfitIds: string[] = [];
    const tryOnIds: string[] = [];

    for (const item of items) {
      switch (item.itemType) {
        case CollectionItemType.POST: postIds.push(item.itemId); break;
        case CollectionItemType.OUTFIT: outfitIds.push(item.itemId); break;
        case CollectionItemType.TRY_ON: tryOnIds.push(item.itemId); break;
      }
    }

    // 批量查询各类型数据
    const [posts, outfits, tryOns] = await Promise.all([
      postIds.length > 0
        ? this.prisma.communityPost.findMany({
            where: { id: { in: postIds } },
            select: { id: true, title: true, images: true, likeCount: true, author: { select: { id: true, nickname: true, avatar: true } } },
          })
        : [],
      outfitIds.length > 0
        ? this.prisma.outfit.findMany({
            where: { id: { in: outfitIds } },
            select: { id: true, name: true, coverImage: true, rating: true },
          })
        : [],
      tryOnIds.length > 0
        ? this.prisma.virtualTryOn.findMany({
            where: { id: { in: tryOnIds } },
            select: { id: true, resultImageUrl: true, status: true },
          })
        : [],
    ]);

    // 构建查找映射
    const detailMap = new Map<string, any>();
    for (const post of posts) {detailMap.set(post.id, post);}
    for (const outfit of outfits) {detailMap.set(outfit.id, outfit);}
    for (const tryOn of tryOns) {detailMap.set(tryOn.id, tryOn);}

    // 组装结果
    return items.map((item) => ({
      ...item,
      detail: detailMap.get(item.itemId) || null,
    }));
  }

  /**
   * 获取引用项详情（单条查询，保留用于非批量场景）
   */
  private async getItemDetail(itemType: string, itemId: string) {
    switch (itemType) {
      case CollectionItemType.POST: {
        return this.prisma.communityPost.findUnique({
          where: { id: itemId },
          select: {
            id: true,
            title: true,
            images: true,
            likeCount: true,
            author: {
              select: { id: true, nickname: true, avatar: true },
            },
          },
        });
      }
      case CollectionItemType.OUTFIT: {
        return this.prisma.outfit.findUnique({
          where: { id: itemId },
          select: {
            id: true,
            name: true,
            coverImage: true,
            rating: true,
          },
        });
      }
      case CollectionItemType.TRY_ON: {
        return this.prisma.virtualTryOn.findUnique({
          where: { id: itemId },
          select: {
            id: true,
            resultImageUrl: true,
            status: true,
          },
        });
      }
      default:
        return null;
    }
  }

  /**
   * 自动更新分类封面图（当添加第一项时）
   */
  private async updateCollectionCoverImage(
    collectionId: string,
    itemType: string,
    itemId: string,
  ) {
    const collection = await this.prisma.wardrobeCollection.findUnique({
      where: { id: collectionId },
      select: { coverImage: true },
    });

    // 已有封面图则不覆盖
    if (collection?.coverImage) {return;}

    let coverImage: string | null = null;

    switch (itemType) {
      case CollectionItemType.POST: {
        const post = await this.prisma.communityPost.findUnique({
          where: { id: itemId },
          select: { images: true },
        });
        coverImage = post?.images?.[0] ?? null;
        break;
      }
      case CollectionItemType.OUTFIT: {
        const outfit = await this.prisma.outfit.findUnique({
          where: { id: itemId },
          select: { coverImage: true },
        });
        coverImage = outfit?.coverImage ?? null;
        break;
      }
      case CollectionItemType.TRY_ON: {
        const tryOn = await this.prisma.virtualTryOn.findUnique({
          where: { id: itemId },
          select: { resultImageUrl: true },
        });
        coverImage = tryOn?.resultImageUrl ?? null;
        break;
      }
    }

    if (coverImage) {
      await this.prisma.wardrobeCollection.update({
        where: { id: collectionId },
        data: { coverImage },
      });
    }
  }

  /**
   * 获取引用类型中文名
   */
  private getItemTypeName(itemType: string): string {
    switch (itemType) {
      case CollectionItemType.POST:
        return "社区帖子";
      case CollectionItemType.OUTFIT:
        return "穿搭方案";
      case CollectionItemType.TRY_ON:
        return "虚拟试衣";
      default:
        return "项目";
    }
  }
}

import {
  Logger,
  UsePipes,
  ValidationPipe,
  Inject,
  OnModuleInit,
  OnModuleDestroy,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import Redis from 'ioredis';
import { Server, Socket } from 'socket.io';

import { REDIS_CLIENT } from '../../../common/redis/redis.service';
import { AI_EVENTS } from '../events';
import { EventBusService } from '../services/event-bus.service';

interface UserConnection {
  socketId: string;
  userId: string;
  connectedAt: Date;
  lastHeartbeat: Date;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(',').filter(Boolean) || (process.env.NODE_ENV === 'production' ? [] : ['http://localhost:3000']),
    credentials: true,
  },
  namespace: '/ws/ai',
  transports: ['websocket', 'polling'],
})
@UsePipes(new ValidationPipe())
export class AIGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect, OnModuleInit, OnModuleDestroy
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(AIGateway.name);

  private userSocketMap = new Map<string, Set<string>>();
  private connections = new Map<string, UserConnection>();

  private heartbeatInterval: NodeJS.Timeout | null = null;
  private readonly HEARTBEAT_TIMEOUT = 60000;

  private eventUnsubscribers: Array<() => void> = [];

  constructor(
    private configService: ConfigService,
    private jwtService: JwtService,
    @Inject(REDIS_CLIENT) private redis: Redis,
    private eventBus: EventBusService,
  ) {}

  onModuleInit() {
    const taskStartedHandler = (envelope: { userId: string; payload: Record<string, unknown> }) => {
      this.pushToUser(envelope.userId, 'ai_task_started', envelope.payload);
    };

    const taskProgressHandler = (envelope: { userId: string; payload: Record<string, unknown> }) => {
      const progress = typeof envelope.payload.progress === 'number'
        ? Math.max(0, Math.min(100, envelope.payload.progress))
        : 0;
      const clampedPayload = { ...envelope.payload, progress };

      this.pushToUser(envelope.userId, 'ai_task_progress', clampedPayload);

      const jobId = envelope.payload.jobId as string | undefined;
      if (jobId) {
        this.server.to(`task:${jobId}`).emit('ai_task_progress', {
          type: 'ai_task_progress',
          payload: clampedPayload,
          timestamp: new Date().toISOString(),
        });
      }
    };

    const taskCompletedHandler = (envelope: { userId: string; payload: Record<string, unknown> }) => {
      this.pushToUser(envelope.userId, 'ai_task_completed', envelope.payload);

      const jobId = envelope.payload.jobId as string | undefined;
      if (jobId) {
        this.server.to(`task:${jobId}`).emit('ai_task_completed', {
          type: 'ai_task_completed',
          payload: envelope.payload,
          timestamp: new Date().toISOString(),
        });
      }
    };

    this.eventBus.on(AI_EVENTS.AI_TASK_STARTED, taskStartedHandler);
    this.eventBus.on(AI_EVENTS.AI_TASK_PROGRESS, taskProgressHandler);
    this.eventBus.on(AI_EVENTS.AI_TASK_COMPLETED, taskCompletedHandler);

    this.eventUnsubscribers.push(
      () => this.eventBus.off(AI_EVENTS.AI_TASK_STARTED, taskStartedHandler),
      () => this.eventBus.off(AI_EVENTS.AI_TASK_PROGRESS, taskProgressHandler),
      () => this.eventBus.off(AI_EVENTS.AI_TASK_COMPLETED, taskCompletedHandler),
    );

    this.startHeartbeatCheck();

    this.logger.log('AI WebSocket gateway initialized');
  }

  onModuleDestroy() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }

    for (const unsubscribe of this.eventUnsubscribers) {
      unsubscribe();
    }
    this.eventUnsubscribers = [];

    this.connections.clear();
    this.userSocketMap.clear();

    this.logger.log('AI WebSocket gateway destroyed');
  }

  afterInit(server: Server) {
    this.logger.log('AI WebSocket server initialized');
  }

  async handleConnection(client: Socket) {
    try {
      const userId = this.extractUserId(client);
      if (!userId) {
        this.logger.warn(`Client ${client.id} rejected: no valid token`);
        client.emit('error', { message: 'Authentication required' });
        client.disconnect();
        return;
      }

      const connection: UserConnection = {
        socketId: client.id,
        userId,
        connectedAt: new Date(),
        lastHeartbeat: new Date(),
      };

      this.connections.set(client.id, connection);

      if (!this.userSocketMap.has(userId)) {
        this.userSocketMap.set(userId, new Set());
      }
      this.userSocketMap.get(userId)!.add(client.id);

      await client.join(`user:${userId}`);

      this.logger.log(`Client ${client.id} connected for user ${userId}`);

      client.emit('connected', {
        message: 'Connected to AI task updates',
        userId,
        timestamp: new Date().toISOString(),
      });

      await this.sendPendingTaskUpdates(client, userId);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Connection error: ${message}`);
      client.disconnect();
    }
  }

  async handleDisconnect(client: Socket) {
    const connection = this.connections.get(client.id);

    if (connection) {
      const { userId } = connection;

      const userSocketSet = this.userSocketMap.get(userId);
      if (userSocketSet) {
        userSocketSet.delete(client.id);
        if (userSocketSet.size === 0) {
          this.userSocketMap.delete(userId);
        }
      }

      this.connections.delete(client.id);

      this.logger.log(`Client ${client.id} disconnected for user ${userId}`);
    }
  }

  @SubscribeMessage('subscribe_task')
  async handleSubscribeTask(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { jobId: string },
  ) {
    const { jobId } = data;
    const connection = this.connections.get(client.id);

    if (!connection) {
      return { error: 'Not connected' };
    }

    await client.join(`task:${jobId}`);

    this.logger.debug(`Client ${client.id} subscribed to task ${jobId}`);

    const taskStatus = await this.getTaskStatus(jobId);
    if (taskStatus) {
      client.emit('task_status', taskStatus);
    }

    return { subscribed: true, jobId };
  }

  @SubscribeMessage('unsubscribe_task')
  async handleUnsubscribeTask(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { jobId: string },
  ) {
    await client.leave(`task:${data.jobId}`);
    this.logger.debug(`Client ${client.id} unsubscribed from task ${data.jobId}`);
    return { unsubscribed: true, jobId: data.jobId };
  }

  @SubscribeMessage('heartbeat')
  handleHeartbeat(@ConnectedSocket() client: Socket) {
    const connection = this.connections.get(client.id);
    if (connection) {
      connection.lastHeartbeat = new Date();
      client.emit('heartbeat_ack', { timestamp: Date.now() });
    }
  }

  isUserOnline(userId: string): boolean {
    return this.userSocketMap.has(userId);
  }

  private pushToUser(userId: string, event: string, payload: unknown): void {
    const room = `user:${userId}`;
    this.server.to(room).emit(event, {
      type: event,
      payload,
      timestamp: new Date().toISOString(),
    });
  }

  private extractUserId(client: Socket): string | null {
    const auth = client.handshake.auth;

    const token = auth?.token;
    if (!token) {
      this.logger.warn(`Client ${client.id} rejected: token must be provided in auth object`);
      return null;
    }

    return this.validateToken(token as string);
  }

  private validateToken(token: string): string | null {
    try {
      const jwtSecret = this.configService.get<string>('JWT_SECRET');
      if (!jwtSecret) {
        this.logger.error('JWT_SECRET is not configured');
        return null;
      }

      const payload = this.jwtService.verify(token, {
        secret: jwtSecret,
      });

      const userId = payload.sub || payload.userId;
      return userId || null;
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.debug(`Token validation failed: ${message}`);
      return null;
    }
  }

  private async getTaskStatus(jobId: string): Promise<Record<string, unknown> | null> {
    const key = `job:${jobId}`;
    const data = await this.redis.get(key);
    if (!data) {return null;}
    try {
      return JSON.parse(data) as Record<string, unknown>;
    } catch {
      return null;
    }
  }

  private async sendPendingTaskUpdates(client: Socket, userId: string): Promise<void> {
    try {
      const userJobsKey = `user_jobs:${userId}`;
      const jobIds = await this.redis.lrange(userJobsKey, 0, 10);

      for (const jobId of jobIds) {
        const jobStatus = await this.getTaskStatus(jobId);
        if (jobStatus) {
          const status = jobStatus.status as string;
          if (status === 'pending' || status === 'processing') {
            client.emit('task_status', jobStatus);
          }
        }
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Error sending pending updates: ${message}`);
    }
  }

  private startHeartbeatCheck(): void {
    this.heartbeatInterval = setInterval(() => {
      const now = Date.now();

      for (const [socketId, connection] of this.connections.entries()) {
        const timeSinceLastHeartbeat = now - connection.lastHeartbeat.getTime();

        if (timeSinceLastHeartbeat > this.HEARTBEAT_TIMEOUT) {
          this.logger.warn(`Client ${socketId} timed out (no heartbeat)`);

          const socket = this.server.sockets.sockets.get(socketId);
          if (socket) {
            socket.disconnect(true);
          }
          this.connections.delete(socketId);
        }
      }
    }, 30000);
  }
}

import {
  Logger,
  UsePipes,
  ValidationPipe,
  Inject,
  OnModuleInit,
  OnModuleDestroy,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import Redis from 'ioredis';
import { Server, Socket } from 'socket.io';

import { REDIS_CLIENT } from '../../../common/redis/redis.service';
import {
  PROFILE_EVENTS,
  QUIZ_EVENTS,
  NOTIFICATION_EVENTS,
  COMMUNITY_EVENTS,
} from '../events';
import { EventBusService } from '../services/event-bus.service';

interface UserConnection {
  socketId: string;
  userId: string;
  connectedAt: Date;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(',').filter(Boolean) || (process.env.NODE_ENV === 'production' ? [] : ['http://localhost:3000']),
    credentials: true,
  },
  namespace: '/ws/app',
  transports: ['websocket', 'polling'],
})
@UsePipes(new ValidationPipe())
export class AppGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect, OnModuleInit, OnModuleDestroy
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(AppGateway.name);

  private userSocketMap = new Map<string, Set<string>>();
  private connections = new Map<string, UserConnection>();

  private eventUnsubscribers: Array<() => void> = [];

  constructor(
    private configService: ConfigService,
    private jwtService: JwtService,
    @Inject(REDIS_CLIENT) private redis: Redis,
    private eventBus: EventBusService,
  ) {}

  onModuleInit() {
    const eventMappings: Array<{ eventType: string; wsEvent: string }> = [
      { eventType: PROFILE_EVENTS.PROFILE_UPDATED, wsEvent: 'profile_updated' },
      { eventType: PROFILE_EVENTS.ONBOARDING_COMPLETED, wsEvent: 'onboarding_completed' },
      { eventType: QUIZ_EVENTS.QUIZ_PROGRESS_SAVED, wsEvent: 'quiz_progress_saved' },
      { eventType: NOTIFICATION_EVENTS.NEW_NOTIFICATION, wsEvent: 'new_notification' },
      { eventType: NOTIFICATION_EVENTS.NOTIFICATION_READ, wsEvent: 'notification_read' },
      { eventType: COMMUNITY_EVENTS.NEW_POST, wsEvent: 'new_post' },
      { eventType: COMMUNITY_EVENTS.NEW_COMMENT, wsEvent: 'new_comment' },
      { eventType: COMMUNITY_EVENTS.NEW_LIKE, wsEvent: 'new_like' },
    ];

    for (const mapping of eventMappings) {
      const handler = (envelope: { userId: string; payload: unknown }) => {
        this.pushToUser(envelope.userId, mapping.wsEvent, envelope.payload);
      };

      this.eventBus.on(mapping.eventType, handler);
      this.eventUnsubscribers.push(() => {
        this.eventBus.off(mapping.eventType, handler);
      });
    }

    this.logger.log('App WebSocket gateway initialized');
  }

  onModuleDestroy() {
    for (const unsubscribe of this.eventUnsubscribers) {
      unsubscribe();
    }
    this.eventUnsubscribers = [];
    this.connections.clear();
    this.userSocketMap.clear();
    this.logger.log('App WebSocket gateway destroyed');
  }

  afterInit(server: Server) {
    this.logger.log('App WebSocket server initialized');
  }

  async handleConnection(client: Socket) {
    try {
      const userId = this.extractUserId(client);
      if (!userId) {
        this.logger.warn(`Client ${client.id} rejected: no valid token`);
        client.emit('error', { message: 'Authentication required' });
        client.disconnect();
        return;
      }

      const connection: UserConnection = {
        socketId: client.id,
        userId,
        connectedAt: new Date(),
      };

      this.connections.set(client.id, connection);

      if (!this.userSocketMap.has(userId)) {
        this.userSocketMap.set(userId, new Set());
      }
      this.userSocketMap.get(userId)!.add(client.id);

      await client.join(`user:${userId}`);

      this.logger.log(`Client ${client.id} connected for user ${userId}`);

      client.emit('connected', {
        message: 'Connected to app events',
        userId,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Connection error: ${message}`);
      client.disconnect();
    }
  }

  async handleDisconnect(client: Socket) {
    const connection = this.connections.get(client.id);

    if (connection) {
      const { userId } = connection;

      const userSocketSet = this.userSocketMap.get(userId);
      if (userSocketSet) {
        userSocketSet.delete(client.id);
        if (userSocketSet.size === 0) {
          this.userSocketMap.delete(userId);
        }
      }

      this.connections.delete(client.id);

      this.logger.log(`Client ${client.id} disconnected for user ${userId}`);
    }
  }

  @SubscribeMessage('joinRoom')
  async handleJoinRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { room: string },
  ) {
    await client.join(data.room);
    this.logger.debug(`Client ${client.id} joined room: ${data.room}`);
    client.emit('joinedRoom', { room: data.room });
  }

  @SubscribeMessage('leaveRoom')
  async handleLeaveRoom(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { room: string },
  ) {
    await client.leave(data.room);
    this.logger.debug(`Client ${client.id} left room: ${data.room}`);
  }

  @SubscribeMessage('ping')
  handlePing(@ConnectedSocket() client: Socket) {
    client.emit('pong', { timestamp: Date.now() });
  }

  isUserOnline(userId: string): boolean {
    return this.userSocketMap.has(userId);
  }

  getOnlineUserCount(): number {
    return this.userSocketMap.size;
  }

  private pushToUser(userId: string, event: string, payload: unknown): void {
    const room = `user:${userId}`;
    this.server.to(room).emit(event, {
      type: event,
      payload,
      timestamp: new Date().toISOString(),
    });
  }

  private extractUserId(client: Socket): string | null {
    const auth = client.handshake.auth;

    const token = auth?.token;
    if (!token) {
      this.logger.warn(`Client ${client.id} rejected: token must be provided in auth object`);
      return null;
    }

    return this.validateToken(token as string);
  }

  private validateToken(token: string): string | null {
    try {
      const jwtSecret = this.configService.get<string>('JWT_SECRET');
      if (!jwtSecret) {
        this.logger.error('JWT_SECRET is not configured');
        return null;
      }

      const payload = this.jwtService.verify(token, {
        secret: jwtSecret,
      });

      const userId = payload.sub || payload.userId;
      return userId || null;
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.debug(`Token validation failed: ${message}`);
      return null;
    }
  }
}

import {
  Logger,
  UsePipes,
  ValidationPipe,
  Inject,
  OnModuleInit,
  OnModuleDestroy,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { JwtService } from '@nestjs/jwt';
import {
  WebSocketGateway,
  WebSocketServer,
  SubscribeMessage,
  OnGatewayConnection,
  OnGatewayDisconnect,
  OnGatewayInit,
  ConnectedSocket,
  MessageBody,
} from '@nestjs/websockets';
import Redis from 'ioredis';
import { Server, Socket } from 'socket.io';

import { REDIS_CLIENT } from '../../common/redis/redis.service';

export type AITaskEventType = 'task_created' | 'task_progress' | 'task_completed' | 'task_failed' | 'task_cancelled';

export interface AITaskData {
  jobId: string;
  progress?: number;
  stage?: string;
  message?: string;
  status?: string;
  result?: TaskResult;
  error?: string;
}

export interface TaskResult {
  success: boolean;
  data?: Record<string, unknown>;
  error?: string;
}

export interface AITaskEvent {
  type: AITaskEventType;
  jobId: string;
  userId: string;
  data?: AITaskData | TaskProgressPayload | TaskCompletedPayload | TaskFailedPayload;
  timestamp: string;
}

export interface TaskProgressPayload {
  jobId: string;
  progress: number;
  stage: string;
  message?: string;
}

export interface TaskCompletedPayload {
  jobId: string;
  result: TaskResult;
  duration: number;
}

export interface TaskFailedPayload {
  jobId: string;
  error: string;
  retryable: boolean;
}

export interface TaskStatus {
  jobId: string;
  status: 'pending' | 'processing' | 'completed' | 'failed';
  progress: number;
  stage: string;
  message?: string;
  result?: TaskResult;
  error?: string;
  createdAt: string;
  updatedAt: string;
}

interface UserConnection {
  socketId: string;
  userId: string;
  connectedAt: Date;
  lastHeartbeat: Date;
}

interface WSNotifyPayload {
  userId: string;
  event: AITaskEventType;
  data: AITaskData;
}

interface TaskProgressRedisPayload {
  jobId: string;
  userId: string;
  progress: number;
  stage: string;
  message?: string;
}

interface TaskCompletedRedisPayload {
  jobId: string;
  userId: string;
  result: TaskResult;
}

interface TaskFailedRedisPayload {
  jobId: string;
  userId: string;
  error: string;
}

@WebSocketGateway({
  cors: {
    origin: process.env.CORS_ORIGINS?.split(',').filter(Boolean) || (process.env.NODE_ENV === 'production' ? [] : ['http://localhost:3000']),
    credentials: true,
  },
  namespace: '/ws/ai',
  transports: ['websocket', 'polling'],
})
@UsePipes(new ValidationPipe())
export class AIWebSocketGateway
  implements OnGatewayInit, OnGatewayConnection, OnGatewayDisconnect, OnModuleInit, OnModuleDestroy
{
  @WebSocketServer()
  server!: Server;

  private readonly logger = new Logger(AIWebSocketGateway.name);

  private connections = new Map<string, UserConnection>();
  private userSockets = new Map<string, Set<string>>();

  private subscriber: Redis;

  private heartbeatInterval: NodeJS.Timeout | null = null;
  private readonly HEARTBEAT_TIMEOUT = 60000;

  constructor(
    private configService: ConfigService,
    private jwtService: JwtService,
    @Inject(REDIS_CLIENT) private redis: Redis,
  ) {
    this.subscriber = new Redis(
      this.configService.get<string>('REDIS_URL', 'redis://localhost:6379'),
    );
  }

  async onModuleInit() {
    await this.subscriber.subscribe('ws:notify', 'task:progress', 'task:completed', 'task:failed');

    this.subscriber.on('message', (channel, message) => {
      this.handleRedisMessage(channel, message);
    });

    this.startHeartbeatCheck();

    this.logger.log('AI WebSocket gateway initialized');
  }

  async onModuleDestroy() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval);
    }
    await this.subscriber.quit();
    this.connections.clear();
    this.logger.log('AI WebSocket gateway destroyed');
  }

  afterInit(server: Server) {
    this.logger.log('AI WebSocket server initialized');
  }

  async handleConnection(client: Socket) {
    try {
      const userId = this.extractUserId(client);
      if (!userId) {
        this.logger.warn(`Client ${client.id} rejected: no valid token`);
        client.emit('error', { message: 'Authentication required' });
        client.disconnect();
        return;
      }

      const connection: UserConnection = {
        socketId: client.id,
        userId,
        connectedAt: new Date(),
        lastHeartbeat: new Date(),
      };

      this.connections.set(client.id, connection);

      if (!this.userSockets.has(userId)) {
        this.userSockets.set(userId, new Set());
      }
      this.userSockets.get(userId)!.add(client.id);

      await client.join(`user:${userId}`);

      this.logger.log(`Client ${client.id} connected for user ${userId}`);

      client.emit('connected', {
        message: 'Connected to AI task updates',
        userId,
        timestamp: new Date().toISOString(),
      });

      await this.sendPendingTaskUpdates(client, userId);
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Connection error: ${message}`);
      client.disconnect();
    }
  }

  async handleDisconnect(client: Socket) {
    const connection = this.connections.get(client.id);

    if (connection) {
      const { userId } = connection;

      const userSocketSet = this.userSockets.get(userId);
      if (userSocketSet) {
        userSocketSet.delete(client.id);
        if (userSocketSet.size === 0) {
          this.userSockets.delete(userId);
        }
      }

      this.connections.delete(client.id);

      this.logger.log(`Client ${client.id} disconnected for user ${userId}`);
    }
  }

  @SubscribeMessage('heartbeat')
  handleHeartbeat(@ConnectedSocket() client: Socket) {
    const connection = this.connections.get(client.id);
    if (connection) {
      connection.lastHeartbeat = new Date();
      client.emit('heartbeat_ack', { timestamp: Date.now() });
    }
  }

  @SubscribeMessage('subscribe_task')
  async handleSubscribeTask(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { jobId: string },
  ) {
    const { jobId } = data;
    const connection = this.connections.get(client.id);

    if (!connection) {
      return { error: 'Not connected' };
    }

    await client.join(`task:${jobId}`);

    this.logger.debug(`Client ${client.id} subscribed to task ${jobId}`);

    const taskStatus = await this.getTaskStatus(jobId);
    if (taskStatus) {
      client.emit('task_status', taskStatus);
    }

    return { subscribed: true, jobId };
  }

  @SubscribeMessage('unsubscribe_task')
  async handleUnsubscribeTask(
    @ConnectedSocket() client: Socket,
    @MessageBody() data: { jobId: string },
  ) {
    await client.leave(`task:${data.jobId}`);
    return { unsubscribed: true, jobId: data.jobId };
  }

  @SubscribeMessage('get_online_count')
  handleGetOnlineCount(@ConnectedSocket() client: Socket) {
    return {
      onlineUsers: this.userSockets.size,
      totalConnections: this.connections.size,
    };
  }

  async sendTaskUpdate(userId: string, event: AITaskEvent): Promise<boolean> {
    const room = `user:${userId}`;

    this.server.to(room).emit('task_update', event);

    this.server.to(`task:${event.jobId}`).emit('task_update', event);

    this.logger.debug(`Task update sent to user ${userId}: ${event.type} - ${event.jobId}`);

    return this.isUserOnline(userId);
  }

  async sendProgressUpdate(userId: string, payload: TaskProgressPayload): Promise<void> {
    const room = `user:${userId}`;

    this.server.to(room).emit('task_progress', {
      ...payload,
      timestamp: new Date().toISOString(),
    });

    this.server.to(`task:${payload.jobId}`).emit('task_progress', {
      ...payload,
      timestamp: new Date().toISOString(),
    });
  }

  async broadcastTaskComplete(userId: string, payload: TaskCompletedPayload): Promise<void> {
    const room = `user:${userId}`;

    const event: AITaskEvent = {
      type: 'task_completed',
      jobId: payload.jobId,
      userId,
      data: payload,
      timestamp: new Date().toISOString(),
    };

    this.server.to(room).emit('task_completed', event);
    this.server.to(`task:${payload.jobId}`).emit('task_completed', event);

    this.logger.log(`Task completed notification sent: ${payload.jobId}`);
  }

  async broadcastTaskFailed(userId: string, payload: TaskFailedPayload): Promise<void> {
    const room = `user:${userId}`;

    const event: AITaskEvent = {
      type: 'task_failed',
      jobId: payload.jobId,
      userId,
      data: payload,
      timestamp: new Date().toISOString(),
    };

    this.server.to(room).emit('task_failed', event);
    this.server.to(`task:${payload.jobId}`).emit('task_failed', event);

    this.logger.warn(`Task failed notification sent: ${payload.jobId} - ${payload.error}`);
  }

  isUserOnline(userId: string): boolean {
    return this.userSockets.has(userId);
  }

  getOnlineUsers(): string[] {
    return Array.from(this.userSockets.keys());
  }

  private extractUserId(client: Socket): string | null {
    const auth = client.handshake.auth;

    const token = auth?.token;
    if (!token) {
      this.logger.warn(`Client ${client.id} rejected: token must be provided in auth object, not query parameters`);
      return null;
    }

    return this.validateToken(token as string);
  }

  private validateToken(token: string): string | null {
    try {
      const jwtSecret = this.configService.get<string>('JWT_SECRET');
      if (!jwtSecret) {
        this.logger.error('JWT_SECRET is not configured');
        return null;
      }

      const payload = this.jwtService.verify(token, {
        secret: jwtSecret,
      });

      const userId = payload.sub || payload.userId;
      return userId || null;
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.debug(`Token validation failed: ${message}`);
      return null;
    }
  }

  private handleRedisMessage(channel: string, message: string): void {
    try {
      const data = JSON.parse(message);

      switch (channel) {
        case 'ws:notify':
          this.handleWSNotify(data as WSNotifyPayload);
          break;
        case 'task:progress':
          this.handleTaskProgress(data as TaskProgressRedisPayload);
          break;
        case 'task:completed':
          this.handleTaskCompleted(data as TaskCompletedRedisPayload);
          break;
        case 'task:failed':
          this.handleTaskFailed(data as TaskFailedRedisPayload);
          break;
      }
    } catch (error) {
      const errorMessage = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Error handling Redis message: ${errorMessage}`);
    }
  }

  private handleWSNotify(data: WSNotifyPayload): void {
    const { userId, event, data: eventData } = data;

    const taskEvent: AITaskEvent = {
      type: event,
      jobId: eventData.jobId,
      userId,
      data: eventData,
      timestamp: new Date().toISOString(),
    };

    this.sendTaskUpdate(userId, taskEvent);
  }

  private handleTaskProgress(data: TaskProgressRedisPayload): void {
    this.sendProgressUpdate(data.userId, {
      jobId: data.jobId,
      progress: data.progress,
      stage: data.stage,
      message: data.message,
    });
  }

  private handleTaskCompleted(data: TaskCompletedRedisPayload): void {
    this.broadcastTaskComplete(data.userId, {
      jobId: data.jobId,
      result: data.result,
      duration: 0,
    });
  }

  private handleTaskFailed(data: TaskFailedRedisPayload): void {
    this.broadcastTaskFailed(data.userId, {
      jobId: data.jobId,
      error: data.error,
      retryable: true,
    });
  }

  private async getTaskStatus(jobId: string): Promise<TaskStatus | null> {
    const key = `job:${jobId}`;
    const data = await this.redis.get(key);
    if (!data) {return null;}
    try {
      return JSON.parse(data) as TaskStatus;
    } catch {
      return null;
    }
  }

  private async sendPendingTaskUpdates(client: Socket, userId: string): Promise<void> {
    try {
      const userJobsKey = `user_jobs:${userId}`;
      const jobIds = await this.redis.lrange(userJobsKey, 0, 10);

      for (const jobId of jobIds) {
        const jobStatus = await this.getTaskStatus(jobId);
        if (jobStatus && (jobStatus.status === 'pending' || jobStatus.status === 'processing')) {
          client.emit('task_status', jobStatus);
        }
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : 'Unknown error';
      this.logger.error(`Error sending pending updates: ${message}`);
    }
  }

  private startHeartbeatCheck(): void {
    this.heartbeatInterval = setInterval(() => {
      const now = Date.now();

      for (const [socketId, connection] of this.connections.entries()) {
        const timeSinceLastHeartbeat = now - connection.lastHeartbeat.getTime();

        if (timeSinceLastHeartbeat > this.HEARTBEAT_TIMEOUT) {
          this.logger.warn(`Client ${socketId} timed out (no heartbeat)`);

          const socket = this.server.sockets.sockets.get(socketId);
          if (socket) {
            socket.disconnect(true);
          }
          this.connections.delete(socketId);
        }
      }
    }, 30000);
  }
}

import * as fs from "fs";
import * as path from "path";

import { NestFactory } from "@nestjs/core";
import { SwaggerModule } from "@nestjs/swagger";

import { AppModule } from "../app.module";
import { createSwaggerConfig } from "../config/swagger.config";

async function generateOpenApiSpec() {
  const app = await NestFactory.create(AppModule, {
    logger: ["error", "warn"],
  });

  app.setGlobalPrefix("api");
  app.enableVersioning({
    type: require("@nestjs/common").VersioningType.URI,
    defaultVersion: "1",
  });

  const config = createSwaggerConfig();
  const document = SwaggerModule.createDocument(app, config);

  const outputPath = path.resolve(__dirname, "../../docs/api/openapi.json");
  const outputDir = path.dirname(outputPath);

  if (!fs.existsSync(outputDir)) {
    fs.mkdirSync(outputDir, { recursive: true });
  }

  fs.writeFileSync(outputPath, JSON.stringify(document, null, 2), "utf8");

  console.log(`OpenAPI spec generated: ${outputPath}`);
  console.log(`Endpoints: ${Object.keys(document.paths || {}).length} paths`);
  console.log(`Schemas: ${Object.keys(document.components?.schemas || {}).length} schemas`);
  console.log(`Tags: ${(document.tags || []).length} tags`);

  await app.close();
}

generateOpenApiSpec().catch((err) => {
  console.error("Failed to generate OpenAPI spec:", err);
  process.exit(1);
});

