      const perfSessionId = sessionResponse.body.id;

      // 2. 发送消息
      await request(app.getHttpServer())
        .post(`/ai-stylist/sessions/${perfSessionId}/messages`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({ message: "是晚餐约会，地点在法式餐厅" })
        .expect(201);

