import { StructuredLoggerService } from "../../src/common/logging/structured-logger.service";
import { PrismaService } from "../../src/common/prisma/prisma.service";
import { RedisService, REDIS_CLIENT } from "../../src/common/redis/redis.service";
import { AuthController } from "../../src/modules/auth/auth.controller";
import { AuthHelpersService } from "../../src/modules/auth/auth.helpers";
import { AuthService } from "../../src/modules/auth/auth.service";
import { SmsService, ISmsService } from "../../src/modules/auth/services/sms.service";
import { WechatService } from "../../src/modules/auth/services/wechat.service";
import { JwtStrategy } from "../../src/modules/auth/strategies/jwt.strategy";
import {
  RedisKeyTracker,
  createRedisKeyTracker,
  createMockRedisClient,
  createMockRedisService,
} from "../utils/redis-test-utils";

// Inline mock Prisma delegate (avoids importing test-app.module which has broken CloudTryOnProvider import)
function createMockPrismaDelegate() {
  return {
    findUnique: jest.fn(),
    findFirst: jest.fn(),
    findMany: jest.fn(),
    create: jest.fn(),
    createMany: jest.fn(),
    update: jest.fn(),
    delete: jest.fn(),
    deleteMany: jest.fn(),
    updateMany: jest.fn(),
    count: jest.fn(),
    upsert: jest.fn(),
  };
}

function createMockPrisma(): PrismaService {
  return {
    user: createMockPrismaDelegate(),
    userProfile: createMockPrismaDelegate(),
    refreshToken: createMockPrismaDelegate(),
    quizAnswer: createMockPrismaDelegate(),
    styleQuiz: createMockPrismaDelegate(),
    styleQuizResult: createMockPrismaDelegate(),
    quizQuestion: createMockPrismaDelegate(),
    userPhoto: createMockPrismaDelegate(),
    $connect: jest.fn().mockResolvedValue(undefined),
    $disconnect: jest.fn().mockResolvedValue(undefined),
    $transaction: jest.fn((fn: unknown) => {
      if (typeof fn === "function") {
        return fn(createMockPrisma());
      }
      return Promise.all(fn as unknown[]);
    }),
    $queryRaw: jest.fn().mockResolvedValue([]),
    $executeRaw: jest.fn().mockResolvedValue(0),
  } as unknown as PrismaService;
}

describe("Phase 1 Integration: Auth Flow", () => {
  let app: INestApplication;
  let prisma: ReturnType<typeof createMockPrisma>;
  let redisTracker: RedisKeyTracker;
  let jwtService: JwtService;

  const TEST_PHONE = "13800138000";
  const TEST_SMS_CODE = "123456";
  const TEST_WECHAT_CODE = "mock-wechat-code";
  const TEST_WECHAT_OPENID = "mock-open-id-12345";

  beforeAll(async () => {
    prisma = createMockPrisma();
    redisTracker = createRedisKeyTracker();
    const mockRedisService = createMockRedisService(redisTracker);

    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [PassportModule.register({ defaultStrategy: "jwt" })],
      controllers: [AuthController],
      providers: [
        AuthService,
        AuthHelpersService,
        JwtStrategy,
        SmsService,
        {
          provide: "ISmsService",
          useValue: {
            sendCode: jest.fn().mockResolvedValue(undefined),
          } satisfies ISmsService,
        },
        {
          provide: WechatService,
          useValue: {
            getAccessToken: jest.fn().mockResolvedValue({
              access_token: "mock-access-token",
              openid: TEST_WECHAT_OPENID,
              unionid: "mock-union-id",
            }),
            getUserInfo: jest.fn().mockResolvedValue({
              nickname: "微信测试用户",
              headimgurl: "https://example.com/avatar.jpg",
            }),
          },
        },
        { provide: PrismaService, useValue: prisma },
        { provide: REDIS_CLIENT, useValue: createMockRedisClient(redisTracker) },
        { provide: RedisService, useValue: mockRedisService },
        {
          provide: ConfigService,
          useValue: {
            get: jest.fn((key: string, defaultValue?: string) => {
              const config: Record<string, string> = {
                JWT_SECRET: "test-jwt-secret-key-for-testing-only-at-least-64-chars-long-aaaaaa",
                JWT_REFRESH_SECRET: "test-jwt-refresh-secret-key-for-testing-only-at-least-64-chars-long",
                JWT_ACCESS_EXPIRES_IN: "15m",
                JWT_REFRESH_EXPIRES_IN: "7d",
                FRONTEND_URL: "http://localhost:3000",
              };
              return config[key] ?? defaultValue ?? "";
            }),
          },
        },
        {
          provide: StructuredLoggerService,
          useValue: {
            createChildLogger: jest.fn().mockReturnValue({
              log: jest.fn(),
              warn: jest.fn(),
              error: jest.fn(),
              debug: jest.fn(),
            }),
          },
        },
        JwtService,
        EventEmitter2,
      ],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));
    await app.init();

    jwtService = moduleFixture.get(JwtService);
  });

  afterAll(async () => {
    if (app) {
      await app.close();
    }
  });

  afterEach(() => {
    jest.clearAllMocks();
    redisTracker.reset();
  });

  // -------------------------------------------------------------------
  // 1. Send SMS code
  // -------------------------------------------------------------------
  describe("POST /auth/send-code", () => {
    it("should send SMS code to a valid phone number", async () => {
      const response = await request(app.getHttpServer())
        .post("/auth/send-code")
        .send({ phone: TEST_PHONE })
        .expect(201);

      expect(response.body).toEqual({
        success: true,
        message: "验证码已发送",
      });
    });
  });

  // -------------------------------------------------------------------
  // 2. Phone register
  // -------------------------------------------------------------------
  describe("POST /auth/phone-register", () => {
    it("should register a new user with phone and SMS code", async () => {
      // Simulate SMS code stored in Redis by SmsService.sendVerificationCode
      redisTracker.setValue(`sms:code:${TEST_PHONE}`, TEST_SMS_CODE);

      const mockCreatedUser = {
        id: "user-phone-001",
        email: `${TEST_PHONE}@sms.placeholder`,
        phone: TEST_PHONE,
        nickname: "测试用户",
        gender: "female",
        avatar: null,
        createdAt: new Date(),
      };

      (prisma.user.findUnique as jest.Mock).mockResolvedValue(null);
      (prisma.$transaction as jest.Mock).mockImplementation(async (fn: Function) => {
        const txMock = {
          user: {
            create: jest.fn().mockResolvedValue(mockCreatedUser),
          },
          userProfile: {
            create: jest.fn().mockResolvedValue({ userId: mockCreatedUser.id }),
          },
          userConsent: {
            createMany: jest.fn().mockResolvedValue({ count: 2 }),
          },
        };
        return fn(txMock);
      });
      (prisma.refreshToken.create as jest.Mock).mockResolvedValue({
        id: "rt-001",
        token: "hashed-token",
        userId: mockCreatedUser.id,
        expiresAt: new Date(Date.now() + 7 * 24 * 3600 * 1000),
      });

      const response = await request(app.getHttpServer())
        .post("/auth/phone-register")
        .send({
          phone: TEST_PHONE,
          code: TEST_SMS_CODE,
          gender: "female",
          nickname: "测试用户",
        })
        .expect(201);

      expect(response.body).toHaveProperty("accessToken");
      expect(response.body).toHaveProperty("refreshToken");
      expect(response.body.user).toBeDefined();
      expect(response.body.user).toHaveProperty("id");
      expect(response.body.user).toHaveProperty("email");
    });

    it("should return 409 when phone already registered", async () => {
      redisTracker.setValue(`sms:code:${TEST_PHONE}`, TEST_SMS_CODE);
      (prisma.user.findUnique as jest.Mock).mockResolvedValue({ id: "existing-user" });

      await request(app.getHttpServer())
        .post("/auth/phone-register")
        .send({
          phone: TEST_PHONE,
          code: TEST_SMS_CODE,
          gender: "female",
        })
        .expect(409);
    });

    it("should return 401 when SMS code is invalid", async () => {
      // No code stored in Redis -> invalid
      (prisma.user.findUnique as jest.Mock).mockResolvedValue(null);

      await request(app.getHttpServer())
        .post("/auth/phone-register")
        .send({
          phone: TEST_PHONE,
          code: "000000",
          gender: "female",
        })
        .expect(401);
    });
  });

  // -------------------------------------------------------------------
  // 3. Phone login
  // -------------------------------------------------------------------
  describe("POST /auth/phone-login", () => {
    it("should login existing user with phone and code", async () => {
      redisTracker.setValue(`sms:code:${TEST_PHONE}`, TEST_SMS_CODE);

      const mockUser = {
        id: "user-phone-002",
        email: `${TEST_PHONE}@sms.placeholder`,
        phone: TEST_PHONE,
        nickname: "登录测试用户",
        avatar: null,
        createdAt: new Date(),
      };

      (prisma.user.findUnique as jest.Mock).mockResolvedValue(mockUser);
      (prisma.refreshToken.create as jest.Mock).mockResolvedValue({
        id: "rt-002",
        token: "hashed-token",
        userId: mockUser.id,
        expiresAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .post("/auth/phone-login")
        .send({ phone: TEST_PHONE, code: TEST_SMS_CODE })
        .expect(201);

      expect(response.body).toHaveProperty("accessToken");
      expect(response.body).toHaveProperty("refreshToken");
      expect(response.body.user).toBeDefined();
    });

    it("should auto-register new user on phone login", async () => {
      redisTracker.setValue(`sms:code:${TEST_PHONE}`, TEST_SMS_CODE);

      const mockCreatedUser = {
        id: "user-phone-auto",
        email: `${TEST_PHONE}@sms.placeholder`,
        phone: TEST_PHONE,
        nickname: `用户${TEST_PHONE.slice(-4)}`,
        avatar: null,
        createdAt: new Date(),
      };

      (prisma.user.findUnique as jest.Mock).mockResolvedValue(null);
      (prisma.$transaction as jest.Mock).mockImplementation(async (fn: Function) => {
        const txMock = {
          user: {
            create: jest.fn().mockResolvedValue(mockCreatedUser),
          },
          userProfile: {
            create: jest.fn().mockResolvedValue({ userId: mockCreatedUser.id }),
          },
        };
        return fn(txMock);
      });
      (prisma.refreshToken.create as jest.Mock).mockResolvedValue({
        id: "rt-auto",
        token: "hashed-token",
        userId: mockCreatedUser.id,
        expiresAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .post("/auth/phone-login")
        .send({ phone: TEST_PHONE, code: TEST_SMS_CODE })
        .expect(201);

      expect(response.body).toHaveProperty("accessToken");
      expect(response.body.user).toHaveProperty("id", "user-phone-auto");
    });

    it("should return 401 when SMS code is wrong", async () => {
      // Store a different code
      redisTracker.setValue(`sms:code:${TEST_PHONE}`, "654321");

      await request(app.getHttpServer())
        .post("/auth/phone-login")
        .send({ phone: TEST_PHONE, code: "000000" })
        .expect(401);
    });
  });

  // -------------------------------------------------------------------
  // 4. WeChat login
  // -------------------------------------------------------------------
  describe("POST /auth/wechat", () => {
    it("should login via WeChat OAuth code", async () => {
      const mockWechatUser = {
        id: "user-wechat-001",
        email: `wechat_${TEST_WECHAT_OPENID}@placeholder`,
        wechatOpenId: TEST_WECHAT_OPENID,
        nickname: "微信测试用户",
        avatar: "https://example.com/avatar.jpg",
        createdAt: new Date(),
      };

      (prisma.user.findFirst as jest.Mock).mockResolvedValue(null);
      (prisma.$transaction as jest.Mock).mockImplementation(async (fn: Function) => {
        const txMock = {
          user: {
            create: jest.fn().mockResolvedValue(mockWechatUser),
          },
          userProfile: {
            create: jest.fn().mockResolvedValue({ userId: mockWechatUser.id }),
          },
        };
        return fn(txMock);
      });
      (prisma.refreshToken.create as jest.Mock).mockResolvedValue({
        id: "rt-wechat",
        token: "hashed-token",
        userId: mockWechatUser.id,
        expiresAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .post("/auth/wechat")
        .send({ code: TEST_WECHAT_CODE })
        .expect(201);

      expect(response.body).toHaveProperty("accessToken");
      expect(response.body).toHaveProperty("refreshToken");
      expect(response.body.user).toHaveProperty("id", "user-wechat-001");
    });

    it("should return existing user on repeat WeChat login", async () => {
      const existingUser = {
        id: "user-wechat-001",
        email: `wechat_${TEST_WECHAT_OPENID}@placeholder`,
        wechatOpenId: TEST_WECHAT_OPENID,
        nickname: "微信测试用户",
        avatar: "https://example.com/avatar.jpg",
        createdAt: new Date(),
      };

      (prisma.user.findFirst as jest.Mock).mockResolvedValue(existingUser);
      (prisma.refreshToken.create as jest.Mock).mockResolvedValue({
        id: "rt-wechat-2",
        token: "hashed-token",
        userId: existingUser.id,
        expiresAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .post("/auth/wechat")
        .send({ code: TEST_WECHAT_CODE })
        .expect(201);

      expect(response.body.user).toHaveProperty("id", "user-wechat-001");
    });
  });

  // -------------------------------------------------------------------
  // 5. Access protected endpoint with token
  // -------------------------------------------------------------------
  describe("Protected endpoint access", () => {
    it("should access /auth/me with valid token", async () => {
      const token = jwtService.sign(
        { sub: "user-protected-001", email: "test@protected.com" },
        { secret: "test-jwt-secret-key-for-testing-only-at-least-64-chars-long-aaaaaa", expiresIn: "15m" },
      );

      (prisma.user.findUnique as jest.Mock).mockResolvedValue({
        id: "user-protected-001",
        email: "test@protected.com",
        nickname: "Protected User",
        avatar: null,
        createdAt: new Date(),
      });

      const response = await request(app.getHttpServer())
        .get("/auth/me")
        .set("Authorization", `Bearer ${token}`)
        .expect(200);

      expect(response.body).toHaveProperty("id", "user-protected-001");
      expect(response.body).toHaveProperty("email", "test@protected.com");
    });

    it("should reject access without token", async () => {
      await request(app.getHttpServer())
        .get("/auth/me")
        .expect(401);
    });
  });
});

/**
 * 用户完整流程集成测试
 * @description 测试用户从注册到完成虚拟试衣的完整业务流程
 * 
 * 测试流程:
 * 1. 用户注册
 * 2. 用户登录
 * 3. 更新用户画像
 * 4. 获取个性化推荐
 * 5. 虚拟试衣
 */

import { INestApplication, ValidationPipe, VersioningType } from "@nestjs/common";
import { Test, TestingModule } from "@nestjs/testing";
import {
  BodyType,
  SkinTone,
  ColorSeason,
  ClothingCategory,
  PhotoType,
  TryOnStatus,
} from "@prisma/client";
import request from "supertest";

import { AppModule } from "../../src/app.module";
import { PrismaService } from "../../src/common/prisma/prisma.service";
import { profileFixtures, performanceThresholds } from "../utils/fixtures";
import {
  generateTestEmail,
  measureResponseTime,
} from "../utils/test.utils";

const API = "/api/v1";

/** Extract data from JSON:API response, merging id from data level into attributes */
const extractData = (body: Record<string, unknown>) => {
  const d = (body as any).data;
  if (d?.attributes && typeof d === "object") {
    return { id: d.id, ...d.attributes };
  }
  return d ?? body;
};

describe("User Flow E2E - 完整用户流程", () => {
  let app: INestApplication;
  let prisma: PrismaService;
  let accessToken: string;
  let refreshToken: string;
  let userId: string;
  let photoId: string;
  let itemId: string;
  let tryOnId: string;

  const testUser = {
    email: generateTestEmail(),
    password: "Test123456!",
    nickname: "用户流程测试",
  };

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    }).compile();

    app = moduleFixture.createNestApplication();
    app.setGlobalPrefix("api");
    app.enableVersioning({ type: VersioningType.URI, defaultVersion: "1" });
    app.useGlobalPipes(new ValidationPipe({ whitelist: true, transform: true }));
    await app.init();

    prisma = app.get(PrismaService);
  });

  afterAll(async () => {
    // 清理测试数据
    if (userId) {
      await prisma.virtualTryOn.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.aiStylistSession.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.userPhoto.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.userProfile.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.cartItem.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.favorite.deleteMany({ where: { userId } }).catch(() => {});
      await prisma.user.delete({ where: { id: userId } }).catch(() => {});
    }
    if (itemId) {
      await prisma.clothingItem.delete({ where: { id: itemId } }).catch(() => {});
    }
    await app.close();
  });

  describe("阶段 1: 用户注册", () => {
    it("应该成功注册新用户", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/register`)
        .send(testUser)
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");
      expect(response.body.included[0].attributes).toHaveProperty("email", testUser.email);
      expect(response.body.included[0].attributes).toHaveProperty("nickname", testUser.nickname);

      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
      userId = response.body.included[0].id;
    });

    it("注册响应时间应该符合性能要求", async () => {
      const duration = await measureResponseTime(async () => {
        await request(app.getHttpServer())
          .post(`${API}/auth/register`)
          .send({
            email: generateTestEmail(),
            password: "Test123456!",
            nickname: "性能测试用户",
          })
          .expect(201);
      });

      expect(duration).toBeLessThan(performanceThresholds.auth.register);
    });
  });

  describe("阶段 2: 用户登录", () => {
    it("应该成功登录已注册用户", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/login`)
        .send({
          email: testUser.email,
          password: testUser.password,
        })
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");

      // 更新 token
      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
    });

    it("应该获取当前用户信息", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/auth/me`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const meData = extractData(response.body);
      expect(meData).toHaveProperty("id", userId);
      expect(meData).toHaveProperty("email", testUser.email);
    });

    it("应该能够刷新 Token", async () => {
      const response = await request(app.getHttpServer())
        .post(`${API}/auth/refresh`)
        .send({ refreshToken })
        .expect(201);

      expect(response.body.data.attributes).toHaveProperty("accessToken");
      expect(response.body.data.attributes).toHaveProperty("refreshToken");

      accessToken = response.body.data.attributes.accessToken;
      refreshToken = response.body.data.attributes.refreshToken;
    });
  });

  describe("阶段 3: 更新用户画像", () => {
    it("应该成功获取初始画像（可能为空）", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      // 初始画像可能为空或有默认值
      expect(response.body).toBeDefined();
    });

    it("应该成功更新用户画像", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send(profileFixtures.validProfile)
        .expect(200);

      expect(extractData(response.body).profile?.bodyType).toBe(BodyType.hourglass);
      expect(extractData(response.body).profile?.skinTone).toBe(SkinTone.medium);
      expect(extractData(response.body).profile?.colorSeason).toBe(ColorSeason.autumn_warm);
    });

    it("应该成功获取体型分析报告", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile/body-analysis`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("bodyType");
      expect(extractData(response.body)).toHaveProperty("recommendations");
    });

    it("应该成功获取色彩分析报告", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/profile/color-analysis`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("colorSeason");
      expect(extractData(response.body)).toHaveProperty("bestColors");
      expect(extractData(response.body)).toHaveProperty("avoidColors");
    });

    it("应该成功更新风格偏好", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile/preferences/styles`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({
          styles: ["casual", "minimalist", "elegant"],
        })
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("success", true);
    });

    it("应该成功更新颜色偏好", async () => {
      const response = await request(app.getHttpServer())
        .put(`${API}/profile/preferences/colors`)
        .set("Authorization", `Bearer ${accessToken}`)
        .send({
          colors: ["black", "white", "navy", "beige"],
        })
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("success", true);
    });
  });

  describe("阶段 4: 获取个性化推荐", () => {
    it("应该成功获取个性化推荐列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/recommendations`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("items");
      expect(Array.isArray(extractData(response.body).items)).toBe(true);
    });

    it("应该成功获取风格指南", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/recommendations/style-guide`)
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(extractData(response.body)).toHaveProperty("bodyType");
      expect(extractData(response.body)).toHaveProperty("colorSeason");
      expect(extractData(response.body)).toHaveProperty("recommendations");
    });

    it("应该成功获取服装分类列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/clothing/categories`)
        .expect(200);

      const categories = (response.body).data ?? response.body;
      expect(Array.isArray(categories)).toBe(true);
    });

    it("应该成功获取服装列表", async () => {
      const response = await request(app.getHttpServer())
        .get(`${API}/clothing`)
        .query({ limit: 5 })
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const clothingData = extractData(response.body);
      expect(clothingData).toHaveProperty("total");

      // Items are in included array for JSON:API
      const included = (response.body).included ?? [];
      if (included.length > 0) {
        itemId = included[0].id;
      }
    });

    it("推荐响应时间应该符合性能要求", async () => {
      const duration = await measureResponseTime(async () => {
