    it("冷启动用户应该获取热门推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations")
        .set("Authorization", `Bearer ${coldStartAccessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
      expect(Array.isArray(response.body.items)).toBe(true);
    });

    it("未认证时应该返回 401", async () => {
      await request(app.getHttpServer())
        .get("/api/v1/recommendations")
        .expect(401);
    });
  });

  describe("GET /api/v1/recommendations - 分类筛选", () => {
    it("应该支持按分类筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?category=tops")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该支持按风格筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?style=casual")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该支持按场合筛选推荐", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?occasion=daily")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });
  });

  describe("GET /api/v1/recommendations - 分页", () => {
    it("应该支持分页参数", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=1&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
      expect(response.body).toHaveProperty("total");
      expect(response.body).toHaveProperty("hasMore");
    });

    it("应该支持 cursor 分页", async () => {
      const firstPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (firstPage.body.cursor) {
        const secondPage = await request(app.getHttpServer())
          .get(
            `/api/v1/recommendations?cursor=${firstPage.body.cursor}&pageSize=5`,
          )
          .set("Authorization", `Bearer ${accessToken}`)
          .expect(200);

        expect(secondPage.body).toHaveProperty("items");
      }
    });

    it("第二页结果不应与第一页重复", async () => {
      const firstPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=1&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      const secondPage = await request(app.getHttpServer())
        .get("/api/v1/recommendations?page=2&pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (
        firstPage.body.items.length > 0 &&
        secondPage.body.items.length > 0
      ) {
        const firstIds = firstPage.body.items.map((i: any) => i.id);
        const secondIds = secondPage.body.items.map((i: any) => i.id);
        const overlap = firstIds.filter((id: string) =>
          secondIds.includes(id),
        );
        expect(overlap).toHaveLength(0);
      }
    });
  });

  describe("GET /api/v1/recommendations/feed - Feed 流", () => {
    it("应该获取每日推荐 Feed", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations/feed?category=daily")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该获取趋势推荐 Feed", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations/feed?category=trending")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });

    it("应该获取场合推荐 Feed", async () => {
      const response = await request(app.getHttpServer())
        .get(
          "/api/v1/recommendations/feed?category=occasion&subCategory=date",
        )
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      expect(response.body).toHaveProperty("items");
    });
  });

  describe("推荐结果验证", () => {
    it("推荐结果应该包含必要字段", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?pageSize=5")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (response.body.items.length > 0) {
        const item = response.body.items[0];
        expect(item).toHaveProperty("id");
        expect(item).toHaveProperty("price");
      }
    });

    it("分类筛选结果应该匹配请求的分类", async () => {
      const response = await request(app.getHttpServer())
        .get("/api/v1/recommendations?category=tops&pageSize=20")
        .set("Authorization", `Bearer ${accessToken}`)
        .expect(200);

      if (response.body.items.length > 0) {
        for (const item of response.body.items) {
          if (item.category) {
            expect(item.category).toBe("tops");
          }
        }
      }
    });
  });
});

/**
 * @fileoverview AI Mock Interceptor - HTTP interceptor for auto-record/playback of AI API calls.
 *
 * Provides an HTTP interceptor that can operate in three modes:
 *   - 'record': Intercepts requests, forwards them to real APIs, and records responses
 *   - 'playback': Intercepts requests and returns recorded fixture responses
 *   - 'passthrough': Passes requests through to real APIs without interception
 *
 * Supports both axios-based HTTP calls (used by cloud-tryon.provider.ts)
 * and fetch-based calls (used by llm-provider.service.ts).
 *
 * Auto-detects API provider from URL patterns:
 *   - open.bigmodel.cn -> zhipu (GLM)
 *   - volcengineapi.com -> doubao-seedream
 *   - api.fashn.ai -> fashn-ai
 *   - api.deepseek.com -> deepseek
 *   - dashscope.aliyuncs.com -> qwen
 *   - api.openai.com -> openai
 *
 * @module AiMockInterceptor
 */

import type {
  AxiosInstance,
  AxiosRequestConfig,
  AxiosResponse,
  InternalAxiosRequestConfig,
} from "axios";

import { AiMockPlayer } from "./ai-mock-player";
import type { PlaybackStats } from "./ai-mock-player";
import { AiMockRecorder } from "./ai-mock-recorder";
import type { RecordedCall } from "./ai-mock-recorder";

// ==================== Types ====================

/**
 * Interceptor operating mode.
 */
export type InterceptorMode = "record" | "playback" | "passthrough";

/**
 * A recorded API call with full HTTP details.
 */
export interface InterceptedCall {
  /** Unique identifier */
  id: string;
  /** API provider name (auto-detected) */
  provider: string;
  /** Full request URL */
  url: string;
  /** HTTP method */
  method: string;
  /** Request headers (sanitized) */
  requestHeaders: Record<string, string>;
  /** Request body */
  requestBody: unknown;
  /** Response status code */
  statusCode: number;
  /** Response headers */
  responseHeaders: Record<string, string>;
  /** Response body */
  responseBody: unknown;
  /** Request-to-response latency in ms */
  latencyMs: number;
  /** Timestamp */
  timestamp: string;
  /** Whether this was intercepted (true) or passed through (false) */
  intercepted: boolean;
}

/**
 * Options for the interceptor.
 */
export interface InterceptorOptions {
  /** Operating mode (default: 'playback') */
  mode?: InterceptorMode;
  /** Directory for fixture files */
  fixtureDir?: string;
  /** Whether to simulate latency in playback mode (default: false) */
  simulateLatency?: boolean;
  /** Whether to throw on unmatched requests in playback mode (default: true) */
  throwOnMiss?: boolean;
  /** Whether to sanitize API keys in recorded data (default: true) */
  sanitizeKeys?: boolean;
  /** Custom URL patterns to intercept (in addition to known AI providers) */
  additionalUrlPatterns?: RegExp[];
  /** Fixture filename for record mode (default: auto-generated) */
  recordFixtureFile?: string;
}

/**
 * Playback statistics (re-exported from AiMockPlayer for convenience).
 */
export type InterceptorPlaybackStats = PlaybackStats;

// ==================== Constants ====================

/**
 * URL patterns for known AI API providers.
 */
const AI_PROVIDER_PATTERNS: ReadonlyArray<{
  pattern: RegExp;
  provider: string;
}> = [
  { pattern: /open\.bigmodel\.cn/i, provider: "zhipu" },
  { pattern: /volcengineapi\.com/i, provider: "doubao-seedream" },
  { pattern: /fashn\.ai/i, provider: "fashn-ai" },
  { pattern: /api\.deepseek\.com/i, provider: "deepseek" },
  { pattern: /dashscope\.aliyuncs\.com/i, provider: "qwen" },
  { pattern: /api\.openai\.com/i, provider: "openai" },
];

/**
 * Header names to sanitize from recordings.
 */
const SENSITIVE_HEADERS = new Set([
  "authorization",
  "api-key",
  "x-api-key",
  "cookie",
  "set-cookie",
]);

// ==================== AiMockInterceptor Class ====================

/**
 * AiMockInterceptor - HTTP interceptor for recording and playing back AI API calls.
 *
 * Usage in test setup:
 *   const interceptor = AiMockInterceptor.createInterceptor('playback');
 *   interceptor.loadFixtures('glm-chat.json', 'try-on-result.json');
 *   interceptor.setupAxiosInterceptor(axiosInstance);
 *   interceptor.setupFetchInterceptor();
 *
 *   // ... run tests ...
 *
 *   interceptor.teardown();
 *
 * Record mode:
 *   const interceptor = AiMockInterceptor.createInterceptor('record');
 *   // ... run tests that make real API calls ...
 *   interceptor.saveRecordings('my-fixture.json');
 *   interceptor.teardown();
 */
export class AiMockInterceptor {
  private readonly mode: InterceptorMode;
  private readonly recorder: AiMockRecorder;
  private readonly player: AiMockPlayer;
  private readonly additionalUrlPatterns: RegExp[];
  private readonly recordFixtureFile: string;

  private readonly interceptedCalls: InterceptedCall[] = [];

  // Interceptor cleanup functions
  private axiosInterceptorIds: Array<{
    instance: AxiosInstance;
    requestId: number;
    responseId: number;
  }> = [];
  private originalFetch: typeof globalThis.fetch | null = null;
  private isActive = false;

  private constructor(options?: InterceptorOptions) {
    this.mode = options?.mode ?? "playback";
    this.additionalUrlPatterns = options?.additionalUrlPatterns ?? [];
    this.recordFixtureFile = options?.recordFixtureFile ?? "";

    this.recorder = new AiMockRecorder({
      fixtureDir: options?.fixtureDir,
      sanitizeKeys: options?.sanitizeKeys,
    });

    this.player = new AiMockPlayer({
      fixtureDir: options?.fixtureDir,
      simulateLatency: options?.simulateLatency,
      throwOnMiss: options?.throwOnMiss,
    });
  }

  // ==================== Factory ====================

  /**
   * Create an interceptor with the specified mode.
   *
   * @param mode - Operating mode: 'record', 'playback', or 'passthrough'
   * @param options - Additional interceptor options
   */
  static createInterceptor(
    mode: InterceptorMode,
    options?: Omit<InterceptorOptions, "mode">,
  ): AiMockInterceptor {
    return new AiMockInterceptor({ ...options, mode });
  }

  // ==================== Lifecycle ====================

  /**
   * Activate the interceptor. Must be called before requests are made.
   */
  activate(): void {
    if (this.isActive) {
      return;
    }

    if (this.mode === "record") {
      this.recorder.startRecording();
    }

    this.isActive = true;
  }

  /**
   * Deactivate the interceptor and clean up all interceptors.
   */
  teardown(): void {
    if (this.mode === "record") {
      this.recorder.stopRecording();
    }

    // Remove axios interceptors
    for (const { instance, requestId, responseId } of this.axiosInterceptorIds) {
      try {
        instance.interceptors.request.eject(requestId);
        instance.interceptors.response.eject(responseId);
      } catch {
        // Ignore errors during cleanup
      }
    }
    this.axiosInterceptorIds = [];

    // Restore original fetch
    if (this.originalFetch !== null) {
      globalThis.fetch = this.originalFetch;
      this.originalFetch = null;
    }

    this.isActive = false;
  }

  // ==================== Fixture Management ====================

  /**
   * Load fixture files for playback mode.
   *
   * @param fixtureNames - One or more fixture filenames to load
   */
  loadFixtures(...fixtureNames: string[]): void {
    for (const name of fixtureNames) {
      this.player.loadFixture(name);
    }
  }

  /**
   * Load all available fixtures from the fixture directory.
   */
  loadAllFixtures(): void {
    this.player.loadAllFixtures();
  }

  /**
   * Save recorded calls to a fixture file (record mode only).
   *
   * @param filePath - Fixture filename
   * @param description - Optional description
   */
  saveRecordings(filePath?: string, description?: string): string {
    if (this.mode !== "record") {
      throw new Error("saveRecordings() is only available in record mode");
    }
    const target = filePath ?? this.recordFixtureFile;
    if (!target) {
      throw new Error(
        "No fixture file specified. Pass a filename or set recordFixtureFile in options.",
      );
    }
    return this.recorder.saveFixture(target, description);
  }

  // ==================== Axios Interceptor ====================

  /**
   * Set up axios interceptors on an AxiosInstance.
   *
   * In record mode: intercepts responses and records them.
   * In playback mode: intercepts requests and returns fixture responses.
   * In passthrough mode: no interception.
   *
   * @param instance - The axios instance to intercept
   */
  setupAxiosInterceptor(instance: AxiosInstance): void {
    if (this.mode === "passthrough") {
      return;
    }

    const requestId = instance.interceptors.request.use(
      (config: InternalAxiosRequestConfig) => this.handleAxiosRequest(config),
      (error: unknown) => Promise.reject(error),
    );

    const responseId = instance.interceptors.response.use(
      (response: AxiosResponse) => this.handleAxiosResponse(response),
      (error: unknown) => this.handleAxiosError(error),
    );

    this.axiosInterceptorIds.push({ instance, requestId, responseId });
  }

  /**
   * Handle an axios request (playback mode intercepts here).
   */
  private async handleAxiosRequest(
    config: InternalAxiosRequestConfig,
  ): Promise<InternalAxiosRequestConfig> {
    if (this.mode !== "playback") {
      return config;
    }

    const url = this.buildAxiosUrl(config);
    if (!this.shouldIntercept(url)) {
      return config;
    }

    const provider = this.detectProvider(url);
    const endpoint = this.extractEndpoint(url);

    try {
      const response = await this.player.playback(
        provider,
        endpoint,
        config.data ? JSON.parse(config.data as string) : null,
      );

      // Create a fake axios response
      const fakeResponse: AxiosResponse = {
        data: response,
        status: 200,
        statusText: "OK",
        headers: {},
        config: config as unknown as InternalAxiosRequestConfig,
      };

      // Throw a special marker to short-circuit the real request
      const shortcut: Error & { __mockResponse: AxiosResponse } = Object.assign(
        new Error("__AI_MOCK_INTERCEPTOR_SHORTCUT__"),
        { __mockResponse: fakeResponse },
      );
      throw shortcut;
    } catch (error) {
      // If it's our shortcut, re-throw it
      if (
        error instanceof Error &&
        error.message === "__AI_MOCK_INTERCEPTOR_SHORTCUT__"
      ) {
        throw error;
      }
      // If player threw a "no match" error, let the request through
      return config;
    }
  }

  /**
   * Handle an axios response (record mode captures here).
   */
  private handleAxiosResponse(response: AxiosResponse): AxiosResponse {
    if (this.mode !== "record") {
      return response;
    }

    const url = this.buildAxiosUrl(response.config);
    if (!this.shouldIntercept(url)) {
      return response;
    }

    const provider = this.detectProvider(url);
    const endpoint = this.extractEndpoint(url);
    const requestBody = this.parseRequestBody(response.config.data);
    const requestHeaders = this.sanitizeHeaders(
      response.config.headers as Record<string, string> ?? {},
    );

    this.recorder.recordCall({
      apiProvider: provider,
      endpoint,
      method: (response.config.method ?? "GET").toUpperCase(),
      request: requestBody,
      response: response.data,
      statusCode: response.status,
      latencyMs: 0, // Latency not easily available from axios response
    });

    this.interceptedCalls.push({
      id: `call-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`,
      provider,
      url,
      method: (response.config.method ?? "GET").toUpperCase(),
      requestHeaders,
      requestBody,
      statusCode: response.status,
      responseHeaders: response.headers as Record<string, string>,
      responseBody: response.data,
      latencyMs: 0,
      timestamp: new Date().toISOString(),
      intercepted: true,
    });

    return response;
  }

  /**
   * Handle an axios error (record mode captures errors too).
   */
  private handleAxiosError(error: unknown): Promise<never> {
    if (
      error instanceof Error &&
      error.message === "__AI_MOCK_INTERCEPTOR_SHORTCUT__"
    ) {
      const mockResponse = (error as unknown as { __mockResponse: AxiosResponse }).__mockResponse;
      return Promise.reject({
        response: mockResponse,
        __isMockInterceptorResponse: true,
      });
    }

    return Promise.reject(error);
  }

  // ==================== Fetch Interceptor ====================

  /**
   * Set up a global fetch interceptor.
   *
   * Replaces globalThis.fetch with an intercepted version.
   * Call teardown() to restore the original fetch.
   */
  setupFetchInterceptor(): void {
    if (this.mode === "passthrough") {
      return;
    }

    if (this.originalFetch !== null) {
      // Already intercepted
      return;
    }

    this.originalFetch = globalThis.fetch;
    const self = this;

    globalThis.fetch = async function interceptedFetch(
      input: RequestInfo | URL,
      init?: RequestInit,
    ): Promise<Response> {
      const url = typeof input === "string"
        ? input
        : input instanceof URL
          ? input.toString()
          : (input).url;

      if (!self.shouldIntercept(url)) {
        return self.originalFetch!.call(globalThis, input, init);
      }

      const provider = self.detectProvider(url);
      const endpoint = self.extractEndpoint(url);
      const method = init?.method ?? "GET";
      const requestBody = init?.body ? self.parseRequestBody(init.body) : null;

      // Record mode: forward and capture
      if (self.mode === "record") {
        const startTime = Date.now();
        const response = await self.originalFetch!.call(globalThis, input, init);
        const latencyMs = Date.now() - startTime;

        const clonedResponse = response.clone();
        const responseBody = await clonedResponse.json().catch(() => null);

        self.recorder.recordCall({
          apiProvider: provider,
          endpoint,
          method,
          request: requestBody,
          response: responseBody,
          statusCode: response.status,
          latencyMs,
        });

        self.interceptedCalls.push({
          id: `call-${Date.now()}-${Math.random().toString(36).substring(2, 8)}`,
          provider,
          url,
          method,
          requestHeaders: {},
          requestBody,
          statusCode: response.status,
          responseHeaders: Object.fromEntries(response.headers.entries()),
          responseBody,
          latencyMs,
          timestamp: new Date().toISOString(),
          intercepted: true,
        });

        return response;
      }

      // Playback mode: return fixture response
      try {
        const mockResponse = await self.player.playback(
          provider,
          endpoint,
          requestBody,
        );

        return new Response(JSON.stringify(mockResponse), {
          status: 200,
          statusText: "OK",
          headers: { "Content-Type": "application/json" },
        });
      } catch (error) {
        if (self.player.getPlaybackStats().misses > 0) {
          // No match found - fall through to real API if allowed
          return self.originalFetch!.call(globalThis, input, init);
        }
        throw error;
      }
    };
  }

  // ==================== Query Methods ====================

  /**
   * Get all recorded/intercepted API calls.
   */
  getRecordedCalls(): ReadonlyArray<InterceptedCall> {
    return this.interceptedCalls;
  }

  /**
   * Get playback statistics (playback mode only).
   */
  getPlaybackStats(): InterceptorPlaybackStats {
    return this.player.getPlaybackStats();
  }

  /**
   * Get the current operating mode.
   */
  get currentMode(): InterceptorMode {
    return this.mode;
  }

  /**
   * Check if the interceptor is currently active.
   */
  get isInterceptorActive(): boolean {
    return this.isActive;
  }

  /**
   * Get the number of intercepted calls.
   */
  get interceptedCallCount(): number {
    return this.interceptedCalls.length;
  }

  // ==================== Provider Detection ====================

  /**
   * Detect the API provider from a URL.
   */
  private detectProvider(url: string): string {
    for (const { pattern, provider } of AI_PROVIDER_PATTERNS) {
      if (pattern.test(url)) {
        return provider;
      }
    }
    return "unknown";
  }

  /**
   * Check if a URL should be intercepted.
   */
  private shouldIntercept(url: string): boolean {
    // Check known AI provider patterns
    for (const { pattern } of AI_PROVIDER_PATTERNS) {
      if (pattern.test(url)) {
        return true;
      }
    }

    // Check additional URL patterns
    for (const pattern of this.additionalUrlPatterns) {
      if (pattern.test(url)) {
        return true;
      }
    }

    return false;
  }

  /**
   * Extract a normalized endpoint path from a URL.
   */
  private extractEndpoint(url: string): string {
    try {
      const parsed = new URL(url);
      return parsed.pathname;
    } catch {
      return url;
    }
  }

  // ==================== Utilities ====================

  /**
   * Build the full URL from an axios request config.
   */
  private buildAxiosUrl(config: AxiosRequestConfig): string {
    if (config.url?.startsWith("http")) {
      return config.url;
    }
    const baseURL = config.baseURL ?? "";
    return `${baseURL}${config.url ?? ""}`;
  }

  /**
   * Parse a request body (string, Buffer, or object).
   */
  private parseRequestBody(body: unknown): unknown {
    if (body === null || body === undefined) {
      return null;
    }

    if (typeof body === "string") {
      try {
        return JSON.parse(body);
      } catch {
        return body;
      }
    }

    if (body instanceof ArrayBuffer || body instanceof Uint8Array) {
      return "[Binary data]";
    }

    if (typeof body === "object") {
      return body;
    }

    return body;
  }

  /**
   * Sanitize sensitive headers from a headers object.
   */
  private sanitizeHeaders(
    headers: Record<string, string>,
  ): Record<string, string> {
    const result: Record<string, string> = {};
    for (const [key, value] of Object.entries(headers)) {
      if (SENSITIVE_HEADERS.has(key.toLowerCase())) {
        result[key] = "[REDACTED]";
      } else {
        result[key] = value;
      }
    }
    return result;
  }
}

/**
 * @fileoverview AI Mock Player - Playback recorded AI API responses from fixtures.
 *
 * Loads fixture files recorded by AiMockRecorder and provides deterministic
 * response playback for tests. Supports:
 *   - Fuzzy matching (ignores timestamps, request IDs)
 *   - Delayed playback (simulates real API latency)
 *   - Sequential responses (for conversation flows)
 *   - Multiple fixture loading and cross-fixture matching
 *
 * @module AiMockPlayer
 */

import * as crypto from "crypto";
import * as fs from "fs";
import * as path from "path";

import type { RecordedCall, FixtureFile } from "./ai-mock-recorder";

// ==================== Types ====================

/**
 * Options for the mock player.
 */
export interface PlayerOptions {
  /** Base directory for fixture files (default: test/fixtures/ai-responses) */
  fixtureDir?: string;
  /** Whether to simulate real API latency (default: false) */
  simulateLatency?: boolean;
  /** Latency multiplier for simulated delay (default: 1.0 = use recorded latency) */
  latencyMultiplier?: number;
  /** Minimum simulated latency in ms (default: 0) */
  minLatencyMs?: number;
  /** Maximum simulated latency in ms (default: 5000) */
  maxLatencyMs?: number;
  /** Whether to throw on unmatched requests (default: true) */
  throwOnMiss?: boolean;
  /** Whether to use fuzzy matching (default: true) */
  fuzzyMatch?: boolean;
}

/**
 * Playback statistics for monitoring test behavior.
 */
export interface PlaybackStats {
  /** Total number of playback attempts */
  totalAttempts: number;
  /** Number of successful matches */
  hits: number;
  /** Number of failed matches */
  misses: number;
  /** Number of errors during playback */
  errors: number;
  /** Hit rate as a fraction (0-1) */
  hitRate: number;
  /** Average match latency in ms */
  avgMatchLatencyMs: number;
  /** Provider-specific stats */
  byProvider: Record<string, ProviderStats>;
}

/**
 * Per-provider playback statistics.
 */
export interface ProviderStats {
  attempts: number;
  hits: number;
  misses: number;
  errors: number;
}

/**
 * A loaded fixture with its recordings indexed for fast lookup.
 */
interface IndexedFixture {
  fixture: FixtureFile;
  /** Recordings indexed by fingerprint */
  byFingerprint: Map<string, RecordedCall>;
  /** Recordings indexed by provider+endpoint, ordered by recording time */
  byProviderEndpoint: Map<string, RecordedCall[]>;
}

/**
 * Result of a playback attempt.
 */
export interface PlaybackResult {
  /** The matched response */
  response: unknown;
  /** Whether the match was exact or fuzzy */
  matchType: "exact" | "fuzzy" | "sequential";
  /** The fingerprint that was matched */
  matchedFingerprint: string;
  /** Simulated delay applied (0 if no delay) */
  simulatedDelayMs: number;
  /** The provider that was matched */
  provider: string;
}

// ==================== Constants ====================

const DEFAULT_FIXTURE_DIR = path.resolve(
  __dirname,
  "..",
  "fixtures",
  "ai-responses",
);

/**
 * Fields to ignore during fuzzy matching (they change between calls).
 */
const FUZZY_IGNORE_FIELDS = new Set([
  "request_id",
  "requestId",
  "timestamp",
  "created",
  "created_at",
  "completed_at",
  "nonce",
  "seed",
  "id",
  "task_id",
  "run_id",
]);

// ==================== AiMockPlayer Class ====================

/**
 * AiMockPlayer - Loads fixture files and plays back recorded AI responses.
 *
 * Usage:
 *   const player = new AiMockPlayer({ simulateLatency: true });
 *   player.loadFixture("glm-chat.json");
 *   player.loadFixture("doubao-seedream.json");
 *
 *   // In tests:
 *   const response = await player.playback("zhipu", "/chat/completions", requestPayload);
 *
 * Or load all fixtures at once:
 *   player.loadAllFixtures(); // loads all JSON files from fixture dir
 */
export class AiMockPlayer {
  private readonly fixtureDir: string;
  private readonly simulateLatency: boolean;
  private readonly latencyMultiplier: number;
  private readonly minLatencyMs: number;
  private readonly maxLatencyMs: number;
  private readonly throwOnMiss: boolean;
  private readonly fuzzyMatch: boolean;

  private readonly indexedFixtures: IndexedFixture[] = [];
  private readonly sequentialCursors: Map<string, number> = new Map();

  // Playback statistics
  private totalAttempts = 0;
  private hits = 0;
  private misses = 0;
  private errors = 0;
  private totalMatchLatencyMs = 0;
  private readonly providerStats: Record<string, ProviderStats> = {};

  constructor(options?: PlayerOptions) {
    this.fixtureDir = options?.fixtureDir ?? DEFAULT_FIXTURE_DIR;
    this.simulateLatency = options?.simulateLatency ?? false;
    this.latencyMultiplier = options?.latencyMultiplier ?? 1.0;
    this.minLatencyMs = options?.minLatencyMs ?? 0;
    this.maxLatencyMs = options?.maxLatencyMs ?? 5000;
    this.throwOnMiss = options?.throwOnMiss ?? true;
    this.fuzzyMatch = options?.fuzzyMatch ?? true;
  }

  // ==================== Fixture Loading ====================

  /**
   * Load a single fixture file.
   *
   * @param filePath - Relative filename or absolute path
   * @throws Error if file does not exist or is invalid
   */
  loadFixture(filePath: string): FixtureFile {
    const absolutePath = this.resolveFixturePath(filePath);

    if (!fs.existsSync(absolutePath)) {
      throw new Error(`Fixture file not found: ${absolutePath}`);
    }

    const raw = fs.readFileSync(absolutePath, "utf-8");
    const fixture = JSON.parse(raw) as FixtureFile;

    if (fixture.version !== 1) {
      throw new Error(
        `Unsupported fixture version: ${fixture.version}. Expected: 1`,
      );
    }

    const indexed = this.indexFixture(fixture);
    this.indexedFixtures.push(indexed);

    return fixture;
  }

  /**
   * Load all fixture files from a directory.
   *
   * @param directory - Directory to scan (defaults to fixture dir)
   * @returns Array of loaded fixture files
   */
  loadAllFixtures(directory?: string): FixtureFile[] {
    const dir = directory ?? this.fixtureDir;

    if (!fs.existsSync(dir)) {
      throw new Error(`Fixture directory not found: ${dir}`);
    }

    const entries = fs.readdirSync(dir);
    const jsonFiles = entries.filter(
      (entry) => entry.endsWith(".json") && !entry.startsWith("_"),
    );

    const loaded: FixtureFile[] = [];
    for (const file of jsonFiles) {
      try {
        const fixture = this.loadFixture(path.resolve(dir, file));
        loaded.push(fixture);
      } catch (error) {
        // Skip invalid fixture files with a warning
        const message = error instanceof Error ? error.message : String(error);
        console.warn(`Skipping invalid fixture ${file}: ${message}`);
      }
    }

    return loaded;
  }

  /**
   * Clear all loaded fixtures and reset state.
   */
  clearFixtures(): void {
    this.indexedFixtures.length = 0;
    this.sequentialCursors.clear();
  }

  /**
   * Get the number of loaded fixtures.
   */
  get loadedFixtureCount(): number {
    return this.indexedFixtures.length;
  }

  /**
   * Get the total number of available recordings across all fixtures.
   */
  get totalRecordings(): number {
    return this.indexedFixtures.reduce(
      (sum, idx) => sum + idx.fixture.recordings.length,
      0,
    );
  }

  // ==================== Playback ====================

  /**
   * Find a matching recorded response for the given request.
   *
   * Matching strategy (in order):
   *   1. Exact fingerprint match
   *   2. Fuzzy match (ignoring volatile fields)
   *   3. Sequential match (next recording for the same provider+endpoint)
   *
   * @param apiProvider - Provider name
   * @param endpoint - API endpoint
   * @param request - Request payload
   * @returns The matched response, or throws if no match found
   */
  async playback(
    provider: string,
    endpoint: string,
    request: unknown,
  ): Promise<unknown> {
    const startTime = Date.now();
    this.totalAttempts++;
    this.ensureProviderStats(provider);

    try {
      // Strategy 1: Exact fingerprint match
      const fingerprint = this.computeFingerprint(provider, endpoint, request);
      const exactMatch = this.findByFingerprint(fingerprint);
      if (exactMatch) {
        this.recordHit(provider, Date.now() - startTime);
        const delay = await this.applyLatency(exactMatch.latencyMs);
        return exactMatch.response;
      }

      // Strategy 2: Fuzzy match
      if (this.fuzzyMatch) {
        const fuzzyMatch = this.findFuzzyMatch(provider, endpoint, request);
        if (fuzzyMatch) {
          this.recordHit(provider, Date.now() - startTime);
          const delay = await this.applyLatency(fuzzyMatch.latencyMs);
          return fuzzyMatch.response;
        }
      }

      // Strategy 3: Sequential match
      const sequentialMatch = this.findSequentialMatch(provider, endpoint);
      if (sequentialMatch) {
        this.recordHit(provider, Date.now() - startTime);
        const delay = await this.applyLatency(sequentialMatch.latencyMs);
        return sequentialMatch.response;
      }

      // No match found
      this.recordMiss(provider);
      if (this.throwOnMiss) {
        throw new Error(
          `No matching fixture found for ${provider} ${endpoint}. ` +
          `Available recordings: ${this.totalRecordings}. ` +
          `Request fingerprint: ${fingerprint}`,
        );
      }
      return null;
    } catch (error) {
      if (error instanceof Error && error.message.includes("No matching fixture")) {
        throw error;
      }
      this.recordError(provider);
      throw error;
    }
  }

  /**
   * Synchronous version of playback for simpler test scenarios.
   *
   * Note: Does not support latency simulation.
   */
  playbackSync(
    provider: string,
    endpoint: string,
    request: unknown,
  ): unknown {
    this.totalAttempts++;
    this.ensureProviderStats(provider);

    // Exact fingerprint match
    const fingerprint = this.computeFingerprint(provider, endpoint, request);
    const exactMatch = this.findByFingerprint(fingerprint);
    if (exactMatch) {
      this.recordHit(provider, 0);
      return exactMatch.response;
    }

    // Fuzzy match
    if (this.fuzzyMatch) {
      const fuzzyMatch = this.findFuzzyMatch(provider, endpoint, request);
      if (fuzzyMatch) {
        this.recordHit(provider, 0);
        return fuzzyMatch.response;
      }
    }

    // Sequential match
    const sequentialMatch = this.findSequentialMatch(provider, endpoint);
    if (sequentialMatch) {
      this.recordHit(provider, 0);
      return sequentialMatch.response;
    }

    this.recordMiss(provider);
    if (this.throwOnMiss) {
      throw new Error(
        `No matching fixture found for ${provider} ${endpoint}. ` +
        `Request fingerprint: ${fingerprint}`,
      );
    }
    return null;
  }

  /**
   * Match a response without playing it back (for assertion purposes).
   */
  matchResponse(
    apiProvider: string,
    endpoint: string,
    request: unknown,
  ): RecordedCall | null {
    // Exact match
    const fingerprint = this.computeFingerprint(apiProvider, endpoint, request);
    const exactMatch = this.findByFingerprint(fingerprint);
    if (exactMatch) {
      return exactMatch;
    }

    // Fuzzy match
    if (this.fuzzyMatch) {
      return this.findFuzzyMatch(apiProvider, endpoint, request);
    }

    return null;
  }

  // ==================== Statistics ====================

  /**
   * Get playback statistics.
   */
  getPlaybackStats(): PlaybackStats {
    const hitRate = this.totalAttempts > 0
      ? this.hits / this.totalAttempts
      : 0;

    const avgMatchLatencyMs = this.hits > 0
      ? this.totalMatchLatencyMs / this.hits
      : 0;

    return {
      totalAttempts: this.totalAttempts,
      hits: this.hits,
      misses: this.misses,
      errors: this.errors,
      hitRate,
      avgMatchLatencyMs,
      byProvider: { ...this.providerStats },
    };
  }

  /**
   * Reset playback statistics.
   */
  resetStats(): void {
    this.totalAttempts = 0;
    this.hits = 0;
    this.misses = 0;
    this.errors = 0;
    this.totalMatchLatencyMs = 0;
    this.sequentialCursors.clear();
    for (const key of Object.keys(this.providerStats)) {
      this.providerStats[key] = { attempts: 0, hits: 0, misses: 0, errors: 0 };
    }
  }

  // ==================== Matching Strategies ====================

  /**
   * Find a recording by exact fingerprint.
   */
  private findByFingerprint(fingerprint: string): RecordedCall | null {
    for (const indexed of this.indexedFixtures) {
      const match = indexed.byFingerprint.get(fingerprint);
      if (match) {
        return match;
      }
    }
    return null;
  }

  /**
   * Find a recording using fuzzy matching.
   *
   * Compares normalized versions of request payloads, ignoring
   * volatile fields like timestamps and request IDs.
   */
  private findFuzzyMatch(
    provider: string,
    endpoint: string,
    request: unknown,
  ): RecordedCall | null {
    const normalizedRequest = this.normalizeForComparison(request);

    for (const indexed of this.indexedFixtures) {
      const key = `${provider}:${endpoint}`;
      const candidates = indexed.byProviderEndpoint.get(key);

      if (!candidates) {
        continue;
      }

      for (const candidate of candidates) {
        const normalizedCandidate = this.normalizeForComparison(candidate.request);
        if (this.deepEquals(normalizedRequest, normalizedCandidate)) {
          return candidate;
        }
      }
    }

    return null;
  }

  /**
   * Find the next sequential recording for a provider+endpoint.
   *
   * Useful for conversation flows where each call returns a different
   * response in sequence.
   */
  private findSequentialMatch(
    provider: string,
    endpoint: string,
  ): RecordedCall | null {
    const key = `${provider}:${endpoint}`;
    const cursor = this.sequentialCursors.get(key) ?? 0;

    for (const indexed of this.indexedFixtures) {
      const candidates = indexed.byProviderEndpoint.get(key);
      if (!candidates || candidates.length === 0) {
        continue;
      }

      if (cursor < candidates.length) {
        const match = candidates[cursor]!;
        this.sequentialCursors.set(key, cursor + 1);
        return match;
      }
    }

    return null;
  }

  // ==================== Indexing ====================

  /**
   * Index a fixture for fast lookup.
   */
  private indexFixture(fixture: FixtureFile): IndexedFixture {
    const byFingerprint = new Map<string, RecordedCall>();
    const byProviderEndpoint = new Map<string, RecordedCall[]>();

    for (const recording of fixture.recordings) {
      // Index by fingerprint
      byFingerprint.set(recording.fingerprint, recording);

      // Index by provider+endpoint
      const key = `${recording.apiProvider}:${recording.endpoint}`;
      const existing = byProviderEndpoint.get(key) ?? [];
      existing.push(recording);
      byProviderEndpoint.set(key, existing);
    }

    return { fixture, byFingerprint, byProviderEndpoint };
  }

  // ==================== Normalization & Comparison ====================

  /**
   * Compute a fingerprint for a request (same algorithm as AiMockRecorder).
   */
  private computeFingerprint(
    provider: string,
    endpoint: string,
    request: unknown,
  ): string {
    const normalized = this.normalizeForFingerprint(request);
    const input = `${provider}|${endpoint}|${JSON.stringify(normalized)}`;
    return crypto.createHash("sha256").update(input).digest("hex");
  }

  /**
   * Normalize a request payload for fingerprinting.
   */
  private normalizeForFingerprint(payload: unknown): unknown {
    if (payload === null || payload === undefined) {
      return null;
    }

    if (typeof payload !== "object") {
      return payload;
    }

    if (Array.isArray(payload)) {
      return payload.map((item) => this.normalizeForFingerprint(item));
    }

    const obj = payload as Record<string, unknown>;
    const volatileKeys = new Set([
      "request_id",
      "requestId",
      "timestamp",
      "nonce",
      "seed",
      "stream",
    ]);

    const result: Record<string, unknown> = {};
    const sortedKeys = Object.keys(obj).sort();

    for (const key of sortedKeys) {
      if (volatileKeys.has(key)) {
        continue;
      }
      result[key] = this.normalizeForFingerprint(obj[key]);
    }

    return result;
  }

  /**
   * Normalize a payload for fuzzy comparison, stripping volatile fields.
   */
  private normalizeForComparison(payload: unknown): unknown {
    if (payload === null || payload === undefined) {
      return null;
    }

    if (typeof payload !== "object") {
      return payload;
    }

    if (Array.isArray(payload)) {
      return payload.map((item) => this.normalizeForComparison(item));
    }

    const obj = payload as Record<string, unknown>;
    const result: Record<string, unknown> = {};
    const sortedKeys = Object.keys(obj).sort();

    for (const key of sortedKeys) {
      if (FUZZY_IGNORE_FIELDS.has(key)) {
        continue;
      }
      result[key] = this.normalizeForComparison(obj[key]);
    }

    return result;
  }

  /**
   * Deep equality comparison for normalized payloads.
   */
  private deepEquals(a: unknown, b: unknown): boolean {
    if (a === b) {
      return true;
    }

    if (a === null || b === null) {
      return a === b;
    }

    if (typeof a !== typeof b) {
      return false;
    }

    if (typeof a !== "object") {
      return a === b;
    }

    if (Array.isArray(a) && Array.isArray(b)) {
      if (a.length !== b.length) {
        return false;
      }
      return a.every((item, index) => this.deepEquals(item, b[index]));
    }

    if (Array.isArray(a) || Array.isArray(b)) {
      return false;
    }

    const objA = a as Record<string, unknown>;
    const objB = b as Record<string, unknown>;
    const keysA = Object.keys(objA);
    const keysB = Object.keys(objB);

    if (keysA.length !== keysB.length) {
      return false;
    }

    return keysA.every(
      (key) => Object.prototype.hasOwnProperty.call(objB, key) &&
        this.deepEquals(objA[key], objB[key]),
    );
  }

  // ==================== Latency Simulation ====================

  /**
   * Apply simulated latency based on recorded response time.
   *
   * @returns The actual delay applied in ms
   */
  private async applyLatency(recordedLatencyMs: number): Promise<number> {
    if (!this.simulateLatency) {
      return 0;
    }

    let delay = recordedLatencyMs * this.latencyMultiplier;
    delay = Math.max(delay, this.minLatencyMs);
    delay = Math.min(delay, this.maxLatencyMs);

    if (delay > 0) {
      await new Promise((resolve) => setTimeout(resolve, delay));
    }

    return delay;
  }

  // ==================== Statistics Helpers ====================

  private ensureProviderStats(provider: string): void {
    if (!this.providerStats[provider]) {
      this.providerStats[provider] = { attempts: 0, hits: 0, misses: 0, errors: 0 };
    }
    this.providerStats[provider].attempts++;
  }

  private recordHit(provider: string, matchLatencyMs: number): void {
    this.hits++;
    this.totalMatchLatencyMs += matchLatencyMs;
    if (this.providerStats[provider]) {
      this.providerStats[provider].hits++;
    }
  }

  private recordMiss(provider: string): void {
    this.misses++;
    if (this.providerStats[provider]) {
      this.providerStats[provider].misses++;
    }
  }

  private recordError(provider: string): void {
    this.errors++;
    if (this.providerStats[provider]) {
      this.providerStats[provider].errors++;
    }
  }

  // ==================== Path Resolution ====================

  /**
   * Resolve a fixture path to an absolute path.
   */
  private resolveFixturePath(filePath: string): string {
    if (path.isAbsolute(filePath)) {
      return filePath;
    }
    return path.resolve(this.fixtureDir, filePath);
  }
}

